import { useState, useEffect } from "react";
import { ShieldCheck, Loader2, ArrowRight } from "lucide-react";
import OTPInput from "./OTPInput";
import { verifyRegistrationOTP, resendVerification } from "@/Service/Auth";
import axios from "axios";
import { useNavigate } from "react-router-dom";

interface EmailVerificationModalProps {
  isOpen: boolean;
  email: string;
  employeeDbId?: number;
  redirectToLogin?: boolean;
  onSuccess?: () => void;
}

export default function EmailVerificationModal({ isOpen, email, employeeDbId, redirectToLogin, onSuccess }: EmailVerificationModalProps) {
  const navigate = useNavigate();
  const [otp, setOtp] = useState("");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);
  const [resendTimer, setResendTimer] = useState(0);
  const [verifiedData, setVerifiedData] = useState<{ email: string; employeeId: string; fullName: string } | null>(null);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (resendTimer > 0) {
      interval = setInterval(() => {
        setResendTimer((prev) => prev - 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [resendTimer]);

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.length !== 6) {
        setError("Please enter a valid 6-digit code.");
        return;
    }

    setLoading(true);
    setError("");
    setSuccess("");

    try {
        const response = await verifyRegistrationOTP({ email, otp });
        const user = response.data.data;
        
        setSuccess("Account verified successfully!");
        setVerifiedData({
            email: email,
            employeeId: user?.employeeId || "Pending",
            fullName: `${user?.firstName || ''} ${user?.lastName || ''}`.trim()
        });

        if (onSuccess) {
            onSuccess();
        }
    } catch (err: unknown) {
        console.error("Verification error:", err);
        const msg = axios.isAxiosError(err) ? (err.response?.data as { message?: string })?.message : undefined;
        setError(msg || "Verification failed. Please try again.");
    } finally {
        setLoading(false);
    }
  };

  const handleResend = async () => {
      if (resendTimer > 0) return;
      
      try {
          await resendVerification({ email });
          setResendTimer(60);
          setSuccess("Verification code sent to your email.");
          setError("");
      } catch (err: unknown) {
          console.error("Resend error:", err);
          setError("Failed to resend code. Please try again.");
      }
  };

  if (verifiedData) {
    return (
      <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
        <div className="bg-white rounded-[24px] shadow-2xl max-w-md w-full p-8 animate-in zoom-in duration-300">
          <div className="space-y-8 text-center">
            <div className="mx-auto w-20 h-20 bg-green-100 rounded-full flex items-center justify-center shadow-inner">
              <ShieldCheck className="h-10 w-10 text-green-600" />
            </div>
            
            <div className="space-y-2">
              <h3 className="text-2xl font-black text-gray-900">You're all set!</h3>
              <p className="text-sm text-gray-500 font-medium italic">Your account has been successfully verified and activated.</p>
            </div>

            <div className="bg-gray-50 rounded-2xl p-6 border border-gray-100 space-y-4 text-left shadow-sm">
              <div className="flex justify-between items-center border-b border-gray-200 pb-3">
                <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Employee ID</span>
                <span className="text-sm font-bold text-gray-900 font-mono tracking-tighter bg-white px-2 py-0.5 rounded border border-gray-100 shadow-sm">{verifiedData.employeeId}</span>
              </div>
              <div className="flex justify-between items-center border-b border-gray-200 pb-3">
                <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Full Name</span>
                <span className="text-sm font-bold text-gray-900">{verifiedData.fullName}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Login Email</span>
                <span className="text-sm font-bold text-gray-900">{verifiedData.email}</span>
              </div>
            </div>

            <div className="space-y-4 pt-4">
              {redirectToLogin ? (
                <button
                  onClick={() => navigate("/login")}
                  className="w-full bg-gray-900 text-white py-4 rounded-xl font-black text-sm tracking-tight hover:bg-gray-800 transition shadow-lg shadow-gray-200 flex justify-center items-center gap-3 active:scale-95 group"
                >
                  Go to Login
                  <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
                </button>
              ) : employeeDbId ? (
                <button
                  onClick={() => navigate(`/admin-dashboard/employees/profile/${employeeDbId}`)}
                  className="w-full bg-blue-600 text-white py-4 rounded-xl font-black text-sm tracking-tight hover:bg-blue-700 transition shadow-lg shadow-blue-200 flex justify-center items-center gap-3 active:scale-95 group"
                >
                  View Employee Profile
                  <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
                </button>
              ) : (
                <button
                  onClick={() => navigate("/login")}
                  className="w-full bg-gray-900 text-white py-4 rounded-xl font-black text-sm tracking-tight hover:bg-gray-800 transition shadow-lg shadow-gray-200 flex justify-center items-center gap-3 active:scale-95 group"
                >
                  Go to Login
                  <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
                </button>
              )}
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                {redirectToLogin 
                  ? "Access your Administrator / HR portal"
                  : employeeDbId 
                  ? "Redirection available for Administrator" 
                  : "Admin will grant access to your portal soon"}
              </p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="bg-white rounded-[24px] shadow-2xl max-w-md w-full p-8 animate-in zoom-in duration-300">
        <div className="space-y-6">
          <div className="text-center space-y-3">
              <div className="mx-auto w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center shadow-inner">
                  <ShieldCheck className="h-8 w-8 text-blue-600" />
              </div>
              <div>
                <h3 className="text-xl font-bold text-gray-900">Verify Your Account</h3>
                <p className="text-sm text-gray-500 mt-1">
                    We've sent a 6-digit code to <br/>
                    <span className="font-bold text-gray-900 underline underline-offset-4 decoration-blue-200">{email}</span>
                </p>
              </div>
          </div>

          {error && (
              <div className="p-3 bg-red-50 border border-red-200 rounded-xl text-red-700 text-[13px] font-semibold animate-in fade-in slide-in-from-top-2 text-center">
                  {error}
              </div>
          )}

          {success && (
              <div className="p-3 bg-green-50 border border-green-200 rounded-xl text-green-700 text-[13px] font-semibold animate-in fade-in slide-in-from-top-2 text-center">
                  {success}
              </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
              <div className="bg-gray-50/50 p-6 rounded-2xl border border-gray-100 shadow-inner">
                <OTPInput length={6} value={otp} onChange={setOtp} />
              </div>
              
              <button
                  type="submit"
                  disabled={loading || otp.length !== 6 || !!success}
                  className="w-full bg-gray-900 text-white py-4 rounded-xl font-bold hover:bg-gray-800 transition disabled:opacity-50 disabled:cursor-not-allowed shadow-xl shadow-gray-200 flex justify-center items-center gap-2 active:scale-95 group"
              >
                  {loading ? (
                      <>
                          <Loader2 className="animate-spin h-5 w-5" />
                          Verifying...
                      </>
                  ) : (
                      <>
                          Verify and Complete
                          <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
                      </>
                  )}
              </button>
          </form>

          <div className="text-center pt-2">
              <p className="text-sm text-gray-500 font-medium">
                  Didn't receive the code?{" "}
                  <button
                      type="button"
                      onClick={handleResend}
                      disabled={resendTimer > 0}
                      className="font-bold text-blue-600 hover:text-blue-500 disabled:opacity-50 disabled:cursor-not-allowed hover:underline transition-colors"
                  >
                      {resendTimer > 0 ? `Resend in ${resendTimer}s` : "Resend Now"}
                  </button>
              </p>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, FormEvent } from "react";
import { Link } from "react-router-dom";
import { Mail, ArrowLeft, Loader2, CheckCircle } from "lucide-react";
import AuthLayout from "@components/Custom/Auth/AuthLayout";
import { forgotPassword } from "@/Service/Auth";
import axios from "axios";
import SEO from "@/components/Global/SEO";

export default function ForgotPassword() {
  const [email, setEmail] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSent, setIsSent] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    if (!email) return;

    setIsSubmitting(true);
    setError("");

    try {
      await forgotPassword({ email });
      setIsSent(true);
    } catch (err: unknown) {
      const msg = axios.isAxiosError(err) ? err.response?.data?.message : undefined;
      setError(msg || "Failed to send reset email. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <AuthLayout title="Reset Password">
      <SEO 
        title="Forgot Password"
        description="Reset your NEBR account password. Follow the instructions sent to your email."
      />
      <div className="space-y-6">
        <div className="text-center">
          <p className="text-gray-500 mt-2">
            Enter your email address and we'll send you a link to reset your password.
          </p>
        </div>

        {isSent ? (
          <div className="text-center space-y-4 animate-in fade-in zoom-in duration-300">
            <div className="flex items-center space-x-2 justify-center">
              <div className="w-10 h-10 bg-green-600 rounded-xl flex items-center justify-center transform group-hover:rotate-12 transition-transform duration-300 shadow-lg shadow-green-200">
                <span className="text-white font-black text-xl italic tracking-tighter">CM</span>
              </div>
              <span className="text-2xl font-black text-gray-900 tracking-tight group-hover:text-green-600 transition-colors">
                CHRMO <span className="text-green-600 font-extrabold">Mey</span>
              </span>
            </div>
            <div className="mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center">
              <CheckCircle className="h-8 w-8 text-green-600" />
            </div>
            <h3 className="text-lg font-medium text-gray-900">Check your email</h3>
            <p className="text-gray-500 text-sm">
              We have sent a password reset link to <strong>{email}</strong>.
            </p>
            <div className="pt-4">
              <Link
                to="/login"
                className="text-sm font-medium text-blue-600 hover:text-blue-500 flex items-center justify-center gap-2"
              >
                <ArrowLeft size={16} />
                Back to Sign In
              </Link>
            </div>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="space-y-6">
            {error && (
              <div className="p-3 bg-red-50 border border-red-200 rounded-lg text-red-700 text-sm">
                {error}
              </div>
            )}

            <div>
              <label className="text-sm font-medium text-gray-700 mb-1 block">Email Address</label>
              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Mail className="h-5 w-5 text-gray-400 group-focus-within:text-blue-500 transition-colors" />
                </div>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="block w-full pl-10 pr-3 py-2.5 border border-gray-300 rounded-xl bg-gray-50 text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all"
                  placeholder="Enter your email"
                  required
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={isSubmitting}
              className="w-full flex justify-center items-center py-2.5 px-4 border border-transparent rounded-xl shadow-sm text-sm font-semibold text-white bg-slate-900 hover:bg-slate-800 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-slate-900 disabled:opacity-70 disabled:cursor-not-allowed transition-all"
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="animate-spin -ml-1 mr-2 h-4 w-4" />
                  Sending Link...
                </>
              ) : (
                "Send Reset Link"
              )}
            </button>

            <div className="text-center">
              <Link
                to="/login"
                className="text-sm font-medium text-gray-600 hover:text-gray-900 flex items-center justify-center gap-2"
              >
                <ArrowLeft size={16} />
                Back to Sign In
              </Link>
            </div>
          </form>
        )}
      </div>
    </AuthLayout>
  );
}

import { useState, FormEvent, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { Mail, Lock, Eye, EyeOff, Loader2, CheckCircle, ArrowLeft } from "lucide-react";
import AuthLayout from "@/components/Custom/Auth/AuthLayout";
import { useAuthStore, useToastStore, useFormWizardStore } from "@/stores";
import api from "@/api/axios";
import axios, { AxiosError } from "axios";
import OTPInput from "./OTPInput";
import { User, ApiError } from "@/types";
import { useVerify2FAMutation, useResend2FAMutation } from "@/hooks/useAuthQueries";

interface AuthData {
  requires2FA?: boolean;
  maskedEmail?: string;
  identifier?: string;
  token?: string;
  user?: User;
}

interface AuthPayload {
  success: boolean;
  data: AuthData;
  message?: string;
}

interface SetupPositionsResponse {
  positions: Array<{ id: number; positionTitle: string }>;
}

const Login: React.FC = () => {
  const navigate = useNavigate();
  const setUser = useAuthStore((state) => state.setUser);
  const logout = useAuthStore((state) => state.logout);
  const resetWizard = useFormWizardStore((state) => state.resetWizard);
  const showToast = useToastStore((state) => state.showToast);

  const [identifier, setIdentifier] = useState("");
  const [password, setPassword] = useState("");
  const [rememberMe, setRememberMe] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  
  // 2FA state
  const [show2FA, setShow2FA] = useState(false);
  const [maskedEmail, setMaskedEmail] = useState("");
  const [loginIdentifier, setLoginIdentifier] = useState("");
  const [otpValue, setOtpValue] = useState("");

  const verify2FAMutation = useVerify2FAMutation();
  const resend2FAMutation = useResend2FAMutation();

  const [showSetupLink, setShowSetupLink] = useState(false);

  useEffect(() => {
    const checkSetup = async (): Promise<void> => {
      try {
        const res = await api.get<SetupPositionsResponse>("/auth/setup-positions");
        if (res.data.positions && res.data.positions.length > 0) {
          setShowSetupLink(true);
        }
      } catch (err: unknown) {
        // Fallback or log if needed, though link is permanent now
        console.error("Setup check failed", err);
      }
    };
    checkSetup();
  }, []);

  /**
   * 100% Client-Side Cleanup:
   * Wipes all persistent data before entering setup to prevent data leaks or state conflicts.
   */
  const handleSetupClick = (e: React.MouseEvent) => {
    // Prevent default Link behavior to handle cleanup first
    e.preventDefault();

    // 1. Clear Zustand Stores
    logout(); // Resets authStore
    resetWizard(); // Resets registration/PDS wizard

    // 2. Wipe Browser Storage
    localStorage.clear();
    sessionStorage.clear();

    // 3. Force redirect to setup
    navigate("/setup-portal");
  };

  const handleLogin = async (e: FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const response = await api.post<AuthPayload>("/auth/login", { 
        identifier, 
        password,
        rememberMe 
      });
      
      const payload = response.data;
      const authData = payload.data;

      if (authData.requires2FA) {
        setMaskedEmail(authData.maskedEmail || "");
        setLoginIdentifier(authData.identifier || identifier);
        setShow2FA(true);
        showToast("Verification code sent to your email", "success");
      } else if (authData.user) {
        const user = authData.user;
        
        // Ensure persistence layer is synced
        localStorage.setItem('isLoggedIn', 'true');
        
        setUser(user);
        showToast("Login successful!", "success");
        
        if (user.profileStatus === 'Initial') {
          navigate("/admin-dashboard/register?mode=finalize-setup&type=old&duties=Standard");
        } else {
          const role = user.role?.toLowerCase();
          if (role === 'administrator' || role === 'human resource') {
            navigate("/admin-dashboard");
          } else {
            navigate("/employee-dashboard");
          }
        }
      }
    } catch (err: unknown) {
      let message = "Invalid credentials";
      if (axios.isAxiosError(err)) {
          const axiosError = err as AxiosError<{ message?: string }>;
          message = axiosError.response?.data?.message || message;
      }
      setError(message);
      showToast(message, "error");
    } finally {
      setLoading(false);
    }
  };

  const handle2FASuccess = (user: User) => {
    setUser(user);
    showToast("Login successful!", "success");
    if (!user.employeeId) {
      navigate("/admin-dashboard/register?mode=finalize-setup");
    } else {
      navigate("/admin-dashboard");
    }
  };

  const labelClass = "text-xs font-semibold text-gray-600 mb-1.5 ml-1 block";
  const inputContainerClass = "relative flex items-center bg-white border border-gray-300 rounded-lg focus-within:ring-2 focus-within:ring-blue-500/10 focus-within:border-blue-500 transition-all overflow-hidden shadow-sm";
  const iconClass = "absolute left-3.5 text-gray-400";
  const inputClass = "w-full bg-transparent pl-11 pr-4 py-2.5 text-sm text-gray-900 outline-none placeholder:text-gray-400 font-medium";
  const buttonClass = "w-full bg-slate-900 text-white py-3 rounded-lg font-bold text-sm hover:bg-black transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-md flex justify-center items-center gap-2 active:scale-[0.98]";

  if (show2FA) {
    return (
      <AuthLayout 
        title="Verification Required" 
        subtitle={`Enter the 6-digit code sent to ${maskedEmail}`}
      >
        <div className="space-y-6">
          <div className="flex justify-center">
            <div className="bg-blue-50 p-4 rounded-full border border-blue-100">
              <CheckCircle className="text-blue-600 w-8 h-8" />
            </div>
          </div>
          
          <OTPInput 
            length={6}
            value={otpValue}
            onChange={(val) => {
              setOtpValue(val);
              if (val.length === 6) {
                verify2FAMutation.mutate({ identifier: loginIdentifier, otp: val }, {
                  onSuccess: (response: unknown) => {
                    const payload = response as AuthPayload;
                    const userData = payload.data.user;
                    if (userData) {
                        handle2FASuccess(userData);
                    }
                  },
                  onError: (err: unknown) => {
                    let message = "Invalid verification code";
                    if (axios.isAxiosError(err)) {
                        const axiosError = err as AxiosError<{ message?: string }>;
                        message = axiosError.response?.data?.message || message;
                    }
                    showToast(message, "error");
                  }
                });
              }
            }}
          />

          <div className="flex flex-col gap-4">
            <button
              onClick={() => verify2FAMutation.mutate({ identifier: loginIdentifier, otp: otpValue }, {
                onSuccess: (response: unknown) => {
                  const payload = response as AuthPayload;
                  const userData = payload.data.user;
                  if (userData) {
                      handle2FASuccess(userData);
                  }
                }
              })}
              disabled={verify2FAMutation.isPending || otpValue.length !== 6}
              className={buttonClass}
            >
              {verify2FAMutation.isPending ? <Loader2 className="animate-spin" size={18} /> : "Verify Identity"}
            </button>

            <button
              onClick={() => resend2FAMutation.mutate({ identifier: loginIdentifier }, {
                onSuccess: () => showToast("New code sent!", "success")
              })}
              disabled={resend2FAMutation.isPending}
              className="text-xs font-bold text-blue-600 hover:text-blue-700 disabled:opacity-50 transition-colors"
            >
              {resend2FAMutation.isPending ? "Sending code..." : "Resend verification code"}
            </button>

            <button
              onClick={() => setShow2FA(false)}
              className="flex items-center justify-center gap-2 text-xs font-semibold text-gray-400 hover:text-gray-600 transition-colors pt-2"
            >
              <ArrowLeft size={14} />
              Back to login
            </button>
          </div>
        </div>
      </AuthLayout>
    );
  }

  return (
    <AuthLayout 
      title="Employee Portal" 
      subtitle="Sign in to access your HR dashboard"
    >
      <div className="space-y-5">
        {error && (
          <div className="bg-red-50 text-red-600 p-3 rounded-lg text-xs font-medium flex items-center gap-2 border border-red-100">
            <span className="w-1 h-1 bg-red-600 rounded-full shrink-0" />
            {error}
          </div>
        )}

        <form onSubmit={handleLogin} className="space-y-4">
          <div>
            <label className={labelClass}>Email or Employee ID</label>
            <div className={inputContainerClass}>
              <Mail className={iconClass} size={16} />
              <input
                type="text"
                value={identifier}
                onChange={(e) => setIdentifier(e.target.value)}
                className={inputClass}
                placeholder="name@agency.gov.ph"
                required
              />
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center">
              <label className={labelClass}>Password</label>
              <Link to="/forgot-password" className="text-xs font-semibold text-blue-600 hover:text-blue-700 mb-1.5 mr-1">
                Forgot?
              </Link>
            </div>
            <div className={inputContainerClass}>
              <Lock className={iconClass} size={16} />
              <input
                type={showPassword ? "text" : "password"}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className={inputClass}
                placeholder="••••••••"
                required
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3.5 text-gray-400 hover:text-gray-600 transition-colors"
              >
                {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>

          <div className="flex items-center py-1">
            <label className="flex items-center gap-2 cursor-pointer group">
              <div className="relative flex items-center">
                <input
                  type="checkbox"
                  checked={rememberMe}
                  onChange={(e) => setRememberMe(e.target.checked)}
                  className="peer sr-only"
                />
                <div className="w-4 h-4 border-2 border-gray-300 rounded peer-checked:bg-slate-900 peer-checked:border-slate-900 transition-all" />
                <CheckCircle className="absolute inset-0 text-white opacity-0 peer-checked:opacity-100 scale-50 peer-checked:scale-75 transition-all" size={16} />
              </div>
              <span className="text-xs font-medium text-gray-500 group-hover:text-gray-900 transition-colors">Keep me signed in</span>
            </label>
          </div>

          <button
            type="submit"
            disabled={loading}
            className={buttonClass}
          >
            {loading ? (
              <Loader2 className="animate-spin" size={18} />
            ) : (
              "Sign In"
            )}
          </button>
        </form>

        <div className="text-center pt-2">
          <Link 
            to="/setup-portal" 
            onClick={handleSetupClick}
            className={`text-xs font-bold transition-colors uppercase tracking-wider ${
              showSetupLink ? 'text-blue-600 hover:text-blue-800' : 'text-gray-400 hover:text-gray-900'
            }`}
          >
            Initialize Portal
          </Link>
        </div>
      </div>
    </AuthLayout>
  );
};

