import React, { useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { AlertTriangle, Info, X } from 'lucide-react';

interface ConfirmationModalProps {
    isOpen: boolean;
    onClose: () => void;
    onConfirm: () => void;
    title: string;
    message: string;
    confirmText?: string;
    cancelText?: string;
    variant?: 'danger' | 'info';
}

const ConfirmationModal: React.FC<ConfirmationModalProps> = ({
    isOpen,
    onClose,
    onConfirm,
    title,
    message,
    confirmText = "Confirm",
    cancelText = "Cancel",
    variant = 'info'
}) => {
    // Lock body scroll when modal is open
    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = 'unset';
            // Wait for animation to finish before removing from DOM is handled by AnimatePresence, 
            // but we reset overflow immediately on close trigger or after interaction.
        }
        return () => { document.body.style.overflow = 'unset'; };
    }, [isOpen]);

    return createPortal(
        <AnimatePresence>
            {isOpen && (
                <div className="relative z-50">
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                        className="fixed inset-0 bg-gray-500 bg-opacity-75 transition-opacity"
                    />

                    <div className="fixed inset-0 z-10 w-screen overflow-y-auto">
                        <div className="flex min-h-full items-end justify-center p-4 text-center sm:items-center sm:p-0">
                            {/* Modal Panel */}
                            <motion.div
                                initial={{ opacity: 0, scale: 0.95, y: 20 }}
                                animate={{ opacity: 1, scale: 1, y: 0 }}
                                exit={{ opacity: 0, scale: 0.95, y: 20 }}
                                transition={{ duration: 0.2 }}
                                className="relative transform overflow-hidden rounded-lg bg-white px-4 pb-4 pt-5 text-left shadow-xl transition-all sm:my-8 sm:w-full sm:max-w-lg sm:p-6"
                            >
                                <div className="absolute right-0 top-0 hidden pr-4 pt-4 sm:block">
                                    <button
                                        type="button"
                                        className="rounded-md bg-white text-gray-400 hover:text-gray-500 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2"
                                        onClick={onClose}
                                    >
                                        <span className="sr-only">Close</span>
                                        <X className="h-6 w-6" aria-hidden="true" />
                                    </button>
                                </div>
                                <div className="sm:flex sm:items-start">
                                    <div className={`mx-auto flex h-12 w-12 flex-shrink-0 items-center justify-center rounded-full sm:mx-0 sm:h-10 sm:w-10 ${
                                        variant === 'danger' ? 'bg-red-100' : 'bg-blue-100'
                                    }`}>
                                        {variant === 'danger' ? (
                                            <AlertTriangle className="h-6 w-6 text-red-600" aria-hidden="true" />
                                        ) : (
                                            <Info className="h-6 w-6 text-blue-600" aria-hidden="true" />
                                        )}
                                    </div>
                                    <div className="mt-3 text-center sm:ml-4 sm:mt-0 sm:text-left">
                                        <h3 className="text-base font-semibold leading-6 text-gray-900">
                                            {title}
                                        </h3>
                                        <div className="mt-2">
                                            <p className="text-sm text-gray-500">
                                                {message}
                                            </p>
                                        </div>
                                    </div>
                                </div>
                                <div className="mt-5 sm:mt-4 sm:flex sm:flex-row-reverse">
                                    <button
                                        type="button"
                                        className={`inline-flex w-full justify-center rounded-md px-3 py-2 text-sm font-semibold text-white shadow-sm sm:ml-3 sm:w-auto ${
                                            variant === 'danger' 
                                                ? 'bg-red-600 hover:bg-red-500 focus-visible:outline-red-600' 
                                                : 'bg-indigo-600 hover:bg-indigo-500 focus-visible:outline-indigo-600'
                                        }`}
                                        onClick={() => {
                                            onConfirm();
                                            onClose();
                                        }}
                                    >
                                        {confirmText}
                                    </button>
                                    <button
                                        type="button"
                                        className="mt-3 inline-flex w-full justify-center rounded-md bg-white px-3 py-2 text-sm font-semibold text-gray-900 shadow-sm ring-1 ring-inset ring-gray-300 hover:bg-gray-50 sm:mt-0 sm:w-auto"
                                        onClick={onClose}
                                    >
                                        {cancelText}
                                    </button>
                                </div>
                            </motion.div>
                        </div>
                    </div>
                </div>
            )}
        </AnimatePresence>,
        document.body
    );
};

export default ConfirmationModal;

import { useState, useRef, useEffect, useCallback } from "react";
import { Bell, X, Check, AlertCircle, FileText, Calendar, Clock, RefreshCw, LucideIcon } from "lucide-react";
import { notificationApi } from "@/api/notificationApi";

interface NotificationStyle {
  icon: LucideIcon;
  color: string;
  bg: string;
}

// Get icon and color based on notification type
const getNotificationStyle = (type: string): NotificationStyle => {
  const styles: Record<string, NotificationStyle> = {
    leave_request: { icon: Calendar, color: 'text-amber-600', bg: 'bg-amber-50' },
    leave_process: { icon: RefreshCw, color: 'text-blue-600', bg: 'bg-blue-50' },
    leave_finalize: { icon: Check, color: 'text-cyan-600', bg: 'bg-cyan-50' },
    leave_approval: { icon: Check, color: 'text-green-600', bg: 'bg-green-50' },
    leave_rejection: { icon: X, color: 'text-red-600', bg: 'bg-red-50' },
    dtr_request: { icon: Clock, color: 'text-purple-600', bg: 'bg-purple-50' },
    dtr_approval: { icon: Check, color: 'text-green-600', bg: 'bg-green-50' },
    dtr_rejection: { icon: X, color: 'text-red-600', bg: 'bg-red-50' },
    memo_request: { icon: FileText, color: 'text-indigo-600', bg: 'bg-indigo-50' },
    memo_acknowledged: { icon: Check, color: 'text-green-600', bg: 'bg-green-50' },
    event_created: { icon: Calendar, color: 'text-pink-600', bg: 'bg-pink-50' },
    announcement: { icon: Bell, color: 'text-amber-600', bg: 'bg-amber-50' },
  };
  return styles[type] || { icon: Bell, color: 'text-gray-600', bg: 'bg-gray-50' };
};

// Format relative time
const formatTimeAgo = (dateString?: string) => {
  if (!dateString) return '';
  try {
    const date = new Date(dateString);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    if (diffDays < 7) return `${diffDays}d ago`;
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  } catch {
    return '';
  }
};

interface NotificationItem {
  notificationId: string | number;
  type: string;
  title: string;
  message: string;
  status: 'read' | 'unread';
  createdAt: string;
  senderName?: string;
}

interface NotificationResponse {
  success: boolean;
  notifications: NotificationItem[];
  unreadCount: number;
}

export default function EmployeeNotificationMenu() {
  const [isOpen, setIsOpen] = useState(false);
  const [notifications, setNotifications] = useState<NotificationItem[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Fetch notifications from API
  const fetchNotifications = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await notificationApi.getNotifications({ limit: 20, offset: 0 });
      const data = response.data as NotificationResponse;
      setNotifications(Array.isArray(data.notifications) ? data.notifications : []);
      setUnreadCount(typeof data.unreadCount === 'number' ? data.unreadCount : 0);
    } catch (err) {
      console.error('Notification fetch error:', err);
      setError('Unable to load notifications');
      setNotifications([]);
      setUnreadCount(0);
    } finally {
      setIsLoading(false);
    }
  }, []);

  // Fetch just the unread count for polling
  const fetchUnreadCount = useCallback(async () => {
    try {
      const response = await notificationApi.getUnreadCount();
      const data = response.data as { success: boolean; unreadCount: number };
      setUnreadCount(typeof data.unreadCount === 'number' ? data.unreadCount : 0);
    } catch (err) {
      console.error('Unread count fetch error:', err);
    }
  }, []);

  // Mark notification as read
  const handleMarkAsRead = useCallback(async (id: string | number) => {
    try {
      await notificationApi.markAsRead(id);
      setNotifications(prev => prev.map(n => 
        n.notificationId === id ? { ...n, status: 'read' } : n
      ));
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (err) {
      console.error('Mark as read error:', err);
    }
  }, []);

  // Delete notification
  const handleDelete = useCallback(async (id: string | number) => {
    try {
      const notification = notifications.find(n => n.notificationId === id);
      await notificationApi.deleteNotification(id);
      setNotifications(prev => prev.filter(n => n.notificationId !== id));
      if (notification?.status === 'unread') {
        setUnreadCount(prev => Math.max(0, prev - 1));
      }
    } catch (err) {
      console.error('Delete notification error:', err);
    }
  }, [notifications]);

  // Mark all as read
  const handleMarkAllAsRead = useCallback(async () => {
    try {
      const unreadNotifications = notifications.filter(n => n.status === 'unread');
      await Promise.all(unreadNotifications.map(n => notificationApi.markAsRead(n.notificationId)));
      setNotifications(prev => prev.map(n => ({ ...n, status: 'read' })));
      setUnreadCount(0);
    } catch (err) {
      console.error('Mark all as read error:', err);
    }
  }, [notifications]);


  // Initial fetch and polling
  useEffect(() => {
    fetchNotifications();
    const pollInterval = setInterval(fetchUnreadCount, 30000);
    return () => clearInterval(pollInterval);
  }, [fetchNotifications, fetchUnreadCount]);

  // Refresh when menu opens
  useEffect(() => {
    if (isOpen) fetchNotifications();
  }, [isOpen, fetchNotifications]);

  // Click outside to close
  useEffect(() => {
    if (!isOpen) return;
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  return (
    <div className="relative" ref={menuRef}>
      {/* Bell Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="relative p-2 hover:bg-gray-100 rounded-full transition-colors"
        aria-label="Notifications"
      >
        <Bell className="w-6 h-6 text-slate-700" />
        {unreadCount > 0 && (
          <span className="absolute -top-0.5 -right-0.5 min-w-[18px] h-[18px] flex items-center justify-center text-[10px] font-bold text-white bg-red-500 rounded-full px-1">
            {unreadCount > 99 ? '99+' : unreadCount}
          </span>
        )}
      </button>

      {/* Dropdown Menu */}
      {isOpen && (
        <div className="absolute top-12 right-0 w-80 sm:w-96 bg-white border border-gray-200 rounded-xl shadow-xl z-50 overflow-hidden">
          {/* Header */}
          <div className="bg-gray-200 shadow-md px-4 py-3">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Bell className="w-5 h-5 text-gray-700" />
                <h3 className="text-base font-semibold text-gray-700">Notifications</h3>
              </div>
              <div className="flex items-center gap-2">
                {unreadCount > 0 && (
                  <button
                    onClick={handleMarkAllAsRead}
                    className="text-xs text-gray-600 hover:text-gray-800 transition-colors"
                  >
                    Mark all read
                  </button>
                )}
                <button
                  onClick={fetchNotifications}
                  className="p-1 hover:bg-gray-300 rounded-full transition-colors"
                  title="Refresh"
                >
                  <RefreshCw className={`w-4 h-4 text-gray-700 ${isLoading ? 'animate-spin' : ''}`} />
                </button>
              </div>
            </div>
            <p className="text-xs text-gray-500 mt-1">
              {unreadCount > 0 ? `${unreadCount} unread notification${unreadCount > 1 ? 's' : ''}` : 'All caught up!'}
            </p>
          </div>

          {/* Notification List */}
          <div className="max-h-80 overflow-y-auto">
            {isLoading ? (
              <div className="py-8 text-center">
                <div className="animate-spin rounded-full h-8 w-8 border-2 border-green-700 border-t-transparent mx-auto mb-2" />
                <p className="text-sm text-gray-500">Loading...</p>
              </div>
            ) : error ? (
              <div className="py-8 text-center">
                <AlertCircle className="w-10 h-10 text-red-400 mx-auto mb-2" />
                <p className="text-sm text-red-600 mb-2">{error}</p>
                <button
                  onClick={fetchNotifications}
                  className="text-sm text-green-700 hover:underline"
                >
                  Try again
                </button>
              </div>
            ) : notifications.length === 0 ? (
              <div className="py-8 text-center">
                <Bell className="w-10 h-10 text-gray-300 mx-auto mb-2" />
                <p className="text-sm text-gray-500">No notifications yet</p>
              </div>
            ) : (
              <div className="divide-y divide-gray-100">
                {notifications.map((notification) => {
                  const style = getNotificationStyle(notification.type);
                  const IconComponent = style.icon;
                  const isUnread = notification.status === 'unread';

                  return (
                    <div
                      key={notification.notificationId}
                      onClick={() => isUnread && handleMarkAsRead(notification.notificationId)}
                      className={`group flex items-start gap-3 p-3 hover:bg-gray-50 cursor-pointer transition-colors ${
                        isUnread ? 'bg-blue-50/30' : ''
                      }`}
                    >
                      {/* Icon */}
                      <div className={`flex-shrink-0 w-9 h-9 rounded-full flex items-center justify-center ${style.bg}`}>
                        <IconComponent className={`w-4 h-4 ${style.color}`} />
                      </div>

                      {/* Content */}
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <p className={`text-sm truncate ${isUnread ? 'font-semibold text-gray-900' : 'font-medium text-gray-700'}`}>
                            {notification.senderName?.trim() || notification.title || 'Notification'}
                          </p>
                          {isUnread && (
                            <span className="w-2 h-2 bg-blue-500 rounded-full flex-shrink-0" />
                          )}
                          {/* Status Badge */}
                          {(notification.type?.toLowerCase().includes('request') || 
                            notification.type?.toLowerCase().includes('pending') ||
                            notification.type?.toLowerCase().includes('process') ||
                            notification.type?.toLowerCase().includes('finalize')) && 
                           !notification.type?.toLowerCase().includes('approved') && 
                           !notification.type?.toLowerCase().includes('rejected') && 
                           !notification.type?.toLowerCase().includes('approval') && 
                           !notification.type?.toLowerCase().includes('rejection') && 
                           !notification.type?.toLowerCase().includes('acknowledged') && (
                            <span className="px-1.5 py-0.5 text-[10px] font-medium bg-amber-100 text-amber-700 rounded whitespace-nowrap">Pending</span>
                          )}
                          {(notification.type?.toLowerCase().includes('approved') || 
                            notification.type?.toLowerCase().includes('approval') ||
                            notification.type?.toLowerCase().includes('acknowledged')) && (
                            <span className="px-1.5 py-0.5 text-[10px] font-medium bg-green-100 text-green-700 rounded whitespace-nowrap">Completed</span>
                          )}
                          {(notification.type?.toLowerCase().includes('rejected') || 
                            notification.type?.toLowerCase().includes('rejection')) && (
                            <span className="px-1.5 py-0.5 text-[10px] font-medium bg-red-100 text-red-700 rounded whitespace-nowrap">Rejected</span>
                          )}
                        </div>
                        {notification.senderName?.trim() && (
                          <p className="text-xs text-gray-600 truncate mt-0.5">
                            {notification.title}
                          </p>
                        )}
                        <p className="text-xs text-gray-500 truncate">
                          {notification.message || 'No details'}
                        </p>
                        <p className="text-[10px] text-gray-400 mt-1">
                          {formatTimeAgo(notification.createdAt)}
                        </p>
                      </div>

                      {/* Delete Button */}
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDelete(notification.notificationId);
                        }}
                        className="opacity-0 group-hover:opacity-100 p-1 hover:bg-gray-200 rounded transition-all"
                        title="Delete"
                      >
                        <X className="w-4 h-4 text-gray-400" />
                      </button>
                    </div>
                  );
                })}
              </div>
            )}
          </div>

          {/* Footer */}
          {notifications.length > 0 && (
            <div className="border-t border-gray-100 px-4 py-2 bg-gray-50">
              <p className="text-xs text-center text-gray-500">
                Showing {notifications.length} notification{notifications.length > 1 ? 's' : ''}
              </p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from "react";
import { Bell, X, Check, AlertCircle, FileText, Calendar, Clock, RefreshCw, LucideIcon } from "lucide-react";
import { notificationApi } from "@/api/notificationApi";

interface NotificationStyle {
  icon: LucideIcon;
  color: string;
  bg: string;
}

// Get icon and color based on notification type
const getNotificationStyle = (type: string): NotificationStyle => {
  const styles: Record<string, NotificationStyle> = {
    leave_request: { icon: Calendar, color: 'text-amber-600', bg: 'bg-amber-50' },
    leave_process: { icon: RefreshCw, color: 'text-blue-600', bg: 'bg-blue-50' },
    leave_finalize: { icon: Check, color: 'text-cyan-600', bg: 'bg-cyan-50' },
    leave_approval: { icon: Check, color: 'text-green-600', bg: 'bg-green-50' },
    leave_rejection: { icon: X, color: 'text-red-600', bg: 'bg-red-50' },
    dtr_request: { icon: Clock, color: 'text-purple-600', bg: 'bg-purple-50' },
    dtr_approval: { icon: Check, color: 'text-green-600', bg: 'bg-green-50' },
    dtr_rejection: { icon: X, color: 'text-red-600', bg: 'bg-red-50' },
    memo_request: { icon: FileText, color: 'text-indigo-600', bg: 'bg-indigo-50' },
    memo_acknowledged: { icon: Check, color: 'text-green-600', bg: 'bg-green-50' },
    event_created: { icon: Calendar, color: 'text-pink-600', bg: 'bg-pink-50' },
  };
  return styles[type] || { icon: Bell, color: 'text-gray-600', bg: 'bg-gray-50' };
};

// Format relative time
const formatTimeAgo = (dateString?: string) => {
  if (!dateString) return '';
  try {
    const date = new Date(dateString);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'Just now';
    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    if (diffDays < 7) return `${diffDays}d ago`;
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  } catch {
    return '';
  }
};

interface NotificationItem {
  notificationId: string | number;
  type: string;
  title: string;
  message: string;
  status: 'read' | 'unread';
  createdAt: string;
  senderId?: string;
  referenceId?: number;
}

interface NotificationResponse {
  success: boolean;
  notifications: NotificationItem[];
  unreadCount: number;
}

export default function NotificationMenu() {
  const [isOpen, setIsOpen] = useState(false);
  const [notifications, setNotifications] = useState<NotificationItem[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Fetch notifications from API
  const fetchNotifications = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await notificationApi.getNotifications({ limit: 20, offset: 0 });
      const data = response.data as NotificationResponse;
      setNotifications(Array.isArray(data.notifications) ? data.notifications : []);
      setUnreadCount(typeof data.unreadCount === 'number' ? data.unreadCount : 0);
    } catch (err) {
      console.error('Notification fetch error:', err);
      setError('Unable to load notifications');
      setNotifications([]);
      setUnreadCount(0);
    } finally {
      setIsLoading(false);
    }
  }, []);

  // Fetch just the unread count for polling
  const fetchUnreadCount = useCallback(async () => {
    try {
      const response = await notificationApi.getUnreadCount();
      const data = response.data as { success: boolean; unreadCount: number };
      setUnreadCount(typeof data.unreadCount === 'number' ? data.unreadCount : 0);
    } catch (err) {
      console.error('Unread count fetch error:', err);
    }
  }, []);

  // Mark notification as read
  const handleMarkAsRead = useCallback(async (id: string | number) => {
    try {
      await notificationApi.markAsRead(id);
      setNotifications(prev => prev.map(n => 
        n.notificationId === id ? { ...n, status: 'read' } : n
      ));
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (err) {
      console.error('Mark as read error:', err);
    }
  }, []);

  // Delete notification
  const handleDelete = useCallback(async (id: string | number) => {
    try {
      await notificationApi.deleteNotification(id);
      setNotifications(prev => prev.filter(n => n.notificationId !== id));
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (err) {
      console.error('Delete notification error:', err);
    }
  }, []);

  // Mark all as read
  const handleMarkAllAsRead = useCallback(async () => {
    try {
      const unreadNotifications = notifications.filter(n => n.status === 'unread');
      await Promise.all(unreadNotifications.map(n => notificationApi.markAsRead(n.notificationId)));
      setNotifications(prev => prev.map(n => ({ ...n, status: 'read' })));
      setUnreadCount(0);
    } catch (err) {
      console.error('Mark all as read error:', err);
    }
  }, [notifications]);

  // Initial fetch and polling
  useEffect(() => {
    fetchNotifications();
    const pollInterval = setInterval(fetchUnreadCount, 30000);
    return () => clearInterval(pollInterval);
  }, [fetchNotifications, fetchUnreadCount]);

  // Refresh when menu opens
  useEffect(() => {
    if (isOpen) fetchNotifications();
  }, [isOpen, fetchNotifications]);

  // Click outside to close
  useEffect(() => {
    if (!isOpen) return;
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  return (
    <div className="relative" ref={menuRef}>
      {/* Bell Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="relative p-2 hover:bg-gray-100 rounded-full transition-colors"
        aria-label="Notifications"
      >
        <Bell className="w-6 h-6 text-slate-700" />
        {unreadCount > 0 && (
          <span className="absolute -top-0.5 -right-0.5 min-w-[18px] h-[18px] flex items-center justify-center text-[10px] font-bold text-white bg-red-500 rounded-full px-1">
            {unreadCount > 99 ? '99+' : unreadCount}
          </span>
        )}
      </button>

      {/* Dropdown Menu */}
      {isOpen && (
        <div className="absolute top-12 right-0 w-80 sm:w-96 bg-white border border-gray-200 rounded-xl shadow-xl z-50 overflow-hidden">
          {/* Header */}
          <div className="bg-gray-200 shadow-md px-4 py-3">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Bell className="w-5 h-5 text-gray-700" />
                <h3 className="text-base font-semibold text-gray-700">Notifications</h3>
              </div>
              <div className="flex items-center gap-2">
                {unreadCount > 0 && (
                  <button
                    onClick={handleMarkAllAsRead}
                    className="text-xs text-gray-600 hover:text-gray-800 transition-colors"
                  >
                    Mark all read
                  </button>
                )}
                <button
                  onClick={fetchNotifications}
                  className="p-1 hover:bg-gray-300 rounded-full transition-colors"
                  title="Refresh"
                >
                  <RefreshCw className={`w-4 h-4 text-gray-700 ${isLoading ? 'animate-spin' : ''}`} />
                </button>
              </div>
            </div>
            <p className="text-xs text-gray-500 mt-1">
              {unreadCount > 0 ? `${unreadCount} unread notification${unreadCount > 1 ? 's' : ''}` : 'All caught up!'}
            </p>
          </div>

          {/* Notification List */}
          <div className="max-h-80 overflow-y-auto">
            {isLoading ? (
              <div className="py-8 text-center">
                <div className="animate-spin rounded-full h-8 w-8 border-2 border-gray-400 border-t-transparent mx-auto mb-2" />
                <p className="text-sm text-gray-500">Loading...</p>
              </div>
            ) : error ? (
              <div className="py-8 text-center">
                <AlertCircle className="w-10 h-10 text-red-400 mx-auto mb-2" />
                <p className="text-sm text-red-600 mb-2">{error}</p>
                <button
                  onClick={fetchNotifications}
                  className="text-sm text-gray-600 hover:underline"
                >
                  Try again
                </button>
              </div>
            ) : notifications.length === 0 ? (
              <div className="py-8 text-center">
                <Bell className="w-10 h-10 text-gray-300 mx-auto mb-2" />
                <p className="text-sm text-gray-500">No notifications yet</p>
              </div>
            ) : (
              <div className="divide-y divide-gray-100">
                {notifications.map((notification) => {
                  const style = getNotificationStyle(notification.type);
                  const IconComponent = style.icon;
                  const isUnread = notification.status === 'unread';

                  return (
                    <div
                      key={notification.notificationId}
                      onClick={() => isUnread && handleMarkAsRead(notification.notificationId)}
                      className={`group flex items-start gap-3 p-3 hover:bg-gray-50 cursor-pointer transition-colors ${
                        isUnread ? 'bg-blue-50/30' : ''
                      }`}
                    >
                      {/* Icon */}
                      <div className={`flex-shrink-0 w-9 h-9 rounded-full flex items-center justify-center ${style.bg}`}>
                        <IconComponent className={`w-4 h-4 ${style.color}`} />
                      </div>

                      {/* Content */}
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between gap-2 overflow-hidden">
                          <div className="flex items-center gap-2 min-w-0 flex-1">
                            <p className={`text-sm truncate ${isUnread ? 'font-semibold text-gray-900' : 'font-medium text-gray-700'}`}>
                              {notification.title || 'Notification'}
                            </p>
                            {isUnread && (
                              <span className="w-2 h-2 bg-blue-500 rounded-full flex-shrink-0" />
                            )}
                          </div>
                          
                          {/* Status Badge - Moved to a stable position with shrink-0 */}
                          <div className="flex-shrink-0 flex items-center">
                            {(notification.type?.toLowerCase().includes('request') || 
                              notification.type?.toLowerCase().includes('pending') ||
                              notification.type?.toLowerCase().includes('process') ||
                              notification.type?.toLowerCase().includes('finalize')) && 
                             !notification.type?.toLowerCase().includes('approved') && 
                             !notification.type?.toLowerCase().includes('rejected') && 
                             !notification.type?.toLowerCase().includes('approval') && 
                             !notification.type?.toLowerCase().includes('rejection') && 
                             !notification.type?.toLowerCase().includes('acknowledged') && (
                              <span className="px-1.5 py-0.5 text-[10px] font-medium bg-amber-100 text-amber-700 rounded whitespace-nowrap">Pending</span>
                            )}
                            {(notification.type?.toLowerCase().includes('approved') || 
                              notification.type?.toLowerCase().includes('approval') ||
                              notification.type?.toLowerCase().includes('acknowledged')) && (
                              <span className="px-1.5 py-0.5 text-[10px] font-medium bg-green-100 text-green-700 rounded whitespace-nowrap">Completed</span>
                            )}
                            {(notification.type?.toLowerCase().includes('rejected') || notification.type?.toLowerCase().includes('rejection')) && (
                              <span className="px-1.5 py-0.5 text-[10px] font-medium bg-red-100 text-red-700 rounded whitespace-nowrap">Rejected</span>
                            )}
                          </div>
                        </div>
                        {notification.senderId && (
                          <p className="text-xs text-gray-600 truncate mt-0.5">
                            {notification.message}
                          </p>
                        )}
                        <p className="text-[10px] text-gray-400 mt-1">
                          {formatTimeAgo(notification.createdAt)}
                        </p>
                      </div>

                      {/* Delete Button */}
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDelete(notification.notificationId);
                        }}
                        className="opacity-0 group-hover:opacity-100 p-1 hover:bg-gray-200 rounded transition-all"
                        title="Delete"
                      >
                        <X className="w-4 h-4 text-gray-400" />
                      </button>
                    </div>
                  );
                })}
              </div>
            )}
          </div>

          {/* Footer */}
          {notifications.length > 0 && (
            <div className="border-t border-gray-100 px-4 py-2 bg-gray-50">
              <p className="text-xs text-center text-gray-500">
                Showing {notifications.length} notification{notifications.length > 1 ? 's' : ''}
              </p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { LogOut, ChevronDown, ChevronRight, LucideIcon } from 'lucide-react';

export interface NavChild {
  name: string;
  action: string;
  path?: string;
}

export interface NavItem {
  name: string;
  icon: LucideIcon;
  path?: string;
  action?: string;
  children?: NavChild[]; 
}

interface SidebarProps {
  sidebarOpen: boolean;
  navItems: NavItem[];
  handleLogout?: () => void;
  onLogout?: () => void;
  onSectionChange?: (section: string) => void;
  portalName?: string;
}

export default function Sidebar({ 
    sidebarOpen, 
    navItems, 
    handleLogout, 
    onLogout,
    onSectionChange, 
    portalName = "Portal"
}: SidebarProps) {
  const [openDropdowns, setOpenDropdowns] = useState<Record<string, boolean>>({});
  const location = useLocation();

  const finalLogout = handleLogout || onLogout;

  const toggleDropdown = (name: string) => {
    setOpenDropdowns(prev => ({
      ...prev,
      [name]: !prev[name]
    }));
  };

  const isActive = (action?: string, path?: string) => {
    if (path) {
        return location.pathname === path;
    }
    if (!action) return false;
    
    if (action === 'dashboard') {
        // Generic check for dashboard root, might need adjustment based on route structure
        return location.pathname.endsWith('dashboard') || location.pathname.endsWith('dashboard/');
    }
    return location.pathname.includes(action);
  };

  return (
    <aside 
      className={`bg-slate-950 text-gray-100 p-4 shadow-xl mb-6 flex flex-col justify-between transition-all duration-300 z-40 min-h-screen sticky top-0 overflow-y-auto border-r border-gray-800 ${sidebarOpen ? 'w-72' : 'w-20'}`}
      style={{
        scrollbarWidth: 'none',
        msOverflowStyle: 'none'
      } as React.CSSProperties}
    >
      <div className="flex flex-col"> 
        <div className={`border-b border-gray-800 flex flex-col items-center justify-center flex-shrink-0 py-8 transition-all duration-300 ${
              sidebarOpen ? 'px-6' : 'px-2'}`}>
            <img src="/Logo.Municipal of Meycuayan.png" alt="Meycauayan Logo" className={`transition-all duration-300 ${sidebarOpen ? 'w-20 h-20' : 'w-12 h-12'} rounded-full flex-shrink-0 shadow-lg ring-2 ring-slate-800`}/>
             {sidebarOpen && (<div className="mt-4 text-center transition-all duration-300">
                <h1 className="text-base font-bold leading-tight tracking-wide text-white">{portalName}</h1>
                <p className="text-[10px] font-medium text-gray-400 leading-tight mt-1 uppercase tracking-wider">City Human Resources Management Office</p>
              </div>
            )}
        </div>

        <nav className="p-3 flex-1 mt-4 space-y-1">
          {navItems.map((item) => {
            const Icon = item.icon;
            const hasChildren = item.children && item.children.length > 0;
            const isOpen = openDropdowns[item.name];
            const active = isActive(item.action, item.path);

            const mainOnClick = () => {
              if (hasChildren) {
                toggleDropdown(item.name);
              } else if (item.action && onSectionChange) {
                onSectionChange(item.action);
              }
            };

            return (
              <div key={item.name} className="w-full">
                {item.path ? (
                  <Link
                    to={item.path}
                    onClick={mainOnClick}
                    className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm transition-all duration-200 group relative ${
                      active && !hasChildren 
                      ? 'bg-slate-800/50 text-white font-semibold shadow-sm ring-1 ring-white/10' 
                      : 'text-gray-400 hover:bg-slate-800/50 hover:text-white'
                    }`}
                  >
                    <Icon className={`w-5 h-5 flex-shrink-0 transition-colors duration-200 ${active && !hasChildren ? 'text-white' : 'text-gray-500 group-hover:text-white'}`} />
                    {sidebarOpen && <span className="flex-1 text-left tracking-tight">{item.name}</span>}
                    {sidebarOpen && hasChildren && (
                      isOpen ? <ChevronDown className="w-4 h-4 opacity-50" /> : <ChevronRight className="w-4 h-4 opacity-50" />
                    )}
                  </Link>
                ) : (
                  <button
                    onClick={mainOnClick}
                    className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm transition-all duration-200 group relative ${
                      active && !hasChildren 
                      ? 'bg-slate-800/50 text-white font-semibold shadow-sm ring-1 ring-white/10' 
                      : 'text-gray-400 hover:bg-slate-800/50 hover:text-white'
                    }`}
                  >
                    <Icon className={`w-5 h-5 flex-shrink-0 transition-colors duration-200 ${active && !hasChildren ? 'text-white' : 'text-gray-500 group-hover:text-white'}`} />
                    {sidebarOpen && <span className="flex-1 text-left tracking-tight">{item.name}</span>}
                    {sidebarOpen && hasChildren && (
                      isOpen ? <ChevronDown className="w-4 h-4 opacity-50" /> : <ChevronRight className="w-4 h-4 opacity-50" />
                    )}
                  </button>
                )}
                {hasChildren && isOpen && sidebarOpen && (
                  <div className="ml-4 pl-3 mt-1 space-y-0.5 border-l border-gray-800">
                    {item.children?.map((child: NavChild) => {
                      const childActive = isActive(child.action, child.path);

                      const childOnClick = () => {
                        if (child.action && onSectionChange) {
                          onSectionChange(child.action);
                        }
                      };

                      return child.path ? (
                        <Link
                          key={child.name}
                          to={child.path}
                          onClick={childOnClick}
                          className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-xs transition-all duration-200 ${
                            childActive 
                                ? 'bg-slate-800 text-white font-medium shadow-sm' 
                                : 'text-gray-400 hover:bg-slate-800/30 hover:text-white'
                            }`}
                        >
                          <span className="w-1.5 h-1.5 rounded-full bg-current opacity-40"></span>
                          <span>{child.name}</span>
                        </Link>
                      ) : (
                        <button
                          key={child.name}
                          onClick={childOnClick}
                          className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-xs transition-all duration-200 ${
                            childActive 
                                ? 'bg-slate-800 text-white font-medium shadow-sm' 
                                : 'text-gray-400 hover:bg-slate-800/30 hover:text-white'
                            }`}
                        >
                          <span className="w-1.5 h-1.5 rounded-full bg-current opacity-40"></span>
                          <span>{child.name}</span>
                        </button>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </nav>
      </div>

      <div className="p-4 border-t border-gray-800 flex-shrink-0 bg-slate-900">
        <button
          onClick={finalLogout}
          className="w-full flex items-center justify-center gap-2 py-2.5 text-red-400 font-semibold bg-red-500/10 hover:bg-red-500/20 rounded-lg transition-all border border-red-500/10 hover:border-red-500/20 active:scale-95 text-sm"
        >
          <LogOut className="w-4 h-4 flex-shrink-0" />
          {sidebarOpen && 'Sign Out'}
        </button>
      </div>
    </aside>
  );
}

import { useState, useRef } from 'react';
import { Bold, Italic, Underline as UnderlineIcon, List, AlignLeft, AlignCenter, AlignRight } from 'lucide-react';

interface SimpleRichTextEditorProps {
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  className?: string;
}

export default function SimpleRichTextEditor({ value, onChange, placeholder = "Type something...", className = "" }: SimpleRichTextEditorProps) {
  const editorRef = useRef<HTMLDivElement>(null);
  const [isFocused, setIsFocused] = useState(false);
  const executeCommand = (command: string, arg?: string) => {
    document.execCommand(command, false, arg);
    editorRef.current?.focus();
  };

  const handleInput = () => {
    if (editorRef.current) {
        onChange(editorRef.current.innerHTML);
    }
  };

  return (
    <div className={`border border-gray-300 rounded-xl overflow-hidden bg-white ${isFocused ? 'ring-2 ring-blue-500/20 border-blue-500' : ''} ${className}`}>
        {/* Toolbar */}
        <div className="flex items-center gap-1 p-2 border-b border-gray-100 bg-gray-50/50">
            <button
                type="button"
                onClick={() => executeCommand('bold')}
                className="p-1.5 rounded hover:bg-gray-200 text-gray-600 transition-colors"
                title="Bold"
            >
                <Bold size={16} />
            </button>
            <button
                type="button"
                onClick={() => executeCommand('italic')}
                className="p-1.5 rounded hover:bg-gray-200 text-gray-600 transition-colors"
                title="Italic"
            >
                <Italic size={16} />
            </button>
            <button
                type="button"
                onClick={() => executeCommand('underline')}
                className="p-1.5 rounded hover:bg-gray-200 text-gray-600 transition-colors"
                title="Underline"
            >
                <UnderlineIcon size={16} />
            </button>
            <div className="w-px h-4 bg-gray-300 mx-1" />
            <button
                type="button"
                onClick={() => executeCommand('insertUnorderedList')}
                className="p-1.5 rounded hover:bg-gray-200 text-gray-600 transition-colors"
                title="Bullet List"
            >
                <List size={16} />
            </button>
            <div className="w-px h-4 bg-gray-300 mx-1" />
             <button
                type="button"
                onClick={() => executeCommand('justifyLeft')}
                className="p-1.5 rounded hover:bg-gray-200 text-gray-600 transition-colors"
                title="Align Left"
            >
                <AlignLeft size={16} />
            </button>
            <button
                type="button"
                onClick={() => executeCommand('justifyCenter')}
                className="p-1.5 rounded hover:bg-gray-200 text-gray-600 transition-colors"
                title="Align Center"
            >
                <AlignCenter size={16} />
            </button>
            <button
                type="button"
                onClick={() => executeCommand('justifyRight')}
                className="p-1.5 rounded hover:bg-gray-200 text-gray-600 transition-colors"
                title="Align Right"
            >
                <AlignRight size={16} />
            </button>
        </div>

        {/* Editor Area */}
        <div
            ref={editorRef}
            contentEditable
            onInput={handleInput}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            className="p-4 min-h-[120px] outline-none prose prose-sm max-w-none text-gray-700 font-normal"
            dangerouslySetInnerHTML={{ __html: value }}
            data-placeholder={placeholder}
            style={{
                emptyCells: 'show'
            }}
        />
        <style>{`
            [contenteditable]:empty:before {
                content: attr(data-placeholder);
                color: #9ca3af;
                pointer-events: none;
                display: block; /* For Firefox */
            }
        `}</style>
    </div>
  );
}

import { useState } from "react";

interface PerformanceItem {
  label: string;
  value: number;
  color: string;
}

interface SystemPerformanceChartProps {
  data?: PerformanceItem[];
}

export default function SystemPerformanceChart({ data = [] }: SystemPerformanceChartProps) {
  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);

  // Default data if none provided
  const chartData: PerformanceItem[] = data.length ? data : [
    { label: 'Server Load', value: 45, color: '#79B791' }, // Matching StatCard Present color
    { label: 'Memory', value: 62, color: '#2C497F' },      // Matching StatCard On-Leave color
    { label: 'Disk I/O', value: 28, color: '#CF9033' },    // Matching StatCard Late color
    { label: 'Network', value: 75, color: '#778797' },     // Matching StatCard Hired color
  ];

  const chartHeight = 200;
  const padding = 20;

  // Chart dimensions
  const width = 300;
  const height = 200;
  const barWidth = 40;
  const gap = (width - (padding * 2) - (barWidth * chartData.length)) / (chartData.length - 1);

  return (
    <div className="flex flex-col items-center justify-center p-4 w-full">
      <div className="relative">
        <svg width={width} height={height} className="overflow-visible">
          {/* Grid lines */}
          {[0, 25, 50, 75, 100].map((tick) => {
            const y = height - padding - (tick / 100) * (height - 2 * padding);
            return (
              <g key={tick}>
                <line 
                  x1={padding} 
                  y1={y} 
                  x2={width - padding} 
                  y2={y} 
                  stroke="#e5e7eb" 
                  strokeDasharray="4 4"
                />
                <text 
                  x={0} 
                  y={y + 4} 
                  className="text-[10px] fill-gray-400" 
                  textAnchor="end"
                >
                  {tick}%
                </text>
              </g>
            );
          })}

          {/* Bars */}
          {chartData.map((item, i) => {
            const x = padding + i * (barWidth + gap);
            const barHeight = (item.value / 100) * (height - 2 * padding);
            const y = height - padding - barHeight;

            return (
              <g 
                key={item.label}
                onMouseEnter={() => setHoveredIndex(i)}
                onMouseLeave={() => setHoveredIndex(null)}
                className="cursor-pointer"
              >
                <rect
                  x={x}
                  y={y}
                  width={barWidth}
                  height={barHeight}
                  fill={item.color}
                  rx={4}
                  className={`transition-all duration-300 ${
                    hoveredIndex === i ? 'opacity-100 filter brightness-110' : 'opacity-80'
                  }`}
                />
                {/* Tooltip-ish value on hover */}
                <text
                  x={x + barWidth / 2}
                  y={y - 5}
                  textAnchor="middle"
                  className={`text-xs font-bold fill-gray-700 transition-opacity duration-200 ${
                    hoveredIndex === i ? 'opacity-100' : 'opacity-0'
                  }`}
                >
                  {item.value}%
                </text>
              </g>
            );
          })}
        </svg>
      </div>

      {/* Legend/Labels */}
      <div className="flex justify-between w-full max-w-[300px] mt-4 px-2">
        {chartData.map((item) => (
          <div key={item.label} className="flex flex-col items-center text-center">
            <span className="text-[10px] font-medium text-gray-500 uppercase tracking-wider truncate w-16">
              {item.label}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

import { useState, useEffect, useMemo, ReactNode } from "react";
import { useLocation, Link } from "react-router-dom";

// NOTE: `quotes.json` can be large. Dynamically import it so it doesn't
// bloat the initial auth chunk. It will be loaded only when the AuthLayout
// actually mounts.

const QUOTE_TRANSITION_DURATION = 700;
const QUOTE_DISPLAY_DURATION = 15000;
const DEFAULT_LOGO = "/Logo.Municipal of Meycuayan.png";

interface Quote {
  quoteText: string;
  quoteAuthor: string;
}

interface AnimatedQuoteProps {
  quote: Quote;
  fadeIn: boolean;
}

const AnimatedQuote = ({ quote, fadeIn }: AnimatedQuoteProps) => (
  <div className="absolute left-6 bottom-6 right-6 text-left">
    <p
      className={`text-base italic text-slate-200 font-medium leading-relaxed transition-opacity duration-700 ${
        fadeIn ? "opacity-100" : "opacity-0"
      }`}
    >
      "{quote.quoteText}"
    </p>
    {quote.quoteAuthor && (
      <p 
        className={`text-sm mt-2 text-slate-400 font-semibold transition-opacity duration-700 ${
          fadeIn ? "opacity-100" : "opacity-0"
        }`}
      >
        — {quote.quoteAuthor}
      </p>
    )}
  </div>
);

const BrandingSection = () => (
  <div className="max-w-4xl text-center space-y-6 px-4">
    <Link to="/login" className="block transition-transform duration-300 hover:scale-105 active:scale-95">
      <img 
        src={DEFAULT_LOGO}
        alt="Meycauayan Logo" 
        className="w-56 h-56 mx-auto object-contain mb-4"
      />
    </Link>
    <h2 className="text-3xl font-extrabold text-slate-50 mb-2 tracking-wide drop-shadow-lg">
      City Human Resources Management Office
    </h2>
    <p className="text-lg leading-relaxed text-slate-300">
      A centralized{" "}
      <span className="font-semibold text-white">
        Human Resource Employee Management System
      </span>{" "}
      for the City Government of Meycauayan, Bulacan.
    </p>
  </div>
);

interface FormHeaderProps {
  image?: string;
  title: string;
  subtitle?: string;
}

const FormHeader = ({ image, title, subtitle }: FormHeaderProps) => (
  <div className="flex flex-col items-center justify-center gap-2 mb-4">
    <Link to="/login" className="transition-transform duration-200 hover:scale-110 active:scale-90">
      <img 
        src={image ?? DEFAULT_LOGO} 
        alt="Municipal of Meycauayan Logo" 
        className="w-12 h-12 rounded-lg object-contain" 
      />
    </Link>
    <h1 className="font-bold text-slate-950 text-xl text-center">
      {title}
    </h1>
    {subtitle && (
      <p className="text-xs text-slate-500 text-center">{subtitle}</p>
    )}
  </div>
);

interface AuthLayoutProps {
  children: ReactNode;
  title?: string;
  subtitle?: string;
  image?: string;
  showQuotes?: boolean;
  showBranding?: boolean;
  leftBgGradient?: string;
  maxWidth?: string;
}

/**
 * AuthLayout - Optimized authentication layout component
 */
export default function AuthLayout({
  children,
  title,
  subtitle,
  image,
  showQuotes = true,
  showBranding = true,
  leftBgGradient = "from-slate-950 to-slate-900",
  maxWidth = "max-w-sm"
}: AuthLayoutProps) {
  const [currentQuote, setCurrentQuote] = useState(0);
  const [fadeIn, setFadeIn] = useState(true);
  const [quotes, setQuotes] = useState<Quote[]>([]);
  const location = useLocation();

  // Load quotes dynamically to avoid bundling huge JSON into initial chunk
  useEffect(() => {
    let mounted = true;
    import("@/data/quotes_small.json")
      .then((m: { default: Quote[] }) => {
        if (mounted) setQuotes(m.default);
      })
      .catch((err: Error) => {
        console.error("Failed to load quotes:", err);
        if (mounted) setQuotes([]);
      });

    return () => { mounted = false; };
  }, []);

  // Current quote object
  const quote = useMemo((): Quote => 
    quotes?.[currentQuote] ?? { quoteText: "", quoteAuthor: "" },
    [currentQuote, quotes]
  );

  // Determine if current page is login
  const isLoginPage = useMemo(() => 
    location.pathname === "/login", 
    [location.pathname]
  );

  // Auto-generate title based on page type
  const pageTitle = useMemo(() => 
    title ?? (isLoginPage ? "Login your Account" : "Register your Account"),
    [title, isLoginPage]
  );

  // Check if quotes are available
  const hasQuotes = useMemo(() => 
    Array.isArray(quotes) && quotes.length > 0,
    [quotes]
  );

  useEffect(() => {
    if (!showQuotes || !hasQuotes) return;

    const interval = setInterval(() => {
      setFadeIn(false);

      const timeoutId = setTimeout(() => {
        setCurrentQuote((prev) => (prev + 1) % quotes.length);
        setFadeIn(true);
      }, QUOTE_TRANSITION_DURATION);

      // Cleanup nested timeout
      return () => clearTimeout(timeoutId);
    }, QUOTE_DISPLAY_DURATION);

    return () => clearInterval(interval);
  }, [showQuotes, hasQuotes]);

  return (
    <div className="min-h-screen flex bg-gradient-to-r from-slate-950 to-green-900 text-slate-100">
      {/* Left Section - Hero/Branding */}
      <div className={`hidden md:flex relative w-3/4 bg-gradient-to-r from-slate-950 to-green-900 items-center justify-center p-12 shadow-inner overflow-hidden`}>
        {showBranding && <BrandingSection />}
        
        {/* Rotating Quote */}
        {showQuotes && hasQuotes && (
          <AnimatedQuote quote={quote} fadeIn={fadeIn} />
        )}
      </div>

      {/* Right Section - Form Container */}
      <div className="flex flex-col justify-center w-full md:w-1/2 bg-white p-4 sm:p-6">
        <div className={`mx-auto w-full ${maxWidth}`}>
          <div className="bg-white border border-gray-200 rounded-[15px] shadow-lg p-5 sm:p-6 text-gray-800 hover:shadow-2xl transition-shadow duration-200">
            <FormHeader 
              image={image} 
              title={pageTitle} 
              subtitle={subtitle} 
            />
            
            {/* Form Content */}
            {children}
          </div>
        </div>
      </div>
    </div>
  );
}

import { useEffect } from 'react';
import { X } from 'lucide-react';
