import React from 'react';
import { X } from 'lucide-react';
import MiniCalendar from './MiniCalendar';
import EventsList from './EventsList';
import { isSameDay } from '../utils/dateUtils';
import { GridItem } from './CalendarGrid';
import { Holiday } from '@/types/calendar';

interface DrawerSidebarProps {
  isOpen: boolean;
  onClose: () => void;
  currentDate: Date;
  today: Date;
  month: string;
  year: number | string;
  onDateClick: (date: Date) => void;
  onPrevMonth: () => void;
  onNextMonth: () => void;
  displayedEvents: GridItem[];
  hours: { [key: string]: string };
  onEventClick: (event: GridItem) => void;
  showHolidays: boolean;
  holidays: Holiday[];
  announcements?: GridItem[];
  schedules?: GridItem[];
}

const DrawerSidebar: React.FC<DrawerSidebarProps> = ({isOpen,onClose,currentDate,today,month,year,onDateClick,onPrevMonth,onNextMonth,displayedEvents,hours,onEventClick,showHolidays,holidays,announcements = [],schedules = []}) => {
  
  // Filter and format announcements for the current date
  const todaysAnnouncements = announcements.filter(a => {
     const checkDate = new Date(currentDate);
     checkDate.setHours(0,0,0,0);

     if (a.startDate && a.endDate) {
         const start = new Date(a.startDate);
         const end = new Date(a.endDate);
         start.setHours(0,0,0,0);
         end.setHours(23,59,59,999);
         return checkDate >= start && checkDate <= end;
     } else {
         const created = new Date(a.createdAt ?? '');
         created.setHours(0,0,0,0);
         return created.getTime() === checkDate.getTime();
     }
  }).map(a => {
      let time = '09:00'; // Default time
      if (a.startTime) {
          time = a.startTime;
      }
            let color = 'bg-gray-200 border-gray-300 text-gray-700';
       if (a.priority === 'high') color = 'bg-gray-200 border-gray-300 text-gray-700';
       if (a.priority === 'urgent') color = 'bg-red-50 border-red-400 text-red-800';

      return {
          id: `announcement-${a.id}`,
          title: a.title,
          description: a.content,
          time: time,
          color: color,
          isAnnouncement: true,
          date: currentDate.toISOString().split('T')[0] // Assign current date for filtering
      };
  });

  // Filter schedules from displayedEvents for the current date
  const todaysSchedules = displayedEvents.filter(item => {
    if (item.type !== 'schedule' && !item.isSchedule) return false;
    // @ts-ignore
    const itemDate = new Date(item.date);
    // @ts-ignore
    return isSameDay(itemDate, currentDate);
  }).map(s => ({
    ...s,
    id: `schedule-sidebar-${s.id}`,
    description: `${s.time} - ${s.endTime || 'End'}`,
  }));

  // Filter out schedules from displayedEvents to avoid duplicates (they'll be added back separately)
  const eventsWithoutSchedules = displayedEvents.filter(item => 
    item.type !== 'schedule' && !item.isSchedule
  );

  const allEvents = [...eventsWithoutSchedules, ...todaysAnnouncements, ...todaysSchedules];

  return (
    <>
      {/* Overlay */}
      {isOpen && (
        <div 
          className="fixed inset-0 z-40 transition-opacity"
          onClick={onClose}
        />
      )}

      {/* Drawer */}
      <div 
        className={`fixed top-0 right-0 h-full w-80 bg-gray-100 border-l border-gray-300 shadow-2xl z-50 transform transition-transform duration-300 ease-in-out ${
          isOpen ? 'translate-x-0' : 'translate-x-full'
        }`}
      >
        <div className="h-full overflow-auto p-6">
          {/* Close Button */}
          <button
            onClick={onClose}
            className="absolute top-4 right-4 p-2 hover:bg-gray-200 rounded-lg transition-colors"
            aria-label="Close sidebar"
          >
            <X className="w-5 h-5 text-gray-700" />
          </button>

          {/* Mini Calendar */}
          <MiniCalendar
            currentDate={currentDate}
            today={today}
            month={month}
            year={year}
            onDateClick={onDateClick}
            onPrevMonth={onPrevMonth}
            onNextMonth={onNextMonth}
            showHolidays={showHolidays}
            holidays={holidays}
          />

          {/* Today's Schedule */}
          <EventsList
            events={allEvents}
            currentDate={currentDate}
            hours={hours}
            onEventClick={onEventClick}
          />
        </div>
      </div>
    </>
  );
};

export default DrawerSidebar;

import React, { ReactNode } from 'react';
import { useDrop } from 'react-dnd';
import { GridItem } from './CalendarGrid';

interface DroppableCellProps {
  date: Date;
  onDrop?: (event: GridItem, date: Date) => void;
  children: ReactNode;
}

/**
 * Droppable Cell Component
 * Wraps calendar date cells to accept dropped events
 */
const DroppableCell: React.FC<DroppableCellProps> = ({ date, onDrop, children }) => {
  const [{ isOver, canDrop }, drop] = useDrop(() => ({
    accept: 'EVENT',
    drop: (item: { event: GridItem }) => {
      if (onDrop) {
        onDrop(item.event, date);
      }
    },
    collect: (monitor) => ({
      isOver: monitor.isOver(),
      canDrop: monitor.canDrop(),
    }),
  }), [date, onDrop]);

  const getBackgroundColor = () => {
    if (isOver && canDrop) return 'rgba(39, 75, 70, 0.1)'; // Light green highlight
    if (canDrop) return 'transparent';
    return 'transparent';
  };

  return (
    <div
      // @ts-ignore
      ref={drop}
      style={{
        backgroundColor: getBackgroundColor(),
        transition: 'background-color 0.2s ease',
        height: '100%',
        minHeight: '120px'
      }}
    >
      {children}
    </div>
  );
};

export default DroppableCell;

import React, { useMemo } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { DAYS_SHORT, CALENDAR_STYLES } from '../constants/calendarConstants';
import { getDaysInMonth, getPreviousMonth, isToday } from '../utils/dateUtils';
import { getHolidaysForDay } from '../utils/eventUtils';
import type { Holiday } from '@/types/calendar';

interface MiniCalendarProps {
  currentDate: Date;
  today: Date;
  month: string;
  year: number | string;
  onDateClick: (date: Date) => void;
  onPrevMonth: () => void;
  onNextMonth: () => void;
  showHolidays: boolean;
  holidays: Holiday[];
}

const MiniCalendar: React.FC<MiniCalendarProps> = ({ currentDate, today, month, year, onDateClick, onPrevMonth, onNextMonth, showHolidays, holidays }) => {
  const calendarDays = useMemo(() => {
    const { daysInMonth, startingDayOfWeek } = getDaysInMonth(currentDate);
    const prevMonth = getPreviousMonth(currentDate);
    const { daysInMonth: prevMonthDays } = getDaysInMonth(prevMonth);
    const cells: React.ReactElement[] = [];

    // Previous month days
    for (let i = startingDayOfWeek - 1; i >= 0; i--) {
      const prevDay = prevMonthDays - i;
      cells.push(
        <div
          key={`prev-${i}`}
          className="aspect-square border border-gray-300 rounded flex items-center justify-center text-gray-400 text-xs hover:bg-gray-100 cursor-pointer"
          onClick={() => onDateClick(new Date(prevMonth.getFullYear(), prevMonth.getMonth(), prevDay))}
        >
          {prevDay}
        </div>
      );
    }

    // Current month days
    for (let d = 1; d <= daysInMonth; d++) {
      // @ts-ignore
      const isTodayCell = isToday(currentDate, d, today);
      const isSelected = currentDate.getDate() === d;
      
      const dayHolidays = showHolidays 
        // @ts-ignore
        ? getHolidaysForDay(holidays, currentDate.getMonth(), d) 
        : [];
      const hasHoliday = dayHolidays.length > 0;

      cells.push(
        <div
          key={`curr-${d}`}
          onClick={() => onDateClick(new Date(currentDate.getFullYear(), currentDate.getMonth(), d))}
          className={`aspect-square border rounded flex flex-col items-center justify-center text-xs font-medium cursor-pointer transition-all relative ${
            isTodayCell
              // @ts-ignore
              ? CALENDAR_STYLES.TODAY
              : isSelected
              // @ts-ignore
              ? CALENDAR_STYLES.SELECTED
              // @ts-ignore
              : CALENDAR_STYLES.DEFAULT
          }`}
        >
          {d}
          {hasHoliday && (
            <div className="w-1 h-1 rounded-full bg-red-500 mt-0.5"></div>
          )}
        </div>
      );
    }

    return cells;
  }, [currentDate, today, onDateClick, showHolidays, holidays]);

  return (
    <div className="mb-8 mt-8">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl-md font-bold text-gray-900">{month} {year}</h2>
        <div className="flex gap-1">
          <button
            onClick={onPrevMonth}
            className="p-1 hover:bg-gray-200 rounded transition-colors"
            aria-label="Previous month"
          >
            <ChevronLeft className="w-4 h-4 text-gray-700" />
          </button>
          <button
            onClick={onNextMonth}
            className="p-1 hover:bg-gray-200 rounded transition-colors"
            aria-label="Next month"
          >
            <ChevronRight className="w-4 h-4 text-gray-700" />
          </button>
        </div>
      </div>
      <div className="grid grid-cols-7 gap-1 mb-2">
        {DAYS_SHORT.map((d, i) => (
          <div key={i} className="text-center text-xs font-semibold text-gray-600">
            {d}
          </div>
        ))}
      </div>
      <div className="grid grid-cols-7 gap-1">{calendarDays}</div>
    </div>
  );
};

export default MiniCalendar;

import { getDaysInMonth, isSameDay } from './dateUtils'; 
import type { CalendarDisplayItem, Holiday, Announcement, ScheduleEntry } from '@/types/calendar';

/**
 * Filter events for a specific date
 * @param {Array} events - Array of events
 * @param {Date} date - Date to filter for
 * @returns {Array} - Filtered events
 */
export const filterEventsByDate = (events: CalendarDisplayItem[], date: Date): CalendarDisplayItem[] => {
  if (!events || !Array.isArray(events)) return [];
  
  return events.filter(item => {
    const itemDate = new Date(item.date || '');
    return isSameDay(itemDate, date);
  });
};

/**
 * Sort events by time
 * @param {Array} items - Array of calendar items (events, holidays, schedules)
 * @returns {Array} - Sorted items
 */
export const sortCalendarItemsByTime = (items: CalendarDisplayItem[]): CalendarDisplayItem[] => {
  if (!items || !Array.isArray(items)) return [];
  return [...items].sort((a, b) => {
    // Convert times to a comparable format (e.g., minutes from midnight)
    const timeA = a.time ? parseInt(String(a.time).split(':')[0]) * 60 + parseInt(String(a.time).split(':')[1] || '0') : 0;
    const timeB = b.time ? parseInt(String(b.time).split(':')[0]) * 60 + parseInt(String(b.time).split(':')[1] || '0') : 0;
    return timeA - timeB;
  });
};

/**
 * Combine events, holidays, announcements, and schedules into a single array for display
 * @param {Array} events - Regular events
 * @param {Array} holidays - Holiday data
 * @param {boolean} showHolidays - Whether to include holidays
 * @param {Array} announcements - Announcements data
 * @param {Date} currentDate - Current date context for year and month
 * @param {Array} schedules - Employee schedules
 * @returns {Array} - Combined and sorted calendar items
 */
export const combineCalendarItems = (events: CalendarDisplayItem[], holidays: Holiday[], showHolidays: boolean, announcements: Announcement[], currentDate: Date, schedules: ScheduleEntry[] = []): CalendarDisplayItem[] => {
  let allItems = [...events];
  const currentYear = currentDate.getFullYear();
  const currentMonth = currentDate.getMonth();

  // Add holidays
  if (showHolidays && holidays && Array.isArray(holidays)) {
    const holidayItems: CalendarDisplayItem[] = holidays.map(h => ({
      ...h,
      id: `holiday-${h.id}-${currentYear}`,
      title: h.title || h.name || 'Holiday',
      type: 'holiday', // Explicit type
      time: '00:00', // All day
      isHoliday: true,
      date: new Date(currentYear, h.month, h.day).toISOString().split('T')[0], // Assign a specific date for sorting
    }));
    allItems = [...allItems, ...holidayItems];
  }

  // Add announcements
  if (announcements && Array.isArray(announcements)) {
    const announcementItems = announcements.map(a => ({
      ...a,
      id: `announcement-${a.id}`,
      type: 'announcement', // Explicit type
      time: '00:00', // All day
      isAnnouncement: true,
      date: a.startDate || a.createdAt, // Use startDate or createdAt
    }));
    allItems = [...allItems, ...announcementItems];
  }

  // Add schedules - expand each schedule to show on relevant days
  if (schedules && Array.isArray(schedules) && schedules.length > 0) {
    const scheduleItems: CalendarDisplayItem[] = [];
    console.log('📅 Processing schedules for calendar:', schedules);
    
    schedules.forEach(schedule => {
      const startDateStr = schedule.startDate || schedule.startDate;
      const endDateStr = schedule.endDate || schedule.endDate;
      const daysString = schedule.days || schedule.dayOfWeek || '';
      // @ts-ignore
      const scheduleDays = daysString ? daysString.split(',').map(d => d.trim()) : [];
      
      console.log(`Duty: ${schedule.duties || schedule.scheduleName}`, { startDateStr, endDateStr, scheduleDays });
      
      // Check if we have valid date strings (not 'Recurring' or empty)
      const hasValidDates = startDateStr && endDateStr && 
                            startDateStr !== 'Recurring' && endDateStr !== 'Recurring';
      
      if (hasValidDates) {
        // Parse dates as local time to avoid timezone offset issues
        const parseLocalDate = (dateStr: string | Date) => {
          const str = String(dateStr).split('T')[0]; // Get just the date part
          const [year, month, day] = str.split('-').map(Number);
          return new Date(year, month - 1, day); // month is 0-indexed
        };
        
        const start = parseLocalDate(startDateStr);
        const end = parseLocalDate(endDateStr);
        const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        
        console.log(`Iterating from ${start.toDateString()} to ${end.toDateString()}`);
        
        // Iterate through each day in the schedule range for the current month view
        for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
          // Only add if the day is in the current month being viewed
          if (d.getMonth() === currentMonth && d.getFullYear() === currentYear) {
            const dayName = dayNames[d.getDay()];
            
            // Check if this day of week is in the schedule's days (or if no specific days, show all)
            if (scheduleDays.length === 0 || scheduleDays.includes(dayName)) {
              // Format date as YYYY-MM-DD in local time
              const dateStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
              
              scheduleItems.push({
                id: `schedule-${schedule.id}-${dateStr}`,
                title: schedule.duties || schedule.scheduleName || 'Work Duties',
                type: 'schedule',
                isSchedule: true,
                time: schedule.startTime || schedule.startTime || '09:00',
                endTime: schedule.endTime || schedule.endTime || '17:00',
                date: dateStr,
                startDate: startDateStr,
                endDate: endDateStr,
                originalSchedule: schedule
              });
            }
          }
        }
      } else if (scheduleDays.length > 0) {
        // No date range, but we have specific days - show for current month on those days
        const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
        const daysInCurrentMonth = new Date(currentYear, currentMonth + 1, 0).getDate();
        
        for (let day = 1; day <= daysInCurrentMonth; day++) {
          const d = new Date(currentYear, currentMonth, day);
          const dayName = dayNames[d.getDay()];
          
          if (scheduleDays.includes(dayName)) {
            const dateStr = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            
            scheduleItems.push({
              id: `schedule-${schedule.id}-${dateStr}`,
              title: schedule.duties || schedule.scheduleName || 'Work Duties',
              type: 'schedule',
              isSchedule: true,
              time: schedule.startTime || schedule.startTime || '09:00',
              endTime: schedule.endTime || schedule.endTime || '17:00',
              date: dateStr,
              originalSchedule: schedule
            });
          }
        }
      }
    });
    
    console.log(`Generated ${scheduleItems.length} schedule items for display`);
    allItems = [...allItems, ...scheduleItems];
  }
  
  // Deduplicate items by ID to prevent React key errors
  const uniqueItems = Array.from(new Map(allItems.map(item => [item.id, item])).values());
  
  return sortCalendarItemsByTime(uniqueItems);
};

/**
 * Generate a random event color from available colors
 * @param {Array} colors - Array of color classes
 * @returns {string} - Random color class
 */
export const getRandomEventColor = (colors: string[]): string => {
  return colors[Math.floor(Math.random() * colors.length)];
};

export const getEventStyles = (type: string, title?: string, priority?: string) => {
  // 1. Announcement priority-based colors
  if (type === "announcement") {
    const p = priority?.toLowerCase();
    switch (p) {
      case "high":
        // High priority → Deep Red
        return { textColor: "text-red-950", badgeBg: "bg-red-950/10", badgeText: "text-red-950", borderColor: "border-red-950/20", bgColor: "bg-white" };
      case "urgent":
        // Urgent → Deep Navy
        return { textColor: "text-blue-950", badgeBg: "bg-blue-950/10", badgeText: "text-blue-950", borderColor: "border-blue-950/20", bgColor: "bg-white" };
      default:
        // Normal/Low → Deep Emerald
        return { textColor: "text-gray-900", badgeBg: "bg-gray-100", badgeText: "text-gray-900", borderColor: "border-gray-200", bgColor: "bg-white" };
    }
  }

  // 2. Holiday type-based colors
  const holidayType = type?.toLowerCase();

  // Regular Holiday → Deep Burgundy
  if (holidayType === "regular holiday" || holidayType === "holiday") {
    return { textColor: "text-red-950", badgeBg: "bg-red-950/10", badgeText: "text-red-950", borderColor: "border-red-950/20", bgColor: "bg-white" };
  }

  // Special Non-Working Holiday → Deep Indigo
  if (holidayType === "special non-working" || holidayType === "non-working holiday") {
    return { textColor: "text-indigo-950", badgeBg: "bg-indigo-950/10", badgeText: "text-indigo-950", borderColor: "border-indigo-950/20", bgColor: "bg-white" };
  }

  // Special Holiday / Working Holiday → Deep Amber
  if (holidayType === "special holiday" || holidayType === "working holiday") {
    return { textColor: "text-amber-900", badgeBg: "bg-amber-900/10", badgeText: "text-amber-900", borderColor: "border-amber-900/20", bgColor: "bg-white" };
  }

  // 3. Schedule Type → Deep Slate
  if (type === "schedule") {
    return { textColor: "text-slate-900", badgeBg: "bg-slate-900/10", badgeText: "text-slate-900", borderColor: "border-slate-900/20", bgColor: "bg-white" };
  }

  // 4. Default / Event → Deep Gray
  return { textColor: "text-gray-900", badgeBg: "bg-gray-900/10", badgeText: "text-gray-900", borderColor: "border-gray-900/20", bgColor: "bg-white" };
};

import React, { useState, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import api from '@/api/axios';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { AlertCircle, CheckCircle, ChevronLeft, ChevronRight, Plus, Pencil } from 'lucide-react';

const BudgetFormModal = React.lazy(() => import('@/components/Custom/Compliance/BudgetFormModal'));

// --- Types ---
interface BudgetAllocation {
    id: number;
    year: number;
    department: string;
    totalBudget: number | string;
    utilizedBudget: number | string;
    remainingBudget: number | string;
    utilizationRate: number | string;
    notes?: string;
    updatedAt: string;
}

interface BudgetDashboardProps {
    selectedDeptName?: string; // "CHRMO" or "All"
}

interface BudgetSummary {
    total: number;
    utilized: number;
    remaining: number;
    dept: string;
    rate: number;
}

interface BudgetParams {
    year: number;
    department?: string;
}

const ITEMS_PER_PAGE = 10;

const BudgetTrackingDashboard: React.FC<BudgetDashboardProps> = ({ selectedDeptName = 'All' }) => {
    const currentYear = new Date().getFullYear();
    const [currentPage, setCurrentPage] = useState(1);
    
    // Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalMode, setModalMode] = useState<'create' | 'edit'>('create');
    const [selectedBudget, setSelectedBudget] = useState<BudgetAllocation | undefined>(undefined);
    const [isProcessing, setIsProcessing] = useState(false);

    // Fetch Budget Data
    const { data: budgetData, isLoading, error, refetch } = useQuery<BudgetAllocation[]>({
        queryKey: ['budget-tracking', selectedDeptName],
        queryFn: async () => {
            const params: BudgetParams = { year: currentYear };
            if (selectedDeptName && selectedDeptName !== 'All') {
                params.department = selectedDeptName;
            }

            const response = await api.get('/budget-allocation', { 
                params
            });
            return response.data.allocations || [];
        }
    });

    // Fetch Departments for Dropdown
    const { data: departments = [] } = useQuery<{id: number, name: string}[]>({
        queryKey: ['departments-simple'],
        queryFn: async () => {
             const response = await api.get('/departments');
             return response.data.departments || [];
        }
    });

    // Reset pagination when filter changes
    React.useEffect(() => {
        setCurrentPage(1);
    }, [selectedDeptName]);

    // Derived Data Calculation
    const { summary, activeBudget } = useMemo(() => {
        if (!budgetData) return { summary: null, activeBudget: null };

        const firstBudget = budgetData.length > 0 ? budgetData[0] : null;
        
        // Calculate totals for "All" view
        const totalSummary = budgetData.reduce((acc, curr) => ({
            total: acc.total + Number(curr.totalBudget || 0),
            utilized: acc.utilized + Number(curr.utilizedBudget || 0),
            remaining: acc.remaining + Number(curr.remainingBudget || 0),
        }), { total: 0, utilized: 0, remaining: 0 });

        return { 
            activeBudget: firstBudget,
            summary: totalSummary
        };
    }, [budgetData]);

    const displayData: BudgetSummary = useMemo(() => {
        if (selectedDeptName !== 'All' && activeBudget) {
            return { 
                total: Number(activeBudget.totalBudget), 
                utilized: Number(activeBudget.utilizedBudget), 
                remaining: Number(activeBudget.remainingBudget),
                dept: activeBudget.department,
                rate: Number(activeBudget.utilizationRate)
            };
        }
        return {
            total: summary?.total || 0,
            utilized: summary?.utilized || 0,
            remaining: summary?.remaining || 0,
            dept: 'All Departments',
            rate: (summary?.total || 0) > 0 ? ((summary?.utilized || 0) / (summary?.total || 1)) * 100 : 0
        };
    }, [selectedDeptName, activeBudget, summary]);

    // Pagination Logic
    const paginatedData = useMemo(() => {
        if (!budgetData) return [];
        const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
        return budgetData.slice(startIndex, startIndex + ITEMS_PER_PAGE);
    }, [budgetData, currentPage]);

    const totalPages = budgetData ? Math.ceil(budgetData.length / ITEMS_PER_PAGE) : 0;

    const chartData = [
        { name: 'Utilized', value: displayData.utilized, color: '#d97706' }, // Amber-600
        { name: 'Remaining', value: displayData.remaining, color: '#059669' } // Emerald-600
    ];

    // --- Actions ---
    const handleAddBudget = () => {
        setModalMode('create');
        setSelectedBudget(undefined);
        setIsModalOpen(true);
    };

    const handleEditBudget = (budget: BudgetAllocation) => {
        setModalMode('edit');
        setSelectedBudget(budget);
        setIsModalOpen(true);
    };

    const handleFormSubmit = async (data: Record<string, unknown>) => {
        setIsProcessing(true);
        try {
            if (modalMode === 'create') {
                await api.post('/budget-allocation', data);
            } else {
                if (!selectedBudget?.id) return;
                await api.put(`/budget-allocation/${selectedBudget.id}`, data);
            }
            // Success
            setIsModalOpen(false);
            refetch();
        } catch (err) {
            console.error("Failed to save budget", err);
            alert("Failed to save budget allocation. Please check inputs.");
        } finally {
            setIsProcessing(false);
        }
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="p-8 text-center text-red-500 bg-red-50 rounded-lg border border-red-100">
                <AlertCircle className="mx-auto mb-2 text-red-400" size={32} />
                <p>Failed to load budget data. Please try again later.</p>
            </div>
        );
    }

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h3 className="text-xl font-bold text-gray-900 flex items-center gap-2">
                        Budget Tracking ({currentYear})
                    </h3>
                    <p className="text-sm text-gray-600">
                        {displayData.dept} • Monitor allocation and utilization in real-time.
                    </p>
                </div>
                <div className="flex items-center gap-2">
                    <div className="px-4 py-2 bg-blue-50 text-blue-700 rounded-lg text-sm font-semibold border border-blue-100 shadow-sm">
                        Fiscal Year {currentYear}
                    </div>
                    {(selectedDeptName === 'All' || !activeBudget) && (
                        <button 
                            onClick={handleAddBudget}
                            className="flex items-center gap-2 px-4 py-2 bg-gray-900 text-white rounded-lg text-sm font-semibold shadow-md hover:bg-gray-800 transition-all hover:scale-[1.02] active:scale-95"
                        >
                            <Plus size={16} />
                            Set Budget
                        </button>
                    )}
                </div>
            </div>

            {/* Main Stats Cards - Master Design */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {/* Total Allocated */}
                <div className="bg-white p-4 rounded-lg border border-gray-200 shadow-sm hover:shadow-md transition-all duration-300 group">
                    <div className="flex items-center justify-between mb-2">
                        <div className="w-8 h-8 bg-gray-800 rounded-lg shadow-sm transition-transform"></div>
                    </div>
                    <div className="text-2xl font-bold text-gray-900">₱{displayData.total.toLocaleString()}</div>
                    <div className="text-xs font-semibold text-gray-500 mt-1">Total Allocation</div>
                    <p className="text-[11px] text-gray-400 mt-1 font-medium">Approved Annual Budget</p>
                </div>

                {/* Utilized */}
                <div className="bg-white p-4 rounded-lg border border-gray-200 shadow-sm hover:shadow-md transition-all duration-300 group">
                    <div className="flex items-center justify-between mb-2">
                        <div className="w-8 h-8 bg-gray-700 rounded-lg shadow-sm transition-transform"></div>
                    </div>
                    <div className="text-2xl font-bold text-gray-900">₱{displayData.utilized.toLocaleString()}</div>
                    <div className="text-xs font-semibold text-gray-500 mt-1">Utilized Budget</div>
                    <div className="flex items-center gap-2 mt-2">
                        <div className="flex-1 h-1.5 bg-gray-100 rounded-full overflow-hidden">
                            <div 
                                className="h-full bg-red-500 rounded-full transition-all duration-500" 
                                style={{ width: `${Math.min(displayData.rate, 100)}%` }}
                            />
                        </div>
                        <span className="text-[10px] font-bold text-gray-700">{displayData.rate.toFixed(1)}%</span>
                    </div>
                </div>

                {/* Remaining */}
                <div className="bg-white p-4 rounded-lg border border-gray-200 shadow-sm hover:shadow-md transition-all duration-300 group">
                    <div className="flex items-center justify-between mb-2">
                        <div className="w-8 h-8 bg-gray-600 rounded-lg shadow-sm transition-transform"></div>
                    </div>
                    <div className="text-2xl font-bold text-gray-900">₱{displayData.remaining.toLocaleString()}</div>
                    <div className="text-xs font-semibold text-gray-500 mt-1">Remaining Balance</div>
                     <p className="text-[10px] text-gray-500 mt-1 font-medium flex items-center gap-1">
                        <CheckCircle size={10} /> Available for disbursement
                     </p>
                </div>
            </div>

            {/* Charts & Details */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Chart */}
                <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm lg:col-span-1 flex flex-col items-center justify-center">
                    <h4 className="text-sm font-bold text-gray-800 w-full mb-6 border-b border-gray-100 pb-2">Utilization Breakdown</h4>
                    <div className="h-64 w-full relative" style={{ width: '100%', height: '256px' }}>
                        <ResponsiveContainer width="100%" height="100%" minWidth={200} minHeight={200}>
                            <PieChart>
                                <Pie
                                    data={chartData}
                                    cx="50%"
                                    cy="50%"
                                    innerRadius={70}
                                    outerRadius={90}
                                    paddingAngle={5}
                                    dataKey="value"
                                    cornerRadius={5}
                                    stroke="none"
                                >
                                    {chartData.map((entry, index) => (
                                        <Cell key={`cell-${index}`} fill={entry.color} />
                                    ))}
                                </Pie>
                                <Tooltip 
                                    formatter={(value: unknown) => [`₱${Number(value || 0).toLocaleString()}`, 'Amount']}
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                />
                            </PieChart>
                        </ResponsiveContainer>
                        {/* Center Text */}
                        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                            <span className="text-xs text-gray-400 font-medium">Utilization</span>
                            <span className={`text-xl font-bold ${displayData.rate > 90 ? 'text-red-600' : 'text-green-600'}`}>
                                {displayData.rate.toFixed(1)}%
                            </span>
                        </div>
                    </div>
                </div>

                {/* Allocations List */}
                <div className="bg-white rounded-xl border border-gray-200 shadow-sm lg:col-span-2 flex flex-col">
                    <div className="px-6 py-4 border-b border-gray-100 bg-gray-50/50 flex justify-between items-center">
                        <h4 className="text-sm font-bold text-gray-800">Department Allocations</h4>
                        <div className="text-xs text-gray-500 font-medium">
                            Page {currentPage} of {totalPages}
                        </div>
                    </div>
                    
                    <div className="overflow-x-auto flex-1">
                        <table className="w-full text-sm text-left">
                            <thead className="bg-gray-200 shadow-md text-gray-700">
                                <tr>
                                    <th className="px-6 py-4 text-sm font-bold tracking-wide whitespace-nowrap">Department</th>
                                    <th className="px-6 py-4 text-sm font-bold tracking-wide text-right whitespace-nowrap">Total Budget</th>
                                    <th className="px-6 py-4 text-sm font-bold tracking-wide text-right whitespace-nowrap">Utilized</th>
                                    <th className="px-6 py-4 text-sm font-bold tracking-wide text-right whitespace-nowrap">Remaining</th>
                                    <th className="px-6 py-4 text-sm font-bold tracking-wide text-center whitespace-nowrap">% Used</th>
                                    <th className="px-6 py-4 text-sm font-bold tracking-wide text-center whitespace-nowrap">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {paginatedData.map((item: BudgetAllocation) => (
                                    <tr key={item.id} className="hover:bg-[#F8F9FA] hover:shadow-xl transition-colors group bg-white">
                                        <td className="px-6 py-4 font-semibold text-gray-900 border-l-2 border-transparent group-hover:border-blue-500 transition-all">
                                            {item.department}
                                        </td>
                                        <td className="px-6 py-4 text-right tabular-nums text-gray-700 font-medium">
                                            ₱{Number(item.totalBudget).toLocaleString()}
                                        </td>
                                        <td className="px-6 py-4 text-right tabular-nums text-red-600 font-bold">
                                            ₱{Number(item.utilizedBudget).toLocaleString()}
                                        </td>
                                        <td className="px-6 py-4 text-right tabular-nums text-green-600 font-bold">
                                            ₱{Number(item.remainingBudget).toLocaleString()}
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <span className={`px-2.5 py-1 rounded-full text-xs font-bold inline-block min-w-[3.5rem] text-center ${
                                                Number(item.utilizationRate) > 90 ? 'bg-red-100 text-red-700' : 
                                                Number(item.utilizationRate) > 70 ? 'bg-amber-100 text-amber-700' : 
                                                'bg-green-100 text-green-700'
                                            }`}>
                                                {Number(item.utilizationRate).toFixed(1)}%
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleEditBudget(item)}
                                                className="p-1.5 rounded-lg text-gray-400 hover:text-blue-600 hover:bg-blue-50 transition-all"
                                                title="Edit Allocation"
                                            >
                                                <Pencil size={16} />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                                {(!budgetData || budgetData.length === 0) && (
                                    <tr>
                                        <td colSpan={6} className="px-6 py-12 text-center text-gray-400 italic bg-gray-50/30">
                                            No allocations found. <button onClick={handleAddBudget} className="text-blue-600 font-bold hover:underline">Set a budget</button> to get started.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>

                    {/* Pagination Controls */}
                    {totalPages > 1 && (
                        <div className="px-6 py-3 border-t border-gray-100 bg-gray-50/50 flex justify-end items-center gap-2">
                             {/* ... pagination UI same as before ... */}
                            <button
                                onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                                disabled={currentPage === 1}
                                className="p-2 rounded-lg hover:bg-white hover:shadow-sm border border-transparent hover:border-gray-200 text-gray-500 disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:shadow-none transition-all"
                            >
                                <ChevronLeft size={16} />
                            </button>
                            <span className="text-xs font-medium text-gray-600">
                                {currentPage} / {totalPages}
                            </span>
                            <button
                                onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                                disabled={currentPage === totalPages}
                                className="p-2 rounded-lg hover:bg-white hover:shadow-sm border border-transparent hover:border-gray-200 text-gray-500 disabled:opacity-30 disabled:hover:bg-transparent disabled:hover:shadow-none transition-all"
                            >
                                <ChevronRight size={16} />
                            </button>
                        </div>
                    )}
                </div>
            </div>

            {/* Modals */}
             <React.Suspense fallback={null}>
                <BudgetFormModal 
                    isOpen={isModalOpen}
                    onClose={() => setIsModalOpen(false)}
                    mode={modalMode}
                    departments={departments}
                    initialData={selectedBudget as unknown as { year: number; department: string; totalBudget: number; notes?: string; id?: number }}
                    onSubmit={handleFormSubmit}
                    isProcessing={isProcessing}
                />
            </React.Suspense>
        </div>
    );
};

export default BudgetTrackingDashboard;

import React from 'react';
import { Download, Printer, AlertCircle, X } from 'lucide-react';
import axios from 'axios';

interface ReportType {
    id: string;
    title: string;
    description: string;

    color: string;
    bg: string;
    frequency: string;
}

const reports: ReportType[] = [
    {
        id: 'form9',
        title: 'CSC Form No. 9',
        description: 'Request for Publication of Vacant Positions. Required for posting vacancies.',
        color: 'text-blue-600',
        bg: 'bg-blue-50',
        frequency: 'As needed'
    },
    {
        id: 'form33',
        title: 'CS Form No. 33',
        description: 'Appointment Form (KSS). Official document for new hires and promotions.',
        color: 'text-emerald-600',
        bg: 'bg-emerald-50',
        frequency: 'Per appointment'
    },
    {
        id: 'psipop',
        title: 'PSI-POP',
        description: 'Personal Services Itemization and Plantilla of Personnel.',
        color: 'text-amber-600',
        bg: 'bg-amber-50',
        frequency: 'Annual'
    }
];

import { reportsApi } from '@/api/reportsApi';
import { plantillaApi } from '@/api/plantillaApi';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import * as XLSX from 'xlsx';
import toast from 'react-hot-toast';
import { useState } from 'react';
import AppointmentFormModal from '@features/EmployeeManagement/Admin/Plantilla/components/AppointmentFormModal';
import Form9Modal from '@features/EmployeeManagement/Admin/Plantilla/components/Form9Modal';
import { useForm9 } from '@features/EmployeeManagement/Admin/Plantilla/hooks/useForm9';
import { 
  exportForm9ToPDF, 
  exportForm9ToExcel, 
  type Form9Header,
  type Form9Position 
} from '@/utils/cscFormExports';

import PSIPOPModal from '@features/EmployeeManagement/Admin/Plantilla/components/PSIPOPModal';
import Combobox from '@/components/Custom/Combobox';

import { Position } from '@/api/plantillaApi';

const ComplianceReportsDashboard: React.FC = () => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalReportId, setModalReportId] = useState<string | null>(null);
    const [positions, setPositions] = useState<Position[]>([]);
    const [selectedPositionId, setSelectedPositionId] = useState<string>('');
    const [loadingPositions, setLoadingPositions] = useState(false);
    
    // New state for Complex Modal
    const [isAppointmentFormOpen, setIsAppointmentFormOpen] = useState(false);
    const [selectedAppointmentPosition, setSelectedAppointmentPosition] = useState<Position | null>(null);
    
    // PSI-POP Modal State (New WYSIWYG)
    const [isPSIPOPModalOpen, setIsPSIPOPModalOpen] = useState(false);
    const [psipopPositions, setPsipopPositions] = useState<Position[]>([]); 
    const [loadingPsipop, setLoadingPsipop] = useState(false);
    
    // Form 9 Hook (Zustand + React Query)
    const { openForm9Modal } = useForm9();

    const generatePDF = (reportId: string, data: unknown[], meta: Record<string, unknown>) => {
        // ... (PDF Generation Logic - Unchanged) ...
        const doc = new jsPDF();
        
        // Header
        doc.setFontSize(10);
        doc.text("Republic of the Philippines", 105, 15, { align: "center" });
        doc.text("Province of Bulacan", 105, 20, { align: "center" });
        doc.setFontSize(14);
        doc.setFont("helvetica", "bold");
        doc.text("CITY GOVERNMENT OF LIGAO", 105, 28, { align: "center" });
        
        doc.setFontSize(12);
        doc.setFont("helvetica", "normal");
        doc.text((meta.formName as string) || (meta.form_name as string) || "Official Report", 105, 40, { align: "center" });
        doc.setFontSize(16);
        doc.setFont("helvetica", "bold");
        doc.text((meta.title as string) || "Report Document", 105, 48, { align: "center" });
        
        doc.line(20, 55, 190, 55);
        
        // Content based on ID
        if (reportId === 'form9' || reportId === 'rai' || reportId === 'psipop') {
             const tableColumn = Object.keys(data[0] || {}).map(key => key.toUpperCase().replace(/_/g, " "));
             const tableRows = (data as Record<string, unknown>[]).map((row) => Object.values(row).map(v => String(v ?? '')));
             
             autoTable(doc, {
                head: [tableColumn],
                body: tableRows,
                startY: 60,
                theme: 'grid',
                styles: { fontSize: 8 },
                headStyles: { fillColor: [22, 163, 74] } // Green
             });
        } else if (reportId === 'form33') {
             // Appointment Form (Key-Value)
             let y = 70;
             Object.entries(data as Record<string, unknown>).forEach(([key, value]) => {
                 doc.setFontSize(10);
                 doc.setFont("helvetica", "bold");
                 doc.text(`${key.replace(/_/g, " ").toUpperCase()}:`, 20, y);
                 doc.setFont("helvetica", "normal");
                 doc.text(`${String(value || "N/A")}`, 80, y);
                 y += 10;
             });
        }
        
        // Save/Open
        const pdfBlob = doc.output('blob');
        const url = URL.createObjectURL(pdfBlob);
        window.open(url, '_blank');
    };

    const handlePreviewClick = async (reportId: string) => {
        if (reportId === 'psipop') {
            const toastId = toast.loading("Loading PSI-POP data...");
            try {
                setLoadingPsipop(true);
                const response = await plantillaApi.getPositions({});
                if (response.data && response.data.positions) {
                     setPsipopPositions(response.data.positions);
                     setIsPSIPOPModalOpen(true);
                     toast.dismiss(toastId);
                } else {
                     toast.error("No positions found", { id: toastId });
                }
            } catch (err) {
                console.error(err);
                toast.error("Failed to load positions", { id: toastId });
            } finally {
                setLoadingPsipop(false);
            }
            return;
        }

        // CS Form No. 9 - Request for Publication of Vacant Positions
        if (reportId === 'form9') {
            openForm9Modal();
            return;
        }

        if (reportId === 'form33') {
            setModalReportId(reportId);
            setIsModalOpen(true);
            setLoadingPositions(true);
            try {
                const response = await plantillaApi.getPositions({});
                // Filter only filled positions for appointments
                const filled = response.data.positions.filter((p: Position) => p.incumbentId);
                setPositions(filled);
            } catch (err) {
                toast.error("Failed to load positions");
                setIsModalOpen(false);
            } finally {
                setLoadingPositions(false);
            }
        } else {
            handleDownload(reportId, 'pdf');
        }
    };

    const handleDownload = async (reportId: string, type: 'pdf' | 'excel', params: Record<string, unknown> = {}) => {
        try {
            toast.loading("Generating report...");
            
            // Form 9 - Use official CSC form layout
            if (reportId === 'form9') {
                const response = await reportsApi.getReportData('form9', params);
                toast.dismiss();
                
                if (!response.success || !response.data || response.data.length === 0) {
                    toast.error("No vacant positions found to export");
                    return;
                }
                
                // Transform API data to Form9Position format
                const positionsData: Form9Position[] = response.data.map((pos: Record<string, unknown>, idx: number) => ({
                    no: idx + 1,
                    positionTitle: pos.positionTitle || pos.positionTitle || '',
                    plantillaItemNo: pos.itemNumber || pos.itemNumber || '',
                    salaryGrade: (pos.salaryGrade || pos.salaryGrade || '').toString(),
                    monthlySalary: (pos.monthlySalary || pos.monthlySalary || '').toLocaleString(),
                    education: pos.education || '',
                    training: (pos.training !== undefined) ? `${pos.training} hours` : 'None required',
                    experience: (pos.experience !== undefined) ? `${pos.experience} years` : 'None required',
                    eligibility: pos.eligibility || '',
                    competency: pos.competency || '',
                    placeOfAssignment: pos.assignment || pos.department || ''
                }));
                
                const header: Form9Header = {
                    agencyName: 'CGO MEYCAUAYAN, BULACAN',
                    signatoryName: 'JUDITH S. GUEVARRA, MPA',
                    signatoryTitle: 'City Human Resource Management Officer',
                    date: new Date().toLocaleDateString('en-PH'),
                    deadlineDate: '',
                    officeAddress: 'City Govt. of Meycauayan, Saluysoy, City of Meycauayan',
                    contactInfo: '(044) 840-3020 local 501 / chrmo.meycjobs.csc@gmail.cc'
                };
                
                if (type === 'pdf') {
                    exportForm9ToPDF(header, positionsData);
                } else {
                    await exportForm9ToExcel(header, positionsData);
                }
                toast.success(`Form 9 exported to ${type.toUpperCase()}`);
                return;
            }
            
            // PSI-POP - Open Modal for both PDF/Excel (User checks preview first)
            if (reportId === 'psipop') {
                handlePreviewClick('psipop');
                return;
            }
            
            // Form 33 - Requires position selection first (opens modal just like Preview button)
            if (reportId === 'form33') {
                toast.dismiss();
                setModalReportId(reportId);
                setIsModalOpen(true);
                setLoadingPositions(true);
                try {
                    const response = await plantillaApi.getPositions({});
                    const filled = response.data.positions.filter((p: Position) => p.incumbentId);
                    setPositions(filled);
                } catch (err) {
                    toast.error("Failed to load positions");
                    setIsModalOpen(false);
                } finally {
                    setLoadingPositions(false);
                }
                return;
            }
            
            // Form 33 and other reports - Use generic export
            const response = await reportsApi.getReportData(reportId, params);
            
            if (response.success && response.data) {
                toast.dismiss();
                
                if (type === 'pdf') {
                    generatePDF(reportId, response.data, response.meta);
                    toast.success("PDF generated!");
                } else {
                    // Generic Excel Export
                    const data = Array.isArray(response.data) ? response.data : [response.data];
                    if (data.length === 0) {
                        toast.error("No data to export");
                        return;
                    }
                    
                    const ws = XLSX.utils.json_to_sheet(data);
                    const wb = XLSX.utils.book_new();
                    XLSX.utils.book_append_sheet(wb, ws, response.meta?.formName || response.meta?.form_name || 'Report');
                    const filename = `${response.meta?.formName || response.meta?.form_name || reportId}_${new Date().toISOString().split('T')[0]}.xlsx`;
                    XLSX.writeFile(wb, filename);
                    toast.success(`Exported to ${filename}`);
                }
            } else {
                throw new Error(response.message || "No data returned");
            }
        } catch (error: unknown) {
            toast.dismiss();
            console.error("Failed to generate report:", error);
            const msg = axios.isAxiosError(error) 
                ? error.response?.data?.message || error.message 
                : (error instanceof Error ? error.message : "Failed to generate");
            toast.error(msg);
        }
    };

    const confirmSelection = () => {
        if (!selectedPositionId) {
            toast.error("Please select a position");
            return;
        }
        
        // Find the full position object (Handle string/number mismatch)
        const pos = positions.find(p => String(p.id) === String(selectedPositionId));
        
        if (pos) {
            // Close the selection modal
            setIsModalOpen(false);
            // Open the OFFICIAL Complex Form Modal
            setSelectedAppointmentPosition(pos);
            setIsAppointmentFormOpen(true);
        } else {
            console.error("Position not found logic error", { selectedPositionId, positions });
            toast.error("Error: Could not find selected position details.");
        }
    };



    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Header */}
            <div>
                <h3 className="text-xl font-bold text-gray-900 flex items-center gap-2">
                    Compliance & Regulatory Reports
                </h3>
                <p className="text-sm text-gray-500">
                    Generate and download official Civil Service Commission (CSC) compliant forms and reports.
                </p>
            </div>

            {/* Reports Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {reports.map((report) => (
                    <div 
                        key={report.id} 
                        className="bg-white p-4 rounded-lg border border-gray-200 shadow-sm hover:shadow-md hover:border-gray-300 transition-all duration-300 group"
                    >
                        <div className="flex items-center justify-between mb-3">
                            <div className={`w-8 h-8 rounded-lg shadow-sm group-hover:scale-110 transition-transform ${
                                report.id === 'form9' ? 'bg-blue-500' :
                                report.id === 'form33' ? 'bg-emerald-500' :
                                'bg-amber-500'
                            }`}></div>
                            <span className="px-2.5 py-1 bg-gray-100 text-gray-500 text-[10px] font-bold rounded-full uppercase tracking-widest">
                                {report.frequency}
                            </span>
                        </div>
                        
                        <h4 className="text-sm font-bold text-gray-900 group-hover:text-blue-600 transition-colors mb-1">
                            {report.title}
                        </h4>
                        <p className="text-gray-500 text-[11px] mb-4 h-8 line-clamp-2 leading-relaxed">
                            {report.description}
                        </p>

                        <div className="flex gap-2 pt-3 border-t border-gray-100">
                            <button 
                                onClick={() => handlePreviewClick(report.id)}
                                className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 bg-white hover:bg-gray-50 border border-gray-200 hover:border-gray-300 text-gray-700 hover:text-gray-900 rounded-lg text-xs font-bold transition-all active:scale-95 shadow-sm"
                            >
                                <Printer size={14} className="text-gray-400 group-hover:text-blue-500 transition-colors" />
                                Preview
                            </button>
                            <button 
                                onClick={() => handleDownload(report.id, 'excel')}
                                className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 bg-white hover:bg-gray-50 border border-gray-200 hover:border-gray-300 text-gray-700 hover:text-gray-900 rounded-lg text-xs font-bold transition-all active:scale-95 shadow-sm"
                                title="Export to Excel"
                            >
                                <Download size={14} className="text-gray-400 group-hover:text-green-500 transition-colors" />
                                Excel
                            </button>
                            <button 
                                onClick={() => handleDownload(report.id, 'pdf')}
                                className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 bg-white hover:bg-gray-50 border border-gray-200 hover:border-gray-300 text-gray-700 hover:text-gray-900 rounded-lg text-xs font-bold transition-all active:scale-95 shadow-sm"
                                title="Export to PDF"
                            >
                                <Download size={14} className="text-gray-400 group-hover:text-red-500 transition-colors" />
                                PDF
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            {/* Selection Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 animate-in fade-in">
                    <div className="bg-white rounded-xl shadow-xl w-full max-w-md p-6 animate-in zoom-in-95 duration-200">
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="text-lg font-bold text-gray-900">Select Appointment</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                                <X size={20} />
                            </button>
                        </div>
                        
                        <div className="space-y-4">
                            <p className="text-sm text-gray-600">
                                Please select the employee/position for which you want to generate the Appointment Form (CS Form 33).
                            </p>
                            
                            {loadingPositions ? (
                                <div className="text-center py-4 text-emerald-600">Loading positions...</div>
                            ) : (
                                <Combobox
                                    options={positions.map((p) => ({ 
                                        value: String(p.id), 
                                        label: `${p.positionTitle} - ${p.incumbentName || 'Unknown'} (${p.itemNumber})` 
                                    }))}
                                    value={selectedPositionId}
                                    onChange={(val) => setSelectedPositionId(val)}
                                    placeholder="Select employee/position"
                                />
                            )}
                            
                            <div className="flex justify-end gap-2 mt-6">
                                <button 
                                    onClick={() => setIsModalOpen(false)}
                                    className="px-4 py-2 text-sm text-gray-600 hover:bg-gray-100 rounded-lg"
                                >
                                    Cancel
                                </button>
                                <button 
                                    onClick={confirmSelection}
                                    disabled={!selectedPositionId}
                                    className="px-4 py-2 text-sm font-semibold text-white bg-emerald-600 hover:bg-emerald-700 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                    Generate Form
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* Official Appointment Form Modal (Complex Layout) */}
            <AppointmentFormModal 
                isOpen={isAppointmentFormOpen} 
                onClose={() => setIsAppointmentFormOpen(false)} 
                position={selectedAppointmentPosition} 
            />

            {/* CS Form No. 9 Modal - State managed by Zustand */}
            <Form9Modal />

            {/* PSI-POP Modal (New WYSIWYG) */}
            <PSIPOPModal 
                isOpen={isPSIPOPModalOpen}
                onClose={() => setIsPSIPOPModalOpen(false)}
                positions={psipopPositions}
            />


            {/* Info Footer */}
            <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 flex items-start gap-3">
