      </div>
    </header>
  );
}

import { useState, useMemo, useEffect } from 'react';
import { Search, X, Loader2, Calendar } from 'lucide-react';
import { leaveApi } from '../../../api/leaveApi';

interface LeaveRequest {
  id: number;
  employeeId: string;
  name: string;
  department: string;
  leaveType: string;
  startDate: string;
  endDate: string;
  startDateRaw: string;
  endDateRaw: string;
  status: string;
}

interface LeaveTableProps {
  onClose: () => void;
}

const ITEMS_PER_PAGE = 10;

export default function LeaveTable({ onClose }: LeaveTableProps) {
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => {
    const fetchLeaveRequests = async () => {
      try {
        setLoading(true);
        setError(null);
        const response = await leaveApi.getAllLeaves();
        interface ApiLeaveRequest {
          id: number;
          employeeId?: string;
          firstName?: string;
          lastName?: string;
          department?: string;
          leaveType?: string;
          startDate: string;
          endDate: string;
          status: string;
        }
        const data = response.data as unknown as { success: boolean; applications?: ApiLeaveRequest[]; leaves?: ApiLeaveRequest[] };
        const leavesData = data.applications || data.leaves || [];
        
        if (leavesData.length > 0) {
          const today = new Date();
          today.setHours(0, 0, 0, 0);
          
          const approvedLeaves: LeaveRequest[] = leavesData
            .filter((leave) => {
              if (leave.status !== 'Approved') return false;
              const startDate = new Date(leave.startDate);
              const endDate = new Date(leave.endDate);
              startDate.setHours(0, 0, 0, 0);
              endDate.setHours(23, 59, 59, 999);
              return today >= startDate && today <= endDate;
            })
            .map((leave) => ({
              id: leave.id,
              employeeId: leave.employeeId || 'N/A',
              name: `${leave.firstName || ''} ${leave.lastName || ''}`.trim() || 'Unknown',
              department: leave.department || 'N/A',
              leaveType: leave.leaveType || 'General',
              startDate: new Date(leave.startDate).toLocaleDateString(),
              endDate: new Date(leave.endDate).toLocaleDateString(),
              startDateRaw: leave.startDate,
              endDateRaw: leave.endDate,
              status: leave.status
            }));
          setLeaveRequests(approvedLeaves);
        }
      } catch (err) {
        console.error('Failed to fetch leave requests:', err);
        setError('Failed to load leave requests');
      } finally {
        setLoading(false);
      }
    };
    fetchLeaveRequests();
  }, []);

  const filteredEmployees = useMemo(() => {
    const query = searchQuery.toLowerCase();
    if (!query) return leaveRequests;
    return leaveRequests.filter(leave =>
      leave.name?.toLowerCase().includes(query) ||
      leave.employeeId?.toLowerCase().includes(query) ||
      leave.department?.toLowerCase().includes(query)
    );
  }, [searchQuery, leaveRequests]);

  const paginationData = useMemo(() => {
    const totalPages = Math.ceil(filteredEmployees.length / ITEMS_PER_PAGE);
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    const endIndex = startIndex + ITEMS_PER_PAGE;
    const currentEmployees = filteredEmployees.slice(startIndex, endIndex);
    return { totalPages, startIndex, endIndex, currentEmployees };
  }, [filteredEmployees, currentPage]);

  const { totalPages, startIndex, endIndex, currentEmployees } = paginationData;

  if (loading) {
    return (
      <div className="h-full flex flex-col items-center justify-center py-12">
        <Loader2 className="w-6 h-6 text-gray-500 animate-spin mb-2" />
        <p className="text-sm text-gray-500">Loading...</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col">
      {/* Compact Header */}
      <div className="flex justify-between items-center mb-3">
        <h2 className="text-base font-bold text-gray-800">Employees On Leave</h2>
        <button onClick={onClose} className="p-1 text-gray-400 hover:text-gray-600 rounded">
          <X size={18} />
        </button>
      </div>

      {error && (
        <div className="bg-red-50 text-red-700 px-3 py-2 rounded text-sm mb-3">{error}</div>
      )}

      {/* Compact Search */}
      <div className="flex items-center gap-3 mb-3">
        <div className="relative flex-1 max-w-xs">
          <Search className="absolute left-2.5 top-2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            placeholder="Search..."
            value={searchQuery}
            onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
            className="pl-8 pr-3 py-1.5 bg-gray-50 border border-gray-200 rounded-lg w-full text-sm focus:ring-1 focus:ring-gray-400 outline-none"
          />
        </div>
        {searchQuery && (
          <span className="text-xs text-gray-500">{filteredEmployees.length} found</span>
        )}
      </div>

      {/* Styled Table matching PlantillaTable */}
      {/* Styled Table matching the new design */}
      <div className="flex-1 overflow-auto rounded-lg border border-gray-100">
        <table className="w-full text-sm">
          <thead className="bg-gray-200 shadow-md text-gray-700">
            <tr>
              <th className="px-4 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">ID</th>
              <th className="px-4 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Name</th>
              <th className="px-4 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Department</th>
              <th className="px-4 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Type</th>
              <th className="px-4 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Period</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {currentEmployees.length ? (
              currentEmployees.map(emp => {
                const start = new Date(emp.startDateRaw);
                const end = new Date(emp.endDateRaw);
                const duration = Math.ceil((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
                return (
                  <tr key={emp.id} className="hover:bg-[#F8F9FA] hover:shadow-xl transition-colors group bg-white">
                    <td className="px-4 py-4 text-sm font-medium text-gray-700 whitespace-nowrap">{emp.employeeId}</td>
                    <td className="px-4 py-4 text-sm font-semibold text-gray-900 whitespace-nowrap">{emp.name}</td>
                    <td className="px-4 py-4 text-sm text-gray-600 font-medium whitespace-nowrap">{emp.department}</td>
                    <td className="px-4 py-4 whitespace-nowrap">
                      <span className="px-3 py-1 text-xs font-semibold rounded-full bg-blue-100 text-blue-700">
                        {emp.leaveType}
                      </span>
                    </td>
                    <td className="px-4 py-4 text-sm text-gray-700 whitespace-nowrap">
                      {emp.startDate} - {emp.endDate} <span className="text-xs text-gray-400 font-bold ml-1">({duration}d)</span>
                    </td>
                  </tr>
                );
              })
            ) : (
              <tr>
                <td colSpan={5} className="px-4 py-8 text-center text-gray-400 text-sm font-medium">
                  <Calendar className="w-8 h-8 mx-auto mb-2 opacity-50" />
                  {searchQuery ? 'No matching records' : 'No employees on leave today'}
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Compact Pagination */}
      {filteredEmployees.length > ITEMS_PER_PAGE && (
        <div className="flex justify-between items-center mt-3 pt-3 border-t border-gray-100">
          <span className="text-xs text-gray-500">
            {startIndex + 1}–{Math.min(endIndex, filteredEmployees.length)} of {filteredEmployees.length}
          </span>
          <div className="flex gap-1">
            <button
              onClick={() => setCurrentPage(p => Math.max(p - 1, 1))}
              disabled={currentPage === 1}
              className="px-2 py-1 text-xs bg-gray-100 rounded disabled:opacity-50"
            >
              Prev
            </button>
            <span className="px-2 py-1 text-xs">{currentPage}/{totalPages}</span>
            <button
              onClick={() => setCurrentPage(p => Math.min(p + 1, totalPages))}
              disabled={currentPage === totalPages}
              className="px-2 py-1 text-xs bg-gray-100 rounded disabled:opacity-50"
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { LogOut, ChevronDown, ChevronRight, LucideIcon, Users } from 'lucide-react';

interface NavItem {
  name: string;
  icon?: LucideIcon;
  path?: string;
  action?: string;
  children?: NavItem[];
}

interface SidebarProps {
  sidebarOpen: boolean;
  navItems: NavItem[];
  handleLogout: () => void;
  onSectionChange?: (section: string) => void;
  userRole?: string;
}

export default function Sidebar({ sidebarOpen, navItems, handleLogout, onSectionChange, userRole }: SidebarProps) {
  const [openDropdowns, setOpenDropdowns] = useState<Record<string, boolean>>({});
  const location = useLocation();

  const toggleDropdown = (name: string) => {
    setOpenDropdowns(prev => ({
      ...prev,
      [name]: !prev[name]
    }));
  };

  const isActive = (action?: string) => {
    if (!action) return false;
    // Assuming admin dashboard root is /admin-dashboard
    if (action === 'dashboard') {
        return location.pathname === '/admin-dashboard' || location.pathname === '/admin-dashboard/';
    }
    return location.pathname.includes(action);
  };

  return (
    <aside 
      className={`bg-gradient-to-r from-slate-950 to-green-900 text-gray-100 p-4 shadow-xl mb-6 flex flex-col justify-between transition-all duration-300 z-40 min-h-screen sticky top-0 overflow-y-auto border-r border-green-900/50 ${sidebarOpen ? 'w-72' : 'w-20'}`}
      style={{
        scrollbarWidth: 'none',
        // @ts-ignore
        msOverflowStyle: 'none'
      }}
    >
      <div className="flex flex-col"> 
        <div className={`border-b border-gray-800 flex flex-col items-center justify-center flex-shrink-0 py-8 transition-all duration-300 ${
              sidebarOpen ? 'px-6' : 'px-2'}`}>
            <img src="/Logo.Municipal of Meycuayan.png" alt="Meycauayan Logo" className={`transition-all duration-300 ${sidebarOpen ? 'w-20 h-20' : 'w-12 h-12'} rounded-full flex-shrink-0 shadow-lg ring-2 ring-slate-800`}/>
             {sidebarOpen && (<div className="mt-4 text-center transition-all duration-300">
                <h1 className="text-base font-bold leading-tight tracking-wide text-white">
                  {userRole === 'Human Resource' ? 'Human Resource Portal' : 'Administrator Portal'}
                </h1>
                <p className="text-[10px] font-medium text-gray-400 leading-tight mt-1 uppercase tracking-wider">City Human Resources Management Office</p>
              </div>
            )}
        </div>

        <nav className="p-3 flex-1 mt-4 space-y-1">
          {navItems.map((item) => {
            const Icon = item.icon;
            const hasChildren = item.children && item.children.length > 0;
            const isOpen = openDropdowns[item.name];
            const active = isActive(item.action);

            const mainOnClick = () => {
              console.log('[Sidebar] Main clicked:', item.name, 'hasChildren:', hasChildren, 'action:', item.action);
              if (hasChildren) {
                // Only toggle dropdown for items with children, don't navigate
                toggleDropdown(item.name);
              } else if (item.action && onSectionChange) {
                // Only navigate for items WITHOUT children
                onSectionChange(item.action);
              }
            };

            const MainComponent = item.path ? Link : 'button';

            return (
              <div key={item.name} className="w-full">
                {/* @ts-ignore */}
                <MainComponent
                  to={item.path as string}
                  onClick={mainOnClick}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm transition-all duration-200 group relative ${
                    active && !hasChildren 
                    ? 'bg-slate-800/50 text-white font-semibold shadow-sm ring-1 ring-white/10' 
                    : 'text-gray-400 hover:bg-slate-800/50 hover:text-white'
                  }`}
                >
                  {Icon && <Icon className={`w-5 h-5 flex-shrink-0 transition-colors duration-200 ${active && !hasChildren ? 'text-white' : 'text-gray-500 group-hover:text-white'}`} />}
                  {sidebarOpen && <span className="flex-1 text-left tracking-tight">{item.name}</span>}
                  {sidebarOpen && hasChildren && (
                    isOpen ? <ChevronDown className="w-4 h-4 opacity-50" /> : <ChevronRight className="w-4 h-4 opacity-50" />
                  )}
                </MainComponent>
                {hasChildren && isOpen && sidebarOpen && (
                  <div className="ml-4 pl-3 mt-1 space-y-0.5 border-l border-gray-800">
                    {item.children?.map((child: NavItem) => {
                      const childActive = isActive(child.action);

                      const childOnClick = () => {
                        console.log('[Sidebar] Child clicked:', child.name, 'action:', child.action);
                        if (child.action && onSectionChange) {
                          onSectionChange(child.action);
                        }
                      };

                      const ChildComponent = child.path ? Link : 'button';

                      return (
                        <ChildComponent
                          key={child.name}
                          to={child.path as string}
                          onClick={childOnClick}
                          className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-xs transition-all duration-200 ${
                            childActive 
                                ? 'bg-slate-800 text-white font-medium shadow-sm' 
                                : 'text-gray-400 hover:bg-slate-800/30 hover:text-white'
                            }`}
                        >
                          <span className="w-1.5 h-1.5 rounded-full bg-current opacity-40"></span>
                          <span>{child.name}</span>
                        </ChildComponent>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </nav>
      </div>

      <div className="p-4 border-t border-green-900/50 rounded-b-lg flex-shrink-0 bg-green-900/30 space-y-3">
        <Link 
          to="/employee-dashboard"
          className="w-full flex items-center justify-center gap-2 py-2.5 text-gray-300 font-semibold bg-slate-800/50 hover:bg-slate-800 rounded-md transition-all border border-slate-700 hover:border-slate-600 hover:text-white text-sm"
        >
          <Users className="w-4 h-4 flex-shrink-0" />
          {sidebarOpen && 'Switch to Employee Portal'}
        </Link>
        <button
          onClick={handleLogout}
          className="w-full flex items-center justify-center gap-2 py-2.5 text-[#F8F9FA] font-semibold bg-slate-950 hover:bg-slate-950/20 rounded-md transition-all border border-slate-950/10 hover:border-slate-950/20 focus:ring-2 focus:ring-slate-950/20 active:scale-95 text-sm"
        >
          <LogOut className="w-4 h-4 flex-shrink-0" />
          {sidebarOpen && 'Sign Out'}
        </button>
      </div>
    </aside>
  );
}

import { useState, useEffect } from 'react';
import { Bell } from 'lucide-react';
import { announcementApi } from '../../../api/announcementApi';

interface Announcement {
  id: string | number;
  title: string;
  content: string;
  priority?: 'normal' | 'urgent' | 'high' | 'medium' | string;
}

export default function AnnouncementSection() {
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);

  useEffect(() => {
    const fetchAnnouncements = async () => {
      try {
        const response = await announcementApi.getAnnouncements();
        if (response.data && response.data.announcements) {
          setAnnouncements(response.data.announcements);
        }
      } catch (error) {
        console.error("Failed to fetch announcements:", error);
      }
    };
    fetchAnnouncements();
  }, []);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-5 hover:shadow-md transition-all duration-300">
      <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
        <div className="w-1 h-6 bg-gray-800 rounded-full"></div>
        Announcements
      </h3>
      
      {announcements.length > 0 ? (
        <div className="space-y-4 max-h-64 overflow-y-auto custom-scrollbar">
          {announcements.map((announcement) => (
            <div key={announcement.id || Math.random()} className="p-3 bg-gray-50 rounded-lg border border-gray-200/60 shadow-sm hover:border-emerald-500/30 transition-all">
              <div className="flex justify-between items-start mb-1">
                <h4 className="text-sm font-bold text-gray-800">{announcement.title}</h4>
                {announcement.priority && announcement.priority !== 'normal' && (
                  <span className={`text-[10px] px-2 py-0.5 rounded-full uppercase font-bold ${
                    announcement.priority === 'urgent' ? 'bg-red-100 text-red-700' : 'bg-amber-100 text-amber-700'
                  }`}>
                    {announcement.priority}
                  </span>
