        <div className="flex items-center gap-2">
          <Phone size={14} />
          <span>{employee.phoneNumber || '—'}</span>
        </div>
      </td>
      <td className="px-6 py-4 text-sm text-gray-600">
        <div className="flex items-center gap-2">
          <Calendar size={14} className="text-gray-400" />
          <span>{formatDate(employee.dateHired)}</span>
