              </div>
              <div>
                <label className={labelClass}>Pag-IBIG</label>
                <input type="text" name="pagibigNumber" value={formData.pagibigNumber} onChange={handleChange} className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>TIN</label>
