interface Department {
  id: number;
  name: string;
}

import { Position } from '@/api/plantillaApi';

interface AddEmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  departments: Department[];
  onSuccess?: () => void;
}

interface TabItem {
  id: string;
  label: string;
}

const AddEmployeeModal: React.FC<AddEmployeeModalProps> = ({
  isOpen,
  onClose,
  departments,
  onSuccess
}) => {
  const [activeTab, setActiveTab] = useState('basic');
  const [vacantPositions, setVacantPositions] = useState<Position[]>([]);
  
  const queryClient = useQueryClient();
  const showToast = useToastStore((state) => state.showToast);

  const { register, handleSubmit, formState: { errors }, setValue, reset, watch } = useForm<CreateEmployeeInput>({
    resolver: zodResolver(CreateEmployeeSchema),
    defaultValues: {
      firstName: '',
      lastName: '',
      email: '',
      department: '',
      role: 'Employee',
      stepIncrement: 1,
      nationality: 'Filipino'
    }
  });

  const addEmployeeMutation = useMutation({
    mutationFn: async (data: CreateEmployeeInput) => {
        await employeeApi.addEmployee(data);
    },
    onSuccess: () => {
        showToast('Employee added successfully', 'success');
        queryClient.invalidateQueries({ queryKey: ['employees'] });
        reset();
        onClose();
        if (onSuccess) onSuccess();
    },
    onError: (error: unknown) => {
        const errMessage = error instanceof Error ? error.message : 'Failed to add employee';
        console.error('Failed to add employee', error);
        showToast(errMessage, 'error');
    }
  });

  useEffect(() => {
    if (isOpen) {
      loadVacantPositions();
      reset(); // Reset form when opening
    }
  }, [isOpen, reset]);

  const loadVacantPositions = async () => {
    try {
      const res = await plantillaApi.getPositions({ isVacant: true });
      if (res.data.success) {
        setVacantPositions(res.data.positions);
      }
    } catch (err) {
      console.error("Failed to load plantilla", err);
    }
  };

  const handlePlantillaChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const itemNo = e.target.value;
    setValue('itemNumber', itemNo);
    
    if (itemNo) {
      const position = vacantPositions.find(p => p.itemNumber === itemNo);
      if (position) {
        setValue('positionTitle', position.positionTitle || '');
        const sg = parserSalaryGrade(position.salaryGrade);
        if (sg !== undefined) setValue('salaryGrade', sg);
        setValue('stepIncrement', position.stepIncrement || 1);
        if (position.department) setValue('department', position.department);
      }
    }
  };

  const parserSalaryGrade = (sg: string | number | undefined): number | undefined => {
      if(sg === undefined || sg === null) return undefined;
      const num = Number(sg);
      return isNaN(num) ? undefined : num;
  }

  if (!isOpen) return null;

  const tabs: TabItem[] = [
    { id: 'basic', label: 'Basic Info' },
    { id: 'personal', label: 'Personal' },
    { id: 'government', label: 'Gov\'t IDs' },
    { id: 'employment', label: 'Employment' }
  ];

  const handleFormSubmit = (data: CreateEmployeeInput) => {
    addEmployeeMutation.mutate(data);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 overflow-y-auto">
      <div className="bg-white rounded-xl w-full max-w-md shadow-2xl my-8 border border-gray-100 flex flex-col overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="flex justify-between items-center px-6 py-4">
          <h2 className="text-xl font-bold text-gray-900">Add New Employee</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors p-1 rounded-full hover:bg-gray-100">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex border-b border-gray-200">
          {tabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex-1 px-4 py-3 text-sm font-medium transition-colors ${
                activeTab === tab.id 
                  ? 'text-gray-900 border-b-2 border-gray-900 font-bold' 
                  : 'text-gray-500 hover:text-gray-700'
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
        
        <form onSubmit={handleSubmit(handleFormSubmit)} className="p-6 space-y-4 max-h-[60vh] overflow-y-auto">
          
          {/* Basic Info Tab */}
          {activeTab === 'basic' && (
            <>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                    <User size={14} className="text-gray-400" /> First Name *
                  </label>
                  <input 
                    {...register('firstName')}
                    className={`w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm ${errors.firstName ? 'border-red-500' : ''}`}
                    placeholder="e.g. Juan"
                  />
                  {errors.firstName && <p className="text-red-500 text-xs mt-1">{errors.firstName.message}</p>}
                </div>
                <div>
                  <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                    <User size={14} className="text-gray-400" /> Last Name *
                  </label>
                  <input 
                    {...register('lastName')}
                    className={`w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm ${errors.lastName ? 'border-red-500' : ''}`}
                    placeholder="e.g. Dela Cruz"
                  />
                   {errors.lastName && <p className="text-red-500 text-xs mt-1">{errors.lastName.message}</p>}
                </div>
              </div>
              
              <div>
                <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                  <Mail size={14} className="text-gray-400" /> Email Address *
                </label>
                <input 
                  type="email" 
                  {...register('email')}
                  className={`w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm ${errors.email ? 'border-red-500' : ''}`}
                  placeholder="e.g. juan@agency.gov.ph"
                />
                 {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email.message}</p>}
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="z-50">
                  <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                    <Building size={14} className="text-gray-400" /> Department *
                  </label>
                  <Combobox 
                    options={departments.map(d => ({ value: d.name, label: d.name }))}
                    value={watch('department')}
                    onChange={(val) => setValue('department', val, { shouldValidate: true })}
                    placeholder="Select..."
                    error={!!errors.department}
                  />
                   {errors.department && <p className="text-red-500 text-xs mt-1">{errors.department.message}</p>}
                </div>
                <div className="z-50">
                  <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                    <Shield size={14} className="text-gray-400" /> System Role *
                  </label>
                  <Combobox 
                    options={ROLE_OPTIONS}
                    value={watch('role')}
                    onChange={(val) => setValue('role', val as CreateEmployeeInput['role'], { shouldValidate: true })}
                    placeholder="Select role"
                    error={!!errors.role}
                  />
                   {errors.role && <p className="text-red-500 text-xs mt-1">{errors.role.message}</p>}
                </div>
              </div>
            </>
          )}

          {/* Personal Info Tab */}
          {activeTab === 'personal' && (
            <>
              <div className="grid grid-cols-2 gap-4">
                <div className="z-40">
                  <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                    <Calendar size={14} className="text-gray-400" /> Birth Date
                  </label>
                  <input 
                    type="date" 
                    {...register('birthDate')}
                    className="w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm" 
                  />
                </div>
                <div className="z-40">
                  <label className="text-sm text-gray-600 mb-1 block">Gender</label>
                  <Combobox 
                    options={GENDER_OPTIONS}
                    value={watch('gender')}
                    onChange={(val) => setValue('gender', val)}
                    placeholder="Select..."
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="z-30">
                  <label className="text-sm text-gray-600 mb-1 block">Civil Status</label>
                  <Combobox 
                    options={CIVIL_STATUS_OPTIONS}
                    value={watch('civilStatus')}
                    onChange={(val) => setValue('civilStatus', val)}
                    placeholder="Select..."
                  />
                </div>
                <div>
                  <label className="text-sm text-gray-600 mb-1 block">Nationality</label>
                  <input 
                    type="text" 
                    {...register('nationality')}
                    placeholder="Filipino"
                    className="w-full px-3 py-2 bg-[#F8F9FA] border border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm" 
                  />
                </div>
              </div>

              <div>
                <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                  <Phone size={14} className="text-gray-400" /> Phone Number
                </label>
                <input 
                  type="tel" 
                  {...register('phoneNumber')}
                  className="w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm" 
                  placeholder="e.g. 09171234567"
                />
              </div>

              <div>
                <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                  <MapPin size={14} className="text-gray-400" /> Present Address
                </label>
                <textarea 
                  {...register('address')}
                  className="w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm resize-none" 
                  rows={2}
                  placeholder="House/Unit No., Street, Barangay, City/Municipality"
                />
              </div>
            </>
          )}

          {/* Government IDs Tab */}
          {activeTab === 'government' && (
            <>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                    <CreditCard size={14} className="text-gray-400" /> GSIS Number
                  </label>
                  <input 
                    type="text" 
                    {...register('gsisNumber')}
                    className="w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm" 
                    placeholder="GSIS ID"
                  />
                </div>
                <div>
                  <label className="text-sm text-gray-600 mb-1 block">PhilHealth Number</label>
                  <input 
                    type="text" 
                    {...register('philhealthNumber')}
                    className="w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm" 
                    placeholder="XX-XXXXXXXXX-X"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-sm text-gray-600 mb-1 block">Pag-IBIG Number</label>
                  <input 
                    type="text" 
                    {...register('pagibigNumber')}
                    className="w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm" 
                    placeholder="XXXX-XXXX-XXXX"
                  />
                </div>
                <div>
                  <label className="text-sm text-gray-600 mb-1 block">TIN</label>
                  <input 
                    type="text" 
                    {...register('tinNumber')}
                    className="w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm" 
                    placeholder="XXX-XXX-XXX-XXX"
                  />
                </div>
              </div>
            </>
          )}

          {/* Employment Details Tab */}
          {activeTab === 'employment' && (
            <>
              {/* Plantilla Selection */}
              <div className="bg-gray-50 p-3 rounded-lg border border-gray-200 mb-4 z-40 relative">
                <label className="text-sm font-semibold text-gray-800 mb-1.5 block flex items-center gap-1">
                  <FileText size={14} className="text-gray-500" /> Select Plantilla Item (Optional)
                </label>
                <Combobox 
                  options={vacantPositions.map(pos => ({ 
                    value: pos.itemNumber, 
                    label: `${pos.itemNumber} - ${pos.positionTitle} (SG-${pos.salaryGrade})` 
                  }))}
                  value={watch('itemNumber')}
                  onChange={(val) => handlePlantillaChange({ target: { value: val } } as any)}
                  placeholder="Select available position..."
                  className="w-full"
                />
                <p className="text-xs text-gray-500 mt-1.5">
                  Selecting a position will auto-fill Title, Salary Grade, and Department.
                </p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                    <Briefcase size={14} className="text-gray-400" /> Position Title
                  </label>
                  <input 
                    type="text" 
                    {...register('positionTitle')}
                    className="w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm" 
                    placeholder="e.g. Administrative Officer III"
                  />
                </div>
                <div className="z-30">
                  <label className="text-sm text-gray-600 mb-1 block">Appointment Type</label>
                  <Combobox 
                    options={APPOINTMENT_TYPE_OPTIONS}
                    value={watch('appointmentType')}
                    onChange={(val) => setValue('appointmentType', val as any)}
                    placeholder="Select..."
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="z-20">
                  <label className="text-sm text-gray-600 mb-1 block">Salary Grade</label>
                  <Combobox 
                    options={SALARY_GRADE_OPTIONS.map(opt => ({ value: String(opt.value.replace('SG-', '')), label: opt.label }))}
                    value={String(watch('salaryGrade') || '')}
                    onChange={(val) => setValue('salaryGrade', Number(val))}
                    placeholder="Select..."
                  />
                </div>
                <div className="z-20">
                  <label className="text-sm text-gray-600 mb-1 block">Step Increment</label>
                  <Combobox 
                    options={[1, 2, 3, 4, 5, 6, 7, 8].map(step => ({ value: String(step), label: `Step ${step}` }))}
                    value={String(watch('stepIncrement') || 1)}
                    onChange={(val) => setValue('stepIncrement', Number(val))}
                    placeholder="Select..."
                  />
                </div>
              </div>

              <div>
                <label className="text-sm text-gray-600 mb-1 block">Station/Assignment</label>
                <input 
                  type="text" 
                  {...register('station')}
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm" 
                  placeholder="e.g. Main Office - Manila"
                />
              </div>
            </>
          )}

          {/* Footer Buttons */}
          <div className="flex gap-3 px-6 py-4 bg-gray-50 border-t border-gray-100">
            <button 
              type="button" 
              onClick={onClose} 
              className="flex-1 px-4 py-2 text-sm font-semibold text-gray-700 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm"
            >
              Cancel
            </button>
            <button 
              type="submit" 
              disabled={addEmployeeMutation.isPending} 
              className="flex-1 px-4 py-2 text-sm font-bold text-white bg-gray-900 rounded-lg shadow-md hover:bg-gray-800 transition-all disabled:opacity-50 flex items-center justify-center gap-2"
            >
              {addEmployeeMutation.isPending && <Loader className="animate-spin" size={16} />}
              {addEmployeeMutation.isPending ? 'Saving...' : 'Save Employee'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddEmployeeModal;

import React from 'react';
import { X, Loader } from 'lucide-react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import axios from 'axios';
import { employeeApi } from '@/api/employeeApi';
import { useToastStore } from '@/stores';

interface Employee {
  id: number | string;
  firstName?: string;
  lastName?: string;
}

interface DeleteEmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  employee: Employee | null;
  onSuccess?: () => void; 
}

const DeleteEmployeeModal: React.FC<DeleteEmployeeModalProps> = ({
  isOpen,
  onClose,
  employee,
  onSuccess
}) => {
  const queryClient = useQueryClient();
  const showToast = useToastStore((state) => state.showToast);

  const deleteMutation = useMutation({
    mutationFn: async (id: number | string) => {
      await employeeApi.deleteEmployee(id);
    },
    onSuccess: () => {
      showToast('Employee deleted successfully', 'success');
      queryClient.invalidateQueries({ queryKey: ['employees'] });
      // Also invalidate stats or other related queries if necessary
      onClose();
      if (onSuccess) onSuccess();
    },
    onError: (error: unknown) => {
      console.error('Failed to delete employee:', error);
      const errorMessage = axios.isAxiosError(error) 
        ? error.response?.data?.message || error.message 
        : 'Failed to delete employee';
      showToast(errorMessage, 'error');
    }
  });

  const handleDelete = () => {
    if (employee) {
      deleteMutation.mutate(employee.id);
    }
  };

  if (!isOpen || !employee) return null;

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 transition-all">
      <div className="bg-white rounded-xl w-full max-w-md shadow-2xl border border-gray-100 overflow-hidden animate-in fade-in zoom-in duration-200">
        {/* Clean Header */}
        <div className="flex justify-between items-center px-6 py-4">
          <h2 className="text-xl font-bold text-gray-900">Delete Employee</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors p-1 rounded-full hover:bg-gray-100">
            <X className="w-5 h-5" />
          </button>
        </div>
        
        {/* Content */}
        <div className="p-6">
          <div className="bg-red-50 border border-red-100 rounded-lg p-4 mb-4">
            <div className="flex gap-3">
              <div className="bg-red-100 p-2 rounded-full h-fit">
                <X className="w-5 h-5 text-red-600" />
              </div>
              <div>
                <h4 className="text-sm font-bold text-red-800 mb-1">Confirm Deletion</h4>
                <p className="text-sm text-red-700">
                  Are you sure you want to delete <strong>{employee.firstName} {employee.lastName}</strong>?
                </p>
              </div>
            </div>
          </div>
          <p className="text-gray-500 text-sm pl-1">This action cannot be undone and will remove all associated records.</p>
        </div>
        
        {/* Footer Actions */}
        <div className="flex gap-3 px-6 py-4 bg-gray-50 border-t border-gray-100">
          <button 
            onClick={onClose} 
            className="flex-1 px-4 py-2 text-sm font-semibold text-gray-700 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm"
          >
            Cancel
          </button>
          <button 
            onClick={handleDelete} 
            disabled={deleteMutation.isPending} 
            className="flex-1 px-4 py-2 text-sm font-semibold text-white bg-red-600 hover:bg-red-700 rounded-lg shadow-md transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
          >
            {deleteMutation.isPending && <Loader className="animate-spin" size={16} />}
            {deleteMutation.isPending ? 'Deleting...' : 'Delete Employee'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default DeleteEmployeeModal;

import React, { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@/lib/zodResolver';
import { X, ChevronUp, ChevronDown, FileText, Loader } from 'lucide-react';
import Combobox from '@/components/Custom/Combobox';
import { plantillaApi } from '@/api/plantillaApi';
import { employeeApi } from '@/api/employeeApi';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useToastStore } from '@/stores';
import { UpdateEmployeeSchema, UpdateEmployeeInput } from '@/schemas/employeeSchema';
import {
  ROLE_OPTIONS,
  EMPLOYMENT_STATUS_OPTIONS,
  APPOINTMENT_TYPE_OPTIONS,
  GENDER_OPTIONS,
  CIVIL_STATUS_OPTIONS,
  SALARY_GRADE_OPTIONS,
  BLOOD_TYPE_OPTIONS,
  NATIONALITY_OPTIONS,
  ELIGIBILITY_TYPE_OPTIONS
} from '../constants/employeeConstants';

interface Department {
  id: number;
  name: string;
}

import { Position } from '@/api/plantillaApi';

// Broad interface for incoming employee data
interface Employee extends Record<string, any> {
  id: number | string;
}

interface EditEmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  employee?: Employee;
  departments: Department[];
  onSuccess?: () => void;
}

interface CollapsibleSectionProps {
  title: string;
  isOpen: boolean;
  onToggle: () => void;
  children: React.ReactNode;
}

const CollapsibleSection: React.FC<CollapsibleSectionProps> = ({ title, isOpen, onToggle, children }) => (
  <div className="border border-gray-200 rounded-lg overflow-hidden">
    <button
      type="button"
      onClick={onToggle}
      className="w-full px-3 py-2 bg-gray-100 flex items-center justify-between text-left hover:bg-gray-200 transition-colors"
    >
      <span className="text-xs font-semibold text-gray-700">{title}</span>
      {isOpen ? <ChevronUp size={14} className="text-gray-500" /> : <ChevronDown size={14} className="text-gray-500" />}
    </button>
    <div className={`transition-all duration-300 ease-in-out overflow-hidden ${isOpen ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0'}`}>
      <div className="p-3 space-y-2 bg-white">{children}</div>
    </div>
  </div>
);

const EditEmployeeModal: React.FC<EditEmployeeModalProps> = ({
  isOpen,
  onClose,
  employee,
  departments,
  onSuccess
}) => {
  const [openSections, setOpenSections] = useState({
    personal: false,
    government: false,
    eligibility: false,
    socialMedia: false,
    employment: true
  });
  const [vacantPositions, setVacantPositions] = useState<Position[]>([]);
  
  const queryClient = useQueryClient();
  const showToast = useToastStore((state) => state.showToast);

  const { register, handleSubmit, formState: { errors }, reset, setValue, watch } = useForm<UpdateEmployeeInput>({
    resolver: zodResolver(UpdateEmployeeSchema),
    defaultValues: {}
  });

  const updateMutation = useMutation({
    mutationFn: async (data: UpdateEmployeeInput) => {
        if (!employee?.id) throw new Error("No employee ID");
        await employeeApi.updateEmployee(employee.id, data);
    },
    onSuccess: () => {
        showToast('Employee updated successfully', 'success');
        queryClient.invalidateQueries({ queryKey: ['employees'] });
        queryClient.invalidateQueries({ queryKey: ['employee', employee?.id] });
        if (onSuccess) onSuccess();
        onClose();
    },
    onError: (error: unknown) => {
        const errMessage = error instanceof Error ? error.message : 'Failed to update employee';
        console.error('Failed to update employee', error);
        showToast(errMessage, 'error');
    }
  });

  useEffect(() => {
    if (isOpen && employee) {
      loadPlantillaOptions();
      // Reset form with employee data
      reset({
        firstName: employee.firstName || '',
        lastName: employee.lastName || '',
        email: employee.email || '',
        department: employee.department || '',
        role: employee.role || 'employee',
        employmentStatus: employee.employmentStatus || 'Active',
        itemNumber: employee.itemNumber || '',
        positionTitle: employee.positionTitle || employee.jobTitle || '',
        salaryGrade: employee.salaryGrade ? Number(employee.salaryGrade) : undefined,
        stepIncrement: employee.stepIncrement ? Number(employee.stepIncrement) : 1,
        appointmentType: employee.appointmentType || '',
        station: employee.station || '',
        birthDate: employee.birthDate ? new Date(employee.birthDate).toISOString().split('T')[0] : null,
        gender: employee.gender || '',
        civilStatus: employee.civilStatus || '',
        nationality: employee.nationality || 'Filipino',
        phoneNumber: employee.phoneNumber || '',
        permanentAddress: employee.permanentAddress || '',
        gsisNumber: employee.gsisNumber || '',
        philhealthNumber: employee.philhealthNumber || '',
        pagibigNumber: employee.pagibigNumber || '',
        tinNumber: employee.tinNumber || '',
        address: employee.address || '',
        // Plantilla-required eligibility fields
        eligibilityType: employee.eligibilityType || '',
        eligibilityNumber: employee.eligibilityNumber || '',
        eligibilityDate: employee.eligibilityDate ? new Date(employee.eligibilityDate).toISOString().split('T')[0] : null,
        educationalBackground: employee.educationalBackground || '',
        yearsOfExperience: employee.yearsOfExperience || 0,
        // Social Media
        facebookUrl: employee.facebookUrl || '',
        linkedinUrl: employee.linkedinUrl || '',
        twitterHandle: employee.twitterHandle || '',
      });
    }
  }, [isOpen, employee, reset]); 

  const loadPlantillaOptions = async () => {
    try {
      const res = await plantillaApi.getPositions({ isVacant: true });
      let positions: Position[] = res.data.success ? res.data.positions : [];
      if (employee?.itemNumber) {
         const currentPos: Position = {
             id: 0,
             itemNumber: employee.itemNumber,
             positionTitle: employee.positionTitle || '',
             salaryGrade: Number(employee.salaryGrade || 0),
             stepIncrement: employee.stepIncrement || 1,
             department: employee.department || '',
             isVacant: false
         };
         // Add current position if not in list
         if (!positions.find(p => p.itemNumber === employee.itemNumber)) {
             positions = [currentPos, ...positions];
         }
      }
      setVacantPositions(positions);
    } catch (err) {
      console.error(err);
    }
  };

  const handlePlantillaChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const itemNo = e.target.value;
    setValue('itemNumber', itemNo);
    if (itemNo) {
      const position = vacantPositions.find(p => p.itemNumber === itemNo);
      if (position) {
        setValue('positionTitle', position.positionTitle);
        setValue('salaryGrade', Number(position.salaryGrade));
        setValue('stepIncrement', position.stepIncrement || 1);
        if (position.department) setValue('department', position.department);
      }
    }
  };

  const toggleSection = (section: keyof typeof openSections) => {
    setOpenSections(prev => ({ ...prev, [section]: !prev[section] }));
  };
  
  if (!isOpen || !employee) return null;

  const handleFormSubmit = (data: UpdateEmployeeInput) => {
      updateMutation.mutate(data);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-md max-h-[90vh] overflow-hidden flex flex-col border border-gray-100 animate-in fade-in zoom-in duration-200">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 z-10">
          <h3 className="text-xl font-bold text-gray-900">Edit Employee</h3>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors p-1 rounded-full hover:bg-gray-100">
            <X className="w-5 h-5" />
          </button>
        </div>
        
        {/* Form */}
        <form onSubmit={handleSubmit(handleFormSubmit)} className="flex-1 overflow-y-auto p-6 space-y-4">
          
          {/* Required Information */}
          <div className="space-y-2">
            <p className="text-xs font-bold text-gray-600">Required Information</p>
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="text-xs font-semibold text-gray-700 mb-1 block">First Name <span className="text-red-400">*</span></label>
                <input 
                  {...register('firstName')}
                  className={`w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 ${errors.firstName ? 'border-red-500' : ''}`}
                />
                 {errors.firstName && <p className="text-[10px] text-red-500">{errors.firstName.message}</p>}
              </div>
              <div>
                <label className="text-xs font-semibold text-gray-700 mb-1 block">Last Name <span className="text-red-400">*</span></label>
                <input 
                  {...register('lastName')}
                  className={`w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 ${errors.lastName ? 'border-red-500' : ''}`}
                />
                {errors.lastName && <p className="text-[10px] text-red-500">{errors.lastName.message}</p>}
              </div>
            </div>

            <div>
                <label className="text-xs font-semibold text-gray-700 mb-1 block">Email Address <span className="text-red-400">*</span></label>
                <input 
                  type="email"
                  {...register('email')}
                  className={`w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 ${errors.email ? 'border-red-500' : ''}`}
                />
                {errors.email && <p className="text-[10px] text-red-500">{errors.email.message}</p>}
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="z-50">
                 <label className="text-xs font-semibold text-gray-700 mb-1 block">Department <span className="text-red-400">*</span></label>
                 <Combobox 
                    options={departments.map(d => ({ value: d.name, label: d.name }))}
                    value={watch('department')}
                    onChange={(val) => setValue('department', val, { shouldValidate: true })}
                    placeholder="Select..."
                    error={!!errors.department}
                    buttonClassName="px-2.5 py-1.5 text-sm"
                 />
                 {errors.department && <p className="text-[10px] text-red-500">{errors.department.message}</p>}
              </div>
              <div className="z-50">
                <label className="text-xs font-semibold text-gray-700 mb-1 block">System Role <span className="text-red-400">*</span></label>
                <Combobox 
                   options={ROLE_OPTIONS}
                   value={watch('role')}
                   onChange={(val) => setValue('role', val as UpdateEmployeeInput['role'], { shouldValidate: true })}
                   placeholder="Select role"
                   error={!!errors.role}
                   buttonClassName="px-2.5 py-1.5 text-sm"
                />
                {errors.role && <p className="text-[10px] text-red-500">{errors.role.message}</p>}
              </div>
            </div>

            <div className="z-40">
                 <label className="text-xs font-semibold text-gray-700 mb-1 block">Employment Status</label>
                 <Combobox 
                    options={EMPLOYMENT_STATUS_OPTIONS}
                    value={watch('employmentStatus')}
                    onChange={(val) => setValue('employmentStatus', val)}
                    placeholder="Select status"
                    buttonClassName="px-2.5 py-1.5 text-sm"
                 />
            </div>
          </div>

          {/* Employment Details - Collapsible */}
           <CollapsibleSection title="Employment Details" isOpen={openSections.employment} onToggle={() => toggleSection('employment')}>
             <div className="bg-gray-50 p-2 rounded-lg border border-gray-200 mb-2 z-30 relative">
               <label className="text-xs font-semibold text-gray-800 mb-1 block flex items-center gap-1">
                 <FileText size={12} className="text-gray-500" /> Plantilla Item
               </label>
               <Combobox 
                 options={vacantPositions.map(pos => ({ 
                   value: pos.itemNumber, 
                   label: `${pos.itemNumber} - ${pos.positionTitle} (SG-${pos.salaryGrade})` 
                 }))}
                 value={watch('itemNumber')}
                 onChange={(val) => handlePlantillaChange({ target: { value: val } } as any)}
                 placeholder="Select position..."
                 buttonClassName="px-2.5 py-1.5 text-sm bg-white"
               />
             </div>
             <div className="grid grid-cols-2 gap-2">
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Position Title</label>
                  <input {...register('positionTitle')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
               <div className="z-20">
                 <label className="text-xs font-semibold text-gray-700 mb-1 block">Appointment Type</label>
                 <Combobox 
                    options={APPOINTMENT_TYPE_OPTIONS}
                    value={watch('appointmentType')}
                    onChange={(val) => setValue('appointmentType', val)}
                    placeholder="Select..."
                    buttonClassName="px-2.5 py-1.5 text-sm"
                 />
               </div>
             </div>
             <div className="grid grid-cols-2 gap-2">
                <div className="z-10">
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Salary Grade</label>
                  <Combobox 
                    options={SALARY_GRADE_OPTIONS.map(opt => ({ value: String(opt.value), label: opt.label }))}
                    value={String(watch('salaryGrade') || '')}
                    onChange={(val) => setValue('salaryGrade', Number(val))}
                    placeholder="Select..."
                    buttonClassName="px-2.5 py-1.5 text-sm"
                  />
                </div>
                <div className="z-10">
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Step Increment</label>
                  <Combobox 
                    options={[1, 2, 3, 4, 5, 6, 7, 8].map(s => ({ value: String(s), label: `Step ${s}` }))}
                    value={String(watch('stepIncrement') || 1)}
                    onChange={(val) => setValue('stepIncrement', Number(val))}
                    placeholder="Select..."
                    buttonClassName="px-2.5 py-1.5 text-sm"
                  />
                </div>
              </div>
             <div>
                <label className="text-xs font-semibold text-gray-700 mb-1 block">Station</label>
                <input {...register('station')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
             </div>
           </CollapsibleSection>
 
           {/* Personal Information - Collapsible */}
           <CollapsibleSection title="Personal Information" isOpen={openSections.personal} onToggle={() => toggleSection('personal')}>
             <div className="grid grid-cols-2 gap-2">
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Birth Date</label>
                  <input type="date" {...register('birthDate')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
                <div className="z-10">
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Gender</label>
                  <Combobox 
                    options={GENDER_OPTIONS}
                    value={watch('gender')}
                    onChange={(val) => setValue('gender', val)}
                    placeholder="Select..."
                    buttonClassName="px-2.5 py-1.5 text-sm"
                  />
                </div>
             </div>
             <div className="grid grid-cols-2 gap-2">
                <div className="z-10">
                   <label className="text-xs font-semibold text-gray-700 mb-1 block">Civil Status</label>
                   <Combobox 
                     options={CIVIL_STATUS_OPTIONS}
                     value={watch('civilStatus')}
                     onChange={(val) => setValue('civilStatus', val)}
                     placeholder="Select..."
                     buttonClassName="px-2.5 py-1.5 text-sm"
                   />
                </div>
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Nationality</label>
                  <input type="text" {...register('nationality')} list="nationality-options" className="w-full px-2.5 py-1.5 text-sm border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
                  <datalist id="nationality-options">
                      {NATIONALITY_OPTIONS.map(opt => (<option key={opt.value} value={String(opt.value)} />))}
                  </datalist>
               </div>
             </div>
              <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Phone Number</label>
                  <input type="tel" {...register('phoneNumber')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
              </div>
              <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Permanent Address</label>
                  <textarea rows={2} {...register('permanentAddress')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200 resize-none" />
              </div>
           </CollapsibleSection>
 
           {/* Government IDs - Collapsible */}
           <CollapsibleSection title="Government IDs" isOpen={openSections.government} onToggle={() => toggleSection('government')}>
             <div className="grid grid-cols-2 gap-2">
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">GSIS Number</label>
                  <input type="text" {...register('gsisNumber')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">PhilHealth</label>
                  <input type="text" {...register('philhealthNumber')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
             </div>
             <div className="grid grid-cols-2 gap-2">
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Pag-IBIG</label>
                  <input type="text" {...register('pagibigNumber')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">TIN</label>
                  <input type="text" {...register('tinNumber')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
             </div>
           </CollapsibleSection>

           {/* Eligibility & Qualifications - Collapsible (Plantilla Required) */}
           <CollapsibleSection title="Eligibility & Qualifications (Plantilla Required)" isOpen={openSections.eligibility} onToggle={() => toggleSection('eligibility')}>
             <div className="grid grid-cols-2 gap-2">
                <div className="z-10">
                   <label className="text-xs font-semibold text-gray-700 mb-1 block">Eligibility Type</label>
                   <Combobox 
                     options={ELIGIBILITY_TYPE_OPTIONS}
                     value={watch('eligibilityType')}
                     onChange={(val) => setValue('eligibilityType', val)}
                     placeholder="Select..."
                     buttonClassName="px-2.5 py-1.5 text-sm"
                   />
                </div>
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Eligibility Number</label>
                  <input type="text" {...register('eligibilityNumber')} placeholder="License/Eligibility No." className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
             </div>
             <div className="grid grid-cols-2 gap-2">
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Eligibility Date</label>
                  <input type="date" {...register('eligibilityDate')} className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Years of Experience</label>
                  <input type="number" {...register('yearsOfExperience')} min="0" className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
             </div>
             <div>
                <label className="text-xs font-semibold text-gray-700 mb-1 block">Highest Education</label>
                <input type="text" {...register('educationalBackground')} placeholder="e.g., Bachelor of Science in Accountancy" className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
             </div>
           </CollapsibleSection>

           {/* Social Media - Collapsible */}
           <CollapsibleSection title="Social Media" isOpen={openSections.socialMedia} onToggle={() => toggleSection('socialMedia')}>
             <div className="grid grid-cols-1 gap-2">
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Facebook URL</label>
                  <input type="url" {...register('facebookUrl')} placeholder="https://facebook.com/username" className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">LinkedIn URL</label>
                  <input type="url" {...register('linkedinUrl')} placeholder="https://linkedin.com/in/username" className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
               <div>
                  <label className="text-xs font-semibold text-gray-700 mb-1 block">Twitter/X Handle</label>
                  <input type="text" {...register('twitterHandle')} placeholder="username (without @)" className="w-full px-2.5 py-1.5 text-sm bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-200" />
               </div>
             </div>
           </CollapsibleSection>
        </form>

        {/* Footer Buttons */}
        <div className="flex gap-3 px-6 py-4 bg-gray-50 border-t border-gray-100 mt-auto">
          <button type="button" onClick={onClose} 
            className="flex-1 px-4 py-2 text-sm font-semibold text-gray-700 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm">
            Cancel
          </button>
          <button type="button" onClick={handleSubmit(handleFormSubmit)} disabled={updateMutation.isPending} 
            className="flex-1 px-4 py-2 text-sm font-bold text-white bg-gray-900 rounded-lg shadow-md hover:bg-gray-800 transition-all disabled:opacity-50 flex items-center justify-center gap-2">
            {updateMutation.isPending && <Loader className="animate-spin" size={16} />}
            {updateMutation.isPending ? 'Updating...' : 'Update Employee'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default EditEmployeeModal;

import React, { useState, useEffect, ChangeEvent } from 'react';
import { X, User, Mail, Camera, Save } from 'lucide-react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Employee } from '@/types/employee';
import { updateMyProfile } from '@/api/employeeApi';

// Local schema for this modal
const EditProfileFormSchema = z.object({
  firstName: z.string().min(1, 'First name is required'),
  lastName: z.string().min(1, 'Last name is required'),
  email: z.string().email('Invalid email format'),
  phoneNumber: z.string(),
  address: z.string(),
});

type EditProfileFormInput = z.infer<typeof EditProfileFormSchema>;
type Profile = Partial<Employee> & Record<string, unknown>;

interface EditProfileModalProps {
  isOpen: boolean;
  onClose: () => void;
  profile?: Profile;
  onSave: (data: Profile) => void;
}


const EditProfileModal: React.FC<EditProfileModalProps> = ({
  isOpen,
  onClose,
  profile,
  onSave
}) => {
  const [avatarFile, setAvatarFile] = useState<File | null>(null);
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const {
    register,
    handleSubmit,
    reset,
    watch,
    formState: { errors },
  } = useForm<EditProfileFormInput>({
    resolver: zodResolver(EditProfileFormSchema),
    defaultValues: {
      firstName: '',
      lastName: '',
      email: '',
      phoneNumber: '',
      address: '',
    },
  });

  const firstName = watch('firstName');
  const lastName = watch('lastName');

  useEffect(() => {
    if (profile && isOpen) {
      reset({
        firstName: profile.firstName || '',
        lastName: profile.lastName || '',
        email: profile.email || '',
        phoneNumber: profile.phoneNumber || '',
        address: profile.address || '',
      });
      setAvatarPreview(profile.avatarUrl || null);
    }
  }, [profile, isOpen, reset]);

  const handleAvatarChange = (e: ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setAvatarFile(file);
      setAvatarPreview(URL.createObjectURL(file));
    }
  };

  const onFormSubmit = async (data: EditProfileFormInput) => {
    setLoading(true);
    setError(null);

    try {
      const formData = new FormData();
      formData.append('firstName', data.firstName);
      formData.append('lastName', data.lastName);
      formData.append('email', data.email);
      if (avatarFile) {
        formData.append('avatar', avatarFile);
      }

      const result = await updateMyProfile(formData);
      
      if (result.success && result.data) {
        onSave(result.data);
        onClose();
      } else {
        setError(result.message || 'Failed to update profile');
      }
    } catch (err: unknown) {
      setError('An error occurred while updating profile');
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/30 flex items-start justify-center z-50 p-4">
      <div className="bg-white rounded-lg w-full max-w-md shadow-xl mt-16 border border-gray-200 p-6">
        {/* Header */}
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-lg font-bold text-gray-800">Edit Profile</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit(onFormSubmit)} className="space-y-4">
          {/* Avatar */}
          <div className="flex justify-center">
            <div className="relative">
              <div className="w-20 h-20 rounded-full overflow-hidden bg-gray-200 border-4 border-white">
                {avatarPreview ? (
                  <img src={avatarPreview} alt="Avatar" className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-gray-100 text-gray-600 text-xl font-bold">
                    {firstName?.[0]}{lastName?.[0]}
                  </div>
                )}
              </div>
              <label className="absolute bottom-0 right-0 w-7 h-7 bg-gray-100 rounded-full flex items-center justify-center cursor-pointer hover:bg-gray-200 transition-colors border border-gray-200">
                <Camera size={14} className="text-gray-500" />
                <input type="file" accept="image/*" onChange={handleAvatarChange} className="hidden" />
              </label>
            </div>
          </div>

          {/* Error Message */}
          {error && (
            <div className="bg-red-50 text-red-600 text-sm p-3 rounded-lg">
              {error}
            </div>
          )}

          {/* Fields */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                <User size={14} className="text-gray-400" /> First Name
              </label>
              <input
                type="text"
                {...register('firstName')}
                className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-gray-300 text-sm"
              />
              {errors.firstName && <p className="text-red-500 text-xs mt-1">{errors.firstName.message}</p>}
            </div>
            <div>
              <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                <User size={14} className="text-gray-400" /> Last Name
              </label>
              <input
                type="text"
                {...register('lastName')}
                className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-gray-300 text-sm"
              />
              {errors.lastName && <p className="text-red-500 text-xs mt-1">{errors.lastName.message}</p>}
            </div>
          </div>

          <div>
            <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
              <Mail size={14} className="text-gray-400" /> Email
            </label>
            <input
              type="email"
              {...register('email')}
              className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-gray-300 text-sm"
            />
            {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email.message}</p>}
          </div>

          {/* Actions */}
          <div className="flex gap-3 pt-4 border-t border-gray-200 mt-4">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2.5 text-sm text-gray-600 bg-gray-100 hover:text-red-700 rounded-lg transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="flex-1 px-4 py-2.5 text-sm text-white bg-gray-900 hover:bg-gray-800 rounded-lg transition-colors disabled:opacity-50 flex items-center justify-center gap-1"
            >
              {loading ? (
                <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
              ) : (
                <>
                  <Save size={14} />
                  Save Changes
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditProfileModal;

import React from 'react';
import { X } from 'lucide-react';
import { useQuery } from '@tanstack/react-query';
import { recruitmentApi } from '@/api/recruitmentApi';
import { HiredApplicant } from '@/types/recruitment_applicant';

interface HiredApplicantsListModalProps {
  isOpen: boolean;
  onClose: () => void;
  dutyType: 'Standard' | 'Irregular';
  departmentName: string;
  onSelectApplicant: (applicantId: number) => void;
}

const HiredApplicantsListModal: React.FC<HiredApplicantsListModalProps> = ({ 
  isOpen, 
  onClose, 
  dutyType,
  departmentName,
  onSelectApplicant
}) => {
  const [searchTerm, setSearchTerm] = React.useState('');

  const { data: response, isLoading, error } = useQuery({
    queryKey: ['hiredApplicants', dutyType, departmentName],
    queryFn: () => recruitmentApi.getHiredApplicantsByDuty<HiredApplicant>(dutyType, departmentName),
    enabled: isOpen,
    staleTime: 1000 * 60, // 1 minute
  });

  const applicants = response?.data?.applicants || [];
  const filteredApplicants = applicants.filter(app => {
    const fullName = `${app.firstName} ${app.lastName} ${app.middleName || ''}`.toLowerCase();
    return fullName.includes(searchTerm.toLowerCase()) || 
           (app.jobTitle || '').toLowerCase().includes(searchTerm.toLowerCase());
  });

  if (!isOpen) return null;

  const isStandard = dutyType === 'Standard';

  return (
    <div className="fixed inset-0 min-h-screen bg-black/40 flex items-center justify-center p-4 z-[999] animate-in fade-in duration-200">
      <div className="bg-white border border-gray-100 rounded-2xl w-full max-w-2xl shadow-xl flex flex-col max-h-[90vh] overflow-hidden">
        
        {/* Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between p-6 bg-white border-b border-gray-200">
          <div className="mb-4 md:mb-0">
            <h2 className="text-xl font-bold text-gray-900">
              Newly Hired Candidates
            </h2>
            <p className="text-sm text-gray-500 mt-1">Select a hired candidate to register for <span className="font-semibold text-gray-900">{departmentName}</span></p>
          </div>
          
          <div className="flex items-center gap-3">
             {/* Search box */}
             <div className="relative">
                <input 
                  type="text" 
                  placeholder="Search name or position..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-gray-100 focus:border-gray-300 w-full md:w-48 shadow-sm"
                />
             </div>
             <button 
                type="button"
                onClick={onClose}
                className="text-gray-400 hover:text-gray-600 hover:bg-gray-50 border border-gray-200 p-2 rounded-lg transition-colors shadow-sm focus:outline-none"
             >
                <X size={20} strokeWidth={2.5} />
             </button>
          </div>
        </div>

        {/* Content Table */}
        <div className="flex-1 overflow-y-auto bg-gray-50/30 p-6">
          
          {isLoading ? (
             <div className="flex flex-col items-center justify-center py-20">
                <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-gray-900 mb-4"></div>
                <p className="text-gray-500 text-sm">Loading hired candidates...</p>
             </div>
          ) : error ? (
             <div className="bg-gray-50 border border-gray-200 text-gray-900 p-6 rounded-xl flex flex-col justify-center items-center text-center">
                <h4 className="font-bold">Error loading data</h4>
                <p className="text-sm text-gray-500 mt-1">Could not fetch the hired applicants. Please try again.</p>
             </div>
          ) : filteredApplicants.length === 0 ? (
             <div className="bg-white border text-center border-gray-200 py-16 px-6 rounded-xl flex flex-col items-center justify-center">
                <h4 className="font-bold text-gray-900 text-lg">No candidates found</h4>
                <p className="text-gray-500 text-sm mt-2 max-w-sm">
                   {searchTerm ? "No results match your search." : `There are no newly hired candidates under the ${dutyType} category that need registration.`}
                </p>
                {searchTerm && (
                   <button 
                     onClick={() => setSearchTerm('')}
                     className="mt-4 text-sm font-semibold text-gray-900 underline hover:text-gray-700"
                   >
                     Clear search
                   </button>
                )}
             </div>
          ) : (
             <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                <div className="overflow-x-auto">
                 <table className="w-full text-left text-sm whitespace-nowrap">
                   <thead className="bg-gray-50 border-b border-gray-200 text-gray-500 font-semibold uppercase text-[10px] tracking-wider">
                      <tr>
                         <th className="px-5 py-3">Applicant Name</th>
                         <th className="px-5 py-3">Position & Type</th>
                         <th className="px-5 py-3 text-right">Action</th>
                      </tr>
                   </thead>
                   <tbody className="divide-y divide-gray-100">
                      {filteredApplicants.map((applicant) => (
                         <tr key={applicant.id} className="hover:bg-gray-50 transition-colors">
                            <td className="px-5 py-4">
                               <div className="flex items-center gap-3">
                                  <div className="w-9 h-9 rounded-full bg-gray-100 flex items-center justify-center text-gray-600 font-bold border border-gray-200 flex-shrink-0 text-xs">
                                     {applicant.firstName.charAt(0)}{applicant.lastName.charAt(0)}
                                  </div>
                                  <div>
                                     <p className="font-bold text-gray-900">
                                        {applicant.lastName}, {applicant.firstName} {applicant.middleName || ''}
                                     </p>
                                     <p className="text-[10px] text-gray-500 uppercase tracking-wider">APP-{String(applicant.id).padStart(4, '0')} • Hired {new Date(applicant.hiredDate || '').toLocaleDateString()}</p>
                                  </div>
                               </div>
                            </td>
                            <td className="px-5 py-4">
                               <div>
                                 <span className="font-medium text-gray-700 block">{applicant.jobTitle}</span>
                                 <span className="text-gray-500 text-xs tracking-wide">
                                    {applicant.employmentType}
                                 </span>
                               </div>
                            </td>
                            <td className="px-5 py-4 text-right">
                               <button 
                                 onClick={() => onSelectApplicant(applicant.id)}
                                 className="inline-flex bg-gray-900 hover:bg-gray-800 text-white px-4 py-2 rounded-lg font-bold text-xs transition-colors shadow-sm active:scale-95"
                               >
                                  Register
                               </button>
                            </td>
                         </tr>
                      ))}
                   </tbody>
                </table>
                </div>
             </div>
          )}

        </div>
      </div>
    </div>
  );
};

export default HiredApplicantsListModal;

import React, { useEffect } from 'react';
import { useForm, SubmitHandler } from 'react-hook-form';
import { zodResolver } from '@/lib/zodResolver';
import { X, Loader } from 'lucide-react';
import Combobox from '@/components/Custom/Combobox';
// @ts-ignore
import { plantillaApi } from '@api/plantillaApi';
import { plantillaSchema, PlantillaSchema } from '@/schemas/plantilla';

interface PlantillaFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  mode: 'create' | 'edit';
  departments: string[];
  initialData?: Partial<PlantillaSchema>;
  onSubmit: (data: PlantillaSchema) => Promise<void>;
  isProcessing?: boolean;
}

const PlantillaFormModal: React.FC<PlantillaFormModalProps> = ({ 
  isOpen, 
  onClose, 
  mode, 
  departments, 
  initialData, 
  onSubmit, 
  isProcessing = false 
}) => {
  const { register, handleSubmit, formState: { errors }, reset, watch, setValue } = useForm<PlantillaSchema>({
    resolver: zodResolver(plantillaSchema),
    defaultValues: {
      itemNumber: '',
      positionTitle: '',
      salaryGrade: 0,
      stepIncrement: 1,
      monthlySalary: 0,
      department: '',
      isVacant: true
    }
  });

  const salaryGrade = watch('salaryGrade');
  const stepIncrement = watch('stepIncrement');

  useEffect(() => {
    if (isOpen) {
      if (mode === 'edit' && initialData) {
        reset({
          itemNumber: initialData.itemNumber,
          positionTitle: initialData.positionTitle,
          salaryGrade: Number(initialData.salaryGrade),
          stepIncrement: Number(initialData.stepIncrement),
          monthlySalary: Number(initialData.monthlySalary),
          department: initialData.department,
          isVacant: initialData.isVacant
        });
      } else {
        reset({
           itemNumber: '',
           positionTitle: '',
           salaryGrade: 0,
           stepIncrement: 1,
           monthlySalary: 0,
           department: '',
           isVacant: true
        }); // Clear for create
      }
    }
  }, [isOpen, mode, initialData, reset]);

  // Auto-fetch salary
  useEffect(() => {
    if (isOpen && salaryGrade && stepIncrement) {
        const fetchSalary = async () => {
            try {
                const res = await plantillaApi.getSalarySchedule(salaryGrade, stepIncrement);
                if (res.data.success && res.data.monthlySalary) {
                    setValue('monthlySalary', res.data.monthlySalary);
                }
            } catch (err) {
                console.error("Failed to fetch suggested salary", err);
            }
        };
        // Debounce slightly or just call
        const timer = setTimeout(fetchSalary, 500);
        return () => clearTimeout(timer);
    }
  }, [salaryGrade, stepIncrement, isOpen, setValue]);

  const onFormSubmit: SubmitHandler<PlantillaSchema> = async (data) => {
    await onSubmit(data);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 transition-all">
      <div className="bg-white rounded-xl w-full max-w-md shadow-2xl border border-gray-100 overflow-hidden animate-in fade-in zoom-in duration-200">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 bg-gray-50 border-b border-gray-100">
          <h2 className="text-lg font-bold text-gray-900">
            {mode === 'create' ? 'Add New Position' : 'Edit Position'}
          </h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors p-1 rounded-full hover:bg-gray-200">
            <X size={20} />
          </button>
        </div>
        
        {/* Form */}
        <form onSubmit={handleSubmit(onFormSubmit)} className="flex flex-col max-h-[80vh]">
          <div className="p-6 space-y-4 overflow-y-auto">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-gray-700 mb-1">Item Number*</label>
                <input 
                  type="text"
                  {...register('itemNumber')}
                  className={`w-full px-3 py-2 bg-gray-50 border rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-gray-100 transition-all ${errors.itemNumber ? 'border-red-500' : 'border-gray-200'}`}
                  placeholder="e.g. ADOF3-1"
                />
                {errors.itemNumber && <p className="text-xs text-red-500 mt-1">{errors.itemNumber.message}</p>}
              </div>
              <div className="z-30 relative">
                <label className="block text-xs font-bold text-gray-700 mb-1">Salary Grade (1-33)*</label>
                <Combobox
                  options={Array.from({ length: 33 }, (_, i) => ({ value: String(i + 1), label: `SG ${i + 1}` }))}
                  value={String(watch('salaryGrade') || '')}
                  onChange={(val) => setValue('salaryGrade', Number(val), { shouldValidate: true })}
                  placeholder="Select SG"
                  error={!!errors.salaryGrade}
                  buttonClassName="w-full px-3 py-2 bg-gray-50 border rounded-lg text-sm"
                />
                 {errors.salaryGrade && <p className="text-xs text-red-500 mt-1">{errors.salaryGrade.message}</p>}
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-gray-700 mb-1">Position Title*</label>
              <input 
                type="text" 
                {...register('positionTitle')}
                className={`w-full px-3 py-2 bg-gray-50 border rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-gray-100 transition-all ${errors.positionTitle ? 'border-red-500' : 'border-gray-200'}`}
                placeholder="e.g. Administrative Officer III"
              />
              {errors.positionTitle && <p className="text-xs text-red-500 mt-1">{errors.positionTitle.message}</p>}
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="z-20 relative">
                <label className="block text-xs font-bold text-gray-700 mb-1">Step Increment</label>
                <Combobox
                  options={Array.from({ length: 8 }, (_, i) => ({ value: String(i + 1), label: `Step ${i + 1}` }))}
                  value={String(watch('stepIncrement') || 1)}
                  onChange={(val) => setValue('stepIncrement', Number(val))}
                  placeholder="Select Step"
                  buttonClassName="w-full px-3 py-2 bg-gray-50 border rounded-lg text-sm"
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-700 mb-1">Monthly Salary</label>
                <input 
                  type="number" step="0.01"
                  {...register('monthlySalary', { valueAsNumber: true })}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-gray-100 transition-all"
                />
              </div>
            </div>

            <div className="z-10 relative">
              <label className="block text-xs font-bold text-gray-700 mb-1">Department*</label>
              <Combobox
                options={departments.map(dept => ({ value: dept, label: dept }))}
                value={watch('department')}
                onChange={(val) => setValue('department', val, { shouldValidate: true })}
                placeholder="Select Department"
                error={!!errors.department}
                buttonClassName="w-full px-3 py-2 bg-gray-50 border rounded-lg text-sm"
              />
               {errors.department && <p className="text-xs text-red-500 mt-1">{errors.department.message}</p>}
            </div>
          </div>

          {/* Footer */}
          <div className="flex gap-3 px-6 py-4 bg-gray-50 border-t border-gray-100 mt-auto">
            <button 
              type="button" 
              onClick={onClose}
              className="flex-1 px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-semibold text-gray-700 hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm"
            >
              Cancel
            </button>
            <button 
              type="submit" 
              disabled={isProcessing}
              className="flex-1 px-4 py-2 bg-gray-900 hover:bg-gray-800 text-white rounded-lg text-sm font-bold transition-all shadow-md flex items-center justify-center gap-2"
            >
              {isProcessing && <Loader className="animate-spin" size={16} />}
              {mode === 'create' ? 'Create Position' : 'Save Changes'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

