    defaultValues: {
      firstName: '',
      lastName: '',
      email: '',
      password: '',
      role: 'Employee',
      department: '',
      jobTitle: '',
      employmentStatus: 'Active',
      dateHired: '',
    },
  });

  useEffect(() => {
    const loadDepts = async () => {
      try {
        const data = await fetchDepartments();
        if (data.success) setDepartments(data.departments || []);
