/**
 * useEmployeeMemos Hook
 * Custom hook for managing employee's memo viewing in Employee Portal
 * Optimized with useCallback for performance
 */

import { useState, useEffect, useCallback } from 'react';
// @ts-ignore
import { fetchMyMemos, acknowledgeMemo } from "@api";

export interface Memo {
  id: number;
  memoNumber: string;
  memoType: string;
  subject: string;
  content: string;
  priority: string;
  status: string;
  createdAt: string;
  acknowledgedAt?: string;
  acknowledgmentRequired?: boolean;
}

export interface UseEmployeeMemosReturn {
  memos: Memo[];
  loading: boolean;
  error: string | null;
  acknowledging: boolean;
  isViewOpen: boolean;
  selectedMemo: Memo | null;
  loadMemos: () => Promise<void>;
  openViewModal: (memo: Memo) => void;
  closeViewModal: () => void;
  handleAcknowledge: () => Promise<void>;
}

export const useEmployeeMemos = (): UseEmployeeMemosReturn => {
  // Data state
  const [memos, setMemos] = useState<Memo[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [acknowledging, setAcknowledging] = useState(false);

  // Modal states
  const [isViewOpen, setIsViewOpen] = useState(false);
  const [selectedMemo, setSelectedMemo] = useState<Memo | null>(null);

  // Load memos - memoized with useCallback
  const loadMemos = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const res = await fetchMyMemos();
      // Handle different API response structures from backend safely with 'unknown' middle cast
      const dataPayload = res.data as unknown as { memos?: Memo[] } | undefined;
      const directMemos = ('memos' in res) ? (res as unknown as { memos?: Memo[] }).memos : undefined;
      setMemos(directMemos || dataPayload?.memos || []);
    } catch (err) {
      setError('Failed to load memos');
    } finally {
      setLoading(false);
    }
  }, []);

  // Initial load
  useEffect(() => {
    loadMemos();
  }, [loadMemos]);

  // Open view modal - memoized
  const openViewModal = useCallback((memo: Memo) => {
    setSelectedMemo(memo);
    setIsViewOpen(true);
  }, []);

  // Close view modal - memoized
  const closeViewModal = useCallback(() => {
    setIsViewOpen(false);
    setSelectedMemo(null);
  }, []);

  // Handle acknowledgment - memoized
  const handleAcknowledge = useCallback(async () => {
    if (!selectedMemo || selectedMemo.acknowledgedAt) return;

    try {
      setAcknowledging(true);
      await acknowledgeMemo(selectedMemo.id);
      setIsViewOpen(false);
      loadMemos();
    } catch (err) {
      setError('Failed to acknowledge memo');
    } finally {
      setAcknowledging(false);
    }
  }, [selectedMemo, loadMemos]);

  return {
    // Data
    memos,
    loading,
    error,
    acknowledging,

    // Modal states
    isViewOpen,
    selectedMemo,

    // Actions
    loadMemos,
    openViewModal,
    closeViewModal,
    handleAcknowledge
  };
};

export default useEmployeeMemos;

import { useState, useCallback, useEffect } from 'react';
import axiosInstance from '@/api/axios';
import axios from 'axios';

export interface Profile {
  id?: number;
  firstName?: string;
  lastName?: string;
  email?: string;
  phoneNumber?: string;
  address?: string;
  avatar?: string;
  department?: string;
  jobTitle?: string;
  positionTitle?: string;
  skills?: unknown[];
  education?: unknown[];
  [key: string]: unknown;
}

export interface UpdateResult {
  success: boolean;
  message?: string;
}

export interface UseEmployeeProfileReturn {
  profile: Profile | null;
  loading: boolean;
  error: string | null;
  updating: boolean;
  updateSuccess: boolean;
  fetchProfile: () => Promise<void>;
  updateProfile: (formData: FormData) => Promise<UpdateResult>;
}

export const useEmployeeProfile = (): UseEmployeeProfileReturn => {
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [updating, setUpdating] = useState(false);
  const [updateSuccess, setUpdateSuccess] = useState(false);

  // Fetch Profile (User Me)
  const fetchProfile = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      
      // 1. Get basic identity to know WHO we are
      const authRes = await axiosInstance.get('/auth/me');
      if (!authRes.data.success) throw new Error('Failed to authenticate');
      
      const userId = authRes.data.data.id;

      // 2. Fetch FULL detailed record (Skills, Education, Contacts) using Employee API
      // The backend allows this if req.user.id === params.id
      const fullProfileRes = await axiosInstance.get(`/employees/${userId}`);
      
      if (fullProfileRes.data.success) {
        setProfile(fullProfileRes.data.employee);
      } else {
        // Fallback to basic auth data if full fetch fails
        setProfile(authRes.data.data);
      }

    } catch (err: unknown) {
      console.error(err);
      const message = import.meta.env.DEV ? (err instanceof Error ? err.message : 'Unknown error') : 'Failed to load profile';
      setError(axios.isAxiosError(err) ? err.response?.data?.message || message : message);
    } finally {
      setLoading(false);
    }
  }, []);

  // Update profile function remains the same, targeting auth profile endpoint
  // Note: For updating specific sections like Skills/Education, we would need separate functions
  const updateProfile = useCallback(async (formData: FormData): Promise<UpdateResult> => {
    try {
      setUpdating(true);
      setUpdateSuccess(false);
      
      // Since we mainly update personal info here, auth/profile is still valid
      // or we could use /employees/:id update. using auth/profile for now as it handles avatar well.
      const res = await axiosInstance.put('/auth/profile', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });

      if (res.data.success) {
        setUpdateSuccess(true);
        fetchProfile(); // Reload to show changes
        return { success: true };
      }
      return { success: false, message: res.data.message };
    } catch (err: unknown) {
      return { 
        success: false, 
        message: axios.isAxiosError(err) ? err.response?.data?.message || 'Update failed' : 'Update failed' 
      };
    } finally {
      setUpdating(false);
    }
  }, [fetchProfile]);

  useEffect(() => {
    fetchProfile();
  }, [fetchProfile]);

  return {
    profile,
    loading,
    error,
    updating,
    updateSuccess,
    fetchProfile,
    updateProfile
  };
};

export default useEmployeeProfile;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Plus, Search, SquarePen, Trash2, Sliders, CheckCircle, ListChecks } from 'lucide-react';
import { fetchCriteria, addCriteria, updateCriteria, deleteCriteria } from '@/api/performanceApi';
import EditCriteriaModal from '../Modals/EditCriteriaModal';
import DeleteConfirmationModal from '../Modals/DeleteConfirmationModal';
import { PerformanceItem } from '../../types';
import { PerformanceCriteriaSchema } from '@/schemas/performanceSchema';

interface CriteriaResponse {
  success: boolean;
  criteria: PerformanceItem[];
}

const PerformanceCriteriaContent: React.FC = () => {
  const [criteriaList, setCriteriaList] = useState<PerformanceItem[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [searchTerm, setSearchTerm] = useState<string>('');
  
  // Modal States
  const [isEditModalOpen, setIsEditModalOpen] = useState<boolean>(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState<boolean>(false);
  const [selectedCriteria, setSelectedCriteria] = useState<PerformanceItem | null>(null);

  const loadCriteria = async () => {
    try {
      setLoading(true);
      const data = (await fetchCriteria()) as unknown as CriteriaResponse;
      if (data.success) {
        setCriteriaList(data.criteria);
      }
    } catch (err) {
      console.error("Failed to load criteria", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadCriteria();
  }, []);

  const handleAdd = () => {
    setSelectedCriteria(null);
    setIsEditModalOpen(true);
  };

  const handleEdit = (item: PerformanceItem) => {
    setSelectedCriteria(item);
    setIsEditModalOpen(true);
  };

  const handleDeleteClick = (item: PerformanceItem) => {
    setSelectedCriteria(item);
    setIsDeleteModalOpen(true);
  };

  const handleDeleteConfirm = async () => {
    if (selectedCriteria && selectedCriteria.id) {
      try {
        await deleteCriteria(selectedCriteria.id);
        setIsDeleteModalOpen(false);
        loadCriteria();
      } catch (err) {
        console.error("Failed to delete criteria", err);
      }
    }
  };

  const handleSave = async (formData: PerformanceCriteriaSchema) => {
    try {
      if (selectedCriteria && selectedCriteria.id) {
        await updateCriteria(selectedCriteria.id, formData);
      } else {
        await addCriteria(formData);
      }
      setIsEditModalOpen(false);
      loadCriteria();
    } catch (err) {
      console.error("Failed to save criteria", err);
    }
  };

  const filteredCriteria = criteriaList.filter(item => 
    (item.title || item.criteriaTitle || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
    (item.category || '').toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="flex flex-col gap-6">
      {/* Header Actions */}
      <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-[#F8F9FA] p-4 rounded-lg shadow-sm border border-gray-200">
        <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="p-2 bg-white rounded-lg shadow-sm border border-gray-200 text-gray-500">
                <ListChecks size={20} />
            </div>
            <div>
                <h3 className="text-lg font-bold text-gray-800">Performance Criteria</h3>
                <p className="text-xs text-gray-500">Manage MFOs and success indicators</p>
            </div>
        </div>
        
        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
            <div className="relative flex-1 sm:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                <input
                type="text"
                placeholder="Search criteria..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-9 pr-4 py-2 bg-white border border-gray-200 rounded-lg text-sm outline-none focus:ring-2 focus:ring-gray-200 shadow-sm transition-all"
                />
            </div>
            <button
                onClick={handleAdd}
                className="flex items-center justify-center gap-2 px-4 py-2 bg-gray-800 text-white rounded-lg hover:bg-gray-700 transition-all font-bold shadow-md text-sm whitespace-nowrap"
            >
                <Plus size={16} />
                <span>Add Criteria</span>
            </button>
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-800"></div>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredCriteria.map((item) => {
            const borderColors: Record<string, string> = {
              'Strategic Priorities': 'border-l-slate-800',
              'Core Functions': 'border-l-slate-600',
              'Support Functions': 'border-l-slate-400',
              'General': 'border-l-slate-200'
            };
            const borderColor = (item.category && borderColors[item.category]) ? borderColors[item.category] : 'border-l-gray-300';

            return (
              <motion.div
                key={item.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className={`bg-white p-6 rounded-2xl border border-gray-100 hover:border-gray-200 hover:shadow-lg transition-all group border-l-4 ${borderColor} flex flex-col h-full shadow-sm`}
              >
                <div className="flex justify-between items-start mb-4">
                  <span className="px-3 py-1 bg-gray-50 text-gray-500 rounded-lg text-[9px] font-black uppercase tracking-widest border border-gray-100">
                    {String(item.category || '')}
                  </span>
                  <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all transform translate-x-2 group-hover:translate-x-0">
                    <button onClick={() => handleEdit(item)} className="p-2 text-gray-400 hover:text-gray-900 bg-gray-50 rounded-xl transition-all border border-gray-100 hover:shadow-sm">
                      <SquarePen size={14} />
                    </button>
                    <button onClick={() => handleDeleteClick(item)} className="p-2 text-gray-400 hover:text-red-600 bg-gray-50 rounded-xl transition-all border border-gray-100 hover:shadow-sm">
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>

                <h3 className="text-base font-bold text-gray-900 mb-2 tracking-tight group-hover:text-blue-900 transition-colors leading-tight">{item.title || item.criteriaTitle}</h3>
                <p className="text-gray-500 text-xs mb-6 line-clamp-3 leading-relaxed min-h-[3em] flex-1">{item.description || item.criteriaDescription}</p>

                <div className="flex items-center justify-between pt-5 border-t border-gray-50 text-xs mt-auto">
                  <div className="flex items-center gap-2.5 text-gray-500 font-medium">
                    <div className="p-2 bg-gray-50 rounded-xl border border-gray-100 group-hover:bg-blue-50 group-hover:border-blue-100 transition-colors">
                      <Sliders size={14} className="text-gray-400 group-hover:text-blue-600 transition-colors" />
                    </div>
                    <div className="flex flex-col">
                      <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter leading-none mb-1">Weight</span>
                      <span className="font-black text-gray-900 text-sm leading-none">{item.weight}%</span>
                    </div>
                  </div>
                  <div className="flex items-center gap-2.5 text-gray-500 font-medium text-right items-end justify-end">
                    <div className="p-2 bg-gray-50 rounded-xl border border-gray-100 group-hover:bg-purple-50 group-hover:border-purple-100 transition-colors">
                      <CheckCircle size={14} className="text-gray-400 group-hover:text-purple-600 transition-colors" />
                    </div>
                    <div className="flex flex-col items-end">
                      <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter leading-none mb-1">Max Score</span>
                      <span className="font-black text-gray-900 text-sm leading-none">{String(item.maxScore || '0')}</span>
                    </div>
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>
      )}

      {/* Edit/Add Modal */}
      <EditCriteriaModal 
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        onSubmit={handleSave}
        initialData={selectedCriteria}
      />

      {/* Delete Confirmation Modal */}
      <DeleteConfirmationModal
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        itemName={String(selectedCriteria?.title || selectedCriteria?.criteriaTitle || '')}
      />
    </div>
  );
};

export default PerformanceCriteriaContent;

import React from 'react';
import { Search, ArrowRight } from "lucide-react";
import { TABLE_HEADERS } from "@/components/Custom/Performance/constants/adminPerformance.constant";
import { useNavigate } from 'react-router-dom';
import { PerformanceTableItem } from '@/components/Custom/Performance/Utils/adminPerformanceUtils';

interface FiltersState {
  department: string;
  employee: string;
  status: string;
  [key: string]: unknown;
}

interface PerformanceTableProps {
  currentItems: PerformanceTableItem[];
  getStatusBadge: (status: string) => React.ReactNode;
  debouncedSearchQuery: string;
  filters: FiltersState;
  isLoading: boolean;
}

export const PerformanceTable: React.FC<PerformanceTableProps> = ({ 
  currentItems, 
  getStatusBadge, 
  debouncedSearchQuery, 
  filters, 
  isLoading 
}) => {
  const navigate = useNavigate();
  const hasActiveFilters = debouncedSearchQuery || Object.values(filters).some(v => v && v !== 'All Status');

  const handleView = (reviewId?: string | number, employeeDbId?: string | number) => {
    if (reviewId) {
        navigate(`/admin-dashboard/performance/reviews/${reviewId}`);
    } else if (employeeDbId) {
        navigate(`/admin-dashboard/performance/reviews/new?employeeId=${employeeDbId}`);
    }
  };
  
  // Master Design: Minimalist Monochrome Badge Logic
  const getBadgeStyle = (status?: string) => {
      const s = status?.toLowerCase() || '';
      if (s.includes('completed') || s.includes('finalized') || s.includes('acknowledged')) return 'bg-white text-gray-800 border border-gray-300';
      if (s.includes('pending') || s.includes('process')) return 'bg-black text-white border border-black';
      if (s.includes('draft')) return 'bg-gray-50 text-gray-400 border border-gray-100';
      return 'bg-gray-50 text-gray-500 border border-gray-200';
  }

  if (isLoading) {
    return (
      <div className="w-full h-64 flex items-center justify-center bg-white rounded-xl shadow-sm border border-gray-100 mt-6">
        <div className="flex flex-col items-center gap-3">
          <div className="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-gray-500 text-sm font-medium">Loading performance records...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 overflow-hidden rounded-xl bg-[#F8F9FA] p-1 mt-6">
      <div className="overflow-x-auto bg-gray-50 rounded-lg">
        <table className="w-full min-w-[1000px]">
          <thead className="bg-gray-200 shadow-md text-gray-700">
            <tr>
              {TABLE_HEADERS.map((header: string) => (
                <th key={header} className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">
                  {header}
                </th>
              ))}
              <th className="px-6 py-4 text-right text-sm font-bold tracking-wide whitespace-nowrap">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {currentItems.length ? (
              currentItems.map((item) => (
                <tr 
                    key={`${item.id}-${item.reviewId || 'new'}`} 
                    className="hover:bg-[#F8F9FA] hover:shadow-xl transition-colors cursor-pointer group"
                    onClick={() => handleView(item.reviewId, item.employeeDbId)}
                >
                  <td className="px-6 py-4">
                    <span className={`${getBadgeStyle(item.status)} px-2.5 py-1 text-[10px] font-bold tracking-wider rounded inline-block`}>
                      {item.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-xs font-bold text-gray-900">{item.id}</td>
                  <td className="px-6 py-4">
                      <div className="text-sm font-bold text-gray-900">{item.name}</div>
                  </td>
                  <td className="px-6 py-4 text-xs text-gray-500 font-medium">{item.department}</td>
                  <td className="px-6 py-4 text-xs text-gray-500 font-medium">{item.jobTitle}</td>
                  <td className="px-6 py-4 text-xs text-gray-400 font-medium">{item.lastEvaluation}</td>
                  <td className="px-6 py-4">
                      {item.score ? <span className="text-lg font-black text-gray-900">{item.score}</span> : <span className="text-gray-300 text-xs italic">Pending</span>}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="inline-flex items-center justify-center w-8 h-8 rounded-full bg-white border border-gray-100 text-gray-300 group-hover:border-gray-300 group-hover:text-gray-900 transition-all">
                        <ArrowRight size={16} />
                    </div>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={TABLE_HEADERS.length + 1} className="px-6 py-16 text-center">
                  <div className="flex flex-col items-center justify-center text-gray-400">
                    <p className="text-sm font-bold text-gray-600">No records found</p>
                    <p className="text-xs mt-1 text-gray-400">
                      {hasActiveFilters
                        ? "Try adjusting your filters" 
                        : "No performance data available"}
                    </p>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Calendar, SquarePen, CheckCircle, Trash2, X, Clock, AlertCircle } from 'lucide-react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { reviewCycleSchema, ReviewCycleSchema } from '@/schemas/performanceSchema';
import { fetchReviewCycles, createReviewCycle, updateReviewCycle, deleteReviewCycle } from '@/api/performanceApi';
import { ReviewCycle, ReviewCyclesApiResponse } from '@/types/performance';
import { useToastStore } from '@/stores';
import { AxiosError } from 'axios';

interface ApiErrorResponse {
  message?: string;
}

const ReviewCyclesContent: React.FC = () => {
  const [cycles, setCycles] = useState<ReviewCycle[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [editingCycle, setEditingCycle] = useState<ReviewCycle | null>(null); 
  
  const showToast = useToastStore((state) => state.showToast);
  const showNotification = (message: string, type: 'success' | 'error') => showToast(message, type);

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<ReviewCycleSchema>({
    resolver: zodResolver(reviewCycleSchema),
    defaultValues: {
      title: '',
      description: '',
      startDate: '',
      endDate: '',
    },
  });

  const loadCycles = async () => {
    try {
      setLoading(true);
      const data = await fetchReviewCycles();
      if (data.success) {
        setCycles(data.cycles);
      }
    } catch (err) {
      console.error("Failed to load cycles", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadCycles();
  }, []);

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingCycle(null);
    reset({ title: '', description: '', startDate: '', endDate: '' });
  };

  const handleNewCycle = () => {
    setEditingCycle(null);
    reset({ title: '', description: '', startDate: '', endDate: '' });
    setIsModalOpen(true);
  };

  const handleEditCycle = (cycle: ReviewCycle) => {
    setEditingCycle(cycle);
    reset({
      title: cycle.title || '',
      description: cycle.description || '',
      startDate: cycle.startDate ? cycle.startDate.split('T')[0] : '',
      endDate: cycle.endDate ? cycle.endDate.split('T')[0] : ''
    });
    setIsModalOpen(true);
  };

  const onFormSubmit = async (data: ReviewCycleSchema) => {
    try {
      if (editingCycle) {
        await updateReviewCycle(editingCycle.id, data);
      } else {
        await createReviewCycle(data);
      }
      closeModal();
      loadCycles();
    } catch (err) {
      const axiosErr = err as AxiosError<ApiErrorResponse>;
      console.error("Failed to save cycle", err);
      showNotification(axiosErr.response?.data?.message || "Failed to save cycle", "error");
    }
  };

  const handleDeleteCycle = async (cycleId: string | number) => {
    if (!window.confirm("Are you sure you want to delete this review cycle?")) {
      return;
    }
    try {
      await deleteReviewCycle(cycleId);
      loadCycles();
    } catch (err) {
      const axiosErr = err as AxiosError<ApiErrorResponse>;
      console.error("Failed to delete cycle", err);
      showNotification(axiosErr.response?.data?.message || "Failed to delete cycle", "error");
    }
  };

  const getStatus = (start: string, end: string) => {
    const now = new Date();
    const startDate = new Date(start);
    const endDate = new Date(end);

    if (now < startDate) return { label: 'Upcoming', color: 'bg-blue-50 text-blue-700 border-blue-100', icon: Clock };
    if (now > endDate) return { label: 'Completed', color: 'bg-green-50 text-green-700 border-green-100', icon: CheckCircle };
    return { label: 'Active', color: 'bg-emerald-50 text-emerald-700 border-emerald-100', icon: AlertCircle };
  };

  return (
    <div className="flex flex-col gap-8">
      {/* Header Actions */}
      <div className="flex justify-between items-end">
        <div>
            <h3 className="text-2xl font-bold text-gray-900 tracking-tight">Cycle Management</h3>
            <p className="text-sm text-gray-500 mt-1">Create and manage evaluation periods for your organization</p>
        </div>
        <button
          onClick={handleNewCycle}
          className="group flex items-center gap-2 px-5 py-2.5 bg-gray-900 text-white rounded-xl hover:bg-black transition-all duration-200 font-medium shadow-sm hover:shadow-md active:scale-95"
        >
          <Plus size={18} className="group-hover:rotate-90 transition-transform duration-300" />
          <span>New Cycle</span>
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20">
          <div className="animate-spin rounded-full h-10 w-10 border-2 border-gray-900 border-t-transparent"></div>
        </div>
      ) : cycles.length === 0 ? (
        <div className="text-center py-20 bg-gray-50 rounded-2xl border border-dashed border-gray-200">
          <div className="bg-white p-4 rounded-full shadow-sm inline-block mb-4">
             <Calendar className="h-8 w-8 text-gray-400" />
          </div>
          <h3 className="text-lg font-semibold text-gray-900">No Review Cycles Found</h3>
          <p className="text-gray-500 mt-2 max-w-sm mx-auto">Get started by creating a new performance review cycle for your employees.</p>
          <button 
            onClick={handleNewCycle}
            className="mt-6 text-sm font-medium text-gray-900 hover:underline underline-offset-4"
          >
            Create your first cycle
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {cycles.map((cycle) => {
            const status = getStatus(cycle.startDate, cycle.endDate);
            const StatusIcon = status.icon;
            
            return (
              <motion.div
                key={cycle.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="group relative bg-white rounded-2xl border border-gray-200 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 overflow-hidden"
              >
                <div className="absolute top-0 left-0 w-1.5 h-full bg-gradient-to-b from-gray-200 via-gray-300 to-gray-100 group-hover:from-gray-800 group-hover:to-gray-600 transition-colors duration-500"></div>
                
                <div className="p-6 pl-8">
                  <div className="flex justify-between items-start mb-5">
                    <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-medium border ${status.color}`}>
                        <StatusIcon size={12} />
                        {status.label}
                    </span>
                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
                      <button 
                        onClick={() => handleEditCycle(cycle)}
                        className="p-2 text-gray-400 hover:text-gray-900 hover:bg-gray-100 rounded-lg transition-colors"
                        title="Edit"
                      >
                        <SquarePen size={16} />
                      </button>
                      <button 
                        onClick={() => handleDeleteCycle(cycle.id)}
                        className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                        title="Delete"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>

                  <h3 className="text-xl font-bold text-gray-900 mb-2 leading-tight">{cycle.title}</h3>
                  <p className="text-gray-500 text-sm mb-6 h-10 line-clamp-2 leading-relaxed">{cycle.description || 'No description provided.'}</p>

                  <div className="space-y-3 pt-5 border-t border-gray-100">
                    <div className="flex items-center justify-between text-sm group/date">
                      <span className="text-gray-500 flex items-center gap-2 group-hover/date:text-gray-700 transition-colors">
                          <Calendar size={15} className="text-gray-400 group-hover/date:text-gray-600" /> Start Date
                      </span>
                      <span className="font-semibold text-gray-900">{new Date(cycle.startDate).toLocaleDateString()}</span>
                    </div>
                    <div className="flex items-center justify-between text-sm group/date">
                      <span className="text-gray-500 flex items-center gap-2 group-hover/date:text-gray-700 transition-colors">
                          <CheckCircle size={15} className="text-gray-400 group-hover/date:text-gray-600" /> End Date
                      </span>
                      <span className="font-semibold text-gray-900">{new Date(cycle.endDate).toLocaleDateString()}</span>
                    </div>
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>
      )}

      {/* Modal */}
      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4">
            <motion.div
              initial={{ opacity: 0, scale: 0.95, y: 10 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95, y: 10 }}
              className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-gray-100"
            >
              <div className="px-8 py-6 flex justify-between items-center bg-white border-b border-gray-100">
                <div>
                    <h2 className="text-xl font-bold text-gray-900">
                    {editingCycle ? 'Edit Cycle' : 'Create New Cycle'}
                    </h2>
                    <p className="text-sm text-gray-500 mt-0.5">Define the period for performance evaluations</p>
                </div>
                <button 
                    onClick={closeModal} 
                    className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-400 hover:text-gray-600"
                >
                  <X size={20} />
                </button>
              </div>
              
              <form onSubmit={handleSubmit(onFormSubmit)} className="p-8 space-y-6">
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Cycle Title</label>
                        <input
                        type="text"
                        {...register('title')}
                        className="w-full px-4 py-3 bg-white border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-gray-900 focus:border-transparent outline-none transition-all placeholder:text-gray-400"
                        placeholder={`e.g. Annual Review ${new Date().getFullYear()}`}
                        />
                        {errors.title && <p className="text-red-500 text-xs mt-1">{errors.title.message}</p>}
                    </div>
                    
                    <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Description</label>
                        <textarea
                        rows={3}
                        {...register('description')}
                        className="w-full px-4 py-3 bg-white border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-gray-900 focus:border-transparent outline-none resize-none transition-all placeholder:text-gray-400"
                        placeholder="Briefly describe the purpose of this review cycle..."
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-5">
                        <div>
                        <label className="block text-sm font-semibold text-gray-700 mb-2">Start Date</label>
                        <input
                            type="date"
                            {...register('startDate')}
