  onChangeValue,
  className = "lg:col-span-3",
  gridClassName = "grid-cols-1 md:grid-cols-2 lg:grid-cols-3"
}) => {
  const [showEditModal, setShowEditModal] = useState<boolean>(false);
  const [editingAssessment, setEditingAssessment] = useState<Assessment | null>(null);
  const [showDeleteModal, setShowDeleteModal] = useState<boolean>(false);
  const [deletingAssessment, setDeletingAssessment] = useState<Assessment | null>(null);

  const handleOpenAdd = () => { setEditingAssessment(null); setShowEditModal(true); };
  const handleOpenEdit = (assessment: Assessment) => {
    setEditingAssessment({ ...assessment, title: assessment.title, description: assessment.description });
    setShowEditModal(true);
  };

  const handleSaveModal = (formData: { title: string; description: string }) => {
     const savedData: Partial<Assessment> = {
         title: formData.title,
         description: formData.description,
         // Default to generic gray badge
         badge: editingAssessment?.badge || 'ASSESSMENT',
         badgeColor: editingAssessment?.badgeColor || 'bg-gray-100 text-gray-600',
         iconName: editingAssessment?.iconName || 'MessageSquare'
     };

     if (editingAssessment?.id) { 
        if (onEdit) onEdit({ ...editingAssessment, ...savedData } as Assessment); 
     } else { 
        if (onAdd) onAdd(savedData); 
     }
     
     setShowEditModal(false);
     setEditingAssessment(null);
  };

  const handleDeleteClick = (item: Assessment) => { setDeletingAssessment(item); setShowDeleteModal(true); };
  const handleDeleteConfirm = () => {
    if (onDelete && deletingAssessment) onDelete(deletingAssessment.id);
    setShowDeleteModal(false);
    setDeletingAssessment(null);
  };

  return (
    <div className={`${className} space-y-4 max-w-5xl mx-auto pt-4 border-t border-dashed border-gray-200`}>
      <div className="flex items-center gap-2 mb-1">
        <div className="p-1.5 bg-gray-100 rounded text-gray-600">
           <MessageSquare size={16} />
        </div>
        <div>
            <h3 className="font-bold text-gray-900 text-sm">
            Qualitative Assessment
            </h3>
            <p className="text-xs font-medium text-gray-500">Feedback & Development</p>
        </div>
      </div>

      <div className={`grid ${gridClassName} gap-4`}>
        {assessments.map((assessment) => (
          <motion.div 
            initial={{ opacity: 0, scale: 0.98 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            key={assessment.id}
            className="group relative bg-white rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-all duration-300 flex flex-col overflow-hidden"
          >
            {/* Minimal Header */}
            <div className="px-4 py-3 flex justify-between items-start border-b border-gray-50 bg-white">
               <div className="flex items-center gap-2">
                  <div className={`p-1.5 rounded bg-gray-50 border border-gray-100 text-gray-400 group-hover:text-gray-900 transition-all`}>
                      {ICON_MAP[assessment.iconName || 'MessageSquare'] || ICON_MAP['MessageSquare']}
                  </div>
                  <div>
                     <span className="block text-xs font-medium text-gray-500 mb-px">{assessment.badge || 'Field'}</span>
                     <h4 className="font-bold text-gray-800 text-sm leading-tight">{assessment.title}</h4>
                  </div>
               </div>
               
               {canEdit && (
                 <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => handleOpenEdit(assessment)} className="p-1 text-gray-400 hover:text-gray-900 rounded hover:bg-gray-100 transition-colors">
                      <SquarePen size={12} />
                    </button>
                    <button onClick={() => handleDeleteClick(assessment)} className="p-1 text-gray-400 hover:text-red-700 rounded hover:bg-red-50 transition-colors">
                      <Trash2 size={12} />
                    </button>
                 </div>
               )}
            </div>

            <div className="p-4 pt-3 flex-1 flex flex-col gap-2 bg-white">
              <p className="text-[10px] text-gray-500 font-medium leading-relaxed italic border-l-2 border-gray-100 pl-2">
                 "{assessment.description || 'Provide feedback...'}"
              </p>

              <textarea
                  value={assessment.value || ''}
                  onChange={(e) => onChangeValue && onChangeValue(assessment.id, e.target.value)}
                  readOnly={!canEdit}
                  placeholder="Enter feedback..."
                  className={`w-full p-3 text-xs bg-gray-50/30 hover:bg-gray-50 focus:bg-white border border-gray-100 hover:border-gray-200 focus:border-gray-300 rounded-lg focus:ring-1 focus:ring-gray-200 outline-none flex-1 min-h-[100px] resize-none transition-all placeholder:text-gray-300 text-gray-700 leading-relaxed ${!canEdit ? 'cursor-default bg-gray-50' : ''}`}
                />
            </div>
            
            <div className="h-0.5 w-full bg-gray-50 group-hover:bg-gray-200 transition-all"></div>
          </motion.div>
        ))}
        
        {canEdit && onAdd && (
          <button
            onClick={handleOpenAdd}
            className="group flex flex-col items-center justify-center p-4 border-2 border-dashed border-gray-200 hover:border-gray-400 bg-gray-50/20 hover:bg-gray-50 rounded-xl min-h-[180px] transition-all gap-2 text-gray-300 hover:text-gray-600"
          >
             <div className="p-2 bg-white rounded-full shadow-sm group-hover:scale-110 group-hover:shadow-md transition-all border border-gray-100 text-gray-300 group-hover:text-gray-900">
                <Plus size={20} />
             </div>
             <span className="font-medium text-sm text-gray-500">Add New Assessment</span>
          </button>
        )}
      </div>

      <EditAssessmentModal 
        isOpen={showEditModal} 
        onClose={() => setShowEditModal(false)}
        onSubmit={handleSaveModal}
        initialData={editingAssessment ? {title: editingAssessment.title || '', description: editingAssessment.description || ''} : null}
        title={editingAssessment ? "Edit Assessment" : "Add Assessment"}
      />
      
      <DeleteConfirmationModal
        isOpen={showDeleteModal}
        onClose={() => setShowDeleteModal(false)}
        onConfirm={handleDeleteConfirm}
        itemName={deletingAssessment?.title}
      />
    </div>
  );
};

export default QualitativeAssessment;

import React from 'react';
import { FileText, Edit3, ArrowRight } from 'lucide-react';

interface ReviewItem {
  id: string | number;
  status: string;
  reviewPeriod?: string;
  cycleTitle?: string;
  createdAt?: string;
  reviewerName?: string;
  finalScore?: number | string;
}

interface ReviewListProps {
  reviews: ReviewItem[];
  activeTab: string;
  onViewDetails: (review: ReviewItem) => void;
  onStartSelfRating: (review: ReviewItem) => void;
}

// Minimalist status styling
const getStatusBadge = (status: string) => {
  const styles: Record<string, string> = {
    'Self-Rated': 'bg-black text-white border border-black',
    'Submitted': 'bg-gray-900 text-white border border-gray-900',
    'Acknowledged': 'bg-white text-gray-800 border border-gray-300',
    'Finalized': 'bg-white text-gray-800 border border-gray-300',
    'Disputed': 'bg-white text-gray-800 border border-gray-300 dashed',
    'Draft': 'bg-gray-50 text-gray-400 border border-gray-100',
  };
  return styles[status] || 'bg-gray-50 text-gray-500 border border-gray-100';
};

const formatStatus = (status: string) => {
  const labels: Record<string, string> = {
    'Self-Rated': 'Self Rating Submitted',
    'Submitted': 'Reviewer Review Submitted',
    'Acknowledged': 'Completed',
    'Finalized': 'Finalized',
    'Disputed': 'Under Review',
    'Draft': 'Evaluation Required',
  };
  return labels[status] || status;
};

const formatDate = (dateStr?: string) => {
  if (!dateStr) return '—';
  try {
    return new Date(dateStr).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  } catch {
    return dateStr;
  }
};

const ReviewList: React.FC<ReviewListProps> = ({
  reviews,
  activeTab,
  onViewDetails,
  onStartSelfRating
}) => {
  if (reviews.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-16 px-4 bg-gray-50/50 rounded-xl border-2 border-dashed border-gray-200 text-center">
        <h3 className="text-gray-900 font-bold text-lg tracking-tight mb-1">
          {activeTab === 'pending' ? 'All Caught Up' : 'No History Yet'}
        </h3>
        <p className="text-sm text-gray-500 max-w-sm mx-auto">
          {activeTab === 'pending' 
            ? 'You have no pending performance evaluations.' 
            : "You haven't completed any evaluations yet."}
        </p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full">
          <thead>
            <tr className="border-b border-gray-100 bg-gray-50/50">
              <th className="px-6 py-4 text-left text-[10px] font-black uppercase tracking-widest text-gray-400">Status</th>
              <th className="px-6 py-4 text-left text-[10px] font-black uppercase tracking-widest text-gray-400">Period</th>
              <th className="px-6 py-4 text-left text-[10px] font-black uppercase tracking-widest text-gray-400">Reviewer</th>
              <th className="px-6 py-4 text-left text-[10px] font-black uppercase tracking-widest text-gray-400">Score</th>
              <th className="px-6 py-4 text-right text-[10px] font-black uppercase tracking-widest text-gray-400">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {reviews.map((review) => (
              <tr 
                key={review.id} 
                className="group hover:bg-gray-50 transition-all cursor-pointer"
                onClick={() => onViewDetails(review)}
              >
                <td className="px-6 py-4">
                  <span className={`inline-flex items-center px-2.5 py-1 rounded text-[10px] uppercase font-bold tracking-wider ${getStatusBadge(review.status)}`}>
                    {formatStatus(review.status)}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div>
                      <span className="block text-sm font-bold text-gray-900">
                        {review.reviewPeriod || review.cycleTitle || 'Annual Review'}
                      </span>
                      <span className="text-xs text-gray-400 font-medium">{formatDate(review.createdAt)}</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className="text-sm font-medium text-gray-600">
                    {review.reviewerName || '—'}
                  </span>
                </td>
                <td className="px-6 py-4">
                  {review.finalScore ? (
                    <div className="flex items-center gap-2">
                        <span className="text-lg font-black text-gray-900">{parseFloat(review.finalScore.toString()).toFixed(2)}</span>
                    </div>
                  ) : (
                    <span className="text-xs text-gray-400 font-medium italic">Pending</span>
                  )}
                </td>
                <td className="px-6 py-4 text-right">
                    {review.status === 'Draft' ? (
                      <button
                        onClick={(e) => { e.stopPropagation(); onStartSelfRating(review); }}
                        className="inline-flex items-center gap-2 px-4 py-2 bg-black text-white text-xs font-bold uppercase tracking-wider rounded-lg hover:bg-gray-800 transition-all shadow-lg shadow-gray-200"
                      >
                        <Edit3 size={14} /> Start Rating
                      </button>
                    ) : (
                      <div className="inline-flex items-center justify-center w-8 h-8 rounded-full bg-white border border-gray-200 text-gray-300 group-hover:border-gray-300 group-hover:text-gray-900 transition-all">
                        <ArrowRight size={16} />
                      </div>
                    )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default ReviewList;

import { UI_COLORS, STATUS_GREEN, STATUS_AMBER, STATUS_RED, SLATE_BLUE, DEEP_NAVY } from '../../../../utils/colorPalette';

// CSC Rating Scale (Civil Service Commission MC 6-2012)
export const CSC_RATING_SCALE = [
  { value: 5, label: 'Outstanding', description: 'Performance represents an extraordinary level of achievement' },
  { value: 4, label: 'Very Satisfactory', description: 'Performance exceeded expectations' },
  { value: 3, label: 'Satisfactory', description: 'Performance met expectations' },
  { value: 2, label: 'Unsatisfactory', description: 'Performance failed to meet expectations' },
  { value: 1, label: 'Poor', description: 'Performance was consistently below expectations' }
];

// Review Status Options
export const REVIEW_STATUSES = {
  DRAFT: 'Draft',
  SELF_RATED: 'Self-Rated',
  SUBMITTED: 'Submitted',
  ACKNOWLEDGED: 'Acknowledged',
  APPROVED: 'Approved',
  FINALIZED: 'Finalized'
};

// Status color configurations for badges
export const STATUS_COLORS: Record<string, string> = {
  Draft: 'bg-yellow-100 text-yellow-800 border-yellow-200',
  'Self-Rated': 'bg-purple-100 text-purple-800 border-purple-200',
  Submitted: 'bg-blue-100 text-blue-800 border-blue-200',
  Acknowledged: 'bg-green-100 text-green-800 border-green-200',
  Approved: 'bg-emerald-100 text-emerald-700 border-emerald-200',
  Finalized: 'bg-green-100 text-green-800 border-green-200',
  default: 'bg-gray-100 text-gray-600 border-gray-200'
};

// Get status color helper
export const getStatusColor = (status: string) => {
  return STATUS_COLORS[status] || STATUS_COLORS.default;
};

// Get adjectival rating from numerical score
export const getAdjectivalRating = (score: number | string) => {
  const numScore = typeof score === 'string' ? parseFloat(score) : score;
  if (numScore >= 4.5) return { rating: 'Outstanding', color: 'text-green-600' };
  if (numScore >= 3.5) return { rating: 'Very Satisfactory', color: 'text-blue-600' };
  if (numScore >= 2.5) return { rating: 'Satisfactory', color: 'text-gray-600' };
  if (numScore >= 1.5) return { rating: 'Unsatisfactory', color: 'text-orange-600' };
  return { rating: 'Poor', color: 'text-red-600' };
};

// Initial form state for reviews
export const INITIAL_REVIEW_FORM = {
  employeeId: '',
  reviewCycleId: 0,
  reviewerId: 0,
  status: 'Draft',
  items: [],
  strengths: '',
  improvements: '',
  goals: '',
  trainingRecommendations: '',
  actionPlan: '',
  additionalComments: ''
};

// Tab configurations
export const REVIEW_TABS = [
  { id: 'pending', label: 'Pending', filter: ['Draft', 'Self-Rated', 'Submitted'] },
  { id: 'completed', label: 'Completed', filter: ['Acknowledged', 'Approved', 'Finalized'] }
];

// Score color helper for criteria items
export const getScoreColor = (score: number | string) => {
  const numScore = typeof score === 'string' ? parseInt(score) : score;
  if (numScore >= 4) return 'bg-green-100 text-green-700 border-green-200';
  if (numScore >= 3) return 'bg-blue-100 text-blue-700 border-blue-200';
  return 'bg-red-100 text-red-700 border-red-200';
};

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, CheckCircle, AlertCircle, Clock, ThumbsDown, AlertTriangle, TrendingDown, Info } from 'lucide-react';
import { getAdjectivalRating, getScoreColor } from '../constants/performanceConstants';
import { formatDuration } from '@/utils/formatters';

import { PerformanceItem, PerformanceReview } from '../types';

interface ReviewDetailsModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedReview: PerformanceReview | null;
  onAcknowledge: () => void;
  onOpenDisagree: () => void;
}

const ReviewDetailsModal: React.FC<ReviewDetailsModalProps> = ({
  isOpen,
  onClose,
  selectedReview,
  onAcknowledge,
  onOpenDisagree
}) => {
  if (!isOpen || !selectedReview) return null;

  const selfRatingInfo = (selectedReview.selfRatingScore !== null && selectedReview.selfRatingScore !== undefined)
    ? getAdjectivalRating(Number(selectedReview.selfRatingScore)) 
    : null;
  const reviewerRatingInfo = (selectedReview.totalScore !== null && selectedReview.totalScore !== undefined)
    ? getAdjectivalRating(Number(selectedReview.totalScore)) 
    : null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 transition-all">
        <motion.div 
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          exit={{ opacity: 0, scale: 0.95 }}
          className="bg-white rounded-xl w-full max-w-md max-h-[90vh] overflow-hidden shadow-2xl flex flex-col border border-gray-100"
        >
          {/* Header */}
          <div className="flex items-center justify-between px-6 py-4 shrink-0 bg-white border-b border-gray-100">
            <h2 className="text-xl font-bold text-gray-900">Evaluation Details</h2>
            <button 
              onClick={onClose} 
              className="text-gray-400 hover:text-gray-600 transition-colors p-1 rounded-full hover:bg-gray-100"
            >
