import { useState, useCallback } from 'react';
import { recruitmentApi } from '@/api/recruitmentApi';
import axios from 'axios';
import { JobFormData } from '@/types';

const useJobActions = (
  loadJobs: () => void, 
  showNotification: (message: string, type: 'success' | 'error' | 'info') => void
) => {
  const [saving, setSaving] = useState(false);
  const [pendingJobId, setPendingJobId] = useState<number | null>(null);

  const handleSaveJob = async (
    isEditing: boolean, 
    selectedJobId: number | null, 
    formData: JobFormData, 
    onSuccess: () => void
  ) => {
    setSaving(true);
    try {
      if (isEditing && selectedJobId) {
        await recruitmentApi.updateJob(selectedJobId, formData);
      } else {
        await recruitmentApi.createJob(formData);
      }
      onSuccess();
      loadJobs();
    } catch (err: unknown) { // Changed from 'any' to 'unknown'
      console.error('Failed to save job:', err);
      let errorMessage = 'Failed to save job posting';
      if (axios.isAxiosError(err)) {
        errorMessage = err.response?.data?.message || errorMessage;
      }
      showNotification(errorMessage, 'error');
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteJob = async (jobId: number, onSuccess: () => void) => {
    setSaving(true);
    try {
      await recruitmentApi.deleteJob(jobId);
      onSuccess();
      loadJobs();
    } catch (err) {
      console.error('Failed to delete job:', err);
      showNotification('Failed to delete job posting', 'error');
    } finally {
      setSaving(false);
    }
  };

  return {
    saving,
    handleSaveJob,
    handleDeleteJob
  };
};

export default useJobActions;

import { useState, useCallback } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { recruitmentApi } from '@/api/recruitmentApi';
import { Job } from '@/types';

const useJobData = (showNotification?: (message: string, type: 'success' | 'error' | 'info') => void) => {
  const queryClient = useQueryClient();

  const { data: jobs = [], isLoading: loading, error: queryError, refetch } = useQuery({
    queryKey: ['jobs'],
    queryFn: async () => {
      const response = await recruitmentApi.getJobs({});
      if (response.data.success) {
        return response.data.jobs;
      }
      throw new Error(response.data.message || 'Failed to load jobs');
    },
    // Initial data or placeholder could be set here if needed
  });

  const error = queryError instanceof Error ? queryError.message : (queryError ? String(queryError) : null);

  const loadJobs = useCallback(() => {
    refetch();
  }, [refetch]);

  const checkEmailsMutation = useMutation({
    mutationFn: recruitmentApi.checkEmails,
    onSuccess: (response) => {
       const { data } = response;
       if (data.processed > 0) {
         showNotification?.(`Found ${data.processed} new application(s) from email`, 'success');
         // Invalidate/refetch jobs if email check adds new jobs/applicants? 
         // Assuming it might, good practice to invalidate.
         queryClient.invalidateQueries({ queryKey: ['jobs'] });
       } else {
         showNotification?.('No new email applications found', 'info');
       }
    },
    onError: (err) => {
       console.error('Email check failed:', err);
       showNotification?.('Failed to check emails. Make sure IMAP is configured.', 'error');
    }
  });

  const handleCheckEmails = useCallback(() => {
     checkEmailsMutation.mutate();
  }, [checkEmailsMutation]);

  return {
    jobs,
    loading,
    error,
    checkingEmails: checkEmailsMutation.isPending,
    loadJobs,
    handleCheckEmails
  };
};

export default useJobData;

import { useState, useCallback } from 'react';
import { Job, JobFormData, EmploymentType } from '@/types';

const INITIAL_FORM_DATA: JobFormData = {
  title: '',
  department: '',
  location: 'Main Office',
  employmentType: 'Full-time' as EmploymentType,
  dutyType: 'Standard',
  salaryRange: '',
  applicationEmail: '',
  jobDescription: '',
  requirements: '',
  status: 'Open',
  officeName: '',
  submissionAddress: '',
  education: '',
  experience: '',
  training: '',
  eligibility: '',
  otherQualifications: '',
  requireCivilService: false,
  requireGovernmentIds: false,
  requireEducationExperience: false
};

const useJobForm = () => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState<JobFormData>(INITIAL_FORM_DATA);

  const resetForm = useCallback(() => {
    setFormData(INITIAL_FORM_DATA);
  }, []);

  const openCreateForm = useCallback(() => {
    setIsEditing(false);
    resetForm();
    setIsFormOpen(true);
  }, [resetForm]);

  const openEditForm = useCallback((job: Job) => {
    setIsEditing(true);
    setFormData({
      title: job.title,
      department: job.department,
      location: job.location,
      employmentType: job.employmentType,
      dutyType: (job.dutyType as any) || 'Standard',
      salaryRange: job.salaryRange || '',
      applicationEmail: job.applicationEmail || '',
      jobDescription: job.jobDescription,
      requirements: job.requirements,
      status: job.status,
      officeName: job.officeName || '',
      submissionAddress: job.submissionAddress || '',
      education: job.education || '',
      experience: job.experience || '',
      training: job.training || '',
      eligibility: job.eligibility || '',
      otherQualifications: job.otherQualifications || '',
      requireCivilService: job.requireCivilService || false,
      requireGovernmentIds: job.requireGovernmentIds || false,
      requireEducationExperience: job.requireEducationExperience || false
    });
    setIsFormOpen(true);
  }, []);

  const handleFormChange = useCallback((field: keyof JobFormData, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  return {
    isFormOpen,
    setIsFormOpen,
    isEditing,
    formData,
    handleFormChange,
    openCreateForm,
    openEditForm,
    resetForm
  };
};

