import { useState, useMemo, useCallback, useEffect, useRef } from "react";
import { useUIStore } from '@/stores';
import { attendanceApi } from "@api/attendanceApi";
import { dtrApi } from "@api/dtrApi";
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { 
  filterDTRData, 
  calculatePagination, 
  getUniqueDepartments, 
  getUniqueEmployees, 
  exportToCSV, 
  exportToPDF, 
  getStatusBadge as getStatusBadgeUtil,
  DTRRecord,
  DTRFilters,
  PaginationResult,
  AdminDTRApiResponse,
  DTRRecordUpdate
} from "../Utils/adminDTRUtils";
import { ITEMS_PER_PAGE, MESSAGES, DELAYS, EXPORT_HEADERS, STATUS_STYLES } from "../Constants/adminDTR.constant";

export const useAdminDTR = () => {
  const today = useMemo(() => new Date().toLocaleDateString("en-US"), []);
  const sidebarOpen = useUIStore((state) => state.sidebarOpen);
  const queryClient = useQueryClient();

  // State management
  const [filters, setFilters] = useState<DTRFilters>({  
    department: "", 
    employee: "", 
    fromDate: "", 
    toDate: "", 
  });

  const [searchQuery, setSearchQuery] = useState("");
  const [debouncedSearchQuery, setDebouncedSearchQuery] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [loadingType, setLoadingType] = useState<string>(""); // Used for export loading
  const [errorLocal, setErrorLocal] = useState<string | null>(null); // For non-query errors (exports)
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [editingRecord, setEditingRecord] = useState<DTRRecord | null>(null);

  const searchTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // React Query: Fetch Data
  const { data: dtrData = [], isLoading, error: queryError, refetch } = useQuery({
    queryKey: ['admin-dtr-logs'],
    queryFn: async () => {
        const response = await attendanceApi.getLogs({});
        const data = response.data.data || [];
        
        return data.map((item: AdminDTRApiResponse): DTRRecord => {
            let hoursWorked = '0';
            if (item.timeIn && item.timeOut) {
              const start = new Date(String(item.timeIn)).getTime();
              const end = new Date(String(item.timeOut)).getTime();
              hoursWorked = ((end - start) / (1000 * 60 * 60)).toFixed(2);
            }
            
            let formattedDate = String(item.date ?? '');
            if (item.date) {
              const dateObj = new Date(String(item.date));
              formattedDate = dateObj.toLocaleDateString('en-US', { 
                month: 'short', 
                day: 'numeric', 
                year: 'numeric' 
              });
            }
            
            return {
              id: item.id ?? item.recordId ?? '',
              employeeId: item.employeeId ?? '',
              name: item.employeeName ? String(item.employeeName) : `${item.firstName ?? ''} ${item.lastName ?? ''}`.trim(),
              department: item.department ? String(item.department) : 'N/A',
              date: formattedDate,
              timeIn: item.timeIn ? new Date(String(item.timeIn)).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : '--:--',
              timeOut: item.timeOut ? new Date(String(item.timeOut)).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : '--:--',
              hoursWorked: hoursWorked,
              status: item.status ? String(item.status) : 'Absent',
              remarks: '-'
            };
        });
    },
    initialData: [],
  });

  const error = queryError ? (queryError as Error).message : errorLocal;

  // React Query: Mutation
  const updateRecordMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string | number, data: DTRRecordUpdate }) => {
        await dtrApi.updateRecord(String(id), data);
    },
    onSuccess: () => {
        setSuccessMessage("Record updated successfully");
        queryClient.invalidateQueries({ queryKey: ['admin-dtr-logs'] });
        setEditingRecord(null);
    },
    onError: (err: unknown) => {
        console.error("Failed to update record", err);
        setErrorLocal("Failed to update record");
    }
  });

  // Derived data
  const uniqueDepartments = useMemo(() => getUniqueDepartments(dtrData), [dtrData]);
  const uniqueEmployees = useMemo(() => getUniqueEmployees(dtrData), [dtrData]);
  
  const filteredData = useMemo(
    () => filterDTRData(dtrData, filters, debouncedSearchQuery),
    [filters, debouncedSearchQuery, dtrData]
  );

  const paginationData: PaginationResult = useMemo(
    () => calculatePagination(filteredData, currentPage, ITEMS_PER_PAGE),
    [filteredData, currentPage]
  );

  // Event handlers
  const handleFilterChange = useCallback((field: keyof DTRFilters, value: string) => {
    setFilters((prev) => ({ ...prev, [field]: value }));
  }, []);

  const handleApply = useCallback(() => {
    setSuccessMessage(MESSAGES.FILTERS_APPLIED);
  }, []);

  const handleClear = useCallback(() => {
    setFilters({ department: "", employee: "", fromDate: "", toDate: "" });
    setSearchQuery("");
    setSuccessMessage(MESSAGES.FILTERS_CLEARED);
  }, []);

  const handleSearchChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchQuery(e.target.value);
  }, []);

  const handleRefresh = useCallback(async () => {
    await refetch();
    setSuccessMessage(MESSAGES.DATA_REFRESHED);
  }, [refetch]);

  const handlePrevPage = useCallback(() => {
    setCurrentPage((prev) => Math.max(prev - 1, 1));
  }, []);

  const handleNextPage = useCallback(() => {
    setCurrentPage((prev) => Math.min(prev + 1, paginationData.totalPages));
  }, [paginationData.totalPages]);

  // Export handlers
  const handleExportCSV = useCallback(async () => {
    if (filteredData.length === 0) {
      setErrorLocal(MESSAGES.ERROR_NO_DATA);
      return;
    }
    setLoadingType("CSV");
    setErrorLocal(null);
    try {
      await new Promise(resolve => setTimeout(resolve, DELAYS.EXPORT_DELAY));
      const filename = `dtr_${today.replace(/\//g, '-')}.csv`;
      await exportToCSV(filteredData, EXPORT_HEADERS, filename);
      setSuccessMessage(MESSAGES.CSV_EXPORTED);
    } catch (err: unknown) {
      console.error('Export to CSV failed:', err);
      setErrorLocal(`${MESSAGES.ERROR_EXPORT_CSV}: ${err instanceof Error ? err.message : 'Unknown error. Please try again.'}`);
    } finally {
      setLoadingType("");
    }
  }, [filteredData, today]);

  const handleExportPDF = useCallback(async () => {
    if (filteredData.length === 0) {
      setErrorLocal(MESSAGES.ERROR_NO_DATA);
      return;
    }
    setLoadingType("PDF");
    setErrorLocal(null);
    try {
      await new Promise(resolve => setTimeout(resolve, DELAYS.EXPORT_DELAY));
      await exportToPDF(filteredData, EXPORT_HEADERS, today, DELAYS.PDF_PRINT_DELAY);
      setSuccessMessage(MESSAGES.PDF_EXPORTED);
    } catch (err: unknown) {
      console.error('Export to PDF failed:', err);
      setErrorLocal(`${MESSAGES.ERROR_EXPORT_PDF}: ${err instanceof Error ? err.message : 'Unknown error. Please try again.'}`);
    } finally {
      setLoadingType("");
    }
  }, [filteredData, today]);

  const getStatusBadge = useCallback((status: string) => {
    return getStatusBadgeUtil(status, STATUS_STYLES);
  }, []);

  const handleEdit = useCallback((record: DTRRecord) => {
    setEditingRecord(record);
  }, []);

  const handleSaveEdit = useCallback(async (id: string | number, data: DTRRecordUpdate) => {
     updateRecordMutation.mutate({ id, data });
  }, [updateRecordMutation]);

  // Effects
  useEffect(() => {
    if (searchTimeoutRef.current) {
      clearTimeout(searchTimeoutRef.current);
    }
    searchTimeoutRef.current = setTimeout(() => {
      setDebouncedSearchQuery(searchQuery);
    }, DELAYS.SEARCH_DEBOUNCE);

    return () => {
      if (searchTimeoutRef.current) {
        clearTimeout(searchTimeoutRef.current);
      }
    };
  }, [searchQuery]);

  useEffect(() => {
    if (error || errorLocal) {
      const timer = setTimeout(() => setErrorLocal(null), DELAYS.ERROR_DISMISS);
      return () => clearTimeout(timer);
    }
  }, [error, errorLocal]);

  useEffect(() => {
    if (successMessage) {
      const timer = setTimeout(() => setSuccessMessage(null), DELAYS.SUCCESS_DISMISS);
      return () => clearTimeout(timer);
    }
  }, [successMessage]);

  useEffect(() => {
    setCurrentPage(1);
  }, [filters, debouncedSearchQuery]);

  return {
    // Data
    today,
    sidebarOpen,
    filters,
    searchQuery,
    debouncedSearchQuery,
    currentPage,
    isLoading: isLoading || loadingType !== "",
    loadingType: isLoading ? "data" : loadingType,
    error,
    successMessage,
    dtrData,
    filteredData,
    paginationData,
    uniqueDepartments,
    uniqueEmployees,
    editingRecord,
    
    // Setters
    setError: setErrorLocal,
    setSuccessMessage,
    setEditingRecord,
    
    // Handlers
    handleFilterChange,
    handleApply,
    handleClear,
    handleSearchChange,
    handleRefresh,
    handlePrevPage,
    handleNextPage,
    handleExportCSV,
    handleExportPDF,
    getStatusBadge,
    handleEdit,
    handleSaveEdit
  };
};

/**
 * Map API response data to component format
 */
// ExcelJS import removed

export interface DTRRecord {
  id: string | number;
  employeeId: string | number;
  name: string;
  department: string;
  date: string;
  rawDate?: string; // For filtering
  timeIn: string;
  timeOut: string;
  hoursWorked: string | number;
  status: string;
  remarks: string;
  createdAt?: string;
}

export interface DTRFilters {
  department?: string;
  employeeId?: string; // Filter by ID
  employee?: string; // Legacy name filter
  fromDate?: string;
  toDate?: string;
}

export interface PaginationResult {
  totalPages: number;
  startIndex: number;
  endIndex: number;
  currentItems: DTRRecord[];
  totalRecords: number;
}

export interface AdminDTRApiResponse {
  id?: string | number;
  recordId?: string | number;
  employeeId?: string | number;
  employeeName?: string;
  firstName?: string;
  lastName?: string;
  department?: string;
  date?: string;
  timeIn?: string | null;
  timeOut?: string | null;
  hoursWorked?: string | number;
  status?: string;
  remarks?: string;
  createdAt?: string | null;
}

export interface DTRRecordUpdate {
  status: string;
  lateMinutes: number;
  undertimeMinutes: number;
  timeIn?: string | null;
  timeOut?: string | null;
}

export const mapDTRData = (apiData: AdminDTRApiResponse[]): DTRRecord[] => {
  return apiData.map(item => ({
    id: item.id ?? item.recordId ?? '',
    employeeId: item.employeeId ?? '',
    name: item.employeeName || `${item.firstName ?? ''} ${item.lastName ?? ''}`.trim() || 'N/A',
    department: item.department || 'N/A',
    date: item.date ?? '',
    rawDate: item.date ?? '',
    timeIn: item.timeIn || 'N/A',
    timeOut: item.timeOut || 'N/A',
    hoursWorked: item.hoursWorked ?? '0',
    status: item.status || 'Unknown',
    remarks: item.remarks || '-',
    createdAt: item.createdAt ?? undefined
  }));
};

/**
 * Filter DTR data based on filters and search query
 */
export const filterDTRData = (data: DTRRecord[], filters: DTRFilters, searchQuery: string): DTRRecord[] => {
  let filteredData = [...data];

  // Apply department filter
  if (filters.department) {
    filteredData = filteredData.filter((item) => item.department === filters.department);
  }

  // Apply employee filter
  if (filters.employeeId) {
    filteredData = filteredData.filter((item) => String(item.employeeId) === filters.employeeId);
  }
  
  // Legacy support
  if (filters.employee) {
    filteredData = filteredData.filter((item) => item.name === filters.employee);
  }

  // Apply date range filters
  if (filters.fromDate) {
    filteredData = filteredData.filter((item) => (item.rawDate || item.date) >= filters.fromDate!);
  }

  if (filters.toDate) {
    filteredData = filteredData.filter((item) => (item.rawDate || item.date) <= filters.toDate!);
  }

  // Apply search query
  const query = searchQuery.toLowerCase();
  if (query) {
    filteredData = filteredData.filter((item) =>
      (item.name ?? "").toLowerCase().includes(query) ||
      (String(item.id) ?? "").toLowerCase().includes(query) ||
      (item.department ?? "").toLowerCase().includes(query) ||
      (item.status ?? "").toLowerCase().includes(query)
    );
  }

  return filteredData;
};

/**
 * Calculate pagination data
 */
export const calculatePagination = (data: DTRRecord[], currentPage: number, itemsPerPage: number): PaginationResult => {
  const totalPages = Math.ceil(data.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentItems = data.slice(startIndex, endIndex);
  
  return { totalPages, startIndex, endIndex, currentItems, totalRecords: data.length };
};

/**
 * Get unique departments from data
 */
export const getUniqueDepartments = (data: DTRRecord[]): string[] => {
  return [...new Set(data.map(item => item.department))].sort();
};

/**
 * Get unique employees from data
 */
export const getUniqueEmployees = (data: DTRRecord[]): { id: string; name: string }[] => {
  const uniqueEmps = new Map<string, string>();
  data.forEach(item => {
    if (item.employeeId && item.name) {
      uniqueEmps.set(String(item.employeeId), item.name);
    }
  });
  
  return Array.from(uniqueEmps.entries()).map(([id, name]) => ({ id, name })).sort((a, b) => a.name.localeCompare(b.name));
};

