interface AttendanceExportProps {
  data: AttendanceRecord[];
  title: string;
  dateRange?: { startDate: string; endDate: string };
  filters?: AttendanceQueryValues;
}

/**
 * Format date for display
 */
const formatDate = (dateStr: string): string => {
  if (!dateStr || dateStr === '-') return '-';
  try {
    const date = new Date(dateStr);
    if (isNaN(date.getTime())) return dateStr;
    return date.toLocaleDateString('en-PH', { year: 'numeric', month: 'short', day: 'numeric' });
  } catch {
    return dateStr || '-';
  }
};

/**
 * Format time for display
 */
const formatTime = (timeStr: string): string => {
  if (!timeStr || timeStr === '-' || timeStr === '' || timeStr === 'null') return '-';
  try {
    const date = new Date(timeStr);
    if (!isNaN(date.getTime())) {
      return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
    }
    const parts = timeStr.split(':');
    if (parts.length >= 2) {
      const hours = parseInt(parts[0], 10);
      const minutes = parts[1];
      const ampm = hours >= 12 ? 'PM' : 'AM';
      const displayHours = hours % 12 || 12;
      return `${displayHours}:${minutes} ${ampm}`;
    }
    return timeStr;
  } catch {
    return timeStr || '-';
  }
};

/**
 * Get employee name from record
 */
const getEmployeeName = (record: AttendanceRecord): string => {
  if (record.name) return record.name;
  if ('employeeName' in record && typeof record.employeeName === 'string') return record.employeeName;
  return `Employee #${record.employeeId}`;
};

/**
 * Format minutes to readable format  
 */
const formatMinutes = (value: string | number): string => {
  const mins = typeof value === 'string' ? parseInt(value, 10) : Number(value || 0);
  if (isNaN(mins) || mins <= 0) return '0';
  
  const hours = Math.floor(mins / 60);
  const remainingMinutes = mins % 60;
  
  if (hours > 0) {
    return `${hours}h${remainingMinutes > 0 ? ` ${remainingMinutes}m` : ''}`;
  }
  return `${remainingMinutes}m`;
};

/**
 * Get a short leave type abbreviation for display
 */
const getLeaveAbbreviation = (leaveType: string): string => {
  const map: Record<string, string> = {
    'Vacation Leave': 'VL',
    'Sick Leave': 'SL',
    'Special Privilege Leave': 'SPL',
    'Forced Leave': 'FL',
    'Maternity Leave': 'ML',
    'Paternity Leave': 'PL',
    'Solo Parent Leave': 'SOLO',
    'Study Leave': 'STL',
    'Special Emergency Leave': 'SEL',
    'VAWC Leave': 'VAWC',
    'Rehabilitation Leave': 'RL',
    'Special Leave Benefits for Women': 'SLBW',
    'Wellness Leave': 'WL',
    'Adoption Leave': 'AL',
  };
  return map[leaveType] || 'LV';
};

const AttendanceExport: React.FC<AttendanceExportProps> = ({ data, title, dateRange, filters }) => {
  const showToast = useToastStore((state) => state.showToast);
  const showNotification = (message: string, type: 'success' | 'error') => showToast(message, type);
  const [isExporting, setIsExporting] = useState(false);
  const [groupByDepartment, setGroupByDepartment] = useState(false);
  
  // ═══════════════════════════════════════════════════════════════
  // Period Logic: 1-15 or 16-End of Month (Katapusan)
  // ═══════════════════════════════════════════════════════════════
  let appliedStartDate = filters?.startDate || dateRange?.startDate;
  let appliedEndDate = filters?.endDate || dateRange?.endDate;

  if (!appliedStartDate || !appliedEndDate) {
    const now = new Date();
    const year = now.getFullYear();
    const month = now.getMonth();
    const day = now.getDate();
    
    if (day <= 15) {
      // First Period: 1st to 15th
      appliedStartDate = `${year}-${String(month + 1).padStart(2, '0')}-01`;
      appliedEndDate = `${year}-${String(month + 1).padStart(2, '0')}-15`;
    } else {
      // Second Period: 16th to Katapusan (Last day of month)
      appliedStartDate = `${year}-${String(month + 1).padStart(2, '0')}-16`;
      const lastDay = new Date(year, month + 1, 0).getDate();
      appliedEndDate = `${year}-${String(month + 1).padStart(2, '0')}-${lastDay}`;
    }
  }

  const fetchAllData = async (): Promise<AttendanceRecord[]> => {
    const transformLogs = (logs: DTRApiResponse[]): AttendanceRecord[] => {
        return logs.map(l => ({
            id: l.id,
            employeeId: String(l.employeeId),
            employeeName: l.employeeName || 'Unknown',
            name: l.employeeName || 'Unknown',
            date: String(l.date),
            timeIn: l.timeIn || undefined,
            timeOut: l.timeOut || undefined,
            lateMinutes: Number(l.lateMinutes || 0),
            undertimeMinutes: Number(l.undertimeMinutes || 0),
            status: l.status || 'Present',
            department: l.department || 'N/A',
            duties: l.duties
        }));
    };

    try {
      const selectedDept = filters?.department && filters?.department !== 'All Departments' && filters?.department !== 'all' ? filters.department : undefined;

      // 1. Fetch data in parallel
      const [logsResponse, employeesResponse, leavesResponse] = await Promise.all([
        attendanceApi.getLogs({
          ...filters,
          startDate: appliedStartDate,
          endDate: appliedEndDate,
          page: 1,
          limit: 100000 
        }),
        employeeApi.fetchEmployees({ department: selectedDept } as { department?: string | null }),
        leaveApi.getAllApplications({
          status: 'Approved',
          startDate: appliedStartDate,
          endDate: appliedEndDate,
          limit: 100000,
          page: 1,
        }).catch(() => ({ data: { applications: [] } }))
      ]);

      const rawLogs = logsResponse.data.success && Array.isArray(logsResponse.data.data) ? logsResponse.data.data : [];
      const employees = employeesResponse.success && Array.isArray(employeesResponse.employees) ? employeesResponse.employees : [];
      
      // Leave Lookup: key: "YYYY-MM-DD_empId" → leaveType
      const leaveMap = new Map<string, string>(); 
      const approvedLeavesResponse = leavesResponse.data as { applications?: LeaveApplication[] };
      const approvedLeaves = approvedLeavesResponse.applications || [];
      
      approvedLeaves.forEach((leave: LeaveApplication) => {
        if (leave.status !== 'Approved') return;
        const empId = String(leave.employeeId);

        // Timezone-safe date range generation for leaves
        const start = parseDateStr(leave.startDate);
        const end = parseDateStr(leave.endDate);

        const d = new Date(start);
        while (d <= end) {
          const dateStr = d.toISOString().split('T')[0];
          leaveMap.set(`${dateStr}_${empId}`, leave.leaveType);
          d.setUTCDate(d.getUTCDate() + 1);
        }
      });


      const empLookup = new Map<string, Employee>();
      employees.forEach((emp: Employee) => {
          const empId = String(emp.employeeId || emp.id);
          empLookup.set(empId, emp);
      });

      const logMap = new Map<string, AttendanceRecord>();
      rawLogs.forEach((log: DTRApiResponse) => {
          const logDateVal = log.date ? (String(log.date).includes('T') ? log.date.split('T')[0] : log.date) : '';
          const empId = String(log.employeeId || '');
          if (!empId || !logDateVal) return;
          
          const key = `${logDateVal}_${empId}`;
          const emp = empLookup.get(empId);
          const fullName = emp ? `${emp.firstName || ''} ${emp.lastName || ''}`.trim() : (log.employeeName || `Employee ${empId}`);
          
          logMap.set(key, {
            id: log.id,
            employeeId: empId,
            name: fullName,
            date: String(logDateVal),
            timeIn: log.timeIn || undefined,
            timeOut: log.timeOut || undefined,
            lateMinutes: Number(log.lateMinutes ?? 0),
            undertimeMinutes: Number(log.undertimeMinutes ?? 0),
            status: log.status || 'Present',
            department: log.department || emp?.department || selectedDept || 'N/A',
            duties: log.duties
          });
      });

      // 3. Generate Date Array (UTC safe)
      const parseDateStr = (str: string) => {
          const parts = str.split(/[-/]/).map(Number);
          if (parts[0] > 1000) return new Date(Date.UTC(parts[0], parts[1] - 1, parts[2])); 
          if (parts[2] > 1000) return new Date(Date.UTC(parts[2], parts[0] - 1, parts[1]));
          return new Date(str);
      };

      const dateArray: string[] = [];
      try {
          const current = parseDateStr(appliedStartDate!);
          const end = parseDateStr(appliedEndDate!);
          while (current <= end) {
            dateArray.push(current.toISOString().split('T')[0]);
            current.setUTCDate(current.getUTCDate() + 1);
          }
      } catch (e) {
          console.error("Date parsing failed", e);
          return transformLogs(rawLogs);
      }

      // 4. Build Final Data
      const fullRecords: AttendanceRecord[] = [];
      let targetEmployeesList: { employeeId: string, name: string, department: string }[] = [];
      
      if (employees.length > 0) {
          targetEmployeesList = employees.map(e => ({
              employeeId: String(e.employeeId || e.id),
              name: `${e.firstName || ''} ${e.lastName || ''}`.trim(),
              department: e.department || selectedDept || 'N/A'
          }));
      } else {
          const uniqueIds = Array.from(new Set(rawLogs.map(l => String(l.employeeId))));
          targetEmployeesList = uniqueIds.map(id => {
              const log = rawLogs.find(l => String(l.employeeId) === id);
              return {
                  employeeId: id,
                  name: log?.employeeName || `Employee ${id}`,
                  department: log?.department || selectedDept || 'N/A'
              };
          });
      }

      if (targetEmployeesList.length === 0 && rawLogs.length > 0) {
          return rawLogs.map(l => ({
              id: l.id,
              employeeId: String(l.employeeId),
              name: l.employeeName || 'Unknown',
              date: String(l.date),
              timeIn: l.timeIn || undefined,
              timeOut: l.timeOut || undefined,
              lateMinutes: Number(l.lateMinutes || 0),
              undertimeMinutes: Number(l.undertimeMinutes || 0),
              status: l.status || 'Present',
              department: l.department || 'N/A',
              duties: l.duties
          }));
      }

      const manilaToday = new Date().toLocaleString("en-US", {timeZone: "Asia/Manila"});
      const todayStr = new Date(manilaToday).toISOString().split('T')[0];

      dateArray.forEach(dateStr => {
          targetEmployeesList.forEach(emp => {
              const empId = emp.employeeId;
              const key = `${dateStr}_${empId}`;
              const existingLog = logMap.get(key);
              const leaveType = leaveMap.get(key);
              const isFuture = dateStr > todayStr;

              if (existingLog) {
                  const hasTimes = existingLog.timeIn && existingLog.timeIn !== '-' && existingLog.timeIn !== 'null';
                  let finalStatus = existingLog.status;
                  if (!hasTimes && (finalStatus === 'Present' || !finalStatus) && !leaveType) finalStatus = 'Absent';
                  if (leaveType) finalStatus = `On Leave (${getLeaveAbbreviation(leaveType)})`;

                  fullRecords.push({
                    ...existingLog,
                    name: emp.name,
                    status: finalStatus,
                    department: emp.department
                  });
              } else if (leaveType) {
                  fullRecords.push({
                      id: `leave-${dateStr}-${empId}`,
                      employeeId: empId,
                      name: emp.name,
                      date: dateStr,
                      timeIn: '-',
                      timeOut: '-',
                      status: `On Leave (${getLeaveAbbreviation(leaveType)})`,
                      lateMinutes: 0,
                      undertimeMinutes: 0,
                      department: emp.department
                  });
              } else if (!isFuture) {
                  fullRecords.push({
                      id: `absent-${dateStr}-${empId}`,
                      employeeId: empId,
                      name: emp.name,
                      date: dateStr,
                      timeIn: '-',
                      timeOut: '-',
                      status: 'Absent',
                      lateMinutes: 0,
                      undertimeMinutes: 0,
                      department: emp.department
                  });
              }
          });
      });

      return fullRecords;
    } catch (error) {
      console.error("Error fetching export data:", error);
      return data; 
    }
  };

  const handleExportExcel = async () => {
    setIsExporting(true);
    try {
      const exportData = await fetchAllData();
      if (exportData.length === 0) {
        showNotification("No data to export", "error");
        return;
      }
      await exportAttendanceToExcel(exportData, {
        title,
        dateRange: { startDate: appliedStartDate || '', endDate: appliedEndDate || '' },
        groupByDepartment
      });
      showNotification("Excel report exported successfully!", "success");
    } catch (error) {
      console.error('Export error:', error);
      showNotification("Failed to export Excel report", "error");
    } finally {
      setIsExporting(false);
    }
  };

  const handleExportPDF = async () => {
    setIsExporting(true);
    try {
      const exportData = await fetchAllData();
      if (exportData.length === 0) {
        showNotification("No data to export", "error");
        return;
      }

      const doc = new jsPDF('landscape');
      doc.setFontSize(16);
      doc.setTextColor(30, 58, 95);
      doc.text(title, 14, 15);
      
      doc.setFontSize(10);
      doc.setTextColor(100, 100, 100);
      doc.text(`Period: ${formatDate(appliedStartDate || '') || '-'} to ${formatDate(appliedEndDate || '') || '-'}`, 14, 22);
      doc.text(`Total Records: ${exportData.length}`, 14, 28);

      const tableData = exportData.map(record => {
        const hasTimes = record.timeIn && record.timeIn !== '-' && record.timeIn !== 'null';
        const isOnLeave = (record.status || '').startsWith('On Leave');
        const isAbsent = record.status === 'Absent' || (!isOnLeave && !hasTimes);
        const isLate = Number(record.lateMinutes) > 0;
        const isUndertime = Number(record.undertimeMinutes) > 0;
        const isPresent = !isAbsent && !isOnLeave && hasTimes;
        
        return [
          record.employeeId || '',
          getEmployeeName(record),
          record.department || 'N/A',
          formatDate(record.date),
          formatTime(record.timeIn || ''),
          formatTime(record.timeOut || ''),
          formatMinutes(record.lateMinutes || 0),
          formatMinutes(record.undertimeMinutes || 0),
          isPresent ? 'X' : '',
          isLate ? 'X' : '',
          isUndertime ? 'X' : '',
          isAbsent ? 'X' : '',
          isOnLeave ? record.status?.replace('On Leave ', '').replace('(', '').replace(')', '') || 'LV' : ''
        ]
      });

      autoTable(doc, {
        startY: 35,
        head: [['ID', 'Employee Name', 'Dept', 'Date', 'Time In', 'Time Out', 'Late', 'UT', 'Present', 'Late', 'UT', 'Absent', 'On Leave']],
        body: tableData,
        styles: { fontSize: 5.5, halign: 'center', cellPadding: 1.5 },
        headStyles: { fillColor: [30, 58, 95], textColor: [255, 255, 255], fontStyle: 'bold' },
        alternateRowStyles: { fillColor: [245, 245, 245] },
        columnStyles: {
          0: { cellWidth: 16, halign: 'left' },
          1: { cellWidth: 28, halign: 'left' },
          2: { cellWidth: 28, halign: 'left' }
        }
      });

      doc.save(`${title.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.pdf`);
      showNotification("PDF exported successfully!", "success");
    } catch (error) {
      console.error('PDF Export error:', error);
      showNotification("Failed to export PDF", "error");
    } finally {
        setIsExporting(false);
    }
  };

  return (
    <div className="flex items-center gap-4 mb-4 flex-wrap">
      <span className="text-sm font-semibold text-gray-800">Export Report:</span>
      <label className="flex items-center gap-2 text-sm text-gray-600 cursor-pointer">
        <input
          type="checkbox"
          checked={groupByDepartment}
          onChange={(e) => setGroupByDepartment(e.target.checked)}
          className="w-4 h-4 text-green-600 rounded border-gray-300"
        />
        <span>Group by Department</span>
      </label>

      <button
        onClick={handleExportExcel}
        disabled={isExporting}
        className="flex items-center gap-1.5 text-sm font-semibold transition-colors hover:opacity-80 disabled:opacity-50"
        style={{ color: '#166534' }}
      >
        {isExporting ? <Loader2 size={16} className="animate-spin" /> : <FileSpreadsheet size={16} />}
        <span>Excel</span>
      </button>

      <button
        onClick={handleExportPDF}
        disabled={isExporting}
        className="flex items-center gap-1.5 text-sm font-semibold transition-colors hover:opacity-80 disabled:opacity-50"
        style={{ color: '#991B1B' }}
      >
        {isExporting ? <Loader2 size={16} className="animate-spin" /> : <FileText size={16} />}
        <span>PDF</span>
      </button>

      <span className="text-xs text-gray-500 ml-auto bg-gray-100 px-2 py-1 rounded">
        {filters?.startDate ? `Filtered range export` : `Default 15-day period`}
      </span>
    </div>
  );
};

export default AttendanceExport;

import ExcelJS from 'exceljs';
import { AttendanceRecord } from '@/types';

interface ExportOptions {
  title?: string;
  dateRange?: { startDate: string; endDate: string };
  groupByDepartment?: boolean;
}

/**
 * Format date string for display
 */
const formatDate = (dateStr: string): string => {
  if (!dateStr || dateStr === '-') return '-';
  try {
    const date = new Date(dateStr);
    if (isNaN(date.getTime())) return dateStr;
    return date.toLocaleDateString('en-PH', { 
      year: 'numeric', 
      month: 'short', 
      day: 'numeric' 
    });
  } catch {
    return dateStr || '-';
  }
};

/**
 * Format time string for display
 */
const formatTime = (timeStr: string): string => {
  if (!timeStr || timeStr === '-' || timeStr === '' || timeStr === 'null') return '-';
  try {
    const date = new Date(timeStr);
    if (!isNaN(date.getTime())) {
      return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
    }
    const parts = timeStr.split(':');
    if (parts.length >= 2) {
      const hours = parseInt(parts[0], 10);
      const minutes = parts[1];
      const ampm = hours >= 12 ? 'PM' : 'AM';
      const displayHours = hours % 12 || 12;
      return `${displayHours}:${minutes} ${ampm}`;
    }
    return timeStr;
  } catch {
    return timeStr || '-';
  }
};

/**
 * Get employee name from record
 */
const getEmployeeName = (record: AttendanceRecord): string => {
  if (record.name) return record.name;
  if (record.employeeName) return record.employeeName;
  return `Employee #${record.employeeId}`;
};

/**
 * Make minutes readable but retain numeric value in excel formulas if possible
 * Since this function returns a string for display in other formats, we'll
 * keep it for CSV, but in Excel we will pass raw numbers.
 */
const formatMinutes = (value: string | number): string => {
  const mins = typeof value === 'string' ? parseInt(value, 10) : Number(value || 0);
  if (isNaN(mins) || mins <= 0) return '0';
  
  const hours = Math.floor(mins / 60);
  const remainingMinutes = mins % 60;
  
  if (hours > 0) {
    return `${hours}h${remainingMinutes > 0 ? ` ${remainingMinutes}m` : ''}`;
  }
  return `${remainingMinutes}m`;
};

/**
 * Apply header styling to a row
 */
const applyHeaderStyle = (row: ExcelJS.Row): void => {
  row.eachCell((cell) => {
    cell.fill = {
      type: 'pattern',
      pattern: 'solid',
      fgColor: { argb: 'FF1E3A5F' } // Dark blue
    };
    cell.font = {
      bold: true,
      color: { argb: 'FFFFFFFF' },
      size: 11
    };
    cell.alignment = { horizontal: 'center', vertical: 'middle' };
    cell.border = {
      top: { style: 'thin', color: { argb: 'FF000000' } },
      left: { style: 'thin', color: { argb: 'FF000000' } },
      bottom: { style: 'thin', color: { argb: 'FF000000' } },
      right: { style: 'thin', color: { argb: 'FF000000' } }
    };
  });
  row.height = 22;
};

/**
 * Apply data cell styling
 */
const applyDataStyle = (row: ExcelJS.Row, isAlternate: boolean): void => {
  row.eachCell((cell) => {
    cell.fill = {
      type: 'pattern',
      pattern: 'solid',
      fgColor: { argb: isAlternate ? 'FFF5F5F5' : 'FFFFFFFF' }
    };
    cell.font = { size: 10 };
    cell.alignment = { horizontal: 'center', vertical: 'middle' };
    cell.border = {
      top: { style: 'thin', color: { argb: 'FFE0E0E0' } },
      left: { style: 'thin', color: { argb: 'FFE0E0E0' } },
      bottom: { style: 'thin', color: { argb: 'FFE0E0E0' } },
      right: { style: 'thin', color: { argb: 'FFE0E0E0' } }
    };
  });
  row.height = 20;
};

/**
 * Get status cell fill color
 */
const getStatusColor = (status: string): string => {
  const statusLower = status?.toLowerCase() || '';
  if (statusLower.includes('present')) return 'FF28A745'; // Green
  if (statusLower.includes('absent')) return 'FFDC3545'; // Red
  if (statusLower.includes('late')) return 'FFFD7E14'; // Orange
  if (statusLower.includes('leave')) return 'FF007BFF'; // Blue
  return 'FF6C757D'; // Gray
};

/**
 * Export attendance records to Excel format
 * Optimized for file size < 400KB
 */
export const exportAttendanceToExcel = async (
  data: AttendanceRecord[],
  options: ExportOptions = {}
): Promise<void> => {
  try {
    const { title = 'Attendance Report', dateRange, groupByDepartment = false } = options;

    // Create workbook with optimization settings
    const workbook = new ExcelJS.Workbook();
    workbook.creator = 'CHRMO System';
    workbook.created = new Date();

    // Create worksheet
    const worksheet = workbook.addWorksheet('Attendance Report', {
      views: [{ state: 'frozen', ySplit: 4 }] // Freeze top rows
    });

    // Set column widths (13 columns: A-M)
    worksheet.columns = [
      { header: 'Employee ID', key: 'employeeId', width: 15 },
      { header: 'Employee Name', key: 'employee', width: 25 },
      { header: 'Department', key: 'department', width: 30 },
      { header: 'Date', key: 'date', width: 14 },
      { header: 'Time In', key: 'timeIn', width: 12 },
      { header: 'Time Out', key: 'timeOut', width: 12 },
      { header: 'Late (min)', key: 'late', width: 10 },
      { header: 'Undertime (min)', key: 'undertime', width: 14 },
      { header: 'Present', key: 'present', width: 10 },
      { header: 'Late', key: 'lateStatus', width: 10 },
      { header: 'Undertime', key: 'undertimeStatus', width: 12 },
      { header: 'Absent', key: 'absent', width: 10 },
      { header: 'On Leave', key: 'onLeave', width: 14 }
    ];

    // Add title row
    worksheet.mergeCells('A1:M1');
    const titleCell = worksheet.getCell('A1');
    titleCell.value = title;
    titleCell.font = { bold: true, size: 16, color: { argb: 'FF1E3A5F' } };
    titleCell.alignment = { horizontal: 'center', vertical: 'middle' };
    worksheet.getRow(1).height = 30;

    // Add report metadata
    const dateRangeText = dateRange 
      ? `Period: ${formatDate(dateRange.startDate)} - ${formatDate(dateRange.endDate)}`
      : `Generated: ${new Date().toLocaleDateString('en-PH')}`;
    
    worksheet.mergeCells('A2:M2');
    const metaCell = worksheet.getCell('A2');
    metaCell.value = dateRangeText;
    metaCell.font = { size: 10, italic: true, color: { argb: 'FF666666' } };
    metaCell.alignment = { horizontal: 'center', vertical: 'middle' };
    worksheet.getRow(2).height = 18;

    // Add record count
    worksheet.mergeCells('A3:M3');
    const countCell = worksheet.getCell('A3');
    countCell.value = `Total Records: ${data.length}`;
    countCell.font = { size: 10, color: { argb: 'FF666666' } };
    countCell.alignment = { horizontal: 'center', vertical: 'middle' };
    worksheet.getRow(3).height = 18;

    // Add header row
    const headerRow = worksheet.addRow(['Employee ID', 'Employee Name', 'Department', 'Date', 'Time In', 'Time Out', 'Late (min)', 'Undertime (min)', 'Present', 'Late', 'Undertime', 'Absent', 'On Leave']);
    applyHeaderStyle(headerRow);

    // Group data by department if requested
    const sortedData = [...data];
    if (groupByDepartment) {
      sortedData.sort((a, b) => {
        const deptA = a.department || '';
        const deptB = b.department || '';
        return deptA.localeCompare(deptB);
      });
    }

    // Add data rows - limit to prevent file size bloat
    const MAX_ROWS = 5000; // Limit to maintain file size
    const limitedData = sortedData.slice(0, MAX_ROWS);
    
    let currentDepartment = '';
    limitedData.forEach((record, index) => {
      // Add department separator if grouping
      if (groupByDepartment) {
        const dept = record.department || 'Unassigned';
        if (dept !== currentDepartment) {
          currentDepartment = dept;
          const deptRow = worksheet.addRow([`Department: ${dept}`]);
          worksheet.mergeCells(`A${deptRow.number}:M${deptRow.number}`);
          deptRow.getCell(1).font = { bold: true, size: 11, color: { argb: 'FF1E3A5F' } };
          deptRow.getCell(1).fill = {
            type: 'pattern',
            pattern: 'solid',
            fgColor: { argb: 'FFE8EEF4' }
          };
          deptRow.height = 24;
        }
      }

      const rawLate = record.lateMinutes || 0;
      const rawUndertime = record.undertimeMinutes || 0;
      const hasTimes = record.timeIn && record.timeIn !== '-' && record.timeIn !== 'null';
      const isOnLeave = (record.status || '').startsWith('On Leave');
      const isAbsent = record.status === 'Absent' || (!isOnLeave && !hasTimes);
      const isLate = Number(rawLate) > 0;
      const isUndertime = Number(rawUndertime) > 0;
      const isPresent = !isAbsent && !isOnLeave && hasTimes;

      // Extract leave abbreviation from status like "On Leave (VL)"
      const leaveAbbr = isOnLeave ? (record.status || '').replace('On Leave ', '').replace('(', '').replace(')', '') : '';

      const row = worksheet.addRow([
        record.employeeId || '',
        getEmployeeName(record),
        record.department || 'N/A',
        formatDate(record.date),
        formatTime(record.timeIn || ''),
        formatTime(record.timeOut || ''),
        Number(formatMinutes(rawLate)),
        Number(formatMinutes(rawUndertime)),
        isPresent ? 'X' : '',
        isLate ? 'X' : '',
        isUndertime ? 'X' : '',
        isAbsent ? 'X' : '',
        leaveAbbr
      ]);
      
      applyDataStyle(row, index % 2 === 0);

      // Apply specific background colors to the X markings
      const markColorMap: Record<number, string> = {
        9: 'FF28A745', // Green (Present)
        10: 'FFFD7E14', // Orange (Late)
        11: 'FF007BFF', // Blue (Undertime)
        12: 'FFDC3545', // Red (Absent)
        13: 'FF6F42C1'  // Purple (On Leave)
      };

      for (let col = 9; col <= 13; col++) {
        const cell = row.getCell(col);
        if (cell.value && cell.value !== '') {
          cell.font = { size: 10, bold: true, color: { argb: 'FFFFFFFF' } };
          cell.fill = {
            type: 'pattern',
            pattern: 'solid',
            fgColor: { argb: markColorMap[col] }
          };
          cell.alignment = { horizontal: 'center', vertical: 'middle' };
        }
      }
    });

    // Add a final Auto-Calculation row at the very bottom
    const totalRow = worksheet.addRow([
      'TOTALS',
      '',
      '',
      '',
      '',
      '',
      { formula: `SUM(G5:G${worksheet.rowCount - 1})`, result: 0 },
      { formula: `SUM(H5:H${worksheet.rowCount - 1})`, result: 0 },
      { formula: `COUNTIF(I5:I${worksheet.rowCount - 1},"X")`, result: 0 },
      { formula: `COUNTIF(J5:J${worksheet.rowCount - 1},"X")`, result: 0 },
      { formula: `COUNTIF(K5:K${worksheet.rowCount - 1},"X")`, result: 0 },
      { formula: `COUNTIF(L5:L${worksheet.rowCount - 1},"X")`, result: 0 },
      { formula: `COUNTA(M5:M${worksheet.rowCount - 1})-COUNTBLANK(M5:M${worksheet.rowCount - 1})`, result: 0 }
    ]);
    
    // Style the Total Row
    totalRow.eachCell((cell) => {
      cell.fill = {
        type: 'pattern',
        pattern: 'solid',
        fgColor: { argb: 'FF1E3A5F' } 
      };
      cell.font = { bold: true, color: { argb: 'FFFFFFFF' }, size: 11 };
      cell.alignment = { horizontal: 'center', vertical: 'middle' };
      cell.border = {
        top: { style: 'medium', color: { argb: 'FF000000' } },
        bottom: { style: 'medium', color: { argb: 'FF000000' } },
        left: { style: 'thin', color: { argb: 'FF000000' } },
        right: { style: 'thin', color: { argb: 'FF000000' } }
      };
    });
    totalRow.getCell(1).alignment = { horizontal: 'right', vertical: 'middle' };
    worksheet.mergeCells(`A${totalRow.number}:F${totalRow.number}`);

    // Add warning if data was truncated
    if (data.length > MAX_ROWS) {
      const warnRow = worksheet.addRow([`Note: Showing ${MAX_ROWS} of ${data.length} records to optimize file size.`]);
      worksheet.mergeCells(`A${warnRow.number}:M${warnRow.number}`);
      warnRow.getCell(1).font = { italic: true, color: { argb: 'FFFF6600' } };
    }

    // Generate buffer and download
    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], { 
      type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' 
    });

    // Check file size (should be < 400KB)
    const fileSizeKB = blob.size / 1024;
    console.log(`Excel file size: ${fileSizeKB.toFixed(2)} KB`);

    // Create download link
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    const fileName = `${title.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.xlsx`;
    link.href = url;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);

  } catch (error) {
    console.error('Error exporting to Excel:', error);
    throw new Error('Failed to export attendance to Excel');
  }
};

/**
 * Export attendance records to CSV format (lightweight alternative)
 */
export const exportAttendanceToCSV = (
  data: AttendanceRecord[],
  options: ExportOptions = {}
): void => {
  try {
    const { title = 'Attendance Report' } = options;

    // CSV header
    const headers = ['Employee ID', 'Employee Name', 'Department', 'Date', 'Time In', 'Time Out', 'Late', 'Undertime', 'Present', 'Late', 'Undertime', 'Absent', 'On Leave'];
    
    // Build CSV content
    const csvContent = [
      headers.join(','),
      ...data.map(record => {
        const isOnLeave = (record.status || '').startsWith('On Leave');
        const isAbsent = record.status === 'Absent' || (!isOnLeave && (record.timeIn === '-' || record.timeIn === null));
        const isLate = Number(record.lateMinutes || 0) > 0;
        const isUndertime = Number(record.undertimeMinutes || 0) > 0;
        const isPresent = !isAbsent && !isOnLeave && !isLate && !isUndertime;
        const leaveAbbr = isOnLeave ? (record.status || '').replace('On Leave ', '').replace('(', '').replace(')', '') : '';
        
        return [
          `"${record.employeeId || ''}"`,
          `"${getEmployeeName(record)}"`,
          `"${record.department || 'N/A'}"`,
          `"${formatDate(record.date)}"`,
          `"${formatTime(record.timeIn || '')}"`,
          `"${formatTime(record.timeOut || '')}"`,
          `"${formatMinutes(record.lateMinutes || 0)}"`,
          `"${formatMinutes(record.undertimeMinutes || 0)}"`,
          `"${isPresent ? 'X' : ''}"`,
          `"${isLate ? 'X' : ''}"`,
          `"${isUndertime ? 'X' : ''}"`,
          `"${isAbsent ? 'X' : ''}"`,
          `"${leaveAbbr}"`
        ].join(',')
      })
    ].join('\n');

    // Create and download
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    const fileName = `${title.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.csv`;
    link.href = url;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);

  } catch (error) {
    console.error('Error exporting to CSV:', error);
    throw new Error('Failed to export attendance to CSV');
  }
};

import { useQuery } from '@tanstack/react-query';
import { attendanceApi } from '@/api/attendanceApi';
import { useState, useMemo, useCallback } from 'react';

import { AttendanceRecord } from '@/types/index';

import { DTRApiResponse } from '@/types/attendance';

const ITEMS_PER_PAGE = 15;

export const useAttendanceData = (isAdmin = false) => {
  const [page, setPage] = useState(1);

  const { data: rawData, isLoading, error, refetch } = useQuery({
    queryKey: ['attendance', { isAdmin }],
    queryFn: async () => {
      try {
        const response = await attendanceApi.getLogs({});
        
        if (response && response.data) {
            const resData = response.data;
            const items = Array.isArray(resData) 
              ? resData 
              : (resData.data && Array.isArray(resData.data)) 
                ? resData.data 
                : [];

            // Rely on axios interceptor for camelCase conversion
            return items.map((item: DTRApiResponse) => ({
              id: item.id,
              employeeId: item.employeeId,
              employeeName: item.employeeName,
              name: item.employeeName,
              date: item.date,
              timeIn: item.timeIn || undefined,
              timeOut: item.timeOut || undefined,
              lateMinutes: Number(item.lateMinutes ?? 0),
              undertimeMinutes: Number(item.undertimeMinutes ?? 0),
              status: item.status || 'Present',
              department: item.department,
              duties: item.duties || 'No Schedule',
            }));
        }
        return [] as AttendanceRecord[];
      } catch (err) {
        console.error('[useAttendanceData] Fetch error:', err);
        throw err;
      }
    },
    initialData: [] as AttendanceRecord[] 
  });

  const data = rawData || [];

  // Pagination
  const totalItems = data.length;
  const totalPages = Math.max(1, Math.ceil(totalItems / ITEMS_PER_PAGE));
  const safePage = Math.min(page, totalPages);

  const paginatedData = useMemo(() => {
    const start = (safePage - 1) * ITEMS_PER_PAGE;
    return data.slice(start, start + ITEMS_PER_PAGE);
  }, [data, safePage]);

  const handlePageChange = useCallback((newPage: number) => {
    setPage(Math.max(1, Math.min(newPage, totalPages)));
  }, [totalPages]);

  return { 
    data: paginatedData as AttendanceRecord[], 
    allData: data as AttendanceRecord[],
    isLoading, 
    error: error ? (error as Error).message : null, 
    refetch,
    pagination: {
      page: safePage,
      totalPages,
      totalItems,
      limit: ITEMS_PER_PAGE,
      onPageChange: handlePageChange,
    }
  };
};

