/**
 * Map API response data to component format
 */
// ExcelJS import removed

export interface DTRRecord {
  id: string | number;
  employeeId: string | number;
  name: string;
  department: string;
  date: string;
  rawDate?: string; // ISO date (YYYY-MM-DD) for accurate filtering
  timeIn: string;
  timeOut: string;
  hoursWorked: string | number;
  lateMinutes?: number;
  undertimeMinutes?: number;
  status: string;
  remarks: string;
  duties?: string;
  shift?: string;
  dutyType?: string;
  createdAt?: string;
  correctionId?: number | null;
  correctionStatus?: string | null;
  correctionReason?: string | null;
  correctionTimeIn?: string | null;
  correctionTimeOut?: string | null;
}

export interface DTRFilters {
  department?: string;
  employeeId?: string; // Filter by ID
  employee?: string; // Legacy name filter
  fromDate?: string;
  toDate?: string;
}

export interface PaginationResult {
  totalPages: number;
  startIndex: number;
  endIndex: number;
  currentItems: DTRRecord[];
  totalRecords: number;
}

export const mapDTRData = (apiData: {
  id?: string | number;
  employeeId?: string | number;
  employeeName?: string;
  firstName?: string;
  lastName?: string;
  middleName?: string | null;
  suffix?: string | null;
  department?: string;
  date: string;
  timeIn?: string;
  timeOut?: string;
  hoursWorked?: string | number;
  lateMinutes?: number;
  undertimeMinutes?: number;
  status?: string;
  remarks?: string;
  duties?: string;
  shift?: string;
  dutyType?: string;
  createdAt?: string;
  correctionId?: number | null;
  correctionStatus?: string | null;
  correctionReason?: string | null;
  correctionTimeIn?: string | null;
  correctionTimeOut?: string | null;
}[]): DTRRecord[] => {
  return apiData.map(item => ({
    id: item.id || '',
    employeeId: item.employeeId || '',
    name: item.employeeName || 'N/A',
    department: item.department || 'N/A',
    date: item.date,
    timeIn: item.timeIn || 'N/A',
    timeOut: item.timeOut || 'N/A',
    hoursWorked: item.hoursWorked || '0',
    lateMinutes: item.lateMinutes || 0,
    undertimeMinutes: item.undertimeMinutes || 0,
    status: item.status || 'Unknown',
    remarks: item.remarks || '-',
    duties: item.dutyType || item.duties || 'Standard',
    shift: item.shift || 'No Schedule',
    dutyType: item.dutyType || 'Standard',
    createdAt: item.createdAt,
    correctionId: item.correctionId,
    correctionStatus: item.correctionStatus,
    correctionReason: item.correctionReason,
    correctionTimeIn: item.correctionTimeIn,
    correctionTimeOut: item.correctionTimeOut
  }));
};

/**
 * Filter DTR data based on filters and search query
 */
export const filterDTRData = (data: DTRRecord[], filters: DTRFilters, searchQuery: string): DTRRecord[] => {
  let filteredData = [...data];

  // Apply department filter
  if (filters.department) {
    filteredData = filteredData.filter((item) => item.department === filters.department);
  }

  // Apply employee filter
  if (filters.employeeId) {
    filteredData = filteredData.filter((item) => String(item.employeeId) === filters.employeeId);
  }
  
  // Legacy support
  if (filters.employee) {
    filteredData = filteredData.filter((item) => item.name === filters.employee);
  }

  // Apply date range filters
  if (filters.fromDate) {
    filteredData = filteredData.filter((item) => item.date >= filters.fromDate!);
  }

  if (filters.toDate) {
    filteredData = filteredData.filter((item) => item.date <= filters.toDate!);
  }

  // Apply search query
  const query = searchQuery.toLowerCase();
  if (query) {
    filteredData = filteredData.filter((item) =>
      (item.name ?? "").toLowerCase().includes(query) ||
      (String(item.id) ?? "").toLowerCase().includes(query) ||
      (item.department ?? "").toLowerCase().includes(query) ||
      (item.status ?? "").toLowerCase().includes(query)
    );
  }

  return filteredData;
};

/**
 * Calculate pagination data
 */
export const calculatePagination = (data: DTRRecord[], currentPage: number, itemsPerPage: number): PaginationResult => {
  const totalPages = Math.ceil(data.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentItems = data.slice(startIndex, endIndex);
  
  return { totalPages, startIndex, endIndex, currentItems, totalRecords: data.length };
};

/**
 * Get unique departments from data
 */
export const getUniqueDepartments = (data: DTRRecord[]): string[] => {
  return [...new Set(data.map(item => item.department))].sort();
};

/**
 * Get unique employees from data
 */
export const getUniqueEmployees = (data: DTRRecord[]): { id: string; name: string }[] => {
  const uniqueEmps = new Map<string, string>();
  data.forEach(item => {
    if (item.employeeId && item.name) {
      uniqueEmps.set(String(item.employeeId), item.name);
    }
  });
  
  return Array.from(uniqueEmps.entries()).map(([id, name]) => ({ id, name })).sort((a, b) => a.name.localeCompare(b.name));
};

/**
 * Get status badge styles
 */
export const getStatusBadge = (status: string, statusStyles: Record<string, string>): string => {
  // Try exact match first
  if (statusStyles[status]) return statusStyles[status];
  
  // Try Title Case (e.g. "present" -> "Present")
  const titleCase = status.charAt(0).toUpperCase() + status.slice(1).toLowerCase();
  if (statusStyles[titleCase]) return statusStyles[titleCase];
  
  // Try all lowercase
  const lowerCase = status.toLowerCase();
  if (statusStyles[lowerCase]) return statusStyles[lowerCase];

  return 'bg-gray-100 text-gray-800';
};

import React, { useEffect } from 'react';
import { X, Clock, AlertCircle } from 'lucide-react';
import { useForm, Controller } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import Combobox from '@/components/Custom/Combobox';
import { dtrEditSchema, DtrEditSchema } from '@/schemas/dtr';
import { DTRRecord } from '../../Utils/adminDTRUtils';

export interface DTRUpdatePayload {
  timeIn: string | null;
  timeOut: string | null;
  status: string;
  lateMinutes: number;
  undertimeMinutes: number;
}

interface AdminDTREditModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (id: string | number, data: DTRUpdatePayload) => Promise<void>;
  record: DTRRecord | null;
}

export const AdminDTREditModal: React.FC<AdminDTREditModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  record 
}) => {
  const { register, handleSubmit, reset, watch, control, formState: { errors, isSubmitting } } = useForm<DtrEditSchema>({
    resolver: zodResolver(dtrEditSchema),
    defaultValues: {
      timeIn: '',
      timeOut: '',
      status: 'Present',
      late: 0,
      undertime: 0
    }
  });

  // Helper to convert formatted time (e.g. "08:00 AM") to "HH:mm" for input type="time"
  const toInputTime = (timeStr: string) => {
    if (!timeStr || timeStr === '--:--' || timeStr === '-') return '';
    try {
      const [time, period] = timeStr.split(' ');
      const [hours, minutes] = time.split(':');
      let h = parseInt(hours);
      
      if (period === 'PM' && h !== 12) h += 12;
      if (period === 'AM' && h === 12) h = 0;
      
      return `${h.toString().padStart(2, '0')}:${minutes}`;
    } catch (e) {
      return '';
    }
  };

  useEffect(() => {
    if (isOpen && record) {
      reset({
        timeIn: toInputTime(record.timeIn),
        timeOut: toInputTime(record.timeOut),
        status: record.status || 'Present',
        late: 0,
        undertime: 0
      });
    }
  }, [isOpen, record, reset]);

  const onSubmit = async (data: DtrEditSchema) => {
    if (!record) return;

    try {
      // Reconstruct ISO DateTimes
      const baseDate = new Date(record.date);
      
      let timeInISO = null;
      if (data.timeIn) {
        const [h, m] = data.timeIn.split(':');
        const d = new Date(baseDate);
        d.setHours(parseInt(h), parseInt(m));
        timeInISO = d.toISOString();
      }

      let timeOutISO = null;
      if (data.timeOut) {
        const [h, m] = data.timeOut.split(':');
        const d = new Date(baseDate);
        d.setHours(parseInt(h), parseInt(m));
        timeOutISO = d.toISOString();
      }

      await onSave(record.id, {
        timeIn: timeInISO,
        timeOut: timeOutISO,
        status: data.status,
        lateMinutes: data.late ?? 0,
        undertimeMinutes: data.undertime ?? 0
      });
      onClose();
    } catch (error) {
      console.error("Failed to save DTR", error);
    }
  };

  const getStatusColor = (status: string) => {
    const styles: Record<string, string> = {
      Present: 'bg-green-100 text-green-700',
      Absent: 'bg-red-100 text-red-700',
      Late: 'bg-orange-100 text-orange-700',
      Leave: 'bg-blue-100 text-blue-700',
      Undertime: 'bg-amber-100 text-amber-700',
      'Half Day': 'bg-purple-100 text-purple-700',
      Duty: 'bg-green-800 text-white',
    };
    return styles[status] || 'bg-gray-100 text-gray-700';
  };

  if (!isOpen || !record) return null;

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4 transition-all duration-300" onClick={onClose}>
      <div 
        className="bg-white rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.15)] w-full max-w-md border border-white/20 overflow-hidden animate-in fade-in zoom-in duration-300"
        onClick={(e) => e.stopPropagation()}
      >
        
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 shrink-0 border-b border-gray-100">
            <div className="flex items-center gap-2">
              <div className="p-2 rounded-lg">
                <Clock className="w-5 h-5 text-gray-400" />
              </div>
              <h2 className="text-xl font-bold text-gray-800">Correct Time Record</h2>
            </div>
            <button 
              type="button"
              onClick={onClose} 
              className="text-gray-400 hover:text-gray-600 transition-colors p-1 rounded-full hover:bg-gray-100"
            >
              <X className="w-5 h-5 text-gray-400" />
            </button>
          </div>

        {/* Body */}
        <form onSubmit={handleSubmit(onSubmit)}>
          <div className="px-6 pb-6 space-y-5">
            
            {/* Context Info */}
            <div className="text-sm text-gray-800 mt-4">
              Editing record for <span className="font-semibold text-gray-800">{record.name}</span> on <span className="font-semibold text-gray-800">{record.date}</span>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Time In</label>
                <div className="relative">
                  <input
                    type="time"
                    {...register('timeIn')}
                    className="w-full pl-3 pr-3 py-2.5 bg-white border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-gray-900/10 focus:border-gray-400 text-gray-800"
                  />
                  <Clock className="absolute top-2.5 right-3 text-gray-400 pointer-events-none" size={16} />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Time Out</label>
                <div className="relative">
                  <input
                    type="time"
                    {...register('timeOut')}
                    className="w-full pl-3 pr-3 py-2.5 bg-white border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-gray-900/10 focus:border-gray-400 text-gray-800"
                  />
                  <Clock className="absolute top-2.5 right-3 text-gray-400 pointer-events-none" size={16} />
                </div>
              </div>
            </div>

            <div className="relative z-[60]">
              <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Status</label>
              <Controller
                name="status"
                control={control}
                render={({ field }) => (
                  <Combobox
                    options={[
                      { value: 'Present', label: 'Present' },
                      { value: 'Absent', label: 'Absent' },
                      { value: 'Late', label: 'Late' },
                      { value: 'Leave', label: 'Leave' },
                      { value: 'Undertime', label: 'Undertime' },
                      { value: 'Half Day', label: 'Half Day' },
                      { value: 'Duty', label: 'Duty' }
                    ]}
                    value={field.value}
                    onChange={field.onChange}
                    placeholder="Select Status"
                    buttonClassName={`w-full px-3 py-2.5 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-gray-900/10 focus:border-gray-400 font-bold h-[42px] ${getStatusColor(field.value)}`}
                  />
