              type="text"
              placeholder="Search employees by name, ID, or email..."
              className="w-full pl-8 pr-3 py-1.5 text-sm border border-gray-300 rounded-lg shadow-md focus:outline-none focus:ring-2 focus:ring-gray-200"
              value={searchTerm}
