import React, { memo } from 'react';
import { AlertTriangle, X, Loader } from 'lucide-react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
// @ts-ignore
import { removeEmployeeFromDepartment } from '@/api/departmentApi';
import { useToastStore } from '@/stores';

interface Employee {
  id: number;
  firstName?: string;
  lastName?: string;
}

interface RemoveEmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  departmentId: number; 
  employee?: Employee;
  onSuccess?: () => void;
}

const RemoveEmployeeModal: React.FC<RemoveEmployeeModalProps> = memo(({ 
  isOpen, 
  onClose, 
  departmentId,
  employee, 
  onSuccess 
}) => {
  const queryClient = useQueryClient();
  const showToast = useToastStore((state) => state.showToast);

  const removeMutation = useMutation({
    mutationFn: async (employeeId: number) => {
        await removeEmployeeFromDepartment(departmentId, employeeId);
    },
    onSuccess: () => {
        showToast('Employee removed from department', 'success');
        queryClient.invalidateQueries({ queryKey: ['department-employees', departmentId] });
        onClose();
        if (onSuccess) onSuccess();
    },
    onError: (error: Error) => {
        console.error('Failed to remove employee', error);
        showToast(error.message || 'Failed to remove employee', 'error');
    }
  });

  const handleConfirm = () => {
     if (employee) {
         removeMutation.mutate(employee.id);
     }
  };

  if (!isOpen || !employee) return null;

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 transition-all">
      <div className="bg-white rounded-xl w-full max-w-md shadow-2xl border border-gray-100 overflow-hidden animate-in fade-in zoom-in duration-200">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4">
          <h2 className="text-xl font-bold text-gray-900">Remove Employee</h2>
          <button
            onClick={onClose}
            className="text-gray-400 hover:text-gray-600 transition-colors p-1 rounded-full hover:bg-gray-100"
          >
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="p-6">
          <div className="bg-amber-50 border border-amber-100 rounded-lg p-4 mb-4">
             <div className="flex gap-3">
               <div className="bg-amber-100 p-2 rounded-full h-fit">
                 <AlertTriangle className="text-amber-600" size={20} />
               </div>
               <div>
                  <h4 className="text-sm font-bold text-amber-800 mb-1">Warning</h4>
                  <p className="text-sm text-amber-700">
                    Are you sure you want to remove <strong>{employee.firstName} {employee.lastName}</strong> from this department?
                  </p>
               </div>
             </div>
          </div>
          <p className="text-gray-500 text-sm pl-1">
             This will unassign them from the department but will not delete their account.
          </p>
        </div>

        {/* Footer */}
        <div className="flex gap-3 px-6 py-4 bg-gray-50 border-t border-gray-100">
          <button
            onClick={onClose}
            className="flex-1 px-4 py-2 bg-white border border-gray-200 rounded-lg text-sm font-semibold text-gray-700 hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm"
          >
            Cancel
          </button>
          <button
            onClick={handleConfirm}
            disabled={removeMutation.isPending}
            className="flex-1 px-4 py-2 bg-gray-900 text-white rounded-lg text-sm font-bold hover:bg-gray-800 transition-all shadow-md disabled:opacity-50 flex items-center justify-center gap-2"
          >
            {removeMutation.isPending && <Loader className="animate-spin" size={16} />}
            {removeMutation.isPending ? 'Removing...' : 'Confirm Removal'}
          </button>
        </div>
      </div>
    </div>
  );
});

RemoveEmployeeModal.displayName = 'RemoveEmployeeModal';

export default RemoveEmployeeModal;

/**
 * useDepartmentDetail Hook
 * Custom hook for managing department detail view
 * Optimized with useMemo and useCallback for performance
 */

import { useState, useEffect, useCallback, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { departmentApi } from '@/api/departmentApi';

export interface Department {
  id: number;
  name: string;
  description?: string | null;
  headOfDepartment?: string;
  employeeCount?: number;
}

export interface Employee {
  id: number;
  firstName?: string;
  lastName?: string;
  email?: string;
  jobTitle?: string | null;
  positionTitle?: string | null;
}

export interface UseDepartmentDetailReturn {
  id: string | undefined;
  department: Department | null;
  employees: Employee[];
  filteredEmployees: Employee[];
  loading: boolean;
  searchTerm: string;
  isAddEmployeeModalOpen: boolean;
  deleteConfirm: Employee | null;
  isProcessing: boolean;
  loadData: () => Promise<void>;
  navigateBack: () => void;
  navigateToEmployee: (employeeId: number) => void;
  handleRemoveEmployee: (employeeId: number) => Promise<void>;
  handleSearchChange: (value: string) => void;
  openAddEmployeeModal: () => void;
  closeAddEmployeeModal: () => void;
  openDeleteConfirm: (employee: Employee) => void;
  closeDeleteConfirm: () => void;
}

export const useDepartmentDetail = (): UseDepartmentDetailReturn => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  
  // Data state
  const [department, setDepartment] = useState<Department | null>(null);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  
  // Modal states
  const [isAddEmployeeModalOpen, setIsAddEmployeeModalOpen] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState<Employee | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Load data - memoized with useCallback
  const loadData = useCallback(async () => {
    try {
      setLoading(true);
      if (!id) return;
      
      const deptData = await departmentApi.getDepartmentById(id);
      
      if (deptData.success && deptData.department) {
        setDepartment(deptData.department as unknown as Department);
        setEmployees((deptData.employees as unknown as Employee[]) || []);
      }
    } catch (err) {
      // Silently handle
    } finally {
      setLoading(false);
    }
  }, [id]);

  // Initial load
  useEffect(() => {
    if (id) {
      loadData();
    }
  }, [id, loadData]);

  // Navigate back - memoized
  const navigateBack = useCallback(() => {
    navigate('/admin-dashboard/departments');
  }, [navigate]);

  // Navigate to employee profile - memoized
  const navigateToEmployee = useCallback((employeeId: number) => {
    navigate(`/admin-dashboard/employees/${employeeId}/profile`);
  }, [navigate]);

  // Handle remove employee - memoized
  const handleRemoveEmployee = useCallback(async (employeeId: number) => {
    try {
      setIsProcessing(true);
      if (!id) return;
      const result = await departmentApi.removeEmployeeFromDepartment(id, employeeId);
      if (result.success) {
        await loadData();
      }
    } catch (error) {
      // Handle error
    } finally {
      setIsProcessing(false);
      setDeleteConfirm(null);
    }
  }, [id, loadData]);

  // Search change handler - memoized
  const handleSearchChange = useCallback((value: string) => {
    setSearchTerm(value);
  }, []);

  // Open add employee modal - memoized
  const openAddEmployeeModal = useCallback(() => {
    setIsAddEmployeeModalOpen(true);
  }, []);

  // Close add employee modal - memoized
  const closeAddEmployeeModal = useCallback(() => {
    setIsAddEmployeeModalOpen(false);
  }, []);

  // Open delete confirm - memoized
  const openDeleteConfirm = useCallback((employee: Employee) => {
    setDeleteConfirm(employee);
  }, []);

  // Close delete confirm - memoized
  const closeDeleteConfirm = useCallback(() => {
    setDeleteConfirm(null);
  }, []);

  // Filtered employees - memoized with useMemo
  const filteredEmployees = useMemo(() => {
    return employees.filter(emp => 
      emp.firstName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      emp.lastName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      emp.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (emp.jobTitle && emp.jobTitle.toLowerCase().includes(searchTerm.toLowerCase())) ||
      (emp.positionTitle && emp.positionTitle.toLowerCase().includes(searchTerm.toLowerCase()))
    );
  }, [employees, searchTerm]);

  return {
    // Params
    id,
    
    // Data
    department,
    employees,
    filteredEmployees,
    loading,
    searchTerm,
    
    // Modal states
    isAddEmployeeModalOpen,
    deleteConfirm,
    isProcessing,
    
    // Actions
    loadData,
    navigateBack,
    navigateToEmployee,
    handleRemoveEmployee,
    handleSearchChange,
    openAddEmployeeModal,
    closeAddEmployeeModal,
    openDeleteConfirm,
    closeDeleteConfirm
  };
};

export default useDepartmentDetail;

import { useState, useEffect, useMemo, useCallback } from 'react';
import { departmentApi } from '@/api/departmentApi';

import { DepartmentSchema } from '@/schemas/department';

import { Department } from '@/types/org';

export interface DepartmentStats {
  total: number;
  totalEmployees: number;
  averageEmployees: number;
}

export interface UseDepartmentManagementReturn {
  departments: Department[];
  filteredDepartments: Department[];
  loading: boolean;
  error: string | null;
  stats: DepartmentStats;
  searchTerm: string;
  isModalOpen: boolean;
  editingDepartment: Department | null;
  deleteModalOpen: boolean;
  departmentToDelete: Department | null;
  isDeleting: boolean;
  handleSearchChange: (term: string) => void;
  handleAdd: () => void;
  handleEdit: (dept: Department) => void;
  handleDeleteClick: (dept: Department) => void;
  handleDeleteCancel: () => void;
  handleDeleteConfirm: () => Promise<void>;
  handleModalSubmit: (data: DepartmentSchema) => Promise<{ success: boolean; error?: string }>;
  handleModalClose: () => void;
  refresh: () => Promise<void>;
}


export const useDepartmentManagement = (): UseDepartmentManagementReturn => {
  const [departments, setDepartments] = useState<Department[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  
  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingDepartment, setEditingDepartment] = useState<Department | null>(null);
  
  // Delete Modal State
  const [deleteModalOpen, setDeleteModalOpen] = useState(false);
  const [departmentToDelete, setDepartmentToDelete] = useState<Department | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  const loadDepartments = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await departmentApi.fetchDepartments();
      if (data.success) {
        setDepartments((data.departments as unknown as Department[]) || []);
      } else {
        setError('Failed to fetch departments');
      }
    } catch (err: unknown) {
      console.error("Failed to load departments", err);
      setError(err instanceof Error ? err.message : 'An error occurred');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadDepartments();
  }, [loadDepartments]);

  const handleSearchChange = useCallback((term: string) => {
    setSearchTerm(term);
  }, []);

  const handleAdd = useCallback(() => {
    setEditingDepartment(null);
    setIsModalOpen(true);
  }, []);

  const handleEdit = useCallback((dept: Department) => {
    setEditingDepartment(dept);
    setIsModalOpen(true);
  }, []);

  // Open delete confirmation modal
  const handleDeleteClick = useCallback((dept: Department) => {
    setDepartmentToDelete(dept);
    setDeleteModalOpen(true);
  }, []);

  // Close delete modal
  const handleDeleteCancel = useCallback(() => {
    setDeleteModalOpen(false);
    setDepartmentToDelete(null);
  }, []);

  // Confirm delete
  const handleDeleteConfirm = useCallback(async () => {
    if (!departmentToDelete) return;
    
    try {
      setIsDeleting(true);
      await departmentApi.deleteDepartment(departmentToDelete.id);
      setDepartments(prev => prev.filter(d => d.id !== departmentToDelete.id));
      setDeleteModalOpen(false);
      setDepartmentToDelete(null);
    } catch (err: unknown) {
      console.error("Failed to delete department", err);
      setError(err instanceof Error ? err.message : 'Failed to delete department');
    } finally {
      setIsDeleting(false);
    }
  }, [departmentToDelete]);

  const handleModalSubmit = useCallback(async (data: DepartmentSchema): Promise<{ success: boolean; error?: string }> => {
    try {
      if (editingDepartment) {
        const response = await departmentApi.updateDepartment(editingDepartment.id, data);
        if (response.success) {
          loadDepartments();
        }
      } else {
        const response = await departmentApi.addDepartment(data);
        if (response.success) {
          loadDepartments();
        }
      }
      setIsModalOpen(false);
      return { success: true };
    } catch (err: unknown) {
      console.error("Failed to save department", err);
      return { success: false, error: err instanceof Error ? err.message : 'An error occurred' };
    }
  }, [editingDepartment, loadDepartments]);

  const handleModalClose = useCallback(() => {
    setIsModalOpen(false);
    setEditingDepartment(null);
  }, []);

  // Derived Data
  const filteredDepartments = useMemo(() => {
    return departments.filter(dept => 
      dept.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (dept.headOfDepartment && dept.headOfDepartment.toLowerCase().includes(searchTerm.toLowerCase()))
    );
  }, [departments, searchTerm]);

  const stats = useMemo((): DepartmentStats => {
    const total = departments.length;
    const totalEmp = departments.reduce((acc, curr) => acc + (curr.employeeCount || 0), 0);
    const avg = total > 0 ? Math.round(totalEmp / total) : 0;
    return { total, totalEmployees: totalEmp, averageEmployees: avg };
  }, [departments]);

  return {
    departments,
    filteredDepartments,
    loading,
    error,
    stats,
    searchTerm,
    isModalOpen,
    editingDepartment,
    // Delete modal state
    deleteModalOpen,
    departmentToDelete,
    isDeleting,
    // Actions
    handleSearchChange,
    handleAdd,
    handleEdit,
    handleDeleteClick,
    handleDeleteCancel,
    handleDeleteConfirm,
    handleModalSubmit,
    handleModalClose,
    refresh: loadDepartments
  };
};

