                <input 
                  type="email"
                  {...register('email')}
                  className={`w-full px-3 py-2 bg-[#F8F9FA] border-2 border-gray-200 rounded-lg focus:outline-none focus:border-gray-900 text-sm ${errors.email ? 'border-red-500' : ''}`}
                  placeholder="juan@example.com"
