            className="flex-1 px-4 py-2 border-2 border-gray-200 rounded-lg text-sm font-bold text-gray-600 hover:bg-gray-100 transition-all"
          >
            Cancel
          </button>
          <button 
            type="button"
            onClick={handleSubmit(handleFormSubmit)}
            disabled={addEmployeeMutation.isPending}
            className="flex-1 px-4 py-2 bg-gray-900 text-white rounded-lg text-sm font-bold hover:bg-gray-800 transition-all shadow-md flex items-center justify-center gap-2 disabled:opacity-50"
          >
            {addEmployeeMutation.isPending && <Loader className="animate-spin" size={16} />}
            Onboard Member
          </button>
        </div>
      </div>
    </div>
  );
};

export default AddEmployeeModal;

import React, { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@/lib/zodResolver';
import { X, ChevronUp, ChevronDown, FileText, Loader, Sparkles, Clock, Loader2 } from 'lucide-react';
import { plantillaApi } from '@/api/plantillaApi';
import { employeeApi } from '@/api/employeeApi';
import { scheduleApi, ShiftTemplateData } from '@/api/scheduleApi';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useToastStore } from '@/stores';
import { UpdateEmployeeSchema, UpdateEmployeeInput } from '@/schemas/employeeSchema';
import { formatHour12 } from '@/components/Custom/CalendarComponents/shared/utils/eventUtils';
import Combobox from '@/components/Custom/Combobox';
import {
  ROLE_OPTIONS,
  EMPLOYMENT_STATUS_OPTIONS,
  APPOINTMENT_TYPE_OPTIONS,
  GENDER_OPTIONS,
  CIVIL_STATUS_OPTIONS,
  BLOOD_TYPE_OPTIONS,
  NATIONALITY_OPTIONS,
  ELIGIBILITY_TYPE_OPTIONS
} from '@/constants/referenceData';

interface Department {
  id: number;
  name: string;
}

import { Position } from '@/api/plantillaApi';
import { EmployeeDetailed } from '@/types/employee';

interface EditEmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  employee?: EmployeeDetailed;
  departments: Department[];
  onSuccess?: () => void;
}

interface CollapsibleSectionProps {
  title: string;
  isOpen: boolean;
  onToggle: () => void;
  children: React.ReactNode;
}

const CollapsibleSection: React.FC<CollapsibleSectionProps> = ({ title, isOpen, onToggle, children }) => (
  <div className="border border-gray-200 rounded-lg overflow-hidden">
    <button
      type="button"
      onClick={onToggle}
      className="w-full px-3 py-2 bg-gray-100 flex items-center justify-between text-left hover:bg-gray-200 transition-colors"
    >
      <span className="text-xs font-semibold text-gray-700">{title}</span>
      {isOpen ? <ChevronUp size={14} className="text-gray-500" /> : <ChevronDown size={14} className="text-gray-500" />}
    </button>
    <div className={`transition-all duration-300 ease-in-out overflow-hidden ${isOpen ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0'}`}>
      <div className="p-3 space-y-2 bg-white">{children}</div>
    </div>
  </div>
);

const EditEmployeeModal: React.FC<EditEmployeeModalProps> = ({
  isOpen,
  onClose,
  employee,
  departments,
  onSuccess
}) => {
  const [openSections, setOpenSections] = useState({
    personal: false,
    government: false,
    eligibility: false,
    socialMedia: false,
    employment: true,
    schedule: true
  });
  const [vacantPositions, setVacantPositions] = useState<Position[]>([]);
  const [templates, setTemplates] = useState<ShiftTemplateData[]>([]);
  const [loadingTemplates, setLoadingTemplates] = useState(false);
  
  const queryClient = useQueryClient();
  const showToast = useToastStore((state) => state.showToast);

  const { register, handleSubmit, formState: { errors }, reset, setValue, watch } = useForm<UpdateEmployeeInput>({
    resolver: zodResolver(UpdateEmployeeSchema),
    defaultValues: {}
  });

  const updateMutation = useMutation({
    mutationFn: async (data: UpdateEmployeeInput) => {
        if (!employee?.id) throw new Error("No employee ID");
        return await employeeApi.updateEmployee(employee.id, data);
    },
    onSuccess: (res) => {
        if (res.success) {
            showToast('Employee updated successfully', 'success');
            queryClient.invalidateQueries({ queryKey: ['employees'] });
            queryClient.invalidateQueries({ queryKey: ['employee', employee?.id] });
            if (onSuccess) onSuccess();
            onClose();
        } else {
            showToast(res.message || 'Failed to update employee', 'error');
        }
    },
    onError: (error: Error | { response?: { data?: { message?: string } } }) => {
        const err = error as { response?: { data?: { message?: string } }; message?: string };
        console.error('Failed to update employee', err);
        showToast(err.response?.data?.message || err.message || 'Failed to update employee', 'error');
    }
  });

  useEffect(() => {
    if (isOpen && employee) {
      loadPlantillaOptions();
      fetchTemplates();
      // Reset form with employee data
      reset({
        firstName: employee.firstName || '',
        lastName: employee.lastName || '',
        email: employee.email || '',
        department: employee.department || '',
        role: (employee.role as "Administrator" | "Human Resource" | "Employee") || 'Employee',
        employmentStatus: employee.employmentStatus || 'Active',
        itemNumber: employee.itemNumber || '',
        positionTitle: employee.positionTitle || employee.jobTitle || '',
        salaryGrade: employee.salaryGrade ? Number(employee.salaryGrade) : undefined,
        stepIncrement: employee.stepIncrement ? Number(employee.stepIncrement) : 1,
        appointmentType: employee.appointmentType || '',
        station: employee.station || '',
        birthDate: employee.birthDate ? new Date(employee.birthDate).toISOString().split('T')[0] : null,
        gender: employee.gender || '',
        civilStatus: employee.civilStatus || '',
        nationality: employee.nationality || 'Filipino',
        phoneNumber: employee.phoneNumber || '',
        permanentAddress: employee.permanentAddress || '',
        gsisNumber: employee.gsisNumber || '',
        philhealthNumber: employee.philhealthNumber || '',
        pagibigNumber: employee.pagibigNumber || '',
        tinNumber: employee.tinNumber || '',
        address: employee.address || '',
        // Plantilla-required eligibility fields
        eligibilityType: employee.eligibilityType || '',
        eligibilityNumber: employee.eligibilityNumber || '',
        eligibilityDate: employee.eligibilityDate ? new Date(employee.eligibilityDate).toISOString().split('T')[0] : null,
        educationalBackground: employee.educationalBackground || '',
        yearsOfExperience: employee.yearsOfExperience ? Number(employee.yearsOfExperience) : 0,
        // Schedule fields
        startTime: employee.startTime || '',
        endTime: employee.endTime || '',
        // IDs
        departmentId: employee.departmentId,
        positionId: employee.positionId
      });
    }
  }, [isOpen, employee, reset]); 

  const loadPlantillaOptions = async () => {
    try {
      const res = await plantillaApi.getPositions({ isVacant: true });
      let positions: Position[] = res.data.success ? res.data.positions : [];
      if (employee?.itemNumber) {
          const currentPos: Position = {
              id: 0,
              itemNumber: employee.itemNumber,
              positionTitle: employee.positionTitle || '',
              salaryGrade: Number(employee.salaryGrade || 0), // number
              stepIncrement: employee.stepIncrement || 1,
              department: employee.department || '',
              isVacant: false
          };
         // Add current position if not in list
         if (!positions.find(p => p.itemNumber === employee.itemNumber)) {
             positions = [currentPos, ...positions];
         }
      }
      setVacantPositions(positions);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchTemplates = async () => {
    setLoadingTemplates(true);
    try {
      const response = await scheduleApi.getShiftTemplates();
      if (response.success) {
        setTemplates(response.templates || []);
      }
    } catch (err) {
      console.error('Failed to fetch shift templates:', err);
    } finally {
      setLoadingTemplates(false);
    }
  };

  const handleTemplateChange = (templateId: string) => {
    if (!templateId) return;
    const template = templates.find(t => String(t.id) === templateId);
    if (template) {
      // Input type="time" expects HH:mm or HH:mm:ss
      setValue('startTime', template.startTime, { shouldValidate: true });
      setValue('endTime', template.endTime, { shouldValidate: true });
    }
  };

  const handlePlantillaChange = (itemNo: string) => {
    setValue('itemNumber', itemNo);
    if (itemNo) {
      const position = vacantPositions.find(p => p.itemNumber === itemNo);
      if (position) {
        setValue('positionTitle', position.positionTitle);
        setValue('positionId', position.id);
        setValue('salaryGrade', Number(position.salaryGrade));
        setValue('stepIncrement', position.stepIncrement || 1);
        if (position.department) {
             setValue('department', position.department);
             const dept = departments.find(d => d.name === position.department);
             if (dept) setValue('departmentId', dept.id);
        }
      }
    } else {
        setValue('positionId', null);
    }
  };

  const toggleSection = (section: keyof typeof openSections) => {
    setOpenSections(prev => ({ ...prev, [section]: !prev[section] }));
  };
  
  if (!isOpen || !employee) return null;

  const handleFormSubmit = (data: UpdateEmployeeInput) => {
      updateMutation.mutate(data);
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4 overflow-y-auto">
      <div className="bg-white rounded-xl w-full max-w-lg shadow-2xl my-8 border border-gray-100 flex flex-col overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="flex justify-between items-center px-6 py-4 bg-gray-50 border-b border-gray-100">
          <div>
            <h2 className="text-xl font-bold text-gray-900">Update Employee</h2>
            <p className="text-xs text-gray-500 mt-0.5">ID: {employee.employeeId || 'N/A'}</p>
          </div>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors p-1 rounded-full hover:bg-gray-200">
            <X className="w-5 h-5" />
          </button>
        </div>
        
        <form onSubmit={handleSubmit(handleFormSubmit)} className="p-6 space-y-4 max-h-[70vh] overflow-y-auto bg-gray-50/30">
          
          {/* CORE IDENTITY (Always Visible) */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">First Name</label>
              <input 
                {...register('firstName')}
                className="w-full px-3 py-2 bg-white border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-gray-900/10 text-sm font-semibold"
              />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">Last Name</label>
              <input 
                {...register('lastName')}
                className="w-full px-3 py-2 bg-white border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-gray-900/10 text-sm font-semibold"
              />
            </div>
          </div>

          <div>
            <label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">Email Address</label>
            <input 
              type="email"
              {...register('email')}
              className="w-full px-3 py-2 bg-white border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-gray-900/10 text-sm font-semibold"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">System Role</label>
              <Combobox 
                options={ROLE_OPTIONS}
                value={watch('role')}
                onChange={(val) => setValue('role', val as UpdateEmployeeInput['role'])}
                placeholder="Select role..."
              />
            </div>
            <div>
              <label className="text-[10px] font-black uppercase text-gray-400 mb-1 block">Work Status</label>
              <Combobox 
                options={EMPLOYMENT_STATUS_OPTIONS}
                value={watch('employmentStatus')}
                onChange={(val) => setValue('employmentStatus', val)}
                placeholder="Select status..."
              />
            </div>
          </div>

          {/* COLLAPSIBLE SECTIONS */}

          {/* Work Schedule */}
          <CollapsibleSection title="WORK SCHEDULE & SHIFTS" isOpen={openSections.schedule} onToggle={() => toggleSection('schedule')}>
             <div className="bg-blue-50 p-3 rounded-lg border border-blue-100 mb-2">
                <div className="flex items-center gap-2 mb-2">
                    <Sparkles size={14} className="text-blue-600" />
                    <p className="text-[10px] text-blue-600 font-bold uppercase">Quick Shift Template</p>
                </div>
                <div className="relative">
                    <Combobox 
                    options={templates.map(temp => ({
                        value: String(temp.id),
                        label: `${temp.name} (${temp.startTime.substring(0,5)} - ${temp.endTime.substring(0,5)})`
                    }))}
                    value=""
                    onChange={handleTemplateChange}
                    disabled={loadingTemplates}
                    placeholder={loadingTemplates ? 'Loading templates...' : '(Select a shift template...)'}
                    buttonClassName="border-blue-200 focus:ring-blue-500/20"
                    />
                    {loadingTemplates && (
                        <div className="absolute right-2 top-1/2 -translate-y-1/2">
                            <Loader2 size={12} className="animate-spin text-blue-400" />
                        </div>
                    )}
                </div>
             </div>

             <div className="grid grid-cols-2 gap-3">
                <div className="space-y-1">
                  <label className="text-[9px] font-bold text-gray-500 uppercase flex items-center gap-1">
                      <Clock size={10} /> Shift Start
                  </label>
                  <input 
                    type="time"
                    step="1"
                    {...register('startTime')}
                    className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none focus:border-gray-900 font-mono" 
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-bold text-gray-500 uppercase flex items-center gap-1">
                      <Clock size={10} /> Shift End
                  </label>
                  <input 
                    type="time"
                    step="1"
                    {...register('endTime')}
                    className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none focus:border-gray-900 font-mono" 
                  />
                </div>
             </div>
             <p className="text-[9px] text-gray-400 mt-1 italic italic">Setting the shift here defines the employee's default daily work hours for attendance tracking.</p>
          </CollapsibleSection>
          
          {/* Employment Linkage */}
          <CollapsibleSection title="EMPLOYMENT & PLANTILLA" isOpen={openSections.employment} onToggle={() => toggleSection('employment')}>
             <div className="bg-amber-50 p-3 rounded-lg border border-amber-100 mb-2">
                <p className="text-[9px] text-amber-600 font-bold uppercase mb-1">Plantilla Item</p>
                <Combobox 
                  options={vacantPositions.map(pos => ({
                    value: pos.itemNumber,
                    label: `${pos.itemNumber} - ${pos.positionTitle} (SG ${pos.salaryGrade})`
                  }))}
                  value={watch('itemNumber') || ''}
                  onChange={handlePlantillaChange}
                  placeholder="(Not Linked to Plantilla)"
                  buttonClassName="border-amber-200 focus:ring-amber-500/20"
                />
             </div>

             <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Department</label>
                  <Combobox 
                    options={departments.map(dept => ({ value: dept.name, label: dept.name }))}
                    value={watch('department')}
                    onChange={(val) => {
                      setValue('department', val);
                      const d = departments.find(dep => dep.name === val);
                      if (d) setValue('departmentId', d.id);
                    }}
                    placeholder="Select department..."
                  />
                </div>
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Position Title</label>
                  <input {...register('positionTitle')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none focus:border-gray-900" />
                </div>
             </div>

             <div className="grid grid-cols-3 gap-3">
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">SG</label>
                  <input type="number" {...register('salaryGrade', { valueAsNumber: true })} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none focus:border-gray-900" />
                </div>
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Step</label>
                  <input type="number" {...register('stepIncrement', { valueAsNumber: true })} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none focus:border-gray-900" />
                </div>
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Type</label>
                  <Combobox 
                    options={APPOINTMENT_TYPE_OPTIONS}
                    value={watch('appointmentType')}
                    onChange={(val) => setValue('appointmentType', val)}
                    placeholder="Select type..."
                  />
                </div>
             </div>
          </CollapsibleSection>

          {/* Personal Info */}
          <CollapsibleSection title="PERSONAL DETAILS" isOpen={openSections.personal} onToggle={() => toggleSection('personal')}>
             <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Birth Date</label>
                  <input type="date" {...register('birthDate')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" />
                </div>
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Sex</label>
                  <Combobox 
                    options={GENDER_OPTIONS}
                    value={watch('gender')}
                    onChange={(val) => setValue('gender', val)}
                    placeholder="Select sex..."
                  />
                </div>
             </div>
             <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Civil Status</label>
                  <Combobox 
                    options={CIVIL_STATUS_OPTIONS}
                    value={watch('civilStatus')}
                    onChange={(val) => setValue('civilStatus', val)}
                    placeholder="Select status..."
                  />
                </div>
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Nationality</label>
                  <Combobox 
                    options={NATIONALITY_OPTIONS}
                    value={watch('nationality')}
                    onChange={(val) => setValue('nationality', val)}
                    placeholder="Select nationality..."
                  />
                </div>
             </div>
             <div>
                <label className="text-[9px] font-bold text-gray-500 uppercase">Mobile Number</label>
                <input {...register('phoneNumber')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" placeholder="09xx-xxx-xxxx" />
             </div>
             <div>
                <label className="text-[9px] font-bold text-gray-500 uppercase">Address</label>
                <textarea {...register('address')} rows={2} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none resize-none" />
             </div>
          </CollapsibleSection>

          {/* Eligibility */}
          <CollapsibleSection title="ELIGIBILITY & EDUCATION" isOpen={openSections.eligibility} onToggle={() => toggleSection('eligibility')}>
             <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Eligibility Type</label>
                  <Combobox 
                    options={ELIGIBILITY_TYPE_OPTIONS}
                    value={watch('eligibilityType')}
                    onChange={(val) => setValue('eligibilityType', val)}
                    placeholder="Select type..."
                  />
                </div>
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">License/Reg No.</label>
                  <input {...register('eligibilityNumber')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" />
                </div>
             </div>
             <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Eligibility Date</label>
                  <input type="date" {...register('eligibilityDate')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" />
                </div>
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Exp. (Years)</label>
                  <input type="number" {...register('yearsOfExperience', { valueAsNumber: true })} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" />
                </div>
             </div>
             <div>
                <label className="text-[9px] font-bold text-gray-500 uppercase">Highest Education</label>
                <input {...register('educationalBackground')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" placeholder="e.g. Master of Arts in Public Admin" />
             </div>
          </CollapsibleSection>

          {/* Gov't IDs */}
          <CollapsibleSection title="GOVERNMENT IDENTIFICATION" isOpen={openSections.government} onToggle={() => toggleSection('government')}>
             <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">GSIS BP No.</label>
                  <input {...register('gsisNumber')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" />
                </div>
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">PhilHealth No.</label>
                  <input {...register('philhealthNumber')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" />
                </div>
             </div>
             <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">Pag-IBIG No.</label>
                  <input {...register('pagibigNumber')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" />
                </div>
                <div>
                  <label className="text-[9px] font-bold text-gray-500 uppercase">TIN No.</label>
                  <input {...register('tinNumber')} className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none" />
                </div>
             </div>
          </CollapsibleSection>

        </form>

        <div className="p-6 bg-gray-50 border-t border-gray-100 flex gap-3">
          <button 
            type="button"
            onClick={onClose}
            className="flex-1 px-4 py-2 border-2 border-gray-200 rounded-lg text-sm font-bold text-gray-600 hover:bg-gray-100 transition-all"
          >
            Cancel
          </button>
          <button 
            type="button"
            onClick={handleSubmit(handleFormSubmit)}
            disabled={updateMutation.isPending}
            className="flex-1 px-4 py-2 bg-gray-900 text-white rounded-lg text-sm font-bold hover:bg-gray-800 transition-all shadow-md flex items-center justify-center gap-2 disabled:opacity-50"
          >
            {updateMutation.isPending && <Loader className="animate-spin" size={16} />}
            Save Changes
          </button>
        </div>
      </div>
    </div>
  );
};

export default EditEmployeeModal;

import React, { useState, useEffect, ChangeEvent } from 'react';
import { X, User, Mail, Camera, Save } from 'lucide-react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
// @ts-ignore
import { updateMyProfile } from '@api/employeeApi';

// Local schema for this modal
const EditProfileFormSchema = z.object({
  firstName: z.string().min(1, 'First name is required'),
  lastName: z.string().min(1, 'Last name is required'),
  email: z.string().email('Invalid email format'),
  phoneNumber: z.string(),
  address: z.string(),
});

type EditProfileFormInput = z.infer<typeof EditProfileFormSchema>;

interface Profile {
  firstName?: string;
  lastName?: string;
  email?: string;
  phoneNumber?: string;
  address?: string;
  avatarUrl?: string;
}

interface EditProfileModalProps {
  isOpen: boolean;
  onClose: () => void;
  profile?: Profile;
  onSave: (data: Profile) => void;
}


const EditProfileModal: React.FC<EditProfileModalProps> = ({
  isOpen,
  onClose,
  profile,
  onSave
}) => {
  const [avatarFile, setAvatarFile] = useState<File | null>(null);
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const {
    register,
    handleSubmit,
    reset,
    watch,
    formState: { errors },
  } = useForm<EditProfileFormInput>({
    resolver: zodResolver(EditProfileFormSchema),
    defaultValues: {
      firstName: '',
      lastName: '',
      email: '',
      phoneNumber: '',
      address: '',
    },
  });

  const firstName = watch('firstName');
  const lastName = watch('lastName');

  useEffect(() => {
    if (profile && isOpen) {
      reset({
        firstName: profile.firstName || '',
        lastName: profile.lastName || '',
        email: profile.email || '',
        phoneNumber: profile.phoneNumber || '',
        address: profile.address || '',
      });
      setAvatarPreview(profile.avatarUrl || null);
    }
  }, [profile, isOpen, reset]);

  const handleAvatarChange = (e: ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setAvatarFile(file);
      setAvatarPreview(URL.createObjectURL(file));
    }
  };

  const onFormSubmit = async (data: EditProfileFormInput) => {
    setLoading(true);
    setError(null);

    try {
      const formData = new FormData();
      formData.append('firstName', data.firstName);
      formData.append('lastName', data.lastName);
      formData.append('email', data.email);
      if (avatarFile) {
        formData.append('avatar', avatarFile);
      }

      const result = await updateMyProfile(formData);
      
      if (result.success && result.data) {
        onSave({
          firstName: result.data.firstName || undefined,
          lastName: result.data.lastName || undefined,
          email: result.data.email || undefined,
          phoneNumber: result.data.phoneNumber || undefined,
          address: result.data.address || undefined,
          avatarUrl: result.data.avatarUrl || undefined
        });
        onClose();
      } else {
        setError(result.message || 'Failed to update profile');
      }
    } catch (err) {
      setError('An error occurred while updating profile');
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/30 flex items-start justify-center z-50 p-4">
      <div className="bg-white rounded-lg w-full max-w-md shadow-xl mt-16 border border-gray-200 p-6">
        {/* Header */}
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-lg font-bold text-gray-800">Edit Profile</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit(onFormSubmit)} className="space-y-4">
          {/* Avatar */}
          <div className="flex justify-center">
            <div className="relative">
              <div className="w-20 h-20 rounded-full overflow-hidden bg-gray-200 border-4 border-white">
                {avatarPreview ? (
                  <img src={avatarPreview} alt="Avatar" className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-gray-100 text-gray-600 text-xl font-bold">
                    {firstName?.[0]}{lastName?.[0]}
                  </div>
                )}
              </div>
              <label className="absolute bottom-0 right-0 w-7 h-7 bg-gray-100 rounded-full flex items-center justify-center cursor-pointer hover:bg-gray-200 transition-colors border border-gray-200">
                <Camera size={14} className="text-gray-500" />
                <input type="file" accept="image/*" onChange={handleAvatarChange} className="hidden" />
              </label>
            </div>
          </div>

          {/* Error Message */}
          {error && (
            <div className="bg-red-50 text-red-600 text-sm p-3 rounded-lg">
              {error}
            </div>
          )}

          {/* Fields */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                <User size={14} className="text-gray-400" /> First Name
              </label>
              <input
                type="text"
                {...register('firstName')}
                className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-gray-300 text-sm"
              />
              {errors.firstName && <p className="text-red-500 text-xs mt-1">{errors.firstName.message}</p>}
            </div>
            <div>
              <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
                <User size={14} className="text-gray-400" /> Last Name
              </label>
              <input
                type="text"
                {...register('lastName')}
                className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-gray-300 text-sm"
              />
              {errors.lastName && <p className="text-red-500 text-xs mt-1">{errors.lastName.message}</p>}
            </div>
          </div>

          <div>
            <label className="text-sm text-gray-600 mb-1 block flex items-center gap-1">
              <Mail size={14} className="text-gray-400" /> Email
            </label>
            <input
              type="email"
              {...register('email')}
              className="w-full px-3 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-gray-300 text-sm"
            />
            {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email.message}</p>}
          </div>

          {/* Actions */}
          <div className="flex gap-3 pt-4 border-t border-gray-200 mt-4">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2.5 text-sm text-gray-600 bg-gray-100 hover:text-red-700 rounded-lg transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="flex-1 px-4 py-2.5 text-sm text-white bg-gray-900 hover:bg-gray-800 rounded-lg transition-colors disabled:opacity-50 flex items-center justify-center gap-1"
            >
              {loading ? (
                <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
              ) : (
                <>
                  <Save size={14} />
                  Save Changes
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditProfileModal;

import React, { useState, memo, useMemo } from 'react';
import { 
  TrendingUp, Wallet, CheckCircle, Calculator, 
  Plus, Edit2, RotateCw, AlertTriangle, Search
} from 'lucide-react';
import { useBudget } from '../hooks/useBudget';
import BudgetAllocationModal from './BudgetAllocationModal';
import type { BudgetAllocation, DepartmentBudget } from '@/api/complianceApi';
import type { BudgetAllocationFormData } from '@/schemas/compliance';

interface BudgetDashboardProps {
  departments: string[];
}

const BudgetDashboard: React.FC<BudgetDashboardProps> = memo(({ departments }) => {
  const currentYear = new Date().getFullYear();
  const {
    year, setYear, loading, summary, departmentBudgets, 
    allocations, createAllocation, updateAllocation, recalculate, refresh
  } = useBudget(currentYear);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedAllocation, setSelectedAllocation] = useState<BudgetAllocation | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  // Filtered department list based on search
  const filteredDepartments = useMemo(() => {
    return departmentBudgets.filter(db => 
      db.department.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [departmentBudgets, searchTerm]);

  const handleOpenAdd = () => {
    setSelectedAllocation(null);
    setIsModalOpen(true);
  };

  const handleOpenEdit = (deptName: string) => {
    const existing = allocations.find(a => a.department === deptName);
    if (existing) {
      setSelectedAllocation(existing);
      setIsModalOpen(true);
    } else {
      // If no allocation exists yet for this dept, we skip or handle as add
      setSelectedAllocation(null);
      setIsModalOpen(true);
    }
  };

  const handleSubmit = async (data: BudgetAllocationFormData) => {
    try {
      if (selectedAllocation) {
        await updateAllocation(selectedAllocation.id, {
          totalBudget: data.totalBudget,
          notes: data.notes
        });
      } else {
        await createAllocation(data);
      }
      setIsModalOpen(false);
    } catch (error) {
      // Error handled by hook toast
    }
  };

  const formatPHP = (amount: number) => {
    return new Intl.NumberFormat('en-PH', {
      style: 'currency',
      currency: 'PHP',
    }).format(amount);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Top Action Bar */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="flex items-center gap-3 bg-gray-100 p-1 rounded-lg">
          {[currentYear - 1, currentYear, currentYear + 1].map((y) => (
            <button
              key={y}
              onClick={() => setYear(y)}
              className={`px-4 py-1.5 rounded-md text-sm font-bold transition-all ${
                year === y 
                  ? 'bg-white text-indigo-600 shadow-sm' 
                  : 'text-gray-500 hover:text-gray-700'
              }`}
            >
              FY {y}
            </button>
          ))}
        </div>
        
        <div className="flex items-center gap-2">
            <button 
                onClick={refresh}
                className="p-2 text-gray-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                title="Refresh Data"
            >
                <RotateCw size={20} className={loading ? 'animate-spin' : ''} />
            </button>
            <button
              onClick={handleOpenAdd}
              className="bg-indigo-600 hover:bg-indigo-700 text-white px-5 py-2 rounded-xl flex items-center gap-2 shadow-md transition-all active:scale-95 text-sm font-bold"
            >
              <Plus size={18} />
              Set Department Budget
            </button>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <SummaryCard 
          label="Total Allocated" 
          value={formatPHP(summary?.totalAllocated || 0)} 
          icon={<Wallet className="text-blue-600" size={20} />}
          bg="bg-blue-50"
          border="border-blue-100"
        />
        <SummaryCard 
          label="Total Utilized" 
          value={formatPHP(summary?.totalUtilized || 0)} 
          icon={<TrendingUp className="text-emerald-600" size={20} />}
          bg="bg-emerald-50"
          border="border-emerald-100"
        />
        <SummaryCard 
          label="Remaining Balance" 
          value={formatPHP(summary?.totalRemaining || 0)} 
          icon={<CheckCircle className="text-indigo-600" size={20} />}
          bg="bg-indigo-50"
          border="border-indigo-100"
        />
        <SummaryCard 
          label="Avg. Utilization" 
          value={`${(summary?.avgUtilizationRate || 0).toFixed(2)}%`} 
          icon={<Calculator className="text-amber-600" size={20} />}
          bg="bg-amber-50"
          border="border-amber-100"
        />
      </div>

      {/* Department Table */}
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-gray-50 flex items-center justify-between bg-gray-50/50">
            <h3 className="font-bold text-gray-800 flex items-center gap-2">
                Departmental Budget Breakdown
                <span className="text-xs font-medium text-gray-400 bg-gray-200 px-2 py-0.5 rounded-full">
                    {filteredDepartments.length} Departments
                </span>
            </h3>
            <div className="relative w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={14} />
                <input 
                    type="text"
                    placeholder="Search department..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-9 pr-4 py-1.5 bg-white border border-gray-200 rounded-lg text-xs focus:ring-2 focus:ring-indigo-500/20 outline-none"
                />
            </div>
        </div>
        
        <div className="overflow-x-auto bg-gray-50 rounded-lg">
          <table className="w-full min-w-[800px]">
            <thead className="bg-gray-200 shadow-md text-gray-700">
              <tr>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap uppercase">Department</th>
                <th className="px-6 py-4 text-right text-sm font-bold tracking-wide whitespace-nowrap uppercase">Allocation</th>
                <th className="px-6 py-4 text-right text-sm font-bold tracking-wide whitespace-nowrap uppercase">Utilized (Annual)</th>
                <th className="px-6 py-4 text-center text-sm font-bold tracking-wide whitespace-nowrap uppercase">Utilization %</th>
                <th className="px-6 py-4 text-center text-sm font-bold tracking-wide whitespace-nowrap uppercase">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredDepartments.map((dept) => (
                <tr key={dept.department} className="hover:bg-[#F8F9FA] hover:shadow-xl transition-colors group bg-white">
                  <td className="px-6 py-4">
                    <div className="font-bold text-gray-700 text-sm">{dept.department}</div>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="font-bold text-gray-900 text-sm">{formatPHP(dept.totalBudget)}</div>
                    {dept.totalBudget === 0 && (
                        <div className="text-[10px] text-amber-600 font-bold flex items-center justify-end gap-1">
                            <AlertTriangle size={10} /> NOT SET
                        </div>
                    )}
                  </td>
                  <td className="px-6 py-4 text-right text-sm font-medium text-gray-600">
                    {formatPHP(dept.utilizedBudget)}
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center flex-col gap-1.5">
                        <div className="w-full bg-gray-100 h-2 rounded-full overflow-hidden max-w-[120px] border border-gray-200">
                            <div 
                                className={`h-full rounded-full transition-all duration-1000 ${
                                    dept.utilizationRate > 90 ? 'bg-red-500' : 
                                    dept.utilizationRate > 70 ? 'bg-amber-500' : 'bg-emerald-500'
                                }`}
                                style={{ width: `${Math.min(dept.utilizationRate, 100)}%` }}
                            />
                        </div>
                        <span className={`text-[11px] font-black ${
                            dept.utilizationRate > 90 ? 'text-red-600' : 
                            dept.utilizationRate > 70 ? 'text-amber-600' : 'text-emerald-600'
                        }`}>
                            {dept.utilizationRate.toFixed(1)}%
                        </span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex justify-center gap-3">
                        <button
                          onClick={() => recalculate(year, dept.department)}
                          className="p-1.5 text-gray-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                          title="Recalculate Utilization"
                        >
                          <RotateCw size={18} />
                        </button>
                        <button
                          onClick={() => handleOpenEdit(dept.department)}
                          className="p-1.5 text-gray-500 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                          title="Adjust Budget"
                        >
                          <Edit2 size={18} />
                        </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredDepartments.length === 0 && (
                  <tr>
                      <td colSpan={5} className="px-6 py-16 text-center">
                          <div className="text-gray-400 font-bold uppercase tracking-widest text-xs">No department allocations found for FY {year}</div>
                      </td>
                  </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Allocation Modal */}
      <BudgetAllocationModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSubmit={handleSubmit}
        initialData={selectedAllocation}
        departments={departments}
        year={year}
      />
    </div>
  );
});

// Helper Components
const SummaryCard = ({ label, value, icon, bg, border }: { 
  label: string; value: string; icon: React.ReactNode; bg: string; border: string 
}) => (
  <div className={`${bg} ${border} border p-5 rounded-2xl shadow-sm transition-transform hover:scale-[1.02]`}>
    <div className="flex justify-between items-start mb-3">
        <div className="p-2 bg-white rounded-xl shadow-sm border border-black/5">
            {icon}
        </div>
        <div className="bg-white/50 px-2 py-0.5 rounded-full border border-black/5 text-[10px] font-black text-gray-400">
            FY2026
        </div>
    </div>
    <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{label}</div>
    <div className="text-xl font-black text-slate-900 tracking-tight">{value}</div>
  </div>
);

