import React, { useState } from 'react';
import { Plus, Trash2 } from 'lucide-react';
import { useForm, Controller } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import Combobox from '@/components/Custom/Combobox';
import { AddEducationSchema, AddEducationInput } from '@/schemas/employeeSchema';
// @ts-ignore
import { addEmployeeEducation, deleteEmployeeEducation } from '@api/employeeApi';

interface Education {
  id: number;
  institution: string;
  degree: string;
  fieldOfStudy?: string;
  startDate?: string;
  endDate?: string;
  isCurrent?: boolean;
  type: string;
}

interface Profile {
  id: number;
  education?: Education[];
}

interface ProfileEducationProps {
  profile: Profile;
  onUpdate: () => void;
}

const ProfileEducation: React.FC<ProfileEducationProps> = ({ profile, onUpdate }) => {
  const [isAdding, setIsAdding] = useState(false);

  const {
    register,
    handleSubmit,
    reset,
    watch,
    control,
    formState: { errors },
  } = useForm<AddEducationInput>({
    resolver: zodResolver(AddEducationSchema),
    defaultValues: {
      institution: '',
      degree: '',
      fieldOfStudy: '',
      startDate: '',
      endDate: '',
      isCurrent: false,
      type: 'Education',
    },
  });

  const isCurrent = watch('isCurrent');

  const onFormSubmit = async (data: AddEducationInput) => {
    try {
      await addEmployeeEducation(profile.id, data);
      setIsAdding(false);
      reset();
      onUpdate();
    } catch (err) {
      // Error handled silently
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm("Remove this record?")) {
      try {
        await deleteEmployeeEducation(profile.id, id);
        onUpdate();
      } catch (err) {
        // Error handled silently
      }
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center pb-4 border-b border-gray-100">
        <h2 className="text-sm font-black text-gray-700 uppercase tracking-wider">Education & Certifications</h2>
        <button
          onClick={() => setIsAdding(true)}
          className="bg-white hover:bg-gray-50 text-gray-900 border border-gray-300 px-5 py-2.5 rounded-lg flex items-center gap-2 shadow-sm transition-all active:scale-95 text-sm font-bold"
        >
          <Plus size={16} />
          <span>Add Record</span>
