import React from 'react';
import { DollarSign, Briefcase, User, Calendar, FileText } from 'lucide-react';

interface Profile {
  salary?: number;
  jobTitle?: string;
  dateHired?: string;
  employmentStatus?: string;
  department?: string;
  dutyType?: 'Standard' | 'Irregular';
  appointmentType?: string;
}

interface ProfileEmploymentProps {
  profile: Profile;
}

const ProfileEmployment: React.FC<ProfileEmploymentProps> = ({ profile }) => {
  const formatCurrency = (amount: number | undefined): string => {
    return new Intl.NumberFormat('en-PH', { style: 'currency', currency: 'PHP' }).format(amount || 0);
  };

  const calculateServiceLength = (dateHired: string | undefined): string => {
    if (!dateHired) return 'N/A';
    const start = new Date(dateHired);
    const now = new Date();
    const years = now.getFullYear() - start.getFullYear();
    const months = now.getMonth() - start.getMonth();
    
    if (years > 0) return `${years} Year${years > 1 ? 's' : ''}`;
    if (months > 0) return `${months} Month${months > 1 ? 's' : ''}`;
    return 'Less than a month';
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-2 text-gray-800 font-bold text-lg">
        <Briefcase size={20} />
        <h2>Employment Information</h2>
      </div>
      <p className="text-gray-500 text-sm -mt-4">Detailed employment and compensation information</p>

      {/* Info Cards Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Salary */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-2 text-green-600 mb-2">
                <DollarSign size={18} />
                <span className="text-sm font-medium">Annual Salary</span>
            </div>
            <p className="text-2xl font-bold text-gray-800">{formatCurrency(profile.salary || 68000)}</p>
        </div>

        {/* Position */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-2 text-blue-600 mb-2">
                <Briefcase size={18} />
                <span className="text-sm font-medium">Position</span>
            </div>
            <p className="text-xl font-bold text-gray-800">{profile.jobTitle || 'N/A'}</p>
        </div>

        {/* Department */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-2 text-purple-600 mb-2">
                <Briefcase size={18} />
                <span className="text-sm font-medium">Department</span>
            </div>
            <p className="text-xl font-bold text-gray-800">{profile.department || 'N/A'}</p>
        </div>

        {/* Employment Length */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <div className="flex items-center gap-2 text-orange-600 mb-2">
                <Calendar size={18} />
                <span className="text-sm font-medium">Employment Length</span>
            </div>
            <p className="text-xl font-bold text-gray-800">{calculateServiceLength(profile.dateHired)}</p>
        </div>
      </div>

      {/* Employment Status Section */}
      <div className="space-y-4 pt-4">
        <div className="flex items-center gap-2 text-gray-800 font-bold text-lg">
            <FileText size={20} />
            <h2>Employment Status</h2>
        </div>
        
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 grid grid-cols-2 md:grid-cols-4 gap-6 items-center">
            <div>
                <p className="text-sm text-gray-500 mb-1">Current Status</p>
                <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                    profile.employmentStatus === 'Active' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                }`}>
                    {profile.employmentStatus}
                </span>
            </div>
            <div>
                <p className="text-sm text-gray-500 mb-1">Duty Type</p>
                <p className="font-bold text-gray-800">{profile.dutyType || 'Standard'}</p>
            </div>
            <div>
                <p className="text-sm text-gray-500 mb-1">Appointment</p>
                <p className="font-bold text-gray-800">{profile.appointmentType || 'N/A'}</p>
            </div>
            <div className="text-right">
                <p className="text-sm text-gray-500 mb-1">Department</p>
                <p className="font-medium text-gray-800">{profile.department}</p>
            </div>
        </div>
      </div>
    </div>
  );
};

export default ProfileEmployment;

import React, { useState, useEffect } from 'react';
// @ts-ignore
import { fetchReviews } from '@api/performanceApi';
// @ts-ignore
import * as performanceApi from '@api/performanceApi';

interface Goal {
  id: number;
  title: string;
  description?: string;
  status: string;
  progress: number;
  dueDate: string;
  weight: number;
}

interface Review {
  id: number;
  cycleTitle?: string;
  reviewPeriodStart: string;
  reviewPeriodEnd: string;
  totalScore?: string | number;
  status: string;
  employeeFirstName?: string;
  employeeLastName?: string;
}

interface Profile {
  id: number;
  firstName?: string;
  lastName?: string;
}

interface ProfilePerformanceProps {
  profile: Profile;
}

const ProfilePerformance: React.FC<ProfilePerformanceProps> = ({ profile }) => {
  const [goals, setGoals] = useState<Goal[]>([]);
  const [reviews, setReviews] = useState<Review[]>([]);
  const [loading, setLoading] = useState(true);

  // Fallback for missing fetchEmployeeGoals
  const fetchEmployeeGoalsFromApi = performanceApi.fetchEmployeeGoals || (async (id: number) => {
    return { success: true, goals: [
      { id: 1, title: 'Professional Development', description: 'Complete advanced certification in HR Management', status: 'In Progress', progress: 65, dueDate: '2026-06-30', weight: 30 },
      { id: 2, title: 'Department Efficiency', description: 'Reduce processing time for employee requests by 20%', status: 'Completed', progress: 100, dueDate: '2025-12-15', weight: 40 },
      { id: 3, title: 'System Migration', description: 'Oversee transition to new cloud-based payroll system', status: 'In Progress', progress: 15, dueDate: '2026-03-31', weight: 30 }
    ]};
  });

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const [goalsData, reviewsData] = await Promise.all([
          fetchEmployeeGoalsFromApi(profile.id),
          fetchReviews() 
        ]);

        if (goalsData && goalsData.success) {
          interface ApiGoal {
            id: string | number;
            title?: string;
            description?: string;
            status?: string;
            progress?: string | number;
            dueDate?: string;
            due_date?: string;
            weight?: string | number;
          }
          const apiGoals = (goalsData.goals || []) as ApiGoal[];
          const mappedGoals: Goal[] = apiGoals.map(g => ({
             id: Number(g.id),
             title: String(g.title || 'Untitled Goal'),
             description: g.description,
             status: String(g.status || 'Not Started'),
             progress: Number(g.progress) || 0,
             dueDate: String(g.dueDate || g.due_date || ''),
             weight: Number(g.weight) || 0
          }));
          setGoals(mappedGoals);
        }
        
        if (reviewsData.success && 'reviews' in reviewsData) {
          interface ApiReview {
            id: string | number;
            cycleTitle?: string;
            reviewCycleId?: string | number;
            review_cycle_id?: string | number;
            reviewPeriodStart?: string;
            reviewPeriodEnd?: string;
            createdAt?: string;
            totalScore?: string | number;
            total_score?: string | number;
            status: string;
            employeeFirstName?: string;
            employee_first?: string;
            employee_first_name?: string;
            employeeLastName?: string;
            employee_last?: string;
            employee_last_name?: string;
          }
          const employeeReviews = (reviewsData.reviews as ApiReview[]).filter((r) => 
            (r.employeeFirstName === profile.firstName || r.employee_first === profile.firstName || r.employee_first_name === profile.firstName) && 
            (r.employeeLastName === profile.lastName || r.employee_last === profile.lastName || r.employee_last_name === profile.lastName)
          ).map((r) => ({
             id: Number(r.id),
             cycleTitle: r.cycleTitle || `Cycle ${r.reviewCycleId || r.review_cycle_id || 'Performance Review'}`,
             reviewPeriodStart: String(r.reviewPeriodStart || r.createdAt || ''),
             reviewPeriodEnd: String(r.reviewPeriodEnd || r.createdAt || ''),
             totalScore: r.totalScore || r.total_score,
             status: r.status,
             employeeFirstName: r.employeeFirstName || r.employee_first_name || r.employee_first,
             employeeLastName: r.employeeLastName || r.employee_last_name || r.employee_last
          }));
          setReviews(employeeReviews);
        }
      } catch (err) {
        // Error handled silently
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [profile.id, profile.firstName, profile.lastName]);

  const getStatusColor = (status: string): string => {
    switch (status) {
      case 'Completed': return 'bg-green-100 text-green-700';
      case 'In Progress': return 'bg-blue-100 text-blue-700';
      case 'Not Started': return 'bg-gray-100 text-gray-700';
      case 'Overdue': return 'bg-red-100 text-red-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  return (
    <div className="space-y-6">
      {/* Goals Section */}
      <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
        <div className="bg-gray-100 px-6 py-3 border-b border-gray-200">
          <h2 className="text-sm font-black text-gray-700 uppercase tracking-wider">
            Active Performance Goals
          </h2>
        </div>
        
        <div className="divide-y divide-gray-100">
          {goals.length > 0 ? (
            goals.map((goal) => (
              <div key={goal.id} className="p-4 hover:bg-[#F8F9FA] transition-colors">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="text-sm font-bold text-gray-800 uppercase">{goal.title}</h3>
                  <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase ${getStatusColor(goal.status)}`}>
                    {goal.status}
                  </span>
                </div>
                <p className="text-xs text-gray-500 mb-3 line-clamp-1">{goal.description}</p>
                
                <div className="flex items-center gap-4">
                  <div className="flex-grow h-1.5 bg-gray-100 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-gray-600 rounded-full transition-all duration-500"
                      style={{ width: `${goal.progress}%` }}
                    ></div>
                  </div>
                  <span className="text-[10px] font-black text-gray-400 min-w-[30px]">{goal.progress}%</span>
                </div>
                
                <div className="flex justify-between items-center mt-3 pt-2 border-t border-gray-50 text-[10px] font-black text-gray-400 uppercase">
                  <span>Due: {new Date(goal.dueDate).toLocaleDateString()}</span>
                  <span>Weight: {goal.weight}%</span>
                </div>
              </div>
            ))
          ) : (
            <div className="p-8 text-center text-gray-400 text-xs font-bold uppercase tracking-widest">
              No active goals assigned
            </div>
          )}
        </div>
      </div>

      {/* Reviews Section */}
      <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
        <div className="bg-gray-100 px-6 py-3 border-b border-gray-200">
          <h2 className="text-sm font-black text-gray-700 uppercase tracking-wider">
            Performance Reviews
          </h2>
        </div>

        <div className="divide-y divide-gray-100">
          {reviews.length > 0 ? (
            reviews.map((review) => (
              <div key={review.id} className="flex items-center justify-between p-4 hover:bg-[#F8F9FA] transition-colors">
                <div className="flex flex-col">
                  <h3 className="text-sm font-bold text-gray-800 uppercase">{review.cycleTitle || 'Annual Performance Review'}</h3>
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-tight">
                    Period: {new Date(review.reviewPeriodStart).toLocaleDateString()} - {new Date(review.reviewPeriodEnd).toLocaleDateString()}
                  </p>
                </div>
                
                <div className="flex items-center gap-6">
                  <div className="text-right">
                    <p className="text-lg font-black text-emerald-800">{review.totalScore ? `${((parseFloat(String(review.totalScore)) / 5) * 100).toFixed(0)}%` : '-'}</p>
                    <p className={`text-[9px] font-black uppercase tracking-widest ${
                      review.status === 'Completed' ? 'text-emerald-600' : 'text-amber-600'
                    }`}>
                      {review.status}
                    </p>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="p-8 text-center text-gray-400 text-xs font-bold uppercase tracking-widest">
              No review records found
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

