import { EmployeeLeaveRequest } from '@/components/Custom/Timekeeping/LeaveRequestComponents/Employee/types';
import type { LeaveApplication, ApplicationStatus } from '@/types/leave.types';

export const useLeaveData = (initialFilters?: Record<string, string>) => {
  const queryClient = useQueryClient();
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [filters, setFilters] = useState<{
    search: string;
    startDate: string;
    endDate: string;
    status: ApplicationStatus | '';
    type: string;
  }>({
    search: '',
    startDate: '',
    endDate: '',
    status: '' as ApplicationStatus | '',
    type: ''
  });

  const { data, isLoading: loading, error } = useQuery({
    queryKey: ['employee-leaves', page, limit, filters],
    queryFn: async () => {
      const params = {
        page,
        limit,
        search: filters.search,
        startDate: filters.startDate,
        endDate: filters.endDate,
        status: filters.status
        // Note: 'type' filter logic might need to be added to backend or matched with existing backend logic
        // For now, let's assume 'search' covers general text, and we have specific fields.
        // Wait, the backend updated code handles 'leaveType' via search only?
        // Let's check backend update...
        // Backend: `if (search) whereClause += ' AND (lr.leaveType LIKE ? OR lr.reason LIKE ?)';`
        // It doesn't have a specific `leaveType` filter yet in backend.
        // But `useFilters` has a `type` filter.
        // I should probably add `type` to backend or rely on search.
        // Let's rely on search for now or update backend again if strictly needed.
        // Actually, for better UX, a specific type filter is better.
        // I'll keep it as is for now and maybe update backend if I see the need.
      };
      
      const response = await leaveApi.getMyApplications(params);
      
      const leaves = (response.data?.applications || []).map((l: LeaveApplication) => ({
        id: l.id,
        employeeId: l.employeeId,
        leaveType: l.leaveType,
        fromDate: l.startDate,
        toDate: l.endDate,
        reason: l.reason,
        status: l.status,
        isWithPay: l.isWithPay,
        attachmentPath: l.attachmentPath,
        department: l.department ?? 'N/A',
        name: `${l.firstName || ''} ${l.lastName || ''}`.trim() || 'N/A'
      }));

      return {
        leaves,
        pagination: response.data?.pagination || { page: 1, limit: 10, totalPages: 1, totalItems: 0 }
      };
    },
    staleTime: 1000 * 60 * 5, // 5 minutes
    placeholderData: keepPreviousData
  });

  const refreshLeaves = async () => {
    await queryClient.invalidateQueries({ queryKey: ['employee-leaves'] });
  };

  const updateFilters = (newFilters: Partial<typeof filters>) => {
    setFilters(prev => ({ ...prev, ...newFilters }));
    setPage(1);
  };

  return { 
    leaves: data?.leaves || [], 
    pagination: data?.pagination || { page: 1, limit: 10, totalPages: 1, totalItems: 0 },
    loading, 
    error: error ? (error as Error).message : null, 
    refreshLeaves,
    setPage, // Exported for Pagination component
    updateFilters // Exported for Filters component
  };
};

import React from 'react';
import { Search } from 'lucide-react';
import { SourceFilter } from '../Hooks/useApplicantFilters';
import Combobox from '@/components/Custom/Combobox';

interface ApplicantFiltersProps {
  searchTerm: string;
  setSearchTerm: (value: string) => void;
  sourceFilter: SourceFilter;
  setSourceFilter: (value: SourceFilter) => void;
}

const ApplicantFilters: React.FC<ApplicantFiltersProps> = ({ 
  searchTerm, 
  setSearchTerm, 
  sourceFilter, 
  setSourceFilter 
}) => {
  const sourceOptions: { value: SourceFilter; label: string }[] = [
    { value: 'All', label: 'All Sources' },
    { value: 'Web', label: 'Website' },
    { value: 'Email', label: 'Email' }
  ];

  return (
    <div className="flex flex-col sm:flex-row gap-4 mb-6 justify-between">
      <div className="relative flex-1 max-w-md">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
        <input 
          type="text" 
          placeholder="Search applicants..." 
          className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-gray-200 focus:border-gray-300 bg-white"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>
      <Combobox 
        options={sourceOptions}
        value={sourceFilter}
        onChange={(val) => setSourceFilter(val as SourceFilter)}
        placeholder="Filter Source"
        className="w-40"
        buttonClassName="bg-gray-100 border-gray-200 text-gray-700 py-2"
      />
    </div>
  );
};

export default ApplicantFilters;

import React from 'react';
import { User, UserPlus, Video, Mail, Globe, VideoIcon, Trash2, RotateCcw, Eye, ExternalLink, CalendarPlus, Archive, CheckCircle } from 'lucide-react';
import LoadingOverlay from '@/components/Custom/Shared/LoadingOverlay';
import TableSkeleton from '@/components/Custom/Shared/TableSkeleton';
import type { Applicant } from '@/types/recruitment';
interface ApplicantTableProps {
  loading: boolean;
  isRefetching: boolean;
  filteredApplicants: Applicant[];
  onAssign: (applicant: Applicant) => void;
  onSchedule: (applicant: Applicant) => void;
  onJoinInterview?: (applicant: Applicant) => void;
  onReject: (applicant: Applicant) => void;
  onRestore: (applicant: Applicant) => void;
  onViewDocuments: (applicant: Applicant) => void;
  onDelete: (applicant: Applicant) => void;
  onViewDetails: (applicant: Applicant) => void;
  onConfirm?: (applicant: Applicant) => void;
  isArchiveHired?: boolean;
}

const ApplicantTable: React.FC<ApplicantTableProps> = ({ 
  loading, 
  isRefetching, 
  filteredApplicants, 
  onAssign, 
  onSchedule,
  onJoinInterview,
  onReject,
  onRestore,
  onViewDocuments,
  onDelete,
  onViewDetails,
  onConfirm,
  isArchiveHired = false
}) => {

  const formatDate = (dateString: string | undefined): string => {
    if (!dateString) return '-';
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric', month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
    });
  };

  const getSourceBadge = (source: string | undefined) => (
    <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded bg-gray-100 text-gray-600 text-[10px] font-bold uppercase tracking-wider border border-gray-200">
      {source === 'email' ? <Mail size={10} /> : <Globe size={10} />} {source || 'Unknown'}
    </span>
  );

  const getStatusBadgeColor = (status: string | undefined): string => {
    switch (status) {
      case 'Hired': return 'bg-gray-900 text-white border-gray-900';
      case 'Rejected': return 'bg-gray-100 text-gray-400 border-gray-200 italic';
      default: return 'bg-white text-gray-700 border-gray-200 shadow-sm';
    }
  };

  const hasScheduledInterview = (app: Applicant): boolean => {
    return !!(app.interviewLink && (app.stage === 'Initial Interview' || app.stage === 'Final Interview'));
  };

  if (loading) return <TableSkeleton rows={10} cols={5} />;

  return (
    <div className="flex-1 overflow-hidden rounded-xl bg-[#F8F9FA] p-1 relative min-h-[400px]">
      <LoadingOverlay isVisible={isRefetching} message="Refreshing data..." />
      <div className="overflow-x-auto bg-gray-50 rounded-lg h-full">
        <table className="w-full min-w-[1000px]">
          <thead className="bg-gray-200 shadow-md text-gray-700">
            {isArchiveHired ? (
              <tr>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Applicant Name</th>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Position</th>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Department</th>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Duty Type</th>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Schedule</th>
              </tr>
            ) : (
              <tr>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Applicant</th>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Applied For</th>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Interviewer</th>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Documents</th>
                <th className="px-6 py-4 text-left text-sm font-bold tracking-wide whitespace-nowrap">Status</th>
                <th className="px-6 py-4 text-center text-sm font-bold tracking-wide whitespace-nowrap">Actions</th>
              </tr>
            )}
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredApplicants.map((app) => (
              <tr key={app.id} className="hover:bg-[#F8F9FA] hover:shadow-xl transition-colors">
                {isArchiveHired ? (
                  <>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="bg-gray-100 p-2 rounded-full text-gray-500"><User size={18} /></div>
                        <div>
                          <div className="font-medium text-gray-900">{app.firstName} {app.lastName}</div>
                          <div className="text-sm text-gray-500">{app.email}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm font-medium text-gray-900">{app.jobTitle || 'General Application'}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm text-gray-700">{app.jobDepartment || 'HR'}</div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2.5 py-1 rounded-md text-[10px] font-bold uppercase ${
                        app.jobDutyType === 'Irregular' ? 'bg-amber-50 text-amber-700 border border-amber-200' : 'bg-blue-50 text-blue-700 border border-blue-200'
                      }`}>
                        {app.jobDutyType || 'Standard'}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1.5">
                        <span className="px-2.5 py-1 rounded-md text-[10px] font-bold uppercase bg-gray-100 text-gray-700 border border-gray-200 w-fit">
                            {app.jobEmploymentType || 'Permanent'}
                        </span>
                        {app.isConfirmed && (
                            <div className="flex items-center gap-1 text-emerald-600 font-bold text-[10px] uppercase">
                                <CheckCircle size={10} /> Confirmed for Duty
                            </div>
                        )}
                      </div>
                    </td>
                  </>
                ) : (
                  <>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="bg-gray-100 p-2 rounded-full text-gray-500"><User size={18} /></div>
                        <div>
                          <div className="font-medium text-gray-900">{app.firstName} {app.lastName}</div>
                          <div className="text-sm text-gray-500">{app.email}</div>
                          <div className="mt-1">{getSourceBadge(app.source)}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="text-sm font-medium text-gray-900">
                        {app.jobId === null || app.jobId === undefined ? (
                            <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-gray-100 text-gray-800">
                                General Application
                            </span>
                        ) : (
                            app.jobTitle
                        )}
                      </div>
                      <div className="text-xs text-gray-500">{formatDate(app.createdAt)}</div>
                    </td>
                    <td className="px-6 py-4">
                      {app.interviewerName ? (
                        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded bg-gray-100 text-gray-700 text-xs font-medium border border-gray-200">
                          <User size={12} /> {app.interviewerName}
                        </span>
                      ) : (
                        <span className="text-xs text-gray-400 italic">Unassigned</span>
                      )}
                    </td>
                    <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                            <button 
                                onClick={() => onViewDocuments(app)}
                                className="flex items-center gap-2 px-3 py-1 bg-white border border-gray-200 text-gray-600 hover:bg-gray-50 hover:text-gray-900 rounded-md transition-all shadow-sm"
                                title="View All Documents"
                            >
                                <Eye size={14} />
                                <span className="text-[11px] font-bold">Documents</span>
                            </button>
                        </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-2.5 py-1 rounded-full text-[11px] font-semibold ${getStatusBadgeColor(app.status)}`}>{app.status || app.stage}</span>
                    </td>
                    <td className="px-6 py-4">
                        <div className="flex justify-center gap-3">
                            {/* Confirm for Duty Button (Only for Hired) */}
                            {app.stage === 'Hired' && onConfirm && (
                                <button 
                                    onClick={() => onConfirm(app)}
                                    className="text-emerald-600 hover:text-emerald-800 transition-colors"
                                    title="Confirm for Registration & Duty"
                                >
                                    <CheckCircle size={18} />
                                </button>
                            )}

                            <button 
                                onClick={() => onViewDetails(app)}
                                className="text-gray-500 hover:text-gray-900 transition-colors"
                                title="View Full Profile"
                            >
                                <ExternalLink size={18} />
                            </button>

                            {!app.interviewerName && (
                                <button 
                                    onClick={() => onAssign(app)}
                                    className="text-gray-500 hover:text-gray-900 transition-colors"
                                    title="Assign Interviewer"
                                >
                                    <UserPlus size={18} />
                                </button>
                            )}

                            {app.interviewerName && !['Hired', 'Rejected'].includes(app.stage) && (
                                <button 
                                    onClick={() => onSchedule(app)}
                                    className="text-slate-500 hover:text-slate-900 transition-colors"
                                    title="Schedule Interview"
                                >
                                    <CalendarPlus size={18} />
                                </button>
                            )}

                            {hasScheduledInterview(app) && onJoinInterview && (
                                <button 
                                    onClick={() => onJoinInterview(app)}
                                    className="flex items-center gap-1 px-2.5 py-1 bg-gray-900 border border-gray-900 hover:bg-gray-800 text-white rounded text-[10px] font-bold transition-colors shadow-sm"
                                    title="Join Interview"
                                >
                                    <VideoIcon size={12} />
                                    Join
                                </button>
                            )}

                            {!['Hired', 'Rejected'].includes(app.stage) && (
                                <button 
                                    onClick={() => onReject(app)}
                                    className="text-gray-500 hover:text-gray-800 transition-colors"
                                    title="Reject/Archive Applicant"
                                >
                                    <Archive size={18} />
                                </button>
                            )}

                            {app.stage === 'Rejected' && (
                                <button 
                                    onClick={() => onRestore(app)}
                                    className="text-gray-500 hover:text-gray-900 transition-colors"
                                    title="Restore Applicant"
                                >
                                    <RotateCcw size={18} />
                                </button>
                            )}

                            {app.stage === 'Rejected' && (
                                <button 
                                    onClick={() => onDelete(app)}
                                    className="text-gray-500 hover:text-gray-800 transition-colors"
                                    title="Permanently Delete Applicant"
                                >
                                    <Trash2 size={18} />
                                </button>
                            )}
                        </div>
                    </td>
                  </>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default ApplicantTable;

import React, { useEffect, useRef, useState } from 'react';
import { 
  Video, PhoneOff, FileText, User, Calendar, Clock, 
  Maximize2, MessageSquare, Copy, CheckCircle2, ChevronRight,
  Monitor, Wifi, Sparkles, ExternalLink, Save, Loader2 
} from 'lucide-react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { saveInterviewNotesSchema, SaveInterviewNotesFormData } from '../../../../schemas/recruitmentSchema';
import useInterviewStore from '../../../../stores/useInterviewStore';
import { useInterviewActions } from '../Hooks/useInterviewActions';

interface InterviewPanelProps {
  roomName: string;
  displayName: string;
  onClose: () => void;
  applicantId: number; // Added applicantId
  applicantName?: string;
  applicantEmail?: string;
  jobTitle?: string;
  interviewLink?: string;
  resumePath?: string;
}

const InterviewPanel: React.FC<InterviewPanelProps> = ({
  displayName,
  onClose,
  applicantId,
  applicantName,
  applicantEmail,
  jobTitle,
  interviewLink,
  resumePath
}) => {
  // Zustand Store
  const { 
    isCallActive, 
    setCallActive, 
    startInterview: storeStartInterview, 
    endInterview: storeEndInterview 
  } = useInterviewStore();

  // React Query Mutation
  const { saveInterviewNotesMutation } = useInterviewActions();

  // Local State
  const [copied, setCopied] = useState(false);
  const videoWindowRef = useRef<Window | null>(null);

  // React Hook Form
  const { 
    register, 
    handleSubmit, 
    formState: { isDirty, isSubmitting } 
  } = useForm<SaveInterviewNotesFormData>({
    resolver: zodResolver(saveInterviewNotesSchema),
    defaultValues: {
      applicantId: applicantId,
      notes: '',
      rating: undefined,
      duration: undefined
    }
  });

  const startVideoCall = () => {
    if (interviewLink) {
      videoWindowRef.current = window.open(
        interviewLink,
        'InterviewCall',
        'width=1280,height=720,menubar=no,toolbar=no,location=no,status=no'
      );
      storeStartInterview(applicantId);
      setCallActive(true);
    }
  };

  const endInterview = () => {
    if (videoWindowRef.current && !videoWindowRef.current.closed) {
      videoWindowRef.current.close();
    }
    // Automatically save notes on end
    handleSubmit(onSaveNotes)();
    storeEndInterview();
    onClose();
  };

  const copyLink = () => {
    if (interviewLink) {
      navigator.clipboard.writeText(interviewLink);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const onSaveNotes = (data: SaveInterviewNotesFormData) => {
    saveInterviewNotesMutation.mutate({ ...data, id: applicantId });
  };

  return (
    <div className="fixed inset-0 z-50 bg-gray-900 flex font-sans overflow-hidden">
      
      {/* LEFT PANEL - CONTROLS & INFO */}
      <div className="w-[420px] bg-slate-900 text-slate-200 flex flex-col border-r border-slate-800 shadow-2xl relative z-10">
        
        {/* Header */}
        <div className="p-6 bg-slate-900 border-b border-slate-800 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-[#F8F9FC] flex items-center justify-center shadow-lg shadow-gray-500/20">
              <Video size={20} className="text-slate-950" />
            </div>
            <div>
              <h2 className="font-bold text-base text-white tracking-tight">Interview Session</h2>
              <div className="flex items-center gap-1.5 mt-0.5">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Live Panel</p>
              </div>
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8 custom-scrollbar">
          
          {/* APPLICANT CARD */}
          <div className="relative group">
            <div className="absolute -inset-0.5 bg-gray-900/20 rounded-2xl opacity-20 group-hover:opacity-40 transition duration-500"></div>
            <div className="relative bg-slate-800/80 rounded-xl p-5 border border-gray-900/50">
              <div className="flex items-start gap-4">
                <div className="w-14 h-14 rounded-full bg-gradient-to-br from-slate-700 to-slate-600 p-0.5 shadow-inner">
                  <div className="w-full h-full rounded-full bg-slate-800 flex items-center justify-center overflow-hidden">
                    <User size={28} className="text-slate-400" />
                  </div>
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="text-lg font-bold text-white truncate">{applicantName || 'Applicant Name'}</h3>
                  <p className="text-sm text-slate-400 truncate mb-2">{applicantEmail || 'email@example.com'}</p>
                  
                  {jobTitle && (
                    <div className="inline-flex items-center gap-1.5 px-2 py-0.5 rounded bg-slate-700/50 border border-slate-600/50 text-[10px] font-bold uppercase tracking-wider text-slate-300">
                       <Sparkles size={10} className="text-amber-400" />
                       {jobTitle}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>

          {/* MAIN ACTION - VIDEO CALL */}
          <div className="space-y-4">
            <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
              <Monitor size={12} /> Connection
            </h4>
            
            {!isCallActive ? (
              <button
                onClick={startVideoCall}
                className="w-full group relative overflow-hidden rounded-xl bg-[#F8F9FC] p-px shadow-xl shadow-gray-900/40 transition-all hover:scale-[1.02] active:scale-[0.98]"
              >
                <div className="relative h-14 w-full bg-transparent flex items-center justify-center gap-3 rounded-xl transition-all group-hover:bg-white/5">
                  <div className="w-8 h-8 rounded-full bg-white/20 flex items-center justify-center overflow-hidden">
                    <Video size={16} className="text-gray-950" />
                  </div>
                  <span className="font-bold text-gray-950 text-lg">Start Video Call</span>
                  <ChevronRight size={20} className="text-gray-950/50 group-hover:translate-x-1 transition-transform" />
                </div>
              </button>
            ) : (
              <div className="bg-green-500/10 border border-green-500/20 rounded-xl p-5 flex flex-col gap-4 animate-in fade-in zoom-in-95 duration-300">
                <div className="flex items-center gap-3 text-green-400">
                  <div className="w-8 h-8 rounded-full bg-green-500/20 flex items-center justify-center animate-pulse">
                    <Wifi size={16} />
                  </div>
                  <div>
                    <h3 className="font-bold text-sm">Call in Progress</h3>
                    <p className="text-xs text-green-500/70">Video window is active</p>
                  </div>
                </div>
                <button
                  onClick={startVideoCall}
                  className="w-full py-2.5 bg-gray-800 hover:bg-gray-700 text-gray-200 rounded-lg font-medium text-sm flex items-center justify-center gap-2 transition-colors border border-gray-700"
                >
                  <Maximize2 size={16} />
                  Focus Video Window
                </button>
              </div>
            )}
          </div>

          {/* MEETING LINK */}
          {interviewLink && (
            <div className="space-y-3">
               <div className="flex items-center justify-between">
                <h4 className="text-xs font-bold text-gray-500 uppercase tracking-wider">Meeting Link</h4>
                <div className="flex items-center gap-1.5">
                   <span className="w-1.5 h-1.5 rounded-full bg-amber-500"></span>
                   <span className="text-[10px] text-amber-500 font-medium">For Applicant & Interviewer</span>
                </div>
               </div>
               
               <div className="group relative">
                 <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                   <Video size={14} className="text-gray-500" />
                 </div>
                 <input 
                    type="text" 
                    readOnly 
                    value={interviewLink} 
                    className="w-full bg-gray-950 border border-gray-800 text-gray-400 text-xs rounded-lg py-3 pl-9 pr-24 focus:outline-none focus:border-gray-500/50 focus:ring-1 focus:ring-gray-500/50 transition-all font-mono"
                 />
                 <button 
                    onClick={copyLink}
                    className="absolute inset-y-1 right-1 px-3 bg-gray-800 hover:bg-gray-700 rounded-md text-xs font-medium text-gray-300 transition-colors flex items-center gap-1.5 border border-gray-700"
                 >
                    {copied ? <CheckCircle2 size={12} className="text-green-400" /> : <Copy size={12} />}
                    {copied ? 'Copied' : 'Copy'}
                 </button>
               </div>
               <p className="text-[12px] text-gray-500 leading-relaxed px-1">
                 Share this exact link if the applicant hasn't received it yet. Both parties must join this URL.
               </p>
            </div>
          )}

          {/* RESOURCES */}
          <div className="space-y-3">
             <h4 className="text-xs font-bold text-gray-500 uppercase tracking-wider">Resources</h4>
             {resumePath ? (
               <a
                 href={`http://localhost:5000/uploads/resumes/${resumePath}`}
                 target="_blank"
                 rel="noopener noreferrer"
                 className="flex items-center gap-3 p-3 rounded-lg bg-gray-800/50 border border-gray-800 hover:bg-gray-800 hover:border-gray-700 transition-all group"
               >
                 <div className="w-10 h-10 rounded-lg bg-gray-700 flex items-center justify-center text-gray-400 group-hover:text-white transition-colors">
                   <FileText size={20} />
                 </div>
                 <div className="flex-1">
                   <div className="font-medium text-sm text-slate-200 group-hover:text-white">Applicant Resume</div>
                   <div className="text-xs text-slate-500">PDF Document</div>
                 </div>
                 <ExternalLink size={14} className="text-slate-600 group-hover:text-slate-400" />
               </a>
             ) : (
                <div className="p-4 rounded-lg bg-slate-800/30 border border-slate-800 border-dashed text-center">
                  <span className="text-xs text-slate-500">No resume available</span>
                </div>
             )}
          </div>
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-slate-800 bg-slate-900/50">
          <button
            onClick={endInterview}
            className="w-full py-3.5 bg-rose-500/10 hover:bg-rose-500/20 text-rose-500 hover:text-rose-400 border border-rose-500/20 rounded-xl font-bold text-sm flex items-center justify-center gap-2 transition-all"
          >
            <PhoneOff size={16} />
            End Interview Session
          </button>
        </div>
      </div>

      {/* RIGHT PANEL - NOTES */}
      <div className="flex-1 flex flex-col bg-[#F8F9FC] relative">
        <div className="absolute inset-0 bg-[url('https://optimizely.com/img/backgrounds/grid.svg')] opacity-[0.03] pointer-events-none"></div>
        
        {/* Notes Header */}
        <div className="h-16 px-8 bg-white/80 border-b border-gray-200/60 sticky top-0 flex items-center justify-between z-10">
          <div className="flex items-center gap-3">
            <h3 className="p-2 font-bold text-lg text-gray-800">Interview Notes</h3>
            {isDirty && <span className="text-xs text-amber-500 font-medium px-2 py-0.5 bg-amber-50 rounded-full border border-amber-200">Unsaved Changes</span>}
          </div>
          <div className="flex items-center gap-4">
             <button
               onClick={handleSubmit(onSaveNotes)}
               disabled={isSubmitting || !isDirty}
               className="flex items-center gap-2 px-4 py-2 bg-gray-900 hover:bg-gray-800 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-lg text-sm font-medium transition-colors border border-gray-700 shadow-sm"
             >
               {isSubmitting ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
               Save Notes
             </button>

             <div className="h-6 w-px bg-gray-300 mx-2" />

             <div className="flex items-center gap-6 text-sm font-medium text-gray-500">
              <div className="flex items-center gap-2 px-3 py-1.5 bg-white border border-gray-200 rounded-md shadow-sm">
                <Calendar size={14} className="text-gray-500" />
                <span>{new Date().toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' })}</span>
              </div>
              <div className="flex items-center gap-2 px-3 py-1.5 bg-white border border-gray-200 rounded-md shadow-sm">
                <Clock size={14} className="text-gray-500" />
                <span>{new Date().toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' })}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Notes Editor Area */}
        <div className="flex-1 p-8 overflow-y-auto">
          <div className="max-w-5xl mx-auto h-full flex flex-col gap-2">
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 h-full flex flex-col ring-4 ring-gray-50/50 transition-shadow hover:shadow-md">
              <div className="flex items-center gap-2 p-2 border-b border-gray-100 bg-gray-50/50 rounded-t-xl overflow-x-auto">
                  {['Technical Skills', 'Communication', 'Cultural Fit', 'Experience', 'Questions', 'Decision'].map((tag) => (
                    <span key={tag} className="px-3 py-1 bg-white border border-gray-200 rounded-md text-[11px] font-semibold text-gray-500 cursor-default select-none shadow-sm">
                      {tag}
                    </span>
                  ))}
              </div>
              <textarea
                {...register('notes')}
                className="flex-1 w-full p-8 resize-none focus:outline-none text-gray-700 text-base leading-relaxed placeholder:text-gray-300 rounded-b-xl"
                placeholder="Start typing your interview notes here..."
              />
              <div className="px-4 py-2 bg-gray-50 border-t border-gray-100 rounded-b-xl flex justify-end">
                <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">
                  {isSubmitting ? 'Saving...' : 'Auto-save enabled on exit'}
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default InterviewPanel;

import React, { useEffect, useState } from 'react';
import { inquiryApi, Inquiry } from '@/api/inquiryApi';
import { useToastStore } from '@/stores';
import { CheckCircle, Clock, Trash2, Search } from 'lucide-react';
import ConfirmDialog from '@/components/Custom/Shared/ConfirmDialog';

const PublicInquiries: React.FC = () => {
    const [inquiries, setInquiries] = useState<Inquiry[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('All');
    const showToast = useToastStore((state) => state.showToast);
    
    // Custom Confirm Modal State
    const [confirmModal, setConfirmModal] = useState({
        isOpen: false,
        idToDelete: 0
    });

    const fetchInquiries = async () => {
        try {
            setLoading(true);
            const response = await inquiryApi.getAll();
            if (response.data.success) {
                setInquiries(response.data.inquiries);
            }
        } catch (error) {
            console.error('Failed to fetch inquiries:', error);
            showToast('Failed to load inquiries', 'error');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchInquiries();
    }, []);

    const handleUpdateStatus = async (id: number, status: string) => {
        try {
            const response = await inquiryApi.updateStatus(id, { status });
            if (response.data.success) {
                showToast(`Inquiry marked as ${status}`, 'success');
                fetchInquiries();
            }
        } catch (error) {
            showToast('Failed to update status', 'error');
        }
    };

    const handleDelete = async (id: number) => {
        setConfirmModal({ isOpen: true, idToDelete: id });
    };

    const confirmDelete = async () => {
        const id = confirmModal.idToDelete;
        if (!id) return;
        
        try {
            const response = await inquiryApi.delete(id);
            if (response.data.success) {
                showToast('Inquiry deleted', 'success');
                fetchInquiries();
            }
        } catch (error) {
            showToast('Failed to delete inquiry', 'error');
        } finally {
            setConfirmModal({ isOpen: false, idToDelete: 0 });
        }
    };

    const filteredInquiries = inquiries.filter(inq => {
        const matchesSearch = 
            `${inq.firstName} ${inq.lastName}`.toLowerCase().includes(searchTerm.toLowerCase()) ||
            inq.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
            inq.message.toLowerCase().includes(searchTerm.toLowerCase());
        
        const matchesStatus = statusFilter === 'All' || inq.status === statusFilter;
        
        return matchesSearch && matchesStatus;
    });

    return (
        <div className="space-y-6">
            <div className="flex flex-wrap gap-3 items-center justify-between">
                <div className="relative flex-1 min-w-[300px]">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input
                        type="text"
                        placeholder="Search inquiries..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-slate-300 outline-none text-sm transition-all"
                    />
                </div>
                <div className="flex items-center gap-1 bg-white border border-slate-200 rounded-lg p-1">
                    {['All', 'Pending', 'Read', 'Replied'].map((status) => (
                        <button
                            key={status}
                            onClick={() => setStatusFilter(status)}
                            className={`px-3 py-1.5 rounded-md text-xs font-medium whitespace-nowrap transition-all ${
                                statusFilter === status
                                    ? 'bg-slate-100 text-slate-800'
                                    : 'text-slate-400 hover:text-slate-600'
                            }`}
                        >
                            {status === 'All' ? 'All Status' : status}
                        </button>
                    ))}
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center py-12">
                    <div className="animate-spin rounded-full h-6 w-6 border-2 border-slate-300 border-t-slate-600"></div>
                </div>
            ) : filteredInquiries.length === 0 ? (
                <div className="text-center py-12 bg-white rounded-lg border border-slate-200">
                    <p className="text-sm text-slate-500">No inquiries found</p>
                </div>
            ) : (
                <div className="bg-white border border-slate-200 rounded-lg overflow-hidden">
                    <table className="w-full text-left">
                        <thead>
                            <tr className="border-b border-slate-200 bg-slate-50">
                                <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Sender</th>
                                <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Message</th>
                                <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Status</th>
                                <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Date</th>
                                <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {filteredInquiries.map((inq) => (
                                <tr key={inq.id} className="hover:bg-slate-50/50 transition-colors">
                                    <td className="px-6 py-4">
                                        <div className="min-w-0">
                                            <p className="text-sm font-medium text-slate-800 truncate">{inq.firstName} {inq.lastName}</p>
                                            <p className="text-xs text-slate-400 truncate">{inq.email}</p>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <p className="text-xs text-slate-600 max-w-[300px] truncate" title={inq.message}>
                                            {inq.message}
                                        </p>
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className="inline-flex items-center px-2.5 py-1 rounded text-[11px] font-medium bg-slate-100 text-slate-600 border border-slate-200">
                                            {inq.status}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-1.5">
                                            <Clock size={12} className="text-slate-300" />
                                            <span className="text-xs text-slate-500">
                                                {new Date(inq.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                                            </span>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-1">
                                            {inq.status === 'Pending' && (
                                                <button 
                                                    onClick={() => handleUpdateStatus(inq.id, 'Read')}
                                                    className="px-2.5 py-1.5 text-xs font-medium text-slate-600 bg-slate-50 border border-slate-200 rounded-lg hover:bg-slate-100 transition-all"
                                                >
                                                    Mark Read
                                                </button>
                                            )}
                                            {inq.status !== 'Replied' && (
                                                <button 
                                                    onClick={() => handleUpdateStatus(inq.id, 'Replied')}
                                                    className="px-2.5 py-1.5 text-xs font-medium text-slate-600 bg-slate-50 border border-slate-200 rounded-lg hover:bg-slate-100 transition-all flex items-center gap-1"
                                                >
                                                    <CheckCircle size={12} />
                                                    Replied
                                                </button>
                                            )}
                                            <button 
                                                onClick={() => handleDelete(inq.id)}
                                                className="p-1.5 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-lg transition-all"
                                            >
                                                <Trash2 size={14} />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}

            <ConfirmDialog
                isOpen={confirmModal.isOpen}
                title="Delete Inquiry"
                message="Are you sure you want to permanently delete this inquiry? This cannot be undone."
                isDestructive={true}
                confirmText="Delete"
                onClose={() => setConfirmModal({ isOpen: false, idToDelete: 0 })}
                onConfirm={confirmDelete}
            />
        </div>
    );
};

export default PublicInquiries;

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { recruitmentApi, SecurityLog } from '@/api/recruitmentApi';
import { Search, Loader2, User, Clock } from 'lucide-react';

type ViolationType = 'Spam Bot' | 'Disposable Email' | 'Automated Script' | 'Invalid Email Domain';

const VIOLATION_LABELS: Record<ViolationType, string> = {
  'Spam Bot':             'Spam Bot',
  'Disposable Email':     'Disposable Email',
  'Automated Script':     'Automated Script',
  'Invalid Email Domain': 'Invalid Domain',
};

const getViolationLabel = (type: string): string => {
  return VIOLATION_LABELS[type as ViolationType] || type;
};

const SecurityAuditLogs = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('All');

  const { data, isLoading } = useQuery({
    queryKey: ['security-logs'],
    queryFn: () => recruitmentApi.getSecurityLogs(),
    refetchInterval: 30000,
  });

  const logs: SecurityLog[] = data?.data.logs || [];

  const filteredLogs = logs.filter((log) => {
    const matchesSearch =
      `${log.firstName} ${log.lastName}`.toLowerCase().includes(searchTerm.toLowerCase()) ||
      log.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (log.details || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
      (log.ipAddress || '').includes(searchTerm);

    const matchesFilter = filterType === 'All' || log.violationType === filterType;
    return matchesSearch && matchesFilter;
  });

  const violationTypes = ['All', ...Object.keys(VIOLATION_LABELS)];

  // Stats
  const statCounts = {
    total: logs.length,
    today: logs.filter(l => {
      if (!l.createdAt) return false;
      const d = new Date(l.createdAt);
      const now = new Date();
      return d.toDateString() === now.toDateString();
    }).length,
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl font-bold text-slate-800 tracking-tight">
            Security Audit Logs
          </h2>
          <p className="text-sm text-slate-500 mt-1">
            Blocked threats detected during job applications · Auto-refreshes every 30s
          </p>
        </div>
        <div className="flex items-center gap-3 text-sm">
          <span className="text-slate-500">{statCounts.total} total</span>
          <span className="text-slate-400">·</span>
          <span className="text-slate-500">{statCounts.today} today</span>
        </div>
      </div>

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
          <input
            type="text"
            placeholder="Search by name, email, IP address, or details..."
            className="w-full pl-11 pr-4 py-2.5 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-slate-300 outline-none text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex items-center gap-1 bg-white border border-slate-200 rounded-lg p-1 overflow-x-auto">
          {violationTypes.map((type) => (
            <button
              key={type}
              onClick={() => setFilterType(type)}
              className={`px-3 py-1.5 rounded-md text-xs font-medium whitespace-nowrap transition-all ${
                filterType === type
                  ? 'bg-slate-100 text-slate-800'
                  : 'text-slate-400 hover:text-slate-600'
              }`}
            >
              {type === 'All' ? 'All' : getViolationLabel(type)}
            </button>
          ))}
        </div>
      </div>

      {/* Table */}
      <div className="bg-white border border-slate-200 rounded-lg overflow-hidden">
        <div className="overflow-x-auto">
          {isLoading ? (
            <div className="p-16 flex flex-col items-center gap-3">
              <Loader2 className="animate-spin text-slate-400" size={24} />
              <p className="text-xs text-slate-400 uppercase tracking-wider">Scanning security logs...</p>
            </div>
          ) : filteredLogs.length === 0 ? (
            <div className="p-16 flex flex-col items-center text-center gap-2">
              <p className="text-sm text-slate-500">
                {logs.length === 0 ? 'No violations recorded yet — the system is clean.' : 'No results match your search.'}
              </p>
              {logs.length > 0 && (
                <button 
                  onClick={() => { setSearchTerm(''); setFilterType('All'); }}
                  className="text-xs text-slate-600 underline underline-offset-4 hover:text-slate-800"
                >
                  Clear filters
                </button>
              )}
            </div>
          ) : (
            <table className="w-full text-left">
              <thead>
                <tr className="border-b border-slate-200 bg-slate-50">
                  <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Timestamp</th>
                  <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Applicant</th>
                  <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Violation</th>
                  <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Details</th>
                  <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">Job</th>
                  <th className="px-6 py-3 text-[11px] font-semibold text-slate-500 uppercase tracking-wider">IP</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredLogs.map((log) => {
                  return (
                    <tr key={log.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <Clock size={12} className="text-slate-300" />
                          <div>
                            <p className="text-xs font-medium text-slate-700">
                              {log.createdAt ? new Date(log.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : '—'}
                            </p>
                            <p className="text-[10px] text-slate-400">
                              {log.createdAt ? new Date(log.createdAt).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }) : ''}
                            </p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center shrink-0">
                            <User size={14} className="text-slate-400" />
                          </div>
                          <div className="min-w-0">
                            <p className="text-sm font-medium text-slate-800 truncate">{log.firstName} {log.lastName}</p>
                            <p className="text-xs text-slate-400 truncate">{log.email}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className="inline-flex items-center px-2.5 py-1 rounded text-[11px] font-medium bg-slate-100 text-slate-600 border border-slate-200">
                          {getViolationLabel(log.violationType)}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <p className="text-xs text-slate-600 max-w-[200px] truncate" title={log.details || ''}>
                          {log.details || '—'}
                        </p>
                      </td>
                      <td className="px-6 py-4">
                        <p className="text-xs font-medium text-slate-700 max-w-[150px] truncate">
                          {log.jobTitle || 'N/A'}
                        </p>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-xs font-mono text-slate-500">{log.ipAddress || '—'}</span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          )}
        </div>

        {/* Footer */}
        {filteredLogs.length > 0 && (
          <div className="px-6 py-3 bg-slate-50 border-t border-slate-200 flex justify-between items-center">
            <p className="text-xs text-slate-400">
              Showing {filteredLogs.length} of {logs.length} entries
            </p>
            <p className="text-xs text-slate-400">
              Last 100 records · Auto-logged by system
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default SecurityAuditLogs;

import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { X, Calendar, CheckCircle, AlertCircle } from 'lucide-react';
import axios from 'axios';
import { confirmHiredSchema, type ConfirmHiredData } from '@/schemas/recruitmentSchema';
import type { Applicant } from '@/types/recruitment';

interface ConfirmHiredModalProps {
  isOpen: boolean;
  onClose: () => void;
  applicant: Applicant | null;
  onConfirm: (id: number, startDate: string, selectedDocs: string[], customNotes: string) => Promise<void>;
}

const ConfirmHiredModal: React.FC<ConfirmHiredModalProps> = ({
  isOpen,
  onClose,
  applicant,
  onConfirm
}) => {
  const [selectedDocs, setSelectedDocs] = React.useState<string[]>([]);
  const [customNotes, setCustomNotes] = React.useState<string>('');
  const [defaultShift, setDefaultShift] = React.useState<{ startTime: string } | null>(null);
  
  React.useEffect(() => {
    const fetchDefaultShift = async () => {
      try {
        const response = await axios.get(`${import.meta.env.VITE_API_URL}/api/schedules/shift-templates/default`, { withCredentials: true });
        if (response.data.success) setDefaultShift(response.data.data);
      } catch (err) {
        console.error('Failed to fetch default shift:', err);
      }
    };
    fetchDefaultShift();
  }, []);

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
    reset,
    setValue
  } = useForm<ConfirmHiredData>({
    resolver: zodResolver(confirmHiredSchema),
    defaultValues: {
      startDate: new Date().toISOString().split('T')[0] + 'T08:00'
    }
  });

  React.useEffect(() => {
    if (defaultShift) {
      const timePart = defaultShift.startTime.substring(0, 5);
      setValue('startDate', new Date().toISOString().split('T')[0] + 'T' + timePart);
    }
  }, [defaultShift, setValue]);

  if (!isOpen || !applicant) return null;

  const onSubmit = async (data: ConfirmHiredData) => {
    await onConfirm(applicant.id, data.startDate, selectedDocs, customNotes);
    setSelectedDocs([]);
    setCustomNotes('');
    reset();
    onClose();
  };

  const toggleDoc = (path: string) => {
    setSelectedDocs(prev => 
      prev.includes(path) ? prev.filter(p => p !== path) : [...prev, path]
    );
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="bg-gray-900 px-6 py-4 flex justify-between items-center">
          <h3 className="text-white font-bold flex items-center gap-2">
            <CheckCircle size={20} className="text-emerald-400" />
            Confirm for Duty & Document Audit
          </h3>
          <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="p-6 overflow-y-auto max-h-[85vh]">
          <div className="mb-6 bg-emerald-50 border border-emerald-100 p-4 rounded-xl flex gap-3">
            <AlertCircle className="text-emerald-600 flex-shrink-0" size={20} />
            <div className="text-sm text-emerald-800">
              <p className="font-bold mb-1">Confirmation for {applicant.firstName} {applicant.lastName}</p>
              <p>Verify uploads below. Selected files will be attached to the official "Start of Duty" email.</p>
            </div>
          </div>

          <div className="space-y-5">
            {/* 1. Date & Time */}
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">
                Official Start Date & Time
              </label>
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input
                  type="datetime-local"
                  {...register('startDate')}
                  className={`w-full pl-10 pr-4 py-2.5 bg-gray-50 border ${
                    errors.startDate ? 'border-red-500' : 'border-gray-200'
                  } rounded-xl focus:ring-2 focus:ring-gray-900 outline-none transition-all font-medium`}
                />
              </div>
              {errors.startDate && (
                <p className="text-red-500 text-[10px] mt-1 font-bold ml-1">{errors.startDate.message}</p>
              )}
            </div>

            {/* 2. Document Selection */}
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-2 ml-1">
                Include Uploaded Requirements in Email
              </label>
              <div className="grid grid-cols-1 gap-2">
                {applicant.resumePath && (
                  <label className={`flex items-center gap-3 p-3 border rounded-xl cursor-pointer transition-all ${selectedDocs.includes(applicant.resumePath) ? 'bg-gray-900 border-gray-900 text-white' : 'bg-gray-50 border-gray-200 text-gray-600 hover:bg-gray-100'}`}>
                    <input type="checkbox" className="hidden" checked={selectedDocs.includes(applicant.resumePath)} onChange={() => toggleDoc(applicant.resumePath!)} />
                    <CheckCircle size={16} className={selectedDocs.includes(applicant.resumePath) ? 'text-emerald-400' : 'text-gray-300'} />
                    <span className="text-xs font-bold">Resume / PDS</span>
                  </label>
                )}
                {applicant.eligibilityPath && (
                  <label className={`flex items-center gap-3 p-3 border rounded-xl cursor-pointer transition-all ${selectedDocs.includes(applicant.eligibilityPath) ? 'bg-gray-900 border-gray-900 text-white' : 'bg-gray-50 border-gray-200 text-gray-600 hover:bg-gray-100'}`}>
                    <input type="checkbox" className="hidden" checked={selectedDocs.includes(applicant.eligibilityPath)} onChange={() => toggleDoc(applicant.eligibilityPath!)} />
                    <CheckCircle size={16} className={selectedDocs.includes(applicant.eligibilityPath) ? 'text-emerald-400' : 'text-gray-300'} />
                    <span className="text-xs font-bold">Eligibility Certificate</span>
                  </label>
                )}
              </div>
            </div>

            {/* 3. Custom Instructions */}
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">
                Manual Instructions / Missing Requirements
              </label>
              <textarea
                value={customNotes}
                onChange={(e) => setCustomNotes(e.target.value)}
                placeholder="Example: Please bring original copies of your NBI clearance and Birth Certificate..."
                className="w-full p-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-gray-900 outline-none transition-all font-medium text-sm min-h-[100px]"
              />
            </div>
          </div>

          <div className="mt-8 flex gap-3">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2.5 border border-gray-200 text-gray-600 font-bold rounded-xl hover:bg-gray-50 transition-all"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isSubmitting}
              className="flex-1 px-4 py-2.5 bg-gray-900 text-white font-bold rounded-xl hover:bg-gray-800 disabled:opacity-50 transition-all flex items-center justify-center gap-2 shadow-lg shadow-gray-200"
            >
              {isSubmitting ? 'Processing...' : 'Confirm & Send Email'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ConfirmHiredModal;

import React, { useState, useEffect } from 'react';
import { X, Mail, Video, Globe, Wand2, Loader2, AlertCircle, CalendarCheck, Plug } from 'lucide-react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Applicant } from '@/types/recruitment';
import { recruitmentApi } from '@/api/recruitmentApi';
import { googleCalendarApi } from '@/api/googleCalendarApi';
import { zoomApi } from '@/api/zoomApi';
import { scheduleInterviewSchema, type ScheduleInterviewFormData } from '@/schemas/recruitmentSchema';

interface ScheduleInterviewModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (data: ScheduleInterviewFormData) => void;
  selectedApplicant: Applicant | null;
  initialData?: Partial<ScheduleInterviewFormData>;
}

// Generate instant video meeting link using meet.jit.si (free, no account needed)
const generateJitsiLink = (applicantName: string): string => {
  const roomId = `nebr-interview-${applicantName.toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-')}-${Date.now().toString(36)}`;
  return `https://meet.jit.si/${roomId}`;
};

const ScheduleInterviewModal: React.FC<ScheduleInterviewModalProps> = ({ 
  isOpen, 
  onClose, 
  onConfirm, 
  selectedApplicant,
  initialData
}) => {
  const [isGeneratingJitsi, setIsGeneratingJitsi] = useState(false);
  const queryClient = useQueryClient();

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    reset,
    formState: { errors, isSubmitting }
  } = useForm<ScheduleInterviewFormData>({
    resolver: zodResolver(scheduleInterviewSchema),
    defaultValues: {
      date: initialData?.date || '',
      time: initialData?.time || '',
      platform: initialData?.platform || 'Jitsi Meet',
      link: initialData?.link || '',
      notes: initialData?.notes || ''
    }
  });

  useEffect(() => {
    if (isOpen) {
      reset({
        date: initialData?.date || selectedApplicant?.interviewDate?.split('T')[0] || '',
        time: initialData?.time || (selectedApplicant?.interviewDate ? new Date(selectedApplicant.interviewDate).toTimeString().substring(0, 5) : ''),
        platform: initialData?.platform || selectedApplicant?.interviewPlatform || 'Jitsi Meet',
        link: initialData?.link || selectedApplicant?.interviewLink || '',
        notes: initialData?.notes || selectedApplicant?.interviewNotes || ''
      });
    }
  }, [isOpen, selectedApplicant, initialData, reset]);

  const platform = watch('platform');
  const date = watch('date');
  const time = watch('time');

  // Type-safe error message extractor
  const getErrorMessage = (error: unknown): string => {
    if (error instanceof Error) return error.message;
    if (typeof error === 'string') return error;
    if (error && typeof error === 'object' && 'message' in error) {
      return String((error as { message: unknown }).message);
    }
    return 'An unexpected error occurred';
  };

  // Check Google Calendar Connection Status
  const { data: googleSyncStatus, refetch: checkGoogleStatus } = useQuery({
    queryKey: ['googleCalendarStatus'],
    queryFn: async () => {
      const response = await googleCalendarApi.getSyncStatus();
      return response.data;
    },
    enabled: isOpen && platform === 'Google Meet',
    retry: false
  });

  const isGoogleConnected = googleSyncStatus?.connected;

  // Listen for OAuth callback messages from popup (secure with origin validation)
  useEffect(() => {
    const handleMessage = (event: MessageEvent) => {
      // Validate origin for security (only trust our own frontend URL)
      const trustedOrigins = ['http://localhost:5173', 'http://localhost:5174', window.location.origin];
      if (!trustedOrigins.includes(event.origin)) {
        return;
      }

      // Check if this is our Google auth success message
      const data = event.data as { status?: string; message?: string };
      if (data?.status === 'success' && data?.message === 'google-auth-success') {
        // Refresh the Google Calendar status
        checkGoogleStatus();
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, [checkGoogleStatus]);

  // React Query mutation for Google Meet (requires OAuth)
  const generateGoogleMeetMutation = useMutation({
    mutationFn: async () => {
      if (!selectedApplicant || !date || !time) {
        throw new Error('Please select date and time first');
      }
      const dateTime = `${date}T${time}`;
      const response = await recruitmentApi.generateMeetingLink(
        selectedApplicant.id,
        dateTime,
        60
      );
      return response.data;
    },
    onSuccess: (data) => {
      if (data.success && data.meetingLink) {
        setValue('link', data.meetingLink, { shouldValidate: true });
      }
    }
  });

  // Check Zoom Configuration Status
  const { data: zoomStatus } = useQuery({
    queryKey: ['zoomStatus'],
    queryFn: async () => {
      const response = await zoomApi.getStatus();
      return response.data;
    },
    enabled: isOpen && platform === 'Zoom',
    retry: false
  });

  const isZoomConfigured = zoomStatus?.configured;

  // React Query mutation for Zoom meeting creation
  const generateZoomMeetingMutation = useMutation({
    mutationFn: async () => {
      if (!selectedApplicant || !date || !time) {
        throw new Error('Please select date and time first');
      }
      const response = await zoomApi.createMeeting({
        topic: `Interview Invitation - CHRMO Mey Portal`,
        startTime: `${date}T${time}:00`,
        duration: 60,
        applicantName: `${selectedApplicant.firstName} ${selectedApplicant.lastName}`,
      });
      return response.data;
    },
    onSuccess: (data) => {
      if (data.success && data.meetingLink) {
        setValue('link', data.meetingLink, { shouldValidate: true });
      }
    }
  });

  // Handle Google OAuth Connection
  const handleConnectGoogle = async () => {
    try {
      const { data } = await googleCalendarApi.getAuthUrl();
      if (data.authUrl) {
        const width = 500;
        const height = 600;
        const left = window.screen.width / 2 - width / 2;
        const top = window.screen.height / 2 - height / 2;
        
        const popup = window.open(
          data.authUrl, 
          'Google Calendar Connect', 
          `width=${width},height=${height},top=${top},left=${left}`
        );

        if (popup) {
          const timer = setInterval(() => {
            if (popup.closed) {
              clearInterval(timer);
              checkGoogleStatus(); // Refresh status on close
            }
          }, 1000);
        }
      }
    } catch (error) {
      console.error('Failed to initiate Google Auth', error);
    }
  };

  // Instant Jitsi Meet generation (no backend needed)
  const handleGenerateJitsi = () => {
    if (!selectedApplicant) return;
    setIsGeneratingJitsi(true);
    
    // Small delay to show loading state
    setTimeout(() => {
      const link = generateJitsiLink(`${selectedApplicant.firstName}-${selectedApplicant.lastName}`);
      setValue('link', link, { shouldValidate: true });
      setIsGeneratingJitsi(false);
    }, 300);
  };

  const handleAutoGenerate = () => {
    if (platform === 'Jitsi Meet') {
      handleGenerateJitsi();
    } else if (platform === 'Google Meet') {
      if (isGoogleConnected) {
        generateGoogleMeetMutation.mutate();
      } else {
        handleConnectGoogle();
      }
    } else if (platform === 'Zoom') {
      if (isZoomConfigured) {
        generateZoomMeetingMutation.mutate();
      }
    }
  };

  const onSubmit = (data: ScheduleInterviewFormData) => {
    onConfirm(data);
  };

  if (!isOpen) return null;

  const isGenerating = isGeneratingJitsi || generateGoogleMeetMutation.isPending || generateZoomMeetingMutation.isPending;
  const canAutoGenerate = platform === 'Jitsi Meet' || platform === 'Google Meet' || (platform === 'Zoom' && isZoomConfigured);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-gray-900/40 transition-opacity" onClick={onClose} />
      <div className="relative bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden flex flex-col max-h-[90vh]" onClick={(e) => e.stopPropagation()}>
        {/* Header */}
        <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-white z-10">
          <h3 className="text-lg font-bold text-gray-800">Schedule Interview</h3>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors p-1 rounded-full hover:bg-gray-100">
            <X size={18} />
          </button>
        </div>
        
        <form onSubmit={handleSubmit(onSubmit)} className="flex flex-col flex-1 overflow-hidden">
          <div className="p-6 overflow-y-auto">
            <p className="text-sm text-gray-500 mb-6 bg-blue-50 text-blue-700 px-4 py-3 rounded-lg border border-blue-100 flex items-center gap-2">
              <Mail size={16} />
              <span>This will send an invitation email to <strong>{selectedApplicant?.firstName}</strong>.</span>
            </p>
            
            <div className="space-y-5">
              {/* Date and Time */}
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Date</label>
                  <input 
                    type="date" 
                    {...register('date')}
                    className={`w-full p-2.5 bg-gray-50 border rounded-lg text-sm focus:ring-2 focus:ring-gray-200 outline-none transition-all ${errors.date ? 'border-red-300' : 'border-gray-200'}`}
                    min={new Date().toISOString().split('T')[0]}
                  />
                  {errors.date && (
                    <p className="text-xs text-red-500 mt-1 ml-1">{errors.date.message}</p>
                  )}
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Time</label>
                  <input 
                    type="time" 
                    {...register('time')}
                    className={`w-full p-2.5 bg-gray-50 border rounded-lg text-sm focus:ring-2 focus:ring-gray-200 outline-none transition-all ${errors.time ? 'border-red-300' : 'border-gray-200'}`}
                  />
                  {errors.time && (
                    <p className="text-xs text-red-500 mt-1 ml-1">{errors.time.message}</p>
                  )}
                </div>
              </div>

              {/* Platform */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 ml-1">Platform</label>
                <div className="grid grid-cols-3 gap-2">
                  <label className={`flex items-center justify-center gap-1.5 p-2.5 rounded-lg border cursor-pointer transition-all text-sm ${platform === 'Jitsi Meet' ? 'bg-orange-50 border-orange-200 text-orange-700 font-medium' : 'bg-white border-gray-200 hover:bg-gray-50'}`}>
                    <input 
                      type="radio" 
                      value="Jitsi Meet" 
                      {...register('platform')}
                      className="hidden" 
                    />
                    <Video size={14} /> Jitsi
                  </label>
                  <label className={`flex items-center justify-center gap-1.5 p-2.5 rounded-lg border cursor-pointer transition-all text-sm ${platform === 'Google Meet' ? 'bg-blue-50 border-blue-200 text-blue-700 font-medium' : 'bg-white border-gray-200 hover:bg-gray-50'}`}>
                    <input 
                      type="radio" 
                      value="Google Meet" 
                      {...register('platform')}
                      className="hidden" 
                    />
                    <Video size={14} /> Google
                  </label>
                  <label className={`flex items-center justify-center gap-1.5 p-2.5 rounded-lg border cursor-pointer transition-all text-sm ${platform === 'Zoom' ? 'bg-blue-50 border-blue-200 text-blue-700 font-medium' : 'bg-white border-gray-200 hover:bg-gray-50'}`}>
                    <input 
                      type="radio" 
                      value="Zoom" 
                      {...register('platform')}
                      className="hidden" 
                    />
                    <Video size={14} /> Zoom
                  </label>
                </div>
                {platform === 'Jitsi Meet' && (
                  <p className="text-xs text-green-600 mt-1.5 ml-1">✓ Instant link generation - no setup required</p>
                )}
                {platform === 'Google Meet' && (
                  <div className="mt-1.5 ml-1">
                    {isGoogleConnected ? (
                      <p className="text-xs text-green-600 flex items-center gap-1">
                         <CalendarCheck size={12} /> Connected to Google Calendar
                      </p>
                    ) : (
                      <button 
                        type="button" 
                        onClick={handleConnectGoogle}
                        className="text-xs text-blue-600 font-semibold hover:underline flex items-center gap-1"
                      >
                         <Plug size={12} /> Connect Google Calendar
                      </button>
                    )}
                  </div>
                )}
                {platform === 'Zoom' && (
                  <div className="mt-1.5 ml-1">
                    {isZoomConfigured ? (
                      <p className="text-xs text-green-600 flex items-center gap-1">
                         <CalendarCheck size={12} /> Zoom is configured and ready
                      </p>
                    ) : (
                      <p className="text-xs text-amber-600 flex items-center gap-1">
                         <AlertCircle size={12} /> Zoom not configured. Please add credentials to .env
                      </p>
                    )}
                  </div>
                )}
                {errors.platform && (
                  <p className="text-xs text-red-500 mt-1 ml-1">{errors.platform.message}</p>
                )}
              </div>

              {/* Meeting Link */}
              <div>
                <div className="flex items-center justify-between mb-1.5">
                  <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider ml-1">Meeting Link</label>
                  {canAutoGenerate && (
                    <button
                      type="button"
                      onClick={handleAutoGenerate}
                      disabled={isGenerating}
                      className="flex items-center gap-1.5 text-xs font-semibold text-blue-600 hover:text-blue-700 disabled:text-gray-400 disabled:cursor-not-allowed transition-colors"
                    >
                      {isGenerating ? (
                        <>
                          <Loader2 size={14} className="animate-spin" />
                          Generating...
                        </>
                      ) : (
                        <>
                          <Wand2 size={14} />
                          {platform === 'Google Meet' && !isGoogleConnected ? 'Connect & Generate' : 'Auto-Generate'}
                        </>
                      )}
                    </button>
                  )}
                </div>
                <div className="relative">
                  <Globe size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                  <input 
                    type="url" 
                    {...register('link')}
                    placeholder={platform === 'Zoom' ? "Paste your Zoom link" : "Click Auto-Generate"} 
                    className={`w-full pl-9 p-2.5 border rounded-lg text-sm focus:ring-2 focus:ring-gray-200 outline-none transition-all ${errors.link ? 'border-red-300' : 'border-gray-200'}`}
                  />
                </div>
                {errors.link && (
                  <p className="text-xs text-red-500 mt-1.5 ml-1">{errors.link.message}</p>
                )}
                {generateGoogleMeetMutation.isError && (
                  <div className="mt-1.5 ml-1">
                    <p className="text-xs text-red-500 flex items-center gap-1">
                      <AlertCircle size={12} />
                      {getErrorMessage(generateGoogleMeetMutation.error)}
                    </p>
                    {getErrorMessage(generateGoogleMeetMutation.error).includes('Calendar not connected') && !isGoogleConnected && (
                      <p className="text-xs text-gray-500 mt-1">
                        Please connect your calendar using the link above.
                      </p>
                    )}
                  </div>
                )}
              </div>

              {/* Notes */}
              <div>
                <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1">Message / Notes</label>
                <textarea 
                  {...register('notes')}
                  className="w-full p-3 border border-gray-200 rounded-lg h-24 text-sm focus:ring-2 focus:ring-gray-200 outline-none transition-all resize-none"
                  placeholder="Additional instructions for the applicant..."
                />
              </div>
            </div>
          </div>

          {/* Footer */}
          <div className="bg-gray-50 px-6 py-4 border-t border-gray-100 flex justify-end gap-3">
            <button 
              type="button"
              onClick={onClose} 
              className="px-4 py-2 text-sm font-semibold text-gray-700 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 hover:text-gray-900 transition-all shadow-sm"
            >
              Cancel
            </button>
            <button 
              type="submit"
              disabled={isSubmitting}
              className="px-4 py-2 text-sm font-bold text-white bg-gray-900 rounded-lg hover:bg-gray-800 transition-all shadow-md flex items-center gap-2 disabled:opacity-50"
            >
              {isSubmitting ? (
                <Loader2 size={16} className="animate-spin" />
              ) : (
                <Mail size={16} />
              )}
              Send Invitation
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ScheduleInterviewModal;

import React from 'react';
import { Search } from 'lucide-react';
import { JobStatusFilter } from '@/types';
import Combobox from '@/components/Custom/Combobox';

const JOB_STATUSES: JobStatusFilter[] = ['Open', 'Closed', 'On Hold'];

interface JobFiltersProps {
  searchTerm: string;
  setSearchTerm: (term: string) => void;
  statusFilter: JobStatusFilter;
  setStatusFilter: (status: JobStatusFilter) => void;
}

const JobFilters: React.FC<JobFiltersProps> = ({ 
  searchTerm, 
  setSearchTerm, 
  statusFilter, 
  setStatusFilter 
}) => {
  const statusOptions: { value: JobStatusFilter; label: string }[] = [
    { value: 'All', label: 'All Status' },
    ...JOB_STATUSES.map(status => ({ value: status, label: status }))
  ];

  return (
    <div className="bg-[#F8F9FA] p-4 rounded-lg shadow-md mb-6 flex flex-wrap gap-4 items-center">
      <div className="flex-1 min-w-[200px] relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
        <input 
          type="text" 
          placeholder="Search by title or department..." 
          className="w-full pl-10 bg-white border border-gray-200 rounded-lg shadow-sm px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-gray-200 focus:border-gray-400 transition-all"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>
      <Combobox 
        options={statusOptions}
        value={statusFilter}
        onChange={(val) => setStatusFilter(val as JobStatusFilter)}
        placeholder="Filter Status"
        className="w-40"
        buttonClassName="bg-white border-gray-200 shadow-sm px-3 py-2 text-sm"
      />
    </div>
  );
};


export default JobFilters;

import React from 'react';
import { RefreshCw, Mail, Share2, Plus } from 'lucide-react';

interface JobHeaderProps {
  checkingEmails: boolean;
  onCheckEmails: () => void;
  onCreateJob: () => void;
}

const JobHeader: React.FC<JobHeaderProps> = ({ 
  checkingEmails, 
  onCheckEmails, 
  onCreateJob 
}) => {
  return (
    <div className="flex justify-between items-center mb-6">
      <div>
        <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">
          Job Posting
        </h2>
        <p className="text-sm text-gray-600 mt-1">Create and manage job postings</p>
      </div>
      <div className="flex gap-2">
        <button 
