import React, { memo, useMemo } from 'react';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { User, Mail, Phone, ClipboardList, Calendar, GripVertical } from 'lucide-react';
import { KanbanApplicant } from '../Hooks/useKanbanData';

interface ApplicantCardProps {
  applicant: KanbanApplicant;
  isDragging?: boolean;
  onViewRequirements?: (applicant: KanbanApplicant) => void;
}

const ApplicantCard: React.FC<ApplicantCardProps> = memo(({ applicant, isDragging, onViewRequirements }) => {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging: isSortableDragging,
  } = useSortable({ 
    id: applicant.id.toString(),
    transition: {
      duration: 200,
      easing: 'cubic-bezier(0.25, 1, 0.5, 1)',
    }
  });

  const style = useMemo(() => ({
    transform: CSS.Transform.toString(transform),
    transition: transition || 'transform 200ms cubic-bezier(0.25, 1, 0.5, 1)',
    opacity: isSortableDragging ? 0.4 : 1,
    willChange: isSortableDragging ? 'transform' : 'auto',
  }), [transform, transition, isSortableDragging]);

  if (isSortableDragging) {
    return (
      <div 
        ref={setNodeRef} 
        style={style}
        className="bg-gray-100 rounded-lg border-2 border-dashed border-gray-300 p-4 mb-3 h-[100px]"
      />
    );
  }

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 mb-3 cursor-grab active:cursor-grabbing hover:shadow-md hover:border-gray-300 transition-shadow duration-150"
    >
      <div className="flex items-start gap-3">
        <div
          {...attributes}
          {...listeners}
          className="mt-1 text-gray-400 hover:text-gray-600 touch-none"
        >
          <GripVertical size={16} />
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <div className="bg-gray-100 p-1.5 rounded-full">
              <User size={14} className="text-gray-500" />
            </div>
            <h4 className="font-semibold text-gray-900 truncate text-sm">
              {applicant.firstName} {applicant.lastName}
            </h4>
          </div>
          <div className="mt-2 space-y-1 text-xs text-gray-500">
            <div className="flex items-center gap-1.5">
              <Mail size={11} />
              <span className="truncate">{applicant.email}</span>
            </div>
            {applicant.phoneNumber && (
              <div className="flex items-center gap-1.5">
                <Phone size={11} />
                <span>{applicant.phoneNumber}</span>
              </div>
            )}
            <div className="flex items-center gap-1.5">
              <Calendar size={11} />
              <span>{applicant.jobTitle || 'General Application'}</span>
            </div>
          </div>
          <button
            onClick={(e) => {
              e.stopPropagation();
              onViewRequirements && onViewRequirements(applicant);
            }}
            className="inline-flex items-center gap-1.5 mt-2 px-2.5 py-1 text-xs font-medium text-slate-700 bg-slate-100 hover:bg-slate-200 rounded-md transition-colors"
          >
            <ClipboardList size={11} />
            Requirements
          </button>
        </div>
      </div>
    </div>
  );
});

ApplicantCard.displayName = 'ApplicantCard';

export default ApplicantCard;

import React from 'react';
import { 
  DndContext, 
  closestCenter, 
  DragOverlay, 
  MeasuringStrategy, 
  SensorDescriptor, 
  SensorOptions,
  DragStartEvent,
  DragEndEvent,
  DragOverEvent
} from '@dnd-kit/core';
import KanbanColumn from './KanbanColumn';
import DragOverlayCard from './DragOverlayCard';
import { KanbanApplicant } from '../Hooks/useKanbanData';
import { KanbanColumn as KanbanColumnType } from '../Hooks/useKanbanDragDrop';

interface KanbanBoardProps {
  applicants: KanbanApplicant[];
  COLUMNS: KanbanColumnType[];
  sensors: SensorDescriptor<SensorOptions>[];
  activeId: string | null;
  activeApplicant: KanbanApplicant | null | undefined;
  handleDragStart: (event: DragStartEvent) => void;
  handleDragEnd: (event: DragEndEvent) => Promise<void>;
  handleDragOver: (event: DragOverEvent) => void;
  handleViewRequirements: (applicant: KanbanApplicant) => void;
}

const KanbanBoard: React.FC<KanbanBoardProps> = ({ 
  applicants, 
  COLUMNS, 
  sensors, 
  activeId, 
  activeApplicant, 
  handleDragStart, 
  handleDragEnd, 
  handleDragOver, 
  handleViewRequirements 
}) => {
  const getApplicantsByStage = (stage: string) => {
    return applicants.filter(a => a.stage === stage);
  };

  return (
    <>
      <DndContext 
        sensors={sensors} 
        collisionDetection={closestCenter} 
        onDragStart={handleDragStart} 
        onDragEnd={handleDragEnd} 
        onDragOver={handleDragOver} 
        measuring={{ droppable: { strategy: MeasuringStrategy.Always } }}
      >
        <div className="flex gap-4 overflow-x-auto pb-4">
          {COLUMNS.map((column) => (
            <KanbanColumn 
              key={column.id} 
              column={column} 
              applicants={getApplicantsByStage(column.id)} 
              activeId={activeId} 
              onViewRequirements={handleViewRequirements} 
            />
          ))}
        </div>
        
        <DragOverlay dropAnimation={{ duration: 200, easing: 'cubic-bezier(0.18, 0.67, 0.6, 1.22)' }}>
          {activeApplicant ? <DragOverlayCard applicant={activeApplicant} /> : null}
        </DragOverlay>
      </DndContext>

      <div className="mt-6 pt-4 border-t border-gray-200">
        <p className="text-xs text-gray-500">
          <strong>Final Interview</strong> = Face-to-Face Interview | Drag applicants between columns to update their status
        </p>
      </div>
    </>
  );
};

export default KanbanBoard;

import { useState, useMemo } from 'react';
import { 
  useSensor, 
  useSensors, 
  PointerSensor, 
  KeyboardSensor,
  TouchSensor,
  DragStartEvent,
  DragEndEvent,
  DragOverEvent
} from '@dnd-kit/core';
import { sortableKeyboardCoordinates } from '@dnd-kit/sortable';
import { recruitmentApi } from '@/api/recruitmentApi';
import { KanbanApplicant, ApplicantStage } from './useKanbanData';

export interface KanbanColumn {
  id: string;
  title: string;
  color: string;
}

export const COLUMNS: KanbanColumn[] = [
  { id: 'Applied', title: 'Applicants', color: 'bg-blue-700' },
  { id: 'Screening', title: 'Under Review', color: 'bg-slate-700' },
  { id: 'Initial Interview', title: 'Initial Interview (Online)', color: 'bg-slate-800' },
  { id: 'Final Interview', title: 'Final Interview', color: 'bg-zinc-800' },
  { id: 'Hired', title: 'Hired', color: 'bg-emerald-900' },
  { id: 'Rejected', title: 'Rejected', color: 'bg-rose-900' },
];

const useKanbanDragDrop = (
  applicants: KanbanApplicant[], 
  setApplicants: React.Dispatch<React.SetStateAction<KanbanApplicant[]>>, 
  fetchApplicants: () => void, 
  showNotification: (message: string, type: 'success' | 'error') => void
) => {
  const [activeId, setActiveId] = useState<string | null>(null);

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: { 
        distance: 5,
      },
    }),
    useSensor(TouchSensor, {
      activationConstraint: {
        delay: 200,
        tolerance: 5,
      },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  const activeApplicant = useMemo(() => 
    activeId ? applicants.find(a => a.id.toString() === activeId) : null,
    [activeId, applicants]
  );

  const handleDragStart = (event: DragStartEvent) => {
    setActiveId(event.active.id as string);
  };

  const handleDragEnd = async (event: DragEndEvent) => {
    const { active, over } = event;
    setActiveId(null);

    if (!over) return;

    const applicantId = parseInt(active.id as string);
    
    let targetColumnId = over.id as string;
    let column = COLUMNS.find(c => c.id === targetColumnId);
    
    if (!column) {
      const targetApplicant = applicants.find(a => a.id.toString() === over.id);
      if (targetApplicant) {
        targetColumnId = targetApplicant.stage;
        column = COLUMNS.find(c => c.id === targetColumnId);
      }
    }
    
    if (!column) return;

    const applicant = applicants.find(a => a.id === applicantId);
    if (!applicant || applicant.stage === targetColumnId) return;

    setApplicants(prev => 
      prev.map(a => a.id === applicantId ? { ...a, stage: targetColumnId } : a)
    );

    try {
      await recruitmentApi.updateStage(applicantId, { stage: targetColumnId as ApplicantStage });
      showNotification(`Moved to ${column.title}`, 'success');
    } catch (err) {
      fetchApplicants();
      showNotification('Failed to update stage', 'error');
    }
  };

  const handleDragOver = (event: DragOverEvent) => {
    const { over } = event;
    if (over && COLUMNS.find(c => c.id === over.id)) {
      // Allow drop
    }
  };

  return {
    sensors,
    activeId,
    activeApplicant,
    handleDragStart,
    handleDragEnd,
    handleDragOver,
    COLUMNS
  };
};

export default useKanbanDragDrop;

import { useQuery, useMutation } from '@tanstack/react-query';
import { recruitmentApi } from '@/api/recruitmentApi';
import { PublicJob, JobApplicationSchema } from '@/schemas/recruitment';

export const usePublicJobs = (searchTerm: string = '') => {
    const { data, isLoading, error } = useQuery({
        queryKey: ['public-jobs'],
        queryFn: async () => {
            const res = await recruitmentApi.getJobs({ public_view: true });
            if (res.data.success) {
                return res.data.jobs as PublicJob[];
            }
            return [];
        },
        staleTime: 1000 * 60 * 5, // 5 minutes
    });

    const jobs = data || [];
    const filteredJobs = jobs.filter(job => 
        job.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
        job.department.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return {
        jobs,
        filteredJobs,
        isLoading,
        error
    };
};

export const usePublicJobDetail = (id: string | undefined) => {
    return useQuery({
        queryKey: ['job', id],
        queryFn: async () => {
            if (!id) throw new Error("Job ID is required");
            const res = await recruitmentApi.getJob(id);
            if (res.data.success) {
                return res.data.job as PublicJob;
            }
            throw new Error("Job not found");
        },
        enabled: !!id,
        retry: 1,
        staleTime: 1000 * 60 * 5, // 5 minutes
    });
};

export const useJobApplication = (onSuccess?: (response: { data: { success: boolean, requiresVerification?: boolean, email?: string, applicantId?: number } }) => void, onError?: (error: Error) => void) => {
    return useMutation({
        mutationFn: async ({ id, data }: { id: string; data: JobApplicationSchema }) => {
            const formData = new FormData();
            formData.append('jobId', id);

            // Fields that are frontend-only and should NOT be sent to the backend
            const skipFields = new Set(['photoPreview', 'jobId']);
            // File fields need special handling
            const fileFields = new Set(['resume', 'photo', 'eligibilityCert']);
            
            Object.keys(data).forEach(key => {
                if (skipFields.has(key)) return;

                const value = data[key as keyof JobApplicationSchema];
                if (value === null || value === undefined) return;

                if (fileFields.has(key)) {
                    // Only append if it's actually a File object
                    if (value instanceof File) {
                        formData.append(key, value);
                    }
                } else if (typeof value === 'boolean') {
                    formData.append(key, value ? 'true' : 'false');
                } else if (typeof value === 'number') {
                    formData.append(key, String(value));
                } else if (typeof value === 'string' && value !== '') {
                    formData.append(key, value);
                }
            });
            
            return await recruitmentApi.applyJob(formData);
        },
        onSuccess,
        onError: (error: Error) => onError?.(error)
    });
};

import { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import { attendanceApi } from "@/api";
import { BiometricsLog } from '@/types';
// ExcelJS import removed

const ITEMS_PER_PAGE = 10;

interface Filters {
  department: string;
  employeeId: string;
  startDate: string;
  endDate: string;
}

interface PaginationData {
  totalPages: number;
  startIndex: number;
  endIndex: number;
  currentItems: BiometricsLog[];
  total: number;
}

export const useBiometricsLogs = () => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [biometricsData, setBiometricsData] = useState<BiometricsLog[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const [filters, setFilters] = useState<Filters>({
    department: "",
    employeeId: "",
    startDate: "",
    endDate: "",
  });

  const [searchQuery, setSearchQuery] = useState("");
  const [debouncedSearchQuery, setDebouncedSearchQuery] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [loadingType, setLoadingType] = useState("");

  const searchTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const today = useMemo(() => new Date().toLocaleDateString("en-US"), []);

  const fetchData = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
        // Prepare query parameters from filters
        const queryParams = {
          department: filters.department === 'All Departments' ? '' : filters.department,
          employeeId: filters.employeeId,
          startDate: filters.startDate,
          endDate: filters.endDate,
          search: searchQuery, // Use current search query
          limit: 100 // Fetch a reasonable amount for now, or implement full server pagination
        };

        const response = await attendanceApi.getRawLogs(queryParams);
        if (response.data && response.data.success) {
            // Group raw scans by employee + date, pairing IN/OUT into single rows
            const grouped = new Map<string, {
                id: string;
                employeeId: string;
                name: string;
                department: string;
                date: string;
                scanDate: Date;
                timeIn?: string;
                timeOut?: string;
                source: string;
                status: string;
                duties: string;
                shift: string;
                dutyType: string;
            }>();

            for (const log of response.data.data) {
                const empId = String(log.employeeId || log.id);
                // Fix: Backend uses scanTime (camelCase), not scan_time
                const scanTimeRaw = log.scanTime;
                if (!scanTimeRaw) continue;

                const scanDateObj = new Date(scanTimeRaw);
                if (isNaN(scanDateObj.getTime())) continue;

                const dateStr = scanDateObj.toLocaleDateString();
                const key = `${empId}_${dateStr}`;
                const scanTimeStr = scanDateObj.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
                const empName = (log.firstName && log.lastName)
                    ? `${log.firstName} ${log.lastName}`
                    : 'Unknown';

                if (!grouped.has(key)) {
                    grouped.set(key, {
                        id: empId,
                        employeeId: empId,
                        name: empName,
                        department: log.department || 'N/A',
                        date: dateStr,
                        scanDate: scanDateObj,
                        timeIn: undefined,
                        timeOut: undefined,
                        source: log.source || 'Biometric',
                        status: log.dtrStatus || 'Present', // Fix: dtrStatus, not dtr_status
                        duties: log.dutyType || log.duties || 'Standard',
                        shift: log.shift || 'No Schedule',
                        dutyType: log.dutyType || 'Standard'
                    });
                }

                const entry = grouped.get(key)!;
                if (log.type === 'IN') {
                    // Keep earliest IN scan
                    if (!entry.timeIn || scanDateObj < new Date(entry.scanDate)) {
                        entry.timeIn = scanTimeStr;
                        entry.scanDate = scanDateObj; // Update base scanDate for consistency
                    }
                } else if (log.type === 'OUT') {
                    // Keep latest OUT scan
                    if (!entry.timeOut || scanDateObj > new Date(entry.scanDate)) {
                        entry.timeOut = scanTimeStr;
                    }
                }
                // Update status from DTR if available
                if (log.dtrStatus) {
                    entry.status = log.dtrStatus;
                }
            }

            // Convert grouped map to array
            const transformedData: BiometricsLog[] = Array.from(grouped.values()).map((entry) => ({
                id: entry.id,
                employeeId: entry.employeeId,
                employeeName: entry.name,
                name: entry.name,
                department: entry.department,
                date: entry.date,
                scanDate: entry.scanDate,
                scanTime: entry.timeIn || entry.timeOut || '',
                timeIn: entry.timeIn,
                timeOut: entry.timeOut,
                type: entry.timeOut ? 'OUT' as const : 'IN' as const,
                source: entry.source,
                status: entry.status,
                duties: entry.duties,
                shift: entry.shift,
                dutyType: entry.dutyType,
                lateMinutes: 0,
                undertimeMinutes: 0,
                overtimeMinutes: 0
            }));

            setBiometricsData(transformedData);
        }
    } catch (err) {
        console.error(err);
        setError("Failed to fetch biometrics logs.");
    } finally {
        setIsLoading(false);
    }
  }, [filters, searchQuery]);

  useEffect(() => {
    fetchData();
  }, [fetchData, filters, debouncedSearchQuery]);

  const handleFilterChange = useCallback((field: keyof Filters, value: string) => {
    setFilters((prev) => ({ ...prev, [field]: value }));
  }, []);

  const handleSearchChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => setSearchQuery(e.target.value), []);

  const handleRefresh = useCallback(() => {
    setLoadingType("data");
    fetchData().finally(() => setLoadingType(""));
  }, [fetchData]);

  const handleClear = useCallback(() => {
    setFilters({ department: "", employeeId: "", startDate: "", endDate: "" });
    setSearchQuery("");
  }, []);

  // Derived Data
  const uniqueDepartments = useMemo(() => [...new Set(biometricsData.map(item => item.department || ''))].sort(), [biometricsData]);
  const uniqueEmployees = useMemo(() => {
    const map = new Map();
    biometricsData.forEach(item => {
        if (!map.has(item.id)) {
            map.set(item.id, { id: item.id, name: item.name });
        }
    });
    return Array.from(map.values()).sort((a, b) => (a.name || '').localeCompare(b.name || ''));
  }, [biometricsData]);

  const filteredData = useMemo(() => {
    let data = biometricsData;

    if (filters.department) data = data.filter((item) => item.department === filters.department);

    if (filters.employeeId) data = data.filter((item) => String(item.id) === String(filters.employeeId));

    if (filters.startDate) {
        const from = new Date(filters.startDate);
        from.setHours(0,0,0,0);
        data = data.filter((item) => item.scanDate && item.scanDate >= from);
    }

    if (filters.endDate) {
        const to = new Date(filters.endDate);
        to.setHours(23,59,59,999);
        data = data.filter((item) => item.scanDate && item.scanDate <= to);
    }

    const query = debouncedSearchQuery.toLowerCase();
    if (query) {
      data = data.filter(
        (item) =>
          (item.name && item.name.toLowerCase().includes(query)) ||
          String(item.id).toLowerCase().includes(query) ||
          (item.department && item.department.toLowerCase().includes(query))
      );
    }

    return data;
  }, [filters, debouncedSearchQuery, biometricsData]);

  const handleApply = useCallback(() => {
    const hasFilters = filters.department || filters.employeeId || filters.startDate || filters.endDate;
    if (!hasFilters) {
      setError("Please select at least one filter before applying.");
      setTimeout(() => setError(null), 3000);
      return;
    }
    setSuccessMessage("Filters applied!");
    setTimeout(() => setSuccessMessage(null), 3000);
  }, [filters]);

  const paginationData: PaginationData = useMemo(() => {
    const totalPages = Math.max(1, Math.ceil(filteredData.length / ITEMS_PER_PAGE));
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    const endIndex = startIndex + ITEMS_PER_PAGE;
    const currentItems = filteredData.slice(startIndex, endIndex);
    return { totalPages, startIndex, endIndex, currentItems, total: filteredData.length };
  }, [filteredData, currentPage]);

  const handlePrevPage = () => setCurrentPage(p => Math.max(1, p - 1));
  const handleNextPage = () => setCurrentPage(p => Math.min(paginationData.totalPages, p + 1));


  return {
    today,
    sidebarOpen,
    filters,
    searchQuery,
    debouncedSearchQuery,
    currentPage,
    isLoading,
    loadingType,
    error,
    successMessage,
    filteredData,
    paginationData,
    uniqueDepartments,
    uniqueEmployees,
    setFilters,
    setError,
    setSuccessMessage,
    handleFilterChange,
    handleApply,
    handleClear,
    handleSearchChange,
    handleRefresh,
    handlePrevPage,
    handleNextPage,
    setPage: setCurrentPage
  };
};

import React, { useState, useRef } from 'react';
import { FileText, Download, Trash2, Plus, Loader2, FileCode, FileType, User as LucideUser, Briefcase, Shield, Eye, UploadCloud } from 'lucide-react';
import { EmployeeDocument } from '../types';
import { employeeApi } from '@/api/employeeApi';
import { toast } from 'react-hot-toast';

interface DocumentGalleryProps {
  employeeId: number;
  documents: EmployeeDocument[];
  onDocumentChange: () => void;
}

const DocumentGallery: React.FC<DocumentGalleryProps> = ({ employeeId, documents, onDocumentChange }) => {
  const [uploadingType, setUploadingType] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<number | null>(null);

  const docSlots = [
    { type: '2x2 ID Photo', label: '2x2 ID Photo', required: 'REQUIRED JPG/PNG', accept: 'image/png, image/jpeg', icon: <LucideUser size={14} /> },
    { type: 'Resume', label: 'Resume / CV', required: 'REQUIRED PDF/DOCX', accept: '.pdf,.doc,.docx', icon: <Briefcase size={14} /> },
    { type: 'Eligibility Certificate', label: 'Eligibility Cert.', required: 'REQUIRED PDF', accept: '.pdf', icon: <Shield size={14} /> },
  ];

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: string) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setUploadingType(type);
    try {
      const res = await employeeApi.uploadEmployeeDocument(employeeId, file, type);
      if (res.success) {
        toast.success(`${type} uploaded successfully`);
        onDocumentChange();
      } else {
        toast.error(res.message || 'Upload failed');
      }
    } catch (err) {
      console.error('Upload error:', err);
      toast.error('Failed to upload document');
    } finally {
      setUploadingType(null);
      if (e.target) e.target.value = '';
    }
  };

  const handleDelete = async (docId: number) => {
    if (!window.confirm('Are you sure you want to delete this document?')) return;

    setDeletingId(docId);
    try {
      const res = await employeeApi.deleteEmployeeDocument(employeeId, docId);
      if (res.success) {
        toast.success('Document deleted');
        onDocumentChange();
      } else {
        toast.error(res.message || 'Delete failed');
      }
    } catch (err) {
      console.error('Delete error:', err);
      toast.error('Failed to delete document');
    } finally {
      setDeletingId(null);
    }
  };

  const findDoc = (type: string) => documents.find(d => d.documentType === type);

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 w-full">
      {docSlots.map((slot) => {
        const doc = findDoc(slot.type);
        const isUploading = uploadingType === slot.type;
        const isDeleting = deletingId === doc?.id;

        return (
          <div key={slot.type} className="flex flex-col space-y-1 group">
            <label className="text-[10px] font-bold text-slate-400 tracking-widest flex items-center gap-1 px-1">
               {slot.label} 
               <span className="text-red-500">*</span>
            </label>
            
            <div className={`relative flex items-center gap-3 p-2 rounded-lg border transition-all duration-200 min-h-[50px] ${
              doc 
              ? 'bg-slate-50 border-slate-200' 
              : 'bg-white border-dashed border-slate-300 hover:border-blue-400 hover:bg-blue-50/30'
            }`}>
              
              {/* Icon/Preview */}
              <div className={`flex-shrink-0 w-8 h-8 rounded-md flex items-center justify-center ${
                doc ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-400'
              }`}>
                {isUploading ? (
                  <Loader2 size={16} className="animate-spin" />
                ) : doc ? (
                  doc.mimeType?.includes('image') ? (
                     <img 
                        src={`${import.meta.env.VITE_API_URL || 'http://localhost:5000'}${doc.filePath}`} 
                        alt={slot.label}
                        className="w-full h-full object-cover rounded-md"
                      />
                  ) : (
                     <FileText size={16} />
                  )
                ) : (
                  <UploadCloud size={16} />
                )}
              </div>

              {/* Filename / Info */}
              <div className="flex-grow min-w-0">
                {doc ? (
                  <div className="flex flex-col">
                    <span className="text-xs font-bold text-slate-700 truncate pr-2">
                      {doc.fileName}
                    </span>
                    <span className="text-[9px] text-slate-400 font-bold">
                      {new Date(doc.uploadedAt || '').toLocaleDateString()}
                    </span>
                  </div>
                ) : (
                  <span className="text-xs font-bold text-slate-300 italic">
                    {isUploading ? 'Uploading...' : 'Empty'}
                  </span>
                )}
              </div>

              {/* Actions */}
              <div className="flex items-center gap-1">
                {doc ? (
                  <>
                    <a 
                      href={`${import.meta.env.VITE_API_URL || 'http://localhost:5000'}${doc.filePath}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="p-1.5 text-slate-400 hover:text-blue-600 hover:bg-white rounded-md transition-all"
                    >
                      <Eye size={16} />
                    </a>
                    <button
                      onClick={() => handleDelete(doc.id)}
                      disabled={isDeleting}
                      className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-white rounded-md transition-all"
                    >
                      {isDeleting ? <Loader2 size={16} className="animate-spin" /> : <Trash2 size={16} />}
                    </button>
                  </>
                ) : (
                  <label className="cursor-pointer">
                    <input 
                      type="file" 
                      className="hidden" 
                      accept={slot.accept}
                      onChange={(e) => handleUpload(e, slot.type)}
                      disabled={!!uploadingType}
                    />
                    <div className="px-2 py-1 bg-slate-800 text-white text-[9px] font-black rounded-md hover:bg-slate-700 transition-all tracking-tighter">
                      Upload
                    </div>
                  </label>
                )}
              </div>

              {/* Overlay */}
              {isUploading && (
                <div className="absolute inset-0 bg-white/60 backdrop-blur-[1px] rounded-lg flex items-center justify-center z-10">
                   <Loader2 size={14} className="animate-spin text-blue-600" />
                </div>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
};

