import { useState, useEffect } from 'react';
import { useAuth } from '@/hooks/useAuth';
import api from '@/api/axios';
import { updateMyProfile, employeeApi } from '@/api/employeeApi';
import { User, Employee, ApiResponse, EmployeeDetailed } from '@/types';

import { Profile, ProfileFormData } from '../types';

export const useProfile = () => {
  const { user, setUser, updateProfile } = useAuth();
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  
  const initialFormData: ProfileFormData = {
    firstName: '',
    lastName: '',
    middleName: '',
    suffix: '',
    email: '',
    phoneNumber: '',
    mobileNo: '',
    telephoneNo: '',
    birthDate: '',
    gender: '',
    civilStatus: '',
    nationality: '',
    placeOfBirth: '',
    residentialAddress: '',
    permanentAddress: '',
    religion: '',
    citizenship: '',
    citizenshipType: '',
    officeAddress: '',
    station: '',
    educationalBackground: '',
    schoolName: '',
    course: '',
    yearGraduated: '',
    umidNumber: '',
    philsysId: '',
    philhealthNumber: '',
    pagibigNumber: '',
    tinNumber: '',
    gsisNumber: '',
    heightM: '',
    weightKg: '',
    bloodType: '',
    eligibilityType: '',
    eligibilityNumber: '',
    eligibilityDate: '',
    yearsOfExperience: '',
  };

  const [formData, setFormData] = useState<ProfileFormData>(initialFormData);
  const [avatarFile, setAvatarFile] = useState<File | null>(null);
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);

  useEffect(() => {
    const fetchProfile = async () => {
      try {
        setLoading(true);
        const response = await api.get('/auth/me');
        if (response.data.success) {
          const userData = response.data.data.user || response.data.data;
          
          let detailedData: Partial<Profile> = {};
          // Use the primary key ID for fetching detailed profile
          const fetchId = userData.id;
          
          if (fetchId) {
            try {
              const [employeeRes, docsRes] = await Promise.all([
                employeeApi.fetchEmployeeProfile(fetchId),
                employeeApi.fetchEmployeeDocuments(fetchId)
              ]);

              if (employeeRes.success && employeeRes.profile) {
                detailedData = employeeRes.profile as Partial<Profile>;
              }

              if (docsRes.success && docsRes.documents) {
                detailedData.documents = docsRes.documents;
              }
            } catch (empErr) {
              console.error('Failed to fetch detailed employee profile/documents:', empErr);
            }
          }

          const mergedData = { ...userData, ...detailedData };
          setProfile(mergedData);
          
          // Populate Form Data
          setFormData({
            firstName: mergedData.firstName || mergedData.name?.split(' ')[0] || '',
            lastName: mergedData.lastName || mergedData.name?.split(' ').slice(1).join(' ') || '',
            middleName: mergedData.middleName || '',
            suffix: mergedData.suffix || '',
            email: mergedData.email || '',
            phoneNumber: mergedData.phoneNumber || '',
            mobileNo: mergedData.mobileNo || '',
            telephoneNo: mergedData.telephoneNo || '',
            birthDate: mergedData.birthDate || '',
            gender: mergedData.gender || '',
            civilStatus: mergedData.civilStatus || '',
            nationality: mergedData.nationality || '',
            placeOfBirth: mergedData.placeOfBirth || '',
            residentialAddress: mergedData.residentialAddress || mergedData.address || '',
            permanentAddress: mergedData.permanentAddress || '',
            religion: mergedData.religion || '',
            citizenship: mergedData.citizenship || '',
            citizenshipType: mergedData.citizenshipType || '',
            officeAddress: mergedData.officeAddress || '',
            station: mergedData.station || '',
            educationalBackground: mergedData.educationalBackground || '',
            schoolName: mergedData.schoolName || '',
            course: mergedData.course || '',
            yearGraduated: mergedData.yearGraduated || '',
            umidNumber: mergedData.umidNumber || '',
            philsysId: mergedData.philsysId || '',
            philhealthNumber: mergedData.philhealthNumber || '',
            pagibigNumber: mergedData.pagibigNumber || '',
            tinNumber: mergedData.tinNumber || '',
            gsisNumber: mergedData.gsisNumber || '',
            heightM: String(mergedData.heightM || ''),
            weightKg: String(mergedData.weightKg || ''),
            bloodType: mergedData.bloodType || '',
            eligibilityType: mergedData.eligibilityType || '',
            eligibilityNumber: mergedData.eligibilityNumber || '',
            eligibilityDate: mergedData.eligibilityDate || '',
            yearsOfExperience: String(mergedData.yearsOfExperience || ''),
          });
          setAvatarPreview(mergedData.avatarUrl || mergedData.avatar || null);
        }
      } catch (err) {
        console.error('Failed to fetch profile:', err);
        setError('Failed to load profile');
      } finally {
        setLoading(false);
      }
    };
    fetchProfile();
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData(prev => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setAvatarFile(file);
      setAvatarPreview(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async () => {
    setSaving(true);
    setError(null);
    setSuccess(null);

    try {
      const data = new FormData();
      // Add all fields to FormData
      Object.entries(formData).forEach(([key, value]) => {
        data.append(key, String(value || ''));
      });
      
      if (avatarFile) {
        data.append('avatar', avatarFile);
      }

      const result = await updateMyProfile(data);
      
      if (result.success) {
        const userData = result.data as Partial<User>;
        const newName = (userData?.name as string) || `${formData.firstName} ${formData.lastName}`.trim();
        const newAvatar = (userData?.avatarUrl as string) || avatarPreview || profile?.avatarUrl;
        
        setSuccess('Profile updated successfully!');
        
        // Update local state
        setProfile(prev => {
          if (!prev) return null;
          return {
            ...prev,
            ...userData,
            ...formData, // Spread all form fields back into profile
            yearsOfExperience: formData.yearsOfExperience ? Number(formData.yearsOfExperience) : null,
            name: newName,
            avatarUrl: newAvatar
          } as Profile;
        });
        
        // Prepare updates for useAuth
        const updates: Partial<User> = {
          firstName: formData.firstName,
          lastName: formData.lastName,
          name: newName,
          email: formData.email,
          avatarUrl: newAvatar
        };

        updateProfile(updates);
        
        setIsEditing(false);
        setAvatarFile(null);
        setTimeout(() => setSuccess(null), 3000);
        return { success: true };
      }
      else {
        setError(result.message || 'Failed to update profile');
        return { success: false, message: result.message };
      }
    } catch (err) {
      setError('An error occurred while updating profile');
      return { success: false };
    } finally {
      setSaving(false);
    }
  };

  const handleCancel = () => {
    setIsEditing(false);
    if (profile) {
      setFormData({
        firstName: profile.firstName || profile.name?.split(' ')[0] || '',
        lastName: profile.lastName || profile.name?.split(' ').slice(1).join(' ') || '',
        middleName: profile.middleName || '',
        suffix: profile.suffix || '',
        email: profile.email || '',
        phoneNumber: profile.phoneNumber || '',
        mobileNo: profile.mobileNo || '',
        telephoneNo: profile.telephoneNo || '',
        birthDate: profile.birthDate || '',
        gender: profile.gender || '',
        civilStatus: profile.civilStatus || '',
        nationality: profile.nationality || '',
        placeOfBirth: profile.placeOfBirth || '',
        residentialAddress: profile.residentialAddress || profile.address || '',
        permanentAddress: profile.permanentAddress || '',
        religion: profile.religion || '',
        citizenship: profile.citizenship || '',
        citizenshipType: profile.citizenshipType || '',
        officeAddress: profile.officeAddress || '',
        station: profile.station || '',
        educationalBackground: profile.educationalBackground || '',
        schoolName: profile.schoolName || '',
        course: profile.course || '',
        yearGraduated: profile.yearGraduated || '',
        umidNumber: profile.umidNumber || '',
        philsysId: profile.philsysId || '',
        philhealthNumber: profile.philhealthNumber || '',
        pagibigNumber: profile.pagibigNumber || '',
        tinNumber: profile.tinNumber || '',
        gsisNumber: profile.gsisNumber || '',
        heightM: String(profile.heightM || ''),
        weightKg: String(profile.weightKg || ''),
        bloodType: profile.bloodType || '',
        eligibilityType: profile.eligibilityType || '',
        eligibilityNumber: profile.eligibilityNumber || '',
        eligibilityDate: profile.eligibilityDate || '',
        yearsOfExperience: String(profile.yearsOfExperience || ''),
      });
      setAvatarPreview(profile.avatarUrl || null);
    }
    setAvatarFile(null);
    setError(null);
  };


  return {
    user,
    profile,
    loading,
    saving,
    error,
    success,
    isEditing,
    formData,
    avatarPreview,
    setIsEditing,
    setError,
    setSuccess,
    handleChange,
    handleAvatarChange,
    handleSubmit,
    handleCancel,
    setProfile
  };
};

import { useMutation, useQueryClient } from '@tanstack/react-query';
import { login, googleLogin, logout, verifyTwoFactorOTP, resendTwoFactorOTP, register, forgotPassword, resetPassword, setupPortal } from '@/Service/Auth';
import { useAuthStore } from '@/stores/authStore';
import { useNavigate } from 'react-router-dom';
import { LoginInput, RegisterInput, VerifyOTPInput, ResendOTPInput } from '@/schemas/authSchema';

export const useLoginMutation = () => {
    const setUser = useAuthStore((state) => state.setUser);
    
    return useMutation({
        mutationFn: (data: LoginInput) => login(data),
        onSuccess: (response) => {
            if (!response.data.requires2FA) {
                const userData = response.data.data;
                setUser(userData);
                localStorage.setItem('isLoggedIn', 'true');
            }
        },
    });
};

export const useGoogleLoginMutation = () => {
    const setUser = useAuthStore((state) => state.setUser);

    return useMutation({
        mutationFn: (credential: string) => googleLogin(credential),
        onSuccess: (response) => {
            if (!response.data.requires2FA) {
                const userData = response.data.data;
                setUser(userData);
                localStorage.setItem('isLoggedIn', 'true');
            }
        },
    });
};

export const useLogoutMutation = () => {
    const logoutStore = useAuthStore((state) => state.logout);
    const navigate = useNavigate();
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: logout,
        onSuccess: () => {
            logoutStore(); // Clear store state
            localStorage.removeItem('isLoggedIn');
            queryClient.clear(); // Clear all queries
            navigate('/login');
        },
    });
};

export const useVerify2FAMutation = () => {
    const setUser = useAuthStore((state) => state.setUser);

    return useMutation({
        mutationFn: (data: VerifyOTPInput) => verifyTwoFactorOTP(data),
        onSuccess: (response) => {
             const userData = response.data; 
             // Note: API returns user data in 'data' or directly? 
             // authController verifyTwoFactorOTP returns { success: true, ..., data: { ... } }
             // Check Service/Auth.ts implementation of verifyTwoFactorOTP
             // It returns response.data directly. So response.data is the payload.
             // Payload has .data property with user info.
             if(userData.data) {
                setUser(userData.data);
                localStorage.setItem('isLoggedIn', 'true');
             } else {
                 // Fallback if structure differs
                 setUser(userData); 
             }
        }
    });
};

export const useResend2FAMutation = () => {
    return useMutation({
        mutationFn: (data: ResendOTPInput) => resendTwoFactorOTP(data)
    });
};

export const useRegisterMutation = () => {
    return useMutation({
        mutationFn: ({ data, mode }: { data: RegisterInput | FormData; mode?: string }) => register(data, mode)
    });
};

export const useSetupPortalMutation = () => {
    return useMutation({
        mutationFn: (data: Record<string, unknown>) => setupPortal(data)
    });
};

import { useState, useCallback } from 'react';
import api from '../api/axios';
import { AxiosRequestConfig, AxiosError, AxiosResponse } from 'axios';
import { z } from 'zod';

interface UseAxiosResult<T> {
  data: T | null;
  error: string | null;
  loading: boolean;
  execute: (config?: AxiosRequestConfig) => Promise<T>;
  reset: () => void;
}

interface UseAxiosOptions<T> {
  method?: 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';
  url: string;
  initialData?: T | null;
  manual?: boolean;
  schema?: z.ZodSchema<T>; // Optional runtime validation
}

/**
 * A generic hook for Axios requests with type safety and optional Zod validation.
 * @param options Configuration options for the hook
 */
export function useAxios<T = any>(options: UseAxiosOptions<T>): UseAxiosResult<T> {
  const [data, setData] = useState<T | null>(options.initialData || null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState<boolean>(!options.manual);

  const execute = useCallback(async (config?: AxiosRequestConfig) => {
    setLoading(true);
    setError(null);

    try {
      const response: AxiosResponse<T> = await api({
        method: options.method || 'GET',
        url: options.url,
        ...config,
      });

      let result = response.data;

      // Optional Zod Validation
      if (options.schema) {
        const validation = options.schema.safeParse(result);
        if (!validation.success) {
          console.error("Type Validation Failed:", validation.error);
          throw new Error("Data validation failed");
        }
        result = validation.data;
      }

      setData(result);
      return result;
    } catch (err) {
      const axiosError = err as AxiosError<{ message: string }>;
      const errorMessage = axiosError.response?.data?.message || axiosError.message || 'An unexpected error occurred';
      setError(errorMessage);
      throw err;
    } finally {
      setLoading(false);
    }
  }, [options.method, options.url, options.schema]);

  return { data, error, loading, execute, reset: () => { setData(null); setError(null); setLoading(false); } };
}

import { useState, useEffect, useCallback, useRef } from 'react';

type ConnectionStatus = 'DISCONNECTED' | 'CONNECTING' | 'CONNECTED' | 'ERROR';

interface UseBiometricDeviceProps {
  onMatch?: (empId: string, name: string) => void;
  onEnrollSuccess?: () => void;
  onEnrollFail?: (reason?: string) => void;
  onEnrollProgress?: (step: number) => void;
}

export const useBiometricDevice = ({
  onMatch,
  onEnrollSuccess,
  onEnrollFail,
  onEnrollProgress
}: UseBiometricDeviceProps = {}) => {
  const [status, setStatus] = useState<ConnectionStatus>('DISCONNECTED');
  const [deviceConnected, setDeviceConnected] = useState(false);
  const [lastMessage, setLastMessage] = useState<string>('');
  const socketRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const reconnectDelayRef = useRef<number>(2000); // Start with 2s
  const isVisibleRef = useRef<boolean>(true);

  // Store callbacks in refs to avoid dependency changes triggering reconnects
  const onMatchRef = useRef(onMatch);
  const onEnrollSuccessRef = useRef(onEnrollSuccess);
  const onEnrollFailRef = useRef(onEnrollFail);
  const onEnrollProgressRef = useRef(onEnrollProgress);

  useEffect(() => {
    onMatchRef.current = onMatch;
    onEnrollSuccessRef.current = onEnrollSuccess;
    onEnrollFailRef.current = onEnrollFail;
    onEnrollProgressRef.current = onEnrollProgress;
  }, [onMatch, onEnrollSuccess, onEnrollFail, onEnrollProgress]);

  const connect = useCallback(() => {
    // If already connected or connecting, or tab is hidden, don't do anything
    if (socketRef.current?.readyState === WebSocket.OPEN || socketRef.current?.readyState === WebSocket.CONNECTING) return;
    if (!isVisibleRef.current) return;

    setStatus('CONNECTING');
    try {
      const ws = new WebSocket('ws://localhost:4649');

      ws.onopen = () => {
        setStatus('CONNECTED');
        setDeviceConnected(true); // Optimistic: Assume device is ready to avoid UI flicker
        console.log('Biometric WS Connected');
        reconnectDelayRef.current = 2000; // Reset delay on successful connection
        if (reconnectTimeoutRef.current) clearTimeout(reconnectTimeoutRef.current);
      };

      ws.onclose = (event) => {
        setStatus('DISCONNECTED');
        socketRef.current = null;
        
        // Only attempt reconnect if tab is visible
        if (isVisibleRef.current) {
            if (reconnectTimeoutRef.current) clearTimeout(reconnectTimeoutRef.current);
            
            // Exponential backoff: cap at 30 seconds
            const delay = reconnectDelayRef.current;
            reconnectTimeoutRef.current = setTimeout(connect, delay);
            reconnectDelayRef.current = Math.min(delay * 1.5, 30000);
        }
      };

      ws.onerror = () => {
        // Silently handle connection refusal to avoid console spam
        setStatus('ERROR');
      };

      ws.onmessage = (event) => {
        const msg = event.data as string;
        setLastMessage(msg);
        console.log('WS Message:', msg);

        if (msg === 'DEVICE_CONNECTED') {
          setDeviceConnected(true);
        } else if (msg === 'DEVICE_DISCONNECTED') {
          setDeviceConnected(false);
        } else if (msg.startsWith('SCAN_MATCH:')) {
          const parts = msg.replace('SCAN_MATCH:', '').split('|');
          if (parts.length >= 2) {
            onMatchRef.current?.(parts[0], parts[1]);
          }
        } else if (msg === 'ENROLL_SUCCESS') {
          onEnrollSuccessRef.current?.();
        } else if (msg.startsWith('ENROLL_PROGRESS')) {
          if (msg.includes('STEP_1')) {
             onEnrollProgressRef.current?.(1);
          } else if (msg.includes('STEP_2')) {
             onEnrollProgressRef.current?.(2);
          } else {
             onEnrollProgressRef.current?.(1);
          }
        } else if (msg.startsWith('ENROLL_ERROR') || msg === 'ENROLL_FAIL' || msg === 'ENROLL_CANCELLED') {
          onEnrollFailRef.current?.(msg);
        }
      };

      socketRef.current = ws;
    } catch (err) {
      console.error('WS Setup Error', err);
      setStatus('ERROR');
    }
  }, []); // Empty dependency array - connect never changes now

  // Handle visibility changes to pause reconnection when tab is backgrounded
  useEffect(() => {
    const handleVisibilityChange = () => {
      isVisibleRef.current = document.visibilityState === 'visible';
      if (isVisibleRef.current && status === 'DISCONNECTED') {
        // Re-trigger connect if we became visible and are disconnected
        connect();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [status, connect]);

  useEffect(() => {
    connect();
    return () => {
      // Cleanup on unmount
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
      }
      if (socketRef.current) {
        const socket = socketRef.current;
        // Remove listeners to prevent zombie callbacks
        socket.onclose = null;
        socket.onmessage = null;
        socket.onerror = null;
        socket.onopen = null;

        if (socket.readyState === WebSocket.CONNECTING) {
            // If connecting, wait for open before closing to avoid "closed before established" error
            socket.onopen = () => socket.close();
        } else {
            socket.close();
        }
        socketRef.current = null;
      }
    };
  }, [connect]);

  const enroll = (id: string | number, name: string, department: string) => {
    console.log(`Sending Enroll Request: ${id}|${name}|${department}`);
    if (socketRef.current?.readyState === WebSocket.OPEN) {
      socketRef.current.send(`ENROLL_START:${id}|${name}|${department}`);
    } else {
      console.warn('Cannot enroll: WS not connected');
      // Try reconnecting?
      if (!socketRef.current || socketRef.current.readyState === WebSocket.CLOSED) {
          connect();
      }
    }
  };

  const cancel = () => {
    if (socketRef.current?.readyState === WebSocket.OPEN) {
      socketRef.current.send('ENROLL_CANCEL');
    }
  };

  return {
    status,
    deviceConnected,
    lastMessage,
    enroll,
    cancel,
    resetDevice: () => {
        console.log('resetDevice called, socket state:', socketRef.current?.readyState);
        if (socketRef.current?.readyState === WebSocket.OPEN) {
            console.log('Sending RESET_DEVICE to middleware');
            socketRef.current.send('RESET_DEVICE');
        } else {
            console.warn('Cannot reset device: WS not connected');
        }
    },
    isConnected: status === 'CONNECTED'
  };
};

