          onView={openViewModal}
          onEdit={openEditForm}
          onDelete={openDeleteModal}
        />

        {/* Create/Edit Modal */}
        <MemoFormModal
          isOpen={isFormOpen}
          onClose={closeFormModal}
          onSubmit={handleSubmit}
          formData={formData}
          onFormChange={handleFormChange}
          employees={employees}
