        {/* View Modal */}
        <MemoViewModal
          isOpen={isViewOpen}
          onClose={closeViewModal}
          memo={selectedMemo ?? undefined}
        />

        {/* Delete Modal */}
        <MemoDeleteModal
          isOpen={isDeleteOpen}
          onClose={closeDeleteModal}
          onConfirm={handleDelete}
          memo={selectedMemo ?? undefined}
          saving={saving}
        />
      </div>
    </div>
  );
});

