import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useUIStore } from '@/stores';
import { ArrowLeft } from 'lucide-react';

import { fetchEmployeeProfile, revertEmployeeStatus } from '@/api/employeeApi';
import { useToastStore } from '@/stores';
import { EmployeeDetailed } from '@/types';

// Profile Components
import ProfileHeader from '@features/EmployeeManagement/Employee/Portal/Profile/ProfileHeader';
import PDSFormWizard from '@features/EmployeeManagement/Employee/Portal/Profile/PDSFormWizard';

// Profile loading skeleton
import ProfileSkeleton from '@features/EmployeeManagement/Employee/Portal/Profile/ProfileSkeleton';

const EmployeeProfile: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const sidebarOpen = useUIStore((state) => state.sidebarOpen);
  
  const [profile, setProfile] = useState<EmployeeDetailed | null>(null);
  const [loading, setLoading] = useState<boolean>(true);

  const showToast = useToastStore((state) => state.showToast);
  const showNotification = useCallback((message: string, type: 'success' | 'error') => showToast(message, type), [showToast]);
  
  const loadData = useCallback(async (): Promise<void> => {
    try {
      setLoading(true);
      if (!id) return;
      const profileRes = await fetchEmployeeProfile(id);
      if (profileRes.success && profileRes.profile) {
        setProfile(profileRes.profile as EmployeeDetailed);
      } else {
        showNotification(profileRes.message || 'Failed to load profile', 'error');
      }
    } catch (error) {
      showNotification('An error occurred while loading profile', 'error');
    } finally {
      setLoading(false);
    }
  }, [id, showNotification]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  // Handle status change (revert/reactivate)
  const handleStatusChange = async (employeeId: number, newStatus: string): Promise<void> => {
    try {
      const result = await revertEmployeeStatus(employeeId, newStatus, 'Reverted by admin');
      if (result.success) {
        showNotification(result.message || 'Status updated', 'success');
        loadData();
      } else {
        showNotification(result.message || 'Failed to update status', 'error');
      }
    } catch (error) {
      showNotification('An error occurred while updating status', 'error');
    }
  };

  if (loading) return (
    <div className={`min-h-screen flex flex-col bg-white rounded-xl shadow-sm border border-gray-200 p-0 w-full overflow-hidden text-gray-800 transition-all duration-300`}>
      <div className="flex items-center justify-between mb-6 pb-4 border-b border-gray-100 px-6 pt-6">
        <button 
          onClick={() => navigate('/admin-dashboard/employees')}
          className="flex items-center gap-2 text-gray-500 hover:text-gray-800 transition-colors"
        >
          <ArrowLeft size={18} />
          <span className="font-bold text-sm">Return to Directory</span>
        </button>
      </div>
      <ProfileSkeleton />
    </div>
  );
  
  if (!profile) return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      <div className="text-center p-8 bg-white rounded-2xl shadow-sm border border-gray-100 max-w-md">
        <h2 className="text-xl font-bold text-gray-800 mb-2">Profile Not Found</h2>
        <p className="text-gray-500 mb-6">The employee record you are looking for might have been removed or moved.</p>
        <button 
          onClick={() => navigate('/admin-dashboard/employees')}
          className="bg-gray-900 text-white px-6 py-2 rounded-xl font-bold"
        >
          Back to Directory
        </button>
      </div>
    </div>
  );

  return (
    <div className={`min-h-screen flex flex-col bg-gray-50 p-0 w-full overflow-hidden text-gray-800 transition-all duration-300`}>

      {/* Navigation Header */}
      <div className="flex items-center justify-between mb-6 pb-4 border-b border-gray-200 bg-white px-6 pt-6 sticky top-0 z-10">
        <button 
          onClick={() => navigate('/admin-dashboard/employees')}
          className="flex items-center gap-2 text-gray-500 hover:text-gray-800 transition-colors"
        >
          <ArrowLeft size={18} />
          <span className="font-bold text-sm">Return to Directory</span>
        </button>
      </div>

      {/* Profile Header with HR Details */}
      <div className="mb-6 px-6">
        <ProfileHeader 
            profile={profile}
            isAdmin={true}
            onStatusToggle={() => {
              const newStatus = profile.employmentStatus === 'Active' ? 'Suspended' : 'Active';
              handleStatusChange(profile.id, newStatus);
            }}
            statusLoading={false}
        />
      </div>

      {/* Primary Content: PDS Form Wizard */}
      <div className="px-6 pb-8">
        <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
          <PDSFormWizard employeeId={Number(id)} />
        </div>
      </div>
    </div>
  );
};

export default EmployeeProfile;

import React, { useEffect, useState } from 'react';
import { Network, Building2, User, Users, ChevronDown, ChevronRight, Search, ZoomIn, ZoomOut, Maximize } from 'lucide-react';
import { getPositions } from '@/api/plantillaApi';
import { type Position } from '@/api/plantillaApi';
import { motion, AnimatePresence } from 'framer-motion';

// Types
interface DepartmentNode {
  id: number;
  name: string;
  head?: Position;
  positions: Position[];
  children?: DepartmentNode[];
}

const OrgChartPage: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [positions, setPositions] = useState<Position[]>([]);
  const [departments, setDepartments] = useState<DepartmentNode[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [zoom, setZoom] = useState(1);
  const [expandedDepts, setExpandedDepts] = useState<Record<string, boolean>>({});

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const { data } = await getPositions({}); 
      if (data.success) {
        setPositions(data.positions);
        processDepartments(data.positions);
      }
    } catch (error) {
      console.error('Failed to fetch org chart data:', error);
    } finally {
      setLoading(false);
    }
  };

  const processDepartments = (allPositions: Position[]) => {
    // Group by department
    const deptMap = new Map<string, Position[]>();
    allPositions.forEach(pos => {
      const dept = pos.department || 'Unassigned';
      if (!deptMap.has(dept)) {
        deptMap.set(dept, []);
      }
      deptMap.get(dept)?.push(pos);
    });

    // Create Department Nodes
    const deptNodes: DepartmentNode[] = Array.from(deptMap.entries()).map(([name, posts], index) => {
      // Find highest ranking position (highest SG) to assume as Head if not explicit
      // Sort by SG desc, Step desc, Item No asc
      const sorted = [...posts].sort((a, b) => b.salaryGrade - a.salaryGrade || b.stepIncrement - a.stepIncrement);
      
      return {
        id: index,
        name,
        head: sorted[0], // Highest SG is likely the head
        positions: sorted.slice(1) // rest
      };
    });

    setDepartments(deptNodes);
    // Expand all by default
    const initialExpanded = deptNodes.reduce((acc, dept) => ({ ...acc, [dept.name]: true }), {});
    setExpandedDepts(initialExpanded);
  };

  const toggleDept = (name: string) => {
    setExpandedDepts(prev => ({ ...prev, [name]: !prev[name] }));
  };

  const filteredDepartments = departments.filter(dept => 
    dept.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    dept.head?.positionTitle.toLowerCase().includes(searchTerm.toLowerCase()) ||
    dept.head?.incumbentName?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="p-6 bg-gray-50 min-h-screen font-sans text-gray-800">
      
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-extrabold text-gray-900 tracking-tight flex items-center gap-3">
            <Network className="text-blue-600" size={32} />
            Organizational Chart
          </h1>
          <p className="text-gray-500 mt-1">Visual hierarchy of departments and positions.</p>
        </div>

        <div className="flex items-center gap-3 bg-white p-1 rounded-lg border border-gray-200 shadow-sm">
           <div className="relative">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
             <input 
               type="text" 
               placeholder="Search department or person..." 
               className="pl-9 pr-4 py-2 bg-transparent outline-none text-sm w-64"
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
             />
           </div>
           <div className="h-6 w-px bg-gray-200 mx-1"></div>
           <button onClick={() => setZoom(Math.max(0.5, zoom - 0.1))} className="p-2 hover:bg-gray-100 rounded text-gray-500"><ZoomOut size={16} /></button>
           <span className="text-xs font-mono w-12 text-center text-gray-400">{Math.round(zoom * 100)}%</span>
           <button onClick={() => setZoom(Math.min(1.5, zoom + 0.1))} className="p-2 hover:bg-gray-100 rounded text-gray-500"><ZoomIn size={16} /></button>
        </div>
      </div>

      {loading ? (
        <div className="flex items-center justify-center h-96">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      ) : (
        <div className="overflow-auto border border-gray-200 rounded-xl bg-white shadow-inner p-8 relative min-h-[600px]">
          
          <div 
            className="transition-transform origin-top-left"
            style={{ transform: `scale(${zoom})`, width: `${filteredDepartments.length * 320}px` }} 
          >
            <div className="flex flex-wrap items-start justify-center gap-8">
              {filteredDepartments.map((dept) => (
                <DepartmentCard 
                  key={dept.name} 
                  dept={dept} 
                  expanded={!!expandedDepts[dept.name]} 
                  onToggle={() => toggleDept(dept.name)}
                />
              ))}
            </div>
          </div>

        </div>
      )}
    </div>
  );
};

const DepartmentCard: React.FC<{ dept: DepartmentNode; expanded: boolean; onToggle: () => void }> = ({ dept, expanded, onToggle }) => {
  return (
    <motion.div 
      layout
      className="w-80 bg-white border border-gray-200 rounded-xl shadow-lg overflow-hidden flex flex-col"
    >
      {/* Head of Office (Header) */}
      <div 
        className="bg-gradient-to-br from-blue-900 to-blue-800 p-4 text-white cursor-pointer relative"
        onClick={onToggle}
      >
        <div className="absolute top-4 right-4 text-blue-200">
           {expanded ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
        </div>
        <div className="flex items-center gap-2 text-blue-200 mb-2">
           <Building2 size={14} />
           <span className="text-xs font-bold uppercase tracking-wider">{dept.name}</span>
        </div>
        
        {/* Head Profile */}
        <div className="flex items-center gap-3">
           <div className="w-10 h-10 rounded-full bg-blue-700/50 flex items-center justify-center border border-blue-500/30">
              <User size={20} className="text-blue-100" />
           </div>
           <div>
              <p className="font-bold text-sm leading-tight">{dept.head?.incumbentName || 'Vacant'}</p>
              <p className="text-[10px] text-blue-200 font-medium">{dept.head?.positionTitle || 'Head of Office'}</p>
              <span className="inline-block mt-1 px-1.5 py-0.5 bg-blue-950/50 rounded text-[9px] text-blue-300">
                 SG {dept.head?.salaryGrade}
              </span>
           </div>
        </div>
      </div>

      {/* Staff List */}
      <AnimatePresence>
        {expanded && (
          <motion.div 
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="bg-gray-50 border-t border-gray-100"
          >
            <div className="p-2 flex items-center justify-between bg-gray-100/50 border-b border-gray-200 px-4">
               <span className="text-[10px] font-bold text-gray-500 uppercase flex items-center gap-1">
                 <Users size={10} /> Workforce
               </span>
               <span className="text-[10px] font-bold text-gray-500 bg-gray-200 px-1.5 rounded-full">{dept.positions.length}</span>
            </div>
            <div className="max-h-[300px] overflow-y-auto p-2 scrollbar-thin">
              {dept.positions.map((pos) => (
                <div key={pos.id} className="flex items-center gap-3 p-2 hover:bg-white rounded-lg transition-colors border border-transparent hover:border-gray-100 group">
                   <div className={`w-2 h-2 rounded-full ${pos.isVacant ? 'bg-amber-400' : 'bg-green-500'}`}></div>
                   <div className="flex-1 min-w-0">
                      <p className={`text-xs font-bold truncate ${pos.isVacant ? 'text-gray-400 italic' : 'text-gray-800'}`}>
                        {pos.incumbentName || 'Vacant'}
                      </p>
                      <p className="text-[10px] text-gray-500 truncate">{pos.positionTitle}</p>
                   </div>
                   <div className="text-[9px] text-gray-400 font-mono bg-gray-100 px-1 rounded opacity-50 group-hover:opacity-100">
                      SG{pos.salaryGrade}
                   </div>
                </div>
              ))}
              {dept.positions.length === 0 && (
                <div className="text-center py-4 text-xs text-gray-400 italic">No additional staff</div>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default OrgChartPage;

import React, { useState, useCallback, forwardRef, useImperativeHandle } from 'react';
import { Plus } from 'lucide-react';
import { useUIStore } from '@/stores';
import { usePlantilla, Position } from '@features/EmployeeManagement/Admin/Plantilla/hooks/usePlantilla';
import PlantillaHeader from '@features/EmployeeManagement/Admin/Plantilla/components/PlantillaHeader';
import PlantillaTable from '@features/EmployeeManagement/Admin/Plantilla/components/PlantillaTable';
import PlantillaFormModal from '@features/EmployeeManagement/Admin/Plantilla/components/PlantillaFormModal';
import AppointmentFormModal from '@features/EmployeeManagement/Admin/Plantilla/components/AppointmentFormModal';
import { AssignModal, VacateModal, HistoryModal, GuideModal } from '@features/EmployeeManagement/Admin/Plantilla/components/PlantillaModals';

const BudgetTrackingDashboard = React.lazy(() => import('@/components/Custom/Compliance/BudgetTrackingDashboard'));
const ComplianceReportsDashboard = React.lazy(() => import('@/components/Custom/Compliance/ComplianceReportsDashboard'));
const StepIncrementDashboard = React.lazy(() => import('@/components/Custom/Compliance/StepIncrementDashboard'));
const QualificationStandardsPage = React.lazy(() => import('@/pages/EmployeeManagementAdmin/QualificationStandardsPage'));

interface OutletContext {
  sidebarOpen?: boolean;
}


interface PlantillaManagementProps {
  hideHeader?: boolean;
}

export interface PlantillaManagementRef {
  openAddModal: () => void;
}

interface FormData {
  itemNumber: string;
  positionTitle: string;
  salaryGrade: string;
  stepIncrement: number;
  department: string;
  monthlySalary: string;
  isVacant: boolean;
}

type TabType = 'positions' | 'qualifications' | 'step-increment' | 'budget' | 'reports';

const PlantillaManagement = forwardRef<PlantillaManagementRef, PlantillaManagementProps>(({ hideHeader = false }, ref) => {
    const sidebarOpen = useUIStore((state) => state.sidebarOpen);
    const [isGuideOpen, setIsGuideOpen] = useState<boolean>(false);
    const [activeTab, setActiveTab] = useState<TabType>('positions');

    const {
        // State
        loading, error, departments, summary,
        selectedDept, setSelectedDept, searchTerm, setSearchTerm,
        isModalOpen, setIsModalOpen, modalMode, setModalMode, 
        currentPosition, setCurrentPosition,
        isAssignModalOpen, setIsAssignModalOpen, availableEmployees, selectedEmployee, setSelectedEmployee,
        isHistoryModalOpen, setIsHistoryModalOpen, positionHistory,
        isVacateModalOpen, setIsVacateModalOpen, vacateReason, setVacateReason,
        filteredPositions,

        // Actions
        handleDelete, handleCreateOrUpdate, handleAssign, handleVacate, fetchHistory, openAssignModal, openAppointmentModal,
        isAppointmentModalOpen, setIsAppointmentModalOpen
    } = usePlantilla();

    const handleOpenCreate = useCallback((): void => {
        setModalMode('create');
        setCurrentPosition(null);
        setIsModalOpen(true);
    }, [setModalMode, setCurrentPosition, setIsModalOpen]);

    // Expose modal trigger to parent
    useImperativeHandle(ref, () => ({
        openAddModal: () => handleOpenCreate()
    }));

    const handleOpenEdit = useCallback((position: Position): void => {
        setModalMode('edit');
        setCurrentPosition(position);
        setIsModalOpen(true);
    }, [setModalMode, setCurrentPosition, setIsModalOpen]);

    const handleOpenVacate = useCallback((pos: Position): void => {
        setCurrentPosition(pos);
        setVacateReason('');
        setIsVacateModalOpen(true);
    }, [setCurrentPosition, setVacateReason, setIsVacateModalOpen]);

    const tabs = [
        { id: 'positions' as TabType, label: 'Positions' },
        { id: 'qualifications' as TabType, label: 'Qualification Standards' },
        { id: 'step-increment' as TabType, label: 'Step Increment' },
        { id: 'budget' as TabType, label: 'Budget Tracking' },
        { id: 'reports' as TabType, label: 'Compliance Reports' },
    ];

    return (
        <div className="w-full">
            {/* Header Section */}
            {!hideHeader && (
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
                    <div>
                        <h2 className="text-2xl font-bold text-gray-900">Plantilla Management System</h2>
                        <p className="text-sm text-gray-600 mt-1">100% CSC/DBM/COA Compliant Position & Personnel Management</p>
                    </div>
                    <div className="flex items-center gap-3">
                        <button 
                            className="px-5 py-2.5 bg-white hover:bg-gray-50 text-gray-700 rounded-lg border border-gray-300 transition-all text-sm font-semibold"
                            onClick={() => setIsGuideOpen(true)}
                        >
                            View Guide
                        </button>
                        {activeTab === 'positions' && (
                            <button 
                                className="bg-white hover:bg-gray-50 text-gray-900 border border-gray-300 px-5 py-2.5 rounded-lg flex items-center gap-2 shadow-sm transition-all active:scale-95 text-sm font-bold"
                                onClick={handleOpenCreate}
                            >
                                <Plus size={18} />
                                New Position
                            </button>
                        )}
                    </div>
                </div>
            )}

            {/* Tabs Navigation */}
            <div className="bg-gray-100 p-1 rounded-xl mb-6 flex gap-1 w-full overflow-hidden">
                <div className="flex overflow-x-auto gap-1 w-full no-scrollbar">
                    {tabs.map((tab) => {
                        const isActive = activeTab === tab.id;
                        return (
                            <button
                                key={tab.id}
                                onClick={() => setActiveTab(tab.id)}
                                className={`flex-1 min-w-fit px-5 py-2 rounded-lg text-sm font-semibold transition-all duration-200 ${
                                    isActive
                                        ? 'text-gray-900 bg-white shadow-sm'
                                        : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                                }`}
                            >
                                {tab.label}
                            </button>
                        );
                    })}
                </div>
            </div>

            {/* Tab Content */}
            <div className="bg-white rounded-lg border border-gray-200 p-6">
                {activeTab === 'positions' && (
                    <>
                        <PlantillaHeader 
                            departments={departments}
                            selectedDept={selectedDept}
                            setSelectedDept={setSelectedDept}
                            searchTerm={searchTerm}
                            setSearchTerm={setSearchTerm}
                            summary={summary}
                            onCreateNew={handleOpenCreate}
                            hideHeader={true}
                            onExportPDF={() => {
                                import('@features/EmployeeManagement/Admin/Plantilla/components/print/psipop_pdf_generator')
                                    .then(({ generatePSIPOPPDF }) => {
                                        const deptName = selectedDept === 'All' 
                                            ? 'All Departments' 
                                            : departments.find(d => String(d.id) === String(selectedDept))?.name || 'Unknown';
                                        
                                        generatePSIPOPPDF(filteredPositions, {
                                            departmentGocc: deptName,
                                            bureauAgency: 'LGU Ligao',
                                            preparedBy: 'HR Officer',
                                            approvedBy: 'City Mayor'
                                        });
                                    });
                            }}
                            onExportExcel={() => {
                                import('@features/EmployeeManagement/Admin/Plantilla/components/print/psipop_excel_generator')
                                    .then(({ generatePSIPOPExcel }) => {
                                        const deptName = selectedDept === 'All' 
                                            ? 'All Departments' 
                                            : departments.find(d => String(d.id) === String(selectedDept))?.name || 'Unknown';
                                        generatePSIPOPExcel(filteredPositions, { departmentGocc: deptName });
                                    });
                            }}
                        />

                        <PlantillaTable 
                            positions={filteredPositions}
                            loading={loading}
                            onEdit={handleOpenEdit}
                            onDelete={handleDelete}
                            onAssign={openAssignModal}
                            onVacate={handleOpenVacate}
                            onViewHistory={fetchHistory}
                        />
                    </>
                )}

                {activeTab === 'qualifications' && (
                    <React.Suspense fallback={
                        <div className="flex items-center justify-center h-64">
                            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-600"></div>
                        </div>
                    }>
                        <QualificationStandardsPage />
                    </React.Suspense>
                )}

                {activeTab === 'step-increment' && (
                    <React.Suspense fallback={
                        <div className="flex items-center justify-center h-64">
                            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-600"></div>
                        </div>
                    }>
                        <StepIncrementDashboard />
                    </React.Suspense>
                )}

                {activeTab === 'budget' && (
                    <React.Suspense fallback={
                        <div className="flex items-center justify-center h-64">
                            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-600"></div>
                        </div>
                    }>
                        <BudgetTrackingDashboard selectedDeptName={
                            selectedDept === 'All' 
                                ? 'All' 
                                : departments.find(d => String(d.id) === String(selectedDept))?.name || 'All'
                        } />
                    </React.Suspense>
                )}

                {activeTab === 'reports' && (
                    <React.Suspense fallback={
                        <div className="flex items-center justify-center h-64">
                            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-600"></div>
                        </div>
                    }>
                        <ComplianceReportsDashboard />
                    </React.Suspense>
                )}
            </div>

            {/* Modals */}
            <PlantillaFormModal 
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                mode={modalMode}
                position={currentPosition}
                onSubmit={handleCreateOrUpdate}
                departments={departments}
            />

            <AssignModal 
                isOpen={isAssignModalOpen}
                onClose={() => setIsAssignModalOpen(false)}
                position={currentPosition}
                availableEmployees={availableEmployees}
                selectedEmployee={selectedEmployee}
                setSelectedEmployee={setSelectedEmployee}
                onAssign={handleAssign}
            />

            <VacateModal 
                isOpen={isVacateModalOpen}
                onClose={() => setIsVacateModalOpen(false)}
                position={currentPosition}
                vacateReason={vacateReason}
                setVacateReason={setVacateReason}
                onVacate={handleVacate}
            />

            <HistoryModal 
                isOpen={isHistoryModalOpen}
                onClose={() => setIsHistoryModalOpen(false)}
                position={currentPosition}
                history={positionHistory}
            />

            <AppointmentFormModal 
                isOpen={isAppointmentModalOpen}
                onClose={() => setIsAppointmentModalOpen(false)}
                position={currentPosition}
            />

            <GuideModal  
                isOpen={isGuideOpen}
                onClose={() => setIsGuideOpen(false)}
            />
        </div>
    );
});

