export default MyProfilePage;

import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { useUIStore } from '@/stores';

// Import components
import EmployeeDepartment from './MyDepartmentPage';
import EmployeeMemos from './MyMemosPage';

interface OutletContext {
  sidebarOpen?: boolean;
}

interface Tab {
  id: string;
  label: string;
}

const OrganizationalHubPage: React.FC = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const sidebarOpen = useUIStore((state) => state.sidebarOpen);

    // Get active tab from URL hash or default to 'department'
    const [activeTab, setActiveTab] = useState<string>(() => {
        const hash = location.hash.replace('#', '');
        return ['department', 'memos'].includes(hash) ? hash : 'department';
    });

    useEffect(() => {
        const hash = location.hash.replace('#', '');
        if (['department', 'memos'].includes(hash)) {
            setActiveTab(hash);
        }
    }, [location.hash]);

    const handleTabChange = (tabId: string): void => {
        setActiveTab(tabId);
        navigate(`#${tabId}`);
    };

    const tabs: Tab[] = [
        { id: 'department', label: 'Department' },
        { id: 'memos', label: 'Memos' }
    ];

    return (
        <div className={`flex flex-col bg-white rounded-2xl shadow-sm border border-gray-200 p-6 w-full overflow-hidden transition-all duration-300 ${!sidebarOpen ? 'max-w-[1600px] xl:max-w-[88vw]' : 'max-w-[1400px] xl:max-w-[77vw]'}`}>
            {/* Header Section */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
                <div>
                    <h1 className="text-xl font-bold text-gray-800">Employee Portal</h1>
                    <p className="text-sm text-gray-500">Access your department information and official memos</p>
                </div>
            </div>

            {/* Segmented Tab Navigation */}
            <div className="bg-gray-100 p-1 rounded-xl mb-6 inline-flex gap-1 w-fit">
                {tabs.map((tab) => {
                    const isActive = activeTab === tab.id;
                    return (
                        <button
                            key={tab.id}
                            onClick={() => handleTabChange(tab.id)}
                            className={`px-5 py-2 rounded-lg text-sm font-semibold transition-all duration-200 ${
                                isActive 
                                    ? 'text-gray-900 bg-white shadow-sm' 
                                    : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                            }`}
                        >
                            {tab.label}
                        </button>
                    );
                })}
            </div>

            {/* Content Area */}
            <div className="w-full">
                {activeTab === 'department' && <EmployeeDepartment hideHeader={true} />}
                {activeTab === 'memos' && <EmployeeMemos hideHeader={true} />}
            </div>
        </div>
    );
};

export default OrganizationalHubPage;

import React from 'react';
import { useToastStore } from '@/stores';
import { ReviewList, TabNavigation } from '@/components/Custom/Performance/components';
import EmployeePerformanceLayout from '@/components/Custom/Performance/EmployeePerformanceLayout';
import useEmployeeReviews from '@/hooks/useEmployeeReviews';
import { useNavigate } from 'react-router-dom';

const EmployeeReviews = () => {
    const navigate = useNavigate();
    const showToast = useToastStore((state) => state.showToast);
    const showNotification = (message: string, type: 'success' | 'error' | 'warning' | 'info') => showToast(message, type);
    
    const {
        loading,
        error,
        activeTab,
        setActiveTab,
        pendingReviews,
        completedReviews,
        handleViewDetails,
        handleStartSelfRating
    } = useEmployeeReviews({ showNotification });

    const onViewReview = (review: { id: string | number }) => {
        // Navigate to the shared ReviewForm component
        navigate(`/employee-dashboard/performance/reviews/${Number(review.id)}`);
    };

    const tabs = [
        { id: 'pending', label: 'Pending Action', count: pendingReviews.length },
        { id: 'completed', label: 'Completed', count: completedReviews.length }
    ];

    if (error) {
        return (
            <EmployeePerformanceLayout>
                <div className="bg-red-50 border border-red-200 p-6 rounded-lg text-center">
                    <p className="text-red-700 font-medium">{error}</p>
                    <button 
                        onClick={() => window.location.reload()}
                        className="mt-4 px-4 py-2 bg-white border border-red-200 rounded-lg text-red-700 hover:bg-red-50"
                    >
                        Try Again
                    </button>
                </div>
            </EmployeePerformanceLayout>
        );
    }

    return (
        <EmployeePerformanceLayout>

            
            <div className="space-y-6">
                <TabNavigation 
                    tabs={tabs} 
                    activeTab={activeTab} 
                    onTabChange={(id) => setActiveTab(String(id))} 
                />

                {loading ? (
                    <div className="flex justify-center py-20">
                        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-green-600"></div>
                    </div>
                ) : (
                    <ReviewList 
                        reviews={(activeTab === 'pending' ? pendingReviews : completedReviews) as unknown as Parameters<typeof ReviewList>[0]['reviews']}
                        activeTab={activeTab}
                        onViewDetails={onViewReview}
                        onStartSelfRating={onViewReview}
                    />
                )}
            </div>
        </EmployeePerformanceLayout>
    );
};

export default EmployeeReviews;

import React from 'react';
import { useState, useEffect, useMemo, useCallback } from 'react';
import { motion } from 'framer-motion';
import { SquarePen, Search, RefreshCw, Plus, AlertTriangle, FileText, Calendar, User, ChevronLeft, ChevronRight, Filter, Trash2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { fetchReviews, deleteReview } from '@api';
import { InternalReview } from '@/types/performance';
import { useFilterOptions } from '@/hooks/useFilterOptions';
import PerformanceLayout from '@components/Custom/Performance/PerformanceLayout';
import { formatFullName } from '../../utils/nameUtils';

import { useToastStore } from '@/stores';
import Combobox from '@/components/Custom/Combobox';

const ITEMS_PER_PAGE = 12;



const EvaluationHistory = () => {
  const navigate = useNavigate();
  const { data: filterOptions, isLoading: loadingFilters } = useFilterOptions();
  const departments = filterOptions.departments;

  const [reviews, setReviews] = useState<InternalReview[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedDepartment, setSelectedDepartment] = useState('All');
  const [currentPage, setCurrentPage] = useState(1);
  const [deleteModalOpen, setDeleteModalOpen] = useState(false);
  const [selectedReview, setSelectedReview] = useState<InternalReview | null>(null);
  const [deleting, setDeleting] = useState(false);
  
  const showToast = useToastStore((state) => state.showToast);
  const showNotification = (message: string, type: 'success' | 'error') => showToast(message, type);

  const loadData = useCallback(async () => {

    try {
      setLoading(true);
      setError(null);
      
      const reviewsRes = await fetchReviews();

      if (reviewsRes.success) {
        setReviews(reviewsRes.reviews);
      }
    } catch (err) {
      console.error('Failed to load evaluation history:', err);
      setError('Failed to load evaluation history. Please try again.');
    } finally {
      setLoading(false);
    }
  }, []);


  useEffect(() => {
    loadData();
  }, [loadData]);

  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, selectedDepartment]);

  const handleAction = useCallback((review: InternalReview) => {
    navigate(`/admin-dashboard/performance/reviews/${review.id}`);
  }, [navigate]);

  const handleDeleteClick = useCallback((review: InternalReview) => {
    setSelectedReview(review);
    setDeleteModalOpen(true);
  }, []);

  const handleConfirmDelete = useCallback(async () => {
    if (!selectedReview) return;
    
    try {
      setDeleting(true);
      const response = await deleteReview(selectedReview.id);
      if (response.success) {
        setReviews(prev => prev.filter(r => r.id !== selectedReview.id));
        setDeleteModalOpen(false);
        setSelectedReview(null);
        showNotification('Evaluation deleted successfully', 'success');
      }
    } catch (err: unknown) {
      console.error('Failed to delete evaluation:', err);
      showNotification(err instanceof Error ? err.message : 'Failed to delete evaluation', 'error');
    } finally {
      setDeleting(false);
    }
  }, [selectedReview, showNotification]);

  const filteredReviews = useMemo(() => {
    return reviews.filter(review => {
      const firstName = review.employeeFirstName || review.employeeFirst || '';
      const lastName = review.employeeLastName || review.employeeLast || '';
      // Evaluation API returns flattened strings; if no mid/suffix assume empty
      const employeeName = formatFullName(lastName, firstName).toLowerCase();
      const matchesSearch = employeeName.includes(searchTerm.toLowerCase());
      const matchesDept = selectedDepartment === 'All' || review.employeeDepartment === selectedDepartment;
      return matchesSearch && matchesDept;
    });
  }, [reviews, searchTerm, selectedDepartment]);

  const totalPages = useMemo(() => 
    Math.ceil(filteredReviews.length / ITEMS_PER_PAGE), 
  [filteredReviews.length]);

  const paginatedReviews = useMemo(() => {
    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
    return filteredReviews.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredReviews, currentPage]);

  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const endIndex = startIndex + paginatedReviews.length;

  const handlePageChange = useCallback((page: number) => {
    if (page >= 1 && page <= totalPages) setCurrentPage(page);
  }, [totalPages]);

  const formatDate = useCallback((dateString: string | null) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  }, []);

  const getStatusStyle = (status: string) => {
    switch (status) {
      case 'Finalized': return 'bg-slate-900 text-white border-transparent shadow-sm';
      case 'Approved': return 'bg-slate-700 text-white border-transparent';
      case 'Acknowledged': return 'bg-slate-500 text-white border-transparent';
      case 'Submitted': return 'bg-slate-100 text-slate-700 border-slate-200';
      case 'Draft': return 'bg-white text-slate-500 border-gray-200';
      default: return 'bg-gray-50 text-gray-400 border-gray-100';
    }
  };

  const getPageNumbers = () => {
    const pages = [];
    const maxVisiblePages = 5;
    if (totalPages <= maxVisiblePages) {
      for (let i = 1; i <= totalPages; i++) pages.push(i);
    } else {
      if (currentPage <= 3) {
        for (let i = 1; i <= 4; i++) pages.push(i);
        pages.push('...');
        pages.push(totalPages);
      } else if (currentPage >= totalPages - 2) {
        pages.push(1);
        pages.push('...');
        for (let i = totalPages - 3; i <= totalPages; i++) pages.push(i);
      } else {
        pages.push(1);
        pages.push('...');
        for (let i = currentPage - 1; i <= currentPage + 1; i++) pages.push(i);
        pages.push('...');
        pages.push(totalPages);
      }
    }
    return pages;
  };

  return (
    <PerformanceLayout>

      
      <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-gray-800">Evaluation History</h2>
          <div className="flex gap-3">
              <button
                onClick={loadData}
                className="flex items-center gap-2 px-4 py-2 bg-white hover:bg-gray-50 text-gray-700 border border-gray-300 rounded-lg shadow-sm transition-all"
                title="Refresh"
              >
                <RefreshCw size={18} className={loading ? 'animate-spin' : ''} />
              </button>
              <button
                onClick={() => navigate('/admin-dashboard/performance/reviews/new')}
                className="bg-white hover:bg-gray-50 text-gray-900 border border-gray-300 px-5 py-2.5 rounded-lg flex items-center gap-2 shadow-sm transition-all active:scale-95 text-sm font-bold"
              >
                <Plus size={18} />
                <span>New Evaluation</span>
              </button>
          </div>
      </div>

      <div className="bg-white p-4 rounded-xl border border-gray-200 mb-6 shadow-sm">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input
              type="text"
              placeholder="Search by employee name..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-gray-200 outline-none text-sm transition-all"
            />
          </div>
          
          <div className="flex items-center gap-2 min-w-[240px] z-[30] relative">
            <Filter size={18} className="text-gray-400" />
            <Combobox
              options={[
                { value: 'All', label: 'All Departments' },
                ...departments.map(dept => ({ value: dept, label: dept }))
              ]}
              value={selectedDepartment}
              onChange={(val) => setSelectedDepartment(val || 'All')}
              placeholder="All Departments"
              buttonClassName="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg outline-none text-sm"
            />
          </div>

          <div className="flex items-center gap-2 px-4 py-2 bg-blue-50 border border-blue-100 rounded-lg text-blue-800">
            <p className="text-xs font-bold uppercase tracking-wide opacity-70">Filtered Total</p>
            <p className="text-lg font-bold">{filteredReviews.length}</p>
          </div>
        </div>
      </div>

      {error && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-6 flex items-center gap-3">
          <AlertTriangle className="text-red-500" size={20} />
          <span className="text-red-700 font-medium">{error}</span>
        </div>
      )}

      {loading ? (
        <div className="flex justify-center py-20">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-800"></div>
        </div>
      ) : filteredReviews.length === 0 ? (
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-16 text-center">
          <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <FileText className="text-gray-400" size={32} />
          </div>
          <h3 className="text-xl font-bold text-gray-800 mb-2">No Evaluations Found</h3>
          <p className="text-gray-500 mb-6 max-w-md mx-auto">
            {searchTerm || selectedDepartment !== 'All' 
              ? 'Try adjusting your filters to find what you are looking for.' 
              : 'There are no performance evaluations recorded in the system yet.'}
          </p>
          {(searchTerm || selectedDepartment !== 'All') && (
            <button
              onClick={() => {setSearchTerm(''); setSelectedDepartment('All');}}
              className="text-gray-800 font-semibold hover:underline"
            >
              Clear all filters
            </button>
          )}
        </div>
      ) : (
        <div className="bg-[#F8F9FA] rounded-xl shadow-sm border border-gray-100 overflow-hidden p-1">
          <div className="overflow-x-auto bg-gray-50 rounded-lg">
            <table className="w-full text-left min-w-[1200px]">
              <thead className="bg-gray-200 shadow-md text-gray-700">
                <tr>
                  <th className="px-6 py-4 font-bold text-sm tracking-wide whitespace-nowrap">Employee</th>
                  <th className="px-6 py-4 font-bold text-sm tracking-wide whitespace-nowrap">Department</th>
                  <th className="px-6 py-4 font-bold text-sm tracking-wide whitespace-nowrap">Cycle / Period</th>
                  <th className="px-6 py-4 font-bold text-sm tracking-wide whitespace-nowrap text-center">Score</th>
                  <th className="px-6 py-4 font-bold text-sm tracking-wide whitespace-nowrap">Status</th>
                  <th className="px-6 py-4 font-bold text-sm tracking-wide whitespace-nowrap text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {paginatedReviews.map((review, index) => (
                  <motion.tr
                    key={review.id}
                    initial={{ opacity: 0, y: 5 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: index * 0.03 }}
                    className="hover:bg-[#F8F9FA] hover:shadow-xl transition-colors group"
                  >
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-9 h-9 bg-gray-200 rounded-full flex items-center justify-center shadow-inner group-hover:bg-white transition-colors">
                          <User className="text-gray-600" size={16} />
                        </div>
                        <div>
                          <p className="font-bold text-gray-800 text-sm">
                            {formatFullName(
                                review.employeeLastName || review.employeeLast,
                                review.employeeFirstName || review.employeeFirst
                            )}
                          </p>
                          <p className="text-[10px] text-gray-500 font-mono">{formatDate(review.createdAt)}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-xs text-gray-800">
                        {review.employeeDepartment || 'N/A'}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <p className="text-sm font-medium text-gray-700">{review.cycleTitle || 'Direct Evaluation'}</p>
                      <p className="text-xs text-gray-400">
                        {formatDate(review.reviewPeriodStart ?? null)} - {formatDate(review.reviewPeriodEnd ?? null)}
                      </p>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <div className="inline-block py-1 px-3 bg-white rounded-lg border border-gray-100 shadow-sm font-bold text-gray-800 text-sm">
                        {review.totalScore ? `${((parseFloat(String(review.totalScore)) / 5) * 100).toFixed(0)}%` : '-'}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border ${getStatusStyle(review.status)}`}>
                        {review.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-2 text-sm">
                        <button
                          onClick={() => handleAction(review)}
                          className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-white text-gray-700 border border-gray-200 text-xs font-medium rounded-lg hover:bg-gray-100 hover:border-gray-300 transition-all shadow-sm"
                        >
                          {review.status === 'Draft' ? <SquarePen size={14} /> : <FileText size={14} />}
                          {review.status === 'Draft' ? 'Continue' : 'Review'}
                        </button>
                        {review.status === 'Draft' && (
                          <button
                            onClick={() => handleDeleteClick(review)}
                            className="p-1.5 text-gray-400 hover:text-red-700 hover:bg-red-50 rounded-lg transition-colors border border-transparent hover:border-red-100"
                            title="Delete Draft"
                          >
                            <Trash2 size={16} />
                          </button>
                        )}
                      </div>
                    </td>
                  </motion.tr>
                ))}
              </tbody>
            </table>
          </div>

          {totalPages > 1 && (
            <div className="flex justify-between items-center mt-6 p-6 border-t border-gray-100 bg-white">
              <div className="text-sm text-gray-800">
                Showing <span className="font-semibold text-gray-800">{startIndex + 1}–{Math.min(endIndex, filteredReviews.length)}</span> of <span className="font-semibold text-gray-800">{filteredReviews.length}</span> records
              </div>
              <div className="flex items-center space-x-2">
                <button
                  onClick={() => handlePageChange(currentPage - 1)}
                  disabled={currentPage === 1}
                  className="px-4 py-2 bg-white border border-gray-300 rounded-lg shadow-sm disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 transition-all text-sm font-bold text-gray-700"
                >
                  Previous
                </button>
                <span className="text-sm px-4 py-2 bg-gray-50 text-gray-800 rounded-lg font-semibold">
                  Page {currentPage} of {totalPages}
                </span>
                <button
                  onClick={() => handlePageChange(currentPage + 1)}
                  disabled={currentPage === totalPages}
                  className="px-6 py-2 bg-white border border-gray-300 rounded-lg shadow-sm disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 transition-all text-sm font-bold text-gray-700"
                >
                  Next
                </button>
              </div>
            </div>
          )}
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {deleteModalOpen && (
        <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="bg-white rounded-xl shadow-2xl p-6 max-w-md w-full mx-4"
          >
            <div className="flex items-center gap-4 mb-4">
              <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center text-red-600">
                <AlertTriangle size={24} />
              </div>
              <div>
                <h3 className="text-lg font-bold text-gray-900">Delete Evaluation?</h3>
                <p className="text-sm text-gray-500">This action cannot be undone and will permanently remove this record.</p>
              </div>
            </div>
            
            <p className="text-sm text-gray-600 mb-6 bg-gray-50 p-4 rounded-lg border border-gray-100">
              Are you sure you want to delete the evaluation for{' '}
              <strong className="text-gray-900">{selectedReview?.employeeFirstName || selectedReview?.employeeFirst} {selectedReview?.employeeLastName || selectedReview?.employeeLast}</strong>?
            </p>

            <div className="flex gap-3 justify-end">
              <button
                onClick={() => {
                  setDeleteModalOpen(false);
                  setSelectedReview(null);
                }}
                disabled={deleting}
                className="px-4 py-2 text-gray-600 font-bold hover:bg-gray-100 rounded-lg transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleConfirmDelete}
                disabled={deleting}
                className="px-4 py-2 bg-red-600 text-white font-bold rounded-lg hover:bg-red-700 transition-colors shadow-sm disabled:opacity-50"
              >
                {deleting ? 'Deleting...' : 'Delete Permanently'}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </PerformanceLayout>
  );
};

export default EvaluationHistory;

import React from 'react';
import { useState, useEffect } from 'react';
import { Plus, Search, SquarePen, Trash2, Sliders, CheckCircle } from 'lucide-react';
import { fetchCriteria, addCriteria, updateCriteria, deleteCriteria } from '@api';
import PerformanceLayout from '@components/Custom/Performance/PerformanceLayout';
import EditCriteriaModal from '@components/Custom/Performance/Admin/Modals/EditCriteriaModal';
import DeleteConfirmationModal from '@components/Custom/Performance/Admin/Modals/DeleteConfirmationModal';
import { PerformanceCriteria as IPerformanceCriteria } from '@/types/performance';

const PerformanceCriteria = () => {
  const [criteriaList, setCriteriaList] = useState<IPerformanceCriteria[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  
  // Modal States
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [selectedCriteria, setSelectedCriteria] = useState<IPerformanceCriteria | null>(null);

  const loadCriteria = async () => {
    try {
      setLoading(true);
      const data = await fetchCriteria();
      if (data.success) {
        setCriteriaList(data.criteria);
      }
    } catch (err) {
      console.error("Failed to load criteria", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadCriteria();
  }, []);

  const handleAdd = () => {
    setSelectedCriteria(null);
    setIsEditModalOpen(true);
  };

  const handleEdit = (item: IPerformanceCriteria) => {
    setSelectedCriteria(item);
    setIsEditModalOpen(true);
  };

  const handleDeleteClick = (item: IPerformanceCriteria) => {
    setSelectedCriteria(item);
    setIsDeleteModalOpen(true);
  };

  const handleDeleteConfirm = async () => {
    if (selectedCriteria) {
      try {
        await deleteCriteria(selectedCriteria.id);
        setIsDeleteModalOpen(false);
        loadCriteria();
      } catch (err) {
        console.error("Failed to delete criteria", err);
      }
    }
  };

  const handleSave = async (formData: Partial<IPerformanceCriteria>) => {
    try {
      if (selectedCriteria) {
        await updateCriteria(selectedCriteria.id, formData);
      } else {
        await addCriteria(formData);
      }
      setIsEditModalOpen(false);
      loadCriteria();
    } catch (err) {
      console.error("Failed to save criteria", err);
    }
  };

  const filteredCriteria = criteriaList.filter(item => 
    item.title?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    item.category?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <PerformanceLayout>
      <div className="flex flex-col gap-6">
        {/* Header with Add Button */}
        <div className="flex justify-end">
          <button
            onClick={handleAdd}
            className="bg-white hover:bg-gray-50 text-gray-900 border border-gray-300 px-5 py-2.5 rounded-lg flex items-center gap-2 shadow-sm transition-all active:scale-95 text-sm font-bold"
          >
            <Plus size={18} />
            <span>Add Criteria</span>
          </button>
        </div>

        {/* Search */}
        <div className="bg-white p-4 rounded-lg border border-gray-200">
          <div className="flex items-center gap-3 bg-[#F8F9FA] px-4 py-2 rounded-lg border border-gray-200 focus-within:ring-2 focus-within:ring-gray-200 transition-all">
            <Search className="text-gray-400" size={18} />
            <input
              type="text"
              placeholder="Search criteria..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="flex-1 bg-transparent outline-none text-sm text-gray-700 placeholder-gray-400"
            />
          </div>
        </div>

        {loading ? (
          <div className="flex justify-center py-12">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-800"></div>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredCriteria.map((item) => {
              const borderColors: Record<string, string> = {
                'Strategic Priorities': 'border-l-slate-800',
                'Core Functions': 'border-l-slate-600',
                'Support Functions': 'border-l-slate-400',
                'General': 'border-l-slate-200'
              };
              const borderColor = borderColors[item.category] || 'border-gray-300';
              
              return (
                <div
                  key={item.id}
                  className={`bg-white p-6 rounded-2xl border border-gray-100 hover:border-gray-200 hover:shadow-lg transition-all group border-l-4 ${borderColor} animate-in fade-in zoom-in duration-300 shadow-sm flex flex-col h-full`}
                >
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex flex-col gap-1.5">
                        <span className="px-3 py-1 w-fit bg-gray-50 text-gray-500 rounded-lg text-[9px] font-black uppercase tracking-widest border border-gray-100">
                        {item.category}
                        </span>
                        {item.section && (
                            <span className="text-[9px] items-start text-gray-400 font-bold uppercase tracking-widest ml-1">
                                {item.section}
                            </span>
                        )}
                    </div>
                    <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all transform translate-x-2 group-hover:translate-x-0">
                      <button onClick={() => handleEdit(item)} className="text-gray-400 hover:text-gray-900 p-2 bg-gray-50 rounded-xl transition-all border border-gray-100 hover:shadow-sm">
                        <SquarePen size={14} />
                      </button>
                      <button onClick={() => handleDeleteClick(item)} className="text-gray-400 hover:text-red-600 p-2 bg-gray-50 rounded-xl transition-all border border-gray-100 hover:shadow-sm">
                        <Trash2 size={14} />
                      </button>
                    </div>
                  </div>

                  <h3 className="text-base font-bold text-gray-900 mb-2 tracking-tight group-hover:text-blue-900 transition-colors">{item.title}</h3>
                  <p className="text-gray-500 text-xs mb-6 line-clamp-2 min-h-[2.5em] leading-relaxed flex-1">{item.description}</p>

                  <div className="flex items-center justify-between pt-5 border-t border-gray-50 mt-auto">
                    <div className="flex items-center gap-2.5 text-gray-500">
                      <div className="p-2 bg-gray-50 rounded-xl border border-gray-100 group-hover:bg-blue-50 group-hover:border-blue-100 transition-colors">
                        <Sliders size={14} className="text-gray-400 group-hover:text-blue-600 transition-colors" />
                      </div>
                      <div className="flex flex-col">
                        <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter">Weight</span>
                        <span className="font-black text-gray-900 text-sm">{item.weight}%</span>
                      </div>
                    </div>
                    <div className="flex items-center gap-2.5 text-gray-500">
                      <div className="p-2 bg-gray-50 rounded-xl border border-gray-100 group-hover:bg-purple-50 group-hover:border-purple-100 transition-colors">
                        <CheckCircle size={14} className="text-gray-400 group-hover:text-purple-600 transition-colors" />
                      </div>
                      <div className="flex flex-col items-end text-right">
                        <span className="text-[10px] font-bold text-gray-400 uppercase tracking-tighter">Max Score</span>
                        <span className="font-black text-gray-900 text-sm">{item.maxScore}</span>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Edit/Add Modal */}
      <EditCriteriaModal 
        isOpen={isEditModalOpen}
        onClose={() => setIsEditModalOpen(false)}
        onSubmit={handleSave}
        initialData={selectedCriteria as unknown as import('@components/Custom/Performance/types').PerformanceItem | null}
      />

      {/* Delete Confirmation Modal */}
      <DeleteConfirmationModal
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        itemName={selectedCriteria?.title}
      />
    </PerformanceLayout>
  );
};

export default PerformanceCriteria;

import { useAdminPerformance } from "@/components/Custom/Performance/Admin/Hooks/useAdminPerformance";
import { PerformanceNotification } from "@/components/Custom/Performance/Admin/Components/PerformanceNotification";
import { PerformanceFilters } from "@/components/Custom/Performance/Admin/Components/PerformanceFilters";
import { PerformanceSearchBar } from "@/components/Custom/Performance/Admin/Components/PerformanceSearchBar";

import { PerformanceTable } from "@/components/Custom/Performance/Admin/Components/PerformanceTable";
import { PerformanceLoadingSpinner } from "@/components/Custom/Performance/Admin/Components/PerformanceLoadingSpinner";
import PerformanceLayout from "@/components/Custom/Performance/PerformanceLayout";
import Pagination from '@/components/CustomUI/Pagination';

const PerformanceEvaluationDashboard = () => {
  const { 
    today, sidebarOpen, filters, searchQuery, debouncedSearchQuery, currentPage, isLoading, loadingType, error, successMessage, filteredData, paginationData, uniqueDepartments, uniqueEmployees, stats,
    handleRefresh, handlePageChange, getStatusBadge,
    handleFilterChange, handleApply, handleClear, handleSearchChange, setError, setSuccessMessage 
  } = useAdminPerformance();

  const { totalPages, startIndex, endIndex, currentItems } = paginationData;

  if (isLoading && loadingType === "data") {
    return <PerformanceLoadingSpinner loadingType={loadingType} />;
  }

  return (
    <PerformanceLayout>
      {/* Error Message */}
      {error && (
        <PerformanceNotification 
          type="error"
          message={error}
          onClose={() => setError(null)}
        />
      )}

      {/* Success Message */}
      {successMessage && (
        <PerformanceNotification 
          type="success"
          message={successMessage}
          onClose={() => setSuccessMessage(null)}
        />
      )}

      <PerformanceFilters 
        filters={filters}
        handleFilterChange={handleFilterChange}
        handleApply={handleApply}
        handleClear={handleClear}
        isLoading={isLoading}
        uniqueDepartments={uniqueDepartments}
        uniqueEmployees={uniqueEmployees}
      />

      <PerformanceSearchBar 
        searchQuery={searchQuery}
        handleSearchChange={handleSearchChange}
        filteredDataLength={filteredData.length}
        isLoading={isLoading}
      />



      <PerformanceTable 
        currentItems={currentItems}
        getStatusBadge={getStatusBadge}
        debouncedSearchQuery={debouncedSearchQuery}
        filters={filters}
        isLoading={isLoading}
      />

      {!isLoading && filteredData.length > 0 && (
        <Pagination 
          currentPage={currentPage}
          totalPages={totalPages}
          onPageChange={handlePageChange}
          totalItems={filteredData.length}
          itemsPerPage={5} // Based on standard or check constant in hook
        />
      )}
    </PerformanceLayout>
  );
};

