                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-6">
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-500 tracking-tight">Eligibility Name / Title {requireCsc && <span className="text-red-500 ml-1">*</span>}</label>
                                            <input type="text" {...register('eligibility')} className="w-full px-3 py-2 bg-white border border-gray-300 border-gray-200 rounded-lg focus:border-green-600 outline-none text-sm font-medium text-slate-700 placeholder:text-slate-300 shadow-sm" placeholder="e.g. CSR Prof, CPA, Driver's License" />
                                        </div>
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-500 tracking-tight">Eligibility Category {requireCsc && <span className="text-red-500 ml-1">*</span>}</label>
                                            <Combobox 
                                                options={ELIGIBILITY_RECRUITMENT_OPTIONS}
                                                value={watch('eligibilityType')}
                                                onChange={(val) => setValue('eligibilityType', val as any)}
                                                placeholder="Select Category"
                                                error={!!errors.eligibilityType}
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-500 tracking-tight">Rating (If Applicable)</label>
                                            <input type="text" {...register('eligibilityRating')} className="w-full px-3 py-2 bg-white border border-gray-300 border-gray-200 rounded-lg focus:border-green-600 outline-none text-sm font-medium text-slate-700 placeholder:text-slate-300 shadow-sm" placeholder="e.g. 85.50%" />
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-500 tracking-tight">Date of Release / Validity {requireCsc && <span className="text-red-500 ml-1">*</span>}</label>
                                            <input type="date" {...register('eligibilityDate')} className="w-full px-3 py-2 bg-white border border-gray-300 border-gray-200 rounded-lg focus:border-green-600 outline-none text-sm font-medium text-slate-700 shadow-sm" />
                                        </div>
                                        <div className="space-y-2">
                                            <label className="text-[11px] font-bold text-slate-500 tracking-tight">Place of Examination / Issue {requireCsc && <span className="text-red-500 ml-1">*</span>}</label>
                                            <input type="text" {...register('eligibilityPlace')} className="w-full px-3 py-2 bg-white border border-gray-300 border-gray-200 rounded-lg focus:border-green-600 outline-none text-sm font-medium text-slate-700 placeholder:text-slate-300 shadow-sm" placeholder="City or Region" />
                                        </div>
                                         <div className="space-y-2">
                                             <label className={`text-[11px] font-bold ${errors.licenseNo || isIdTakenMap.agencyEmployeeNo ? 'text-red-500' : 'text-slate-500'} tracking-tight`}>License / ID Number {requireCsc && <span className="text-red-500 ml-1">*</span>}</label>
                                             <input 
                                                 type="text" 
                                                 {...register('licenseNo')} 
                                                 className={`w-full px-3 py-2 bg-white border ${errors.licenseNo || isIdTakenMap.agencyEmployeeNo ? 'border-red-500 ring-1 ring-red-500/20' : 'border-gray-200'} rounded-lg focus:border-green-600 outline-none text-sm font-medium text-slate-700 placeholder:text-slate-300 shadow-sm`} 
                                                 placeholder="ID or License Number" 
                                             />
                                             {errors.licenseNo && <p className="text-red-500 text-[10px] font-bold mt-1 ml-1">{errors.licenseNo.message}</p>}
                                             {!errors.licenseNo && isIdTakenMap.agencyEmployeeNo && <p className="text-red-500 text-[10px] font-bold mt-1 ml-1 animate-pulse">{isIdTakenMap.agencyEmployeeNo}</p>}
                                         </div>
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <label className="text-[11px] font-bold text-slate-500 tracking-tight ml-0.5">Work Experience Log {requireExp && <span className="text-red-500">*</span>}</label>
                                    <textarea {...register('experience')} rows={3} className={`w-full px-3 py-2 bg-white border border-gray-300 ${errors.experience ? 'border-red-500 ring-2 ring-red-100' : 'border-gray-200'} rounded-md outline-none font-medium text-sm text-slate-700`} placeholder={requireExp ? "List roles and responsibilities... (Required)" : "List roles and responsibilities..."} />
                                    {errors.experience && <p className="text-red-500 text-[10px] font-bold mt-1 ml-1">{errors.experience.message}</p>}
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                    <div className="md:col-span-2 space-y-2">
                                        <label className="text-[11px] font-bold text-slate-500 tracking-tight ml-0.5">Core Competencies {requireExp && <span className="text-red-500">*</span>}</label>
                                        <textarea {...register('skills')} rows={2} className={`w-full px-3 py-2 bg-white border border-gray-300 ${errors.skills ? 'border-red-500 ring-2 ring-red-100' : 'border-gray-200'} rounded-md outline-none font-medium text-sm text-slate-700`} placeholder={requireExp ? "List key skills... (Required)" : "List key skills..."} />
                                        {errors.skills && <p className="text-red-500 text-[10px] font-bold mt-1 ml-1">{errors.skills.message}</p>}
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-[11px] font-bold text-slate-500 tracking-tight ml-0.5">Total Exp. (Years) {requireExp && <span className="text-red-500">*</span>}</label>
                                        <input type="number" step="0.1" min="0" {...register('totalExperienceYears')} className={`w-full px-3 py-2 bg-white border border-gray-300 ${errors.totalExperienceYears ? 'border-red-500 ring-2 ring-red-100' : 'border-gray-200'} rounded-md outline-none font-medium text-sm text-slate-700`} placeholder="Value" />
                                        {errors.totalExperienceYears && <p className="text-red-500 text-[10px] font-bold mt-1 ml-1">{errors.totalExperienceYears.message}</p>}
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-[11px] font-bold text-slate-500 tracking-tight ml-0.5">Total Training (Hrs) {requireTraining && <span className="text-red-500">*</span>}</label>
                                        <input type="number" step="1" min="0" {...register('totalTrainingHours')} className={`w-full px-3 py-2 bg-white border border-gray-300 ${errors.totalTrainingHours ? 'border-red-500 ring-2 ring-red-100' : 'border-gray-200'} rounded-md outline-none font-medium text-sm text-slate-700`} placeholder="Hours" />
                                        {errors.totalTrainingHours && <p className="text-red-500 text-[10px] font-bold mt-1 ml-1">{errors.totalTrainingHours.message}</p>}
                                    </div>
                                </div>
                            </div>
                        </FormSection>

                        {/* Documentation Section */}
                        <FormSection 
                            title="Resume and Files" 
                            subtitle="Upload your documents" 
                        >
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                {/* Photo Upload */}
                                <div className="space-y-2">
                                    <label className="text-[11px] font-bold text-slate-500 tracking-tight ml-0.5">2x2 ID Photo <span className="text-red-500">*</span></label>
                                    <div className="border border-gray-200 rounded-md p-6 text-center bg-gray-50/30 cursor-pointer relative overflow-hidden group h-full">
                                        <input type="file" accept=".jpg,.jpeg,.png" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" onChange={async (e) => {
                                            const file = e.target.files?.[0];
                                            if (file) {
                                                const isValid = await verifyFileHeader(file);
                                                if (!isValid) {
                                                    showToast("Invalid photo integrity. Please upload a real image.", "error");
                                                    e.target.value = '';
                                                    return;
                                                }
                                                setValue('photo', file);
                                            }
                                        }} />
                                        <div className="flex flex-col items-center justify-center gap-3 h-full">
                                            <div className="w-10 h-10 bg-white rounded-lg border border-gray-100 flex items-center justify-center shadow-sm group-hover:bg-green-600 transition-colors">
                                                <UserSquare2 size={18} className="text-slate-400 group-hover:text-white transition-colors" />
                                            </div>
                                            <div>
                                                <p className="text-slate-900 font-bold text-[11px] truncate max-w-[150px]">{watch('photo') ? (watch('photo') as File).name : "Upload Photo"}</p>
                                                <p className="text-red-500 text-[9px] font-bold tracking-widest mt-1 uppercase">Required JPG/PNG</p>
                                            </div>
                                        </div>
                                    </div>
                                    {errors.photo && <p className="text-red-500 text-[10px] font-bold mt-1 ml-1">{errors.photo.message || "Photo is required"}</p>}
                                </div>

                                {/* Resume Upload */}
                                <div className="space-y-2">
                                    <label className="text-[11px] font-bold text-slate-500 tracking-tight ml-0.5">Resume / CV <span className="text-red-500">*</span></label>
                                    <div className="border border-gray-200 rounded-md p-6 text-center bg-gray-50/30 cursor-pointer relative overflow-hidden group h-full">
                                        <input type="file" accept=".pdf,.doc,.docx" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" onChange={async (e) => {
                                            const file = e.target.files?.[0];
                                            if (file) {
                                                const isValid = await verifyFileHeader(file);
                                                if (!isValid) {
                                                    showToast("Invalid file integrity. Please upload a real PDF or Word document.", "error");
                                                    e.target.value = '';
                                                    return;
                                                }
                                                setValue('resume', file);
                                            }
                                        }} />
                                        <div className="flex flex-col items-center justify-center gap-3 h-full">
                                            <div className="w-10 h-10 bg-white rounded-lg border border-gray-100 flex items-center justify-center shadow-sm group-hover:bg-green-600 transition-colors">
                                                <Briefcase size={18} className="text-slate-400 group-hover:text-white transition-colors" />
                                            </div>
                                            <div>
                                                <p className="text-slate-900 font-bold text-[11px] truncate max-w-[150px]">{watch('resume') ? (watch('resume') as File).name : "Select Resume"}</p>
                                                <p className="text-red-500 text-[9px] font-bold tracking-widest mt-1 uppercase">Required PDF/DOCX</p>
                                            </div>
                                        </div>
                                    </div>
                                    {errors.resume && <p className="text-red-500 text-[10px] font-bold mt-1 ml-1">Resume is required</p>}
                                </div>

                                {/* Eligibility Certificate */}
                                <div className="space-y-2">
                                    <label className="text-[11px] font-bold text-slate-500 tracking-tight ml-0.5">Eligibility Cert.</label>
                                    <div className="border border-gray-200 rounded-md p-6 text-center bg-gray-50/30 cursor-pointer relative overflow-hidden group h-full">
                                        <input type="file" accept=".pdf,.jpg,.jpeg,.png" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" onChange={async (e) => {
                                            const file = e.target.files?.[0];
                                            if (file) {
                                                setValue('eligibilityCert', file);
                                            }
                                        }} />
                                        <div className="flex flex-col items-center justify-center gap-3 h-full">
                                            <div className="w-10 h-10 bg-white rounded-lg border border-gray-100 flex items-center justify-center shadow-sm group-hover:bg-green-600 transition-colors">
                                                <ShieldCheck size={18} className="text-slate-400 group-hover:text-white transition-colors" />
                                            </div>
                                            <div>
                                                <p className="text-slate-900 font-bold text-[11px] truncate max-w-[150px]">{watch('eligibilityCert') ? (watch('eligibilityCert') as File).name : "Select Cert"}</p>
                                                <p className={`text-[9px] font-bold tracking-widest mt-1 uppercase ${requireCsc ? 'text-red-500' : 'text-slate-400'}`}>{requireCsc ? 'Required PDF' : 'Optional'}</p>
                                            </div>
                                        </div>
                                    </div>
                                    {errors.eligibilityCert && <p className="text-red-500 text-[10px] font-bold mt-1 ml-1">{errors.eligibilityCert.message as string}</p>}
                                </div>
                            </div>
                        </FormSection>

                        {/* Submission Protocol Footer */}
                        <div className="mt-4 px-6 py-10 bg-gray-50/30 border-t border-gray-100">
                            <div className="flex flex-col gap-6">
                                <div>
                                    <div className="flex items-center gap-2 mb-3">
                                        <ShieldCheck size={14} className="text-green-600" />
                                        <span className="text-[11px] font-bold text-slate-950 tracking-tight">Final verification</span>
                                    </div>
                                    <p className="text-[11px] font-semibold text-slate-500 leading-relaxed max-w-xl">
                                        By sliding the verification toggle, I certify that all information provided is accurate and I authorize the Human Resource Management Office to verify my credentials.
                                    </p>
                                </div>
                                <div className="w-full">
                                    <SlideToApply onVerify={() => setIsVerified(true)} isVerified={isVerified} />
                                </div>
                            </div>
                            
                            <div className="mt-10 pt-10 border-t border-gray-200/50 flex flex-col md:flex-row items-center justify-between gap-6">
                                <div className="flex items-center gap-6">
                                    <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 tracking-widest">
                                        <div className="w-2 h-2 rounded-full bg-green-500"></div>
                                        Transmission encryption active
                                    </div>
                                </div>
    
                                <button 
                                    type="submit" 
                                    disabled={isSubmitting || mutation.isPending}
                                    className={`w-full md:w-auto px-12 py-3 rounded-xl font-bold text-sm tracking-tight transition-all flex items-center justify-center gap-3 active:scale-95 border border-gray-300 shadow-sm ${
                                        isVerified 
                                            ? 'bg-green-600 text-white hover:bg-green-700 shadow-green-900/10 cursor-pointer' 
                                            : 'bg-gray-200 text-slate-500 cursor-not-allowed shadow-none'
                                    }`}
                                >
                                    {(isSubmitting || mutation.isPending) ? (
                                        <>
                                            <Loader2 size={18} className="animate-spin" />
                                            Encrypting...
                                        </>
                                    ) : (
                                        <>
                                            Submit application
                                            <Send size={18} />
                                        </>
                                    )}
                                </button>
                            </div>
                        </div>
                    </form>
                </div>
            </div>
        )}
        </div>
      </div>
    </PublicLayout>
  );
};

export default JobDetail;

import { useState } from 'react';
import { useUIStore } from '@/stores';
import { useToastStore } from '@/stores';
import { Archive, UserCheck } from 'lucide-react';
import { useApplicantData, useApplicantFilters, useApplicantActions, Applicant } from '@applicant/Hooks';
import { AssignInterviewerModal, ScheduleInterviewModal, DocumentListModal, ConfirmHiredModal } from '@applicant/Modals';
import { ApplicantTabs, ApplicantFilters, ApplicantTable, InterviewPanel, PublicInquiries, LiveSupportChat, ApplicantDetailModal, SecurityAuditLogs } from '@applicant/Components';
import ConfirmDialog from '@/components/Custom/Shared/ConfirmDialog';
import Pagination from '@/components/CustomUI/Pagination';
import type { ScheduleInterviewFormData } from '@/schemas/recruitmentSchema';

const ApplicantList = () => {
  const sidebarOpen = useUIStore((state) => state.sidebarOpen);
  const showToast = useToastStore((state) => state.showToast);
  const showNotification = (message: string, type: 'success' | 'error') => showToast(message, type);
  
  // Custom Hooks
  const { applicants, interviewers, loading, isRefetching, fetchData } = useApplicantData(showNotification);
  const { 
  searchTerm, setSearchTerm, 
  sourceFilter, setSourceFilter, 
  activeTab, setActiveTab, 
  archiveSubTab, setArchiveSubTab,
  currentPage, setCurrentPage, 
  filteredApplicants, currentItems, totalPages 
  } = useApplicantFilters(applicants);  
  const { 
    handleAssignInterviewer, 
    handleScheduleInterview, 
    handleRejectApplicant, 
    handleRestoreApplicant, 
    handleDeleteApplicant,
    handleConfirmHired
  } = useApplicantActions(fetchData, showNotification);

  // Modal State - Properly typed
  const [showAssignModal, setShowAssignModal] = useState<boolean>(false);
  const [showScheduleModal, setShowScheduleModal] = useState<boolean>(false);
  const [showDocumentModal, setShowDocumentModal] = useState<boolean>(false);
  const [showDetailModal, setShowDetailModal] = useState<boolean>(false);
  const [showConfirmHiredModal, setShowConfirmHiredModal] = useState<boolean>(false);
  const [selectedApplicant, setSelectedApplicant] = useState<Applicant | null>(null);
  const [selectedInterviewer, setSelectedInterviewer] = useState<string>('');
  const [confirmModal, setConfirmModal] = useState({
    isOpen: false,
    title: '',
    message: '',
    isDestructive: false,
    confirmText: 'Confirm',
    onConfirm: () => {}
  });
  
  // Interview State
  const [showInterview, setShowInterview] = useState<boolean>(false);
  const [interviewApplicant, setInterviewApplicant] = useState<Applicant | null>(null);

  const onAssignClick = (applicant: Applicant): void => {
    setSelectedApplicant(applicant);
    setShowAssignModal(true);
  };

  const onScheduleClick = (applicant: Applicant): void => {
    setSelectedApplicant(applicant);
    setShowScheduleModal(true);
  };

  const onViewDocumentsClick = (applicant: Applicant): void => {
    setSelectedApplicant(applicant);
    setShowDocumentModal(true);
  };

  const onJoinInterview = (applicant: Applicant): void => {
    if (applicant.interviewLink) {
      setInterviewApplicant(applicant);
      setShowInterview(true);
    } else {
      showNotification('No interview link available. Please schedule an interview first.', 'error');
    }
  };

  const onViewDetailsClick = (applicant: Applicant): void => {
    setSelectedApplicant(applicant);
    setShowDetailModal(true);
  };

  const onConfirmClick = (applicant: Applicant): void => {
    setSelectedApplicant(applicant);
    setShowConfirmHiredModal(true);
  };
  
  const onRejectClick = (applicant: Applicant): void => {
    setConfirmModal({
      isOpen: true,
      title: 'Reject and Archive Applicant',
      message: `Are you sure you want to reject and archive ${applicant.firstName} ${applicant.lastName}?`,
      isDestructive: true,
      confirmText: 'Reject',
      onConfirm: () => handleRejectApplicant(Number(applicant.id))
    });
  };

  const onRestoreClick = (applicant: Applicant): void => {
    setConfirmModal({
      isOpen: true,
      title: 'Restore Applicant',
      message: `Are you sure you want to restore ${applicant.firstName} ${applicant.lastName} to the active pipeline?`,
      isDestructive: false,
      confirmText: 'Restore',
      onConfirm: () => handleRestoreApplicant(Number(applicant.id))
    });
  };

  const onDeleteClick = (applicant: Applicant): void => {
    setConfirmModal({
      isOpen: true,
      title: 'Permanently Delete Applicant',
      message: `WARNING: Are you sure you want to PERMANENTLY delete ${applicant.firstName} ${applicant.lastName}? This cannot be undone.`,
      isDestructive: true,
      confirmText: 'Delete',
      onConfirm: () => handleDeleteApplicant(Number(applicant.id))
    });
  };

  const onConfirmAssign = (): void => {
    if (!selectedApplicant) return;
    handleAssignInterviewer(Number(selectedApplicant.id), Number(selectedInterviewer), () => setShowAssignModal(false));
  };

  const onConfirmSchedule = (data: ScheduleInterviewFormData): void => {
    if (!selectedApplicant) return;
    handleScheduleInterview(Number(selectedApplicant.id), data, () => setShowScheduleModal(false));
  };

  // Show interview panel if active
  if (showInterview && interviewApplicant) {
    return (
      <InterviewPanel
        roomName={interviewApplicant.interviewLink?.split('/').pop() || 'interview'}
        displayName="Interviewer"
        applicantId={interviewApplicant.id}
        applicantName={`${interviewApplicant.firstName} ${interviewApplicant.lastName}`}
        applicantEmail={interviewApplicant.email}
        jobTitle={interviewApplicant.jobTitle}
        interviewLink={interviewApplicant.interviewLink}
        resumePath={interviewApplicant.resumePath}
        onClose={() => {
          setShowInterview(false);
          setInterviewApplicant(null);
        }}
      />
    );
  }

  return (
    <div className={`min-h-screen flex flex-col bg-gradient-to-br from-neutral-100 to-stone-50 rounded-xl shadow-xl p-7 w-full overflow-hidden text-gray-800 transition-all duration-300 ${sidebarOpen ? 'max-w-[1400px] xl:max-w-[77vw]' : 'max-w-[1600px] xl:max-w-[88vw]'}`}>

      
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 flex items-center gap-2">Applicant List</h2>
          <p className="text-sm text-gray-600 mt-1">Fair Hiring Procedure: Review, Assign, Schedule</p>
        </div>
      </div>

      <hr className="mb-6 border-gray-200" />

      <ApplicantTabs activeTab={activeTab} setActiveTab={setActiveTab} />
      
      {activeTab === 'Archive' && (
        <div className="flex gap-2 mb-6 bg-white/50 p-1.5 rounded-xl border border-gray-200 w-fit">
          <button
            onClick={() => setArchiveSubTab('Rejected')}
            className={`px-6 py-2 rounded-lg text-sm font-bold transition-all duration-200 ${
              archiveSubTab === 'Rejected'
                ? 'bg-gray-300 text-gray-800 shadow-sm'
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            Rejected Applicants
          </button>
          <button
            onClick={() => setArchiveSubTab('Hired')}
            className={`px-6 py-2 rounded-lg text-sm font-bold transition-all duration-200 ${
              archiveSubTab === 'Hired'
                ? 'bg-gray-300 text-gray-800 shadow-sm'
                : 'text-gray-500 hover:bg-gray-100'
            }`}
          >
            Archived Hired
          </button>
        </div>
      )}

      <ApplicantFilters 
        searchTerm={searchTerm} 
        setSearchTerm={setSearchTerm} 
        sourceFilter={sourceFilter} 
        setSourceFilter={setSourceFilter} 
      />

      <ApplicantTable 
        loading={loading}
        isRefetching={isRefetching}
        filteredApplicants={currentItems}
        onAssign={onAssignClick}
        onSchedule={onScheduleClick}
        onJoinInterview={onJoinInterview}
        onReject={onRejectClick}
        onRestore={onRestoreClick}
        onViewDetails={onViewDetailsClick}
        onViewDocuments={onViewDocumentsClick}
        onDelete={onDeleteClick}
        onConfirm={onConfirmClick}
        isArchiveHired={activeTab === 'Archive' && archiveSubTab === 'Hired'}
      />

      <Pagination 
        currentPage={currentPage}
        itemsPerPage={10}
        totalItems={filteredApplicants.length}
        onPageChange={setCurrentPage}
        totalPages={totalPages}
      />

      {/* Modals */}
      <ConfirmHiredModal
        isOpen={showConfirmHiredModal}
        onClose={() => setShowConfirmHiredModal(false)}
        applicant={selectedApplicant}
        onConfirm={async (id, startDate, selectedDocs, customNotes) => {
            await handleConfirmHired(id, startDate, selectedDocs, customNotes, () => setShowConfirmHiredModal(false));
        }}
      />
      <ApplicantDetailModal
        isOpen={showDetailModal}
        onClose={() => setShowDetailModal(false)}
        applicant={selectedApplicant!}
      />

      <DocumentListModal
        isOpen={showDocumentModal}
        onClose={() => setShowDocumentModal(false)}
        applicant={selectedApplicant}
      />

      <AssignInterviewerModal 
        isOpen={showAssignModal}
        onClose={() => setShowAssignModal(false)}
        onConfirm={onConfirmAssign}
        interviewers={interviewers}
        selectedApplicant={selectedApplicant}
        selectedInterviewer={selectedInterviewer}
        setSelectedInterviewer={setSelectedInterviewer}
      />

      <ScheduleInterviewModal
        isOpen={showScheduleModal}
        onClose={() => setShowScheduleModal(false)}
        onConfirm={onConfirmSchedule}
        selectedApplicant={selectedApplicant}
        initialData={selectedApplicant ? {
          platform: selectedApplicant.interviewPlatform || 'Jitsi Meet',
          link: selectedApplicant.interviewLink || '',
          date: selectedApplicant.interviewDate ? selectedApplicant.interviewDate.split('T')[0] : '',
          time: selectedApplicant.interviewDate ? new Date(selectedApplicant.interviewDate).toTimeString().substring(0, 5) : '',
          notes: selectedApplicant.interviewNotes || ''
        } : undefined}
      />
      <ConfirmDialog
        isOpen={confirmModal.isOpen}
        title={confirmModal.title}
        message={confirmModal.message}
        isDestructive={confirmModal.isDestructive}
        confirmText={confirmModal.confirmText}
        onClose={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}
        onConfirm={confirmModal.onConfirm}
      />

    </div>
  );
};

export default ApplicantList;

import { useState } from 'react';
import { useUIStore } from '@/stores';
import { useToastStore } from '@/stores';
import { useJobData, useJobForm, useJobFilters, useJobActions } from '../../features/Recruitment/JobPosting/Hooks';
import { JobHeader, JobFilters, JobTable } from '../../features/Recruitment/JobPosting/Components';
import { JobFormModal, JobDetailsModal, DeleteJobModal } from '../../features/Recruitment/JobPosting/Modals';
import { Job } from '@/types';

const JobPosting = () => {
  const sidebarOpen = useUIStore((state) => state.sidebarOpen);
  const showToast = useToastStore((state) => state.showToast);
  const showNotification = (message: string, type: 'success' | 'error' | 'info') => showToast(message, type);
  
  // Custom Hooks
  const { jobs, loading, error, checkingEmails, loadJobs, handleCheckEmails } = useJobData(showNotification);
  const { searchTerm, setSearchTerm, statusFilter, setStatusFilter, filteredJobs } = useJobFilters(jobs);
  const { isFormOpen, setIsFormOpen, isEditing, formData, handleFormChange, openCreateForm, openEditForm, resetForm } = useJobForm();
  const { 
    saving, 
    handleSaveJob, 
    handleDeleteJob 
  } = useJobActions(() => {
    // Refresh logic if needed
    loadJobs();
  }, showNotification);

  // Local Modal Logic
  const [isViewOpen, setIsViewOpen] = useState(false);
  const [isDeleteOpen, setIsDeleteOpen] = useState(false);
  const [selectedJob, setSelectedJob] = useState<Job | null>(null);

  const handleOpenView = (job: Job) => {
    setSelectedJob(job);
    setIsViewOpen(true);
  };

  const handleOpenDelete = (job: Job) => {
    setSelectedJob(job);
    setIsDeleteOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleSaveJob(isEditing, selectedJob?.id ?? null, formData, () => setIsFormOpen(false));
  };

  const onConfirmDelete = () => {
    if (selectedJob) {
      handleDeleteJob(selectedJob.id, () => {
        setIsDeleteOpen(false);
        setSelectedJob(null);
      });
    }
  };

  return (
    <div className={`min-h-screen flex flex-col bg-gradient-to-br from-neutral-100 to-stone-50 rounded-xl shadow-xl p-7 w-full overflow-hidden text-gray-800 transition-all duration-300 ${sidebarOpen ? 'max-w-[1400px] xl:max-w-[77vw]' : 'max-w-[1600px] xl:max-w-[88vw]'}`}>

      
      <JobHeader 
        checkingEmails={checkingEmails}
        onCheckEmails={handleCheckEmails}
        onCreateJob={openCreateForm}
      />

      <hr className="mb-6 border-gray-200" />

      {error && (
        <div className="bg-red-50 text-red-700 px-4 py-3 rounded-lg mb-4">
          {error}
        </div>
      )}

      <JobFilters 
        searchTerm={searchTerm}
        setSearchTerm={setSearchTerm}
        statusFilter={statusFilter}
        setStatusFilter={setStatusFilter}
      />

      <JobTable 
        loading={loading}
        filteredJobs={filteredJobs}
        onEdit={(job: Job) => { 
            setSelectedJob(job); 
            openEditForm(job); 
        }}
        onDelete={handleOpenDelete}
        onView={handleOpenView}
      />

      {/* Modals */}
      <JobFormModal 
        isOpen={isFormOpen}
        onClose={() => setIsFormOpen(false)}
        isEditing={isEditing}
        initialData={formData}
        onSubmit={(data) => handleSaveJob(isEditing, selectedJob?.id ?? null, data, () => setIsFormOpen(false))}
        saving={saving}
      />

      <JobDetailsModal 
        isOpen={isViewOpen}
        onClose={() => setIsViewOpen(false)}
        selectedJob={selectedJob}
        onEdit={(job: Job) => {
            setSelectedJob(job);
            openEditForm(job);
        }}
      />

      <DeleteJobModal 
        isOpen={isDeleteOpen}
        onClose={() => setIsDeleteOpen(false)}
        selectedJob={selectedJob}
        handleDelete={onConfirmDelete}
        saving={saving}
      />
    </div>
  );
};

export default JobPosting;

import React, { useMemo } from 'react';
import { useUIStore } from '@/stores';
import { AttendanceFilterValues } from '@/schemas/attendanceSchema';
import { 
  BiometricsHeader, 
  BiometricsNotification, 
  BiometricsFilters, 
  BiometricsTable,
  useBiometricsLogs 
} from "@settings/Biometrics/Logs";
import { BiometricsLog } from '@/types';
import Pagination from '@/components/CustomUI/Pagination';
import StatCard from '@components/Custom/DashboardAdminComponents/StatCard';

const BiometricsLogsUI = () => {
  const sidebarOpen = useUIStore((state) => state.sidebarOpen);
  
  const {
    today,
    isLoading,
    error,
    successMessage,
    paginationData,
    uniqueDepartments,
    uniqueEmployees,
    handleRefresh,
    handleFilterChange,
    handleApply,
    handleClear,
    handleSearchChange,
    searchQuery,
    filters,
    filteredData,
    handlePrevPage,
    handleNextPage,
    setPage,
    setSuccessMessage,
    setFilters,
    setError
  } = useBiometricsLogs();

  // Stats from Monitor (computed from filtered data)
  const stats = useMemo(() => ({
    onTime: filteredData.filter((l: BiometricsLog) => l.status === 'Present').length,
    late: filteredData.filter((l: BiometricsLog) => l.status === 'Late').length,
    total: filteredData.length,
  }), [filteredData]);

  // Map pagination data for the Pagination component
  const totalPages = paginationData.totalPages;
  const currentPage = Math.ceil((paginationData.startIndex + 1) / 10);
  const totalItems = paginationData.currentItems.length * totalPages;

  const handleFilterSubmit = (newFilters: AttendanceFilterValues) => {
      setFilters({
          department: newFilters.department || '',
          employeeId: newFilters.employeeId || '',
          startDate: newFilters.startDate || '',
          endDate: newFilters.endDate || ''
      });
  };

  return (
    <div className={`min-h-screen flex flex-col bg-gradient-to-br from-neutral-100 to-stone-50 rounded-xl shadow-xl p-7 w-full overflow-hidden text-gray-800 transition-all duration-300 ${!sidebarOpen ? 'max-w-[1600px] xl:max-w-[88vw]' : 'max-w-[1400px] xl:max-w-[77vw]'}`}>
      
      <BiometricsHeader 
        today={today} 
        handleRefresh={handleRefresh} 
        isLoading={isLoading} 
      />

      {/* Stats Cards (matching Admin Dashboard style) */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 my-5">
        <StatCard
          title="On Time"
          data={stats.onTime}
        />
        <StatCard
          title="Late"
          data={stats.late}
        />
        <StatCard
          title="Total Records"
          data={stats.total}
        />
      </div>

      {error && (
        <BiometricsNotification 
          type="error" 
          message={error} 
          onClose={() => setError(null)} 
        />
      )}

      {successMessage && (
        <BiometricsNotification 
          type="success" 
          message={successMessage} 
          onClose={() => setSuccessMessage(null)} 
        />
      )}

      <BiometricsFilters 
        uniqueDepartments={uniqueDepartments}
        uniqueEmployees={uniqueEmployees}
        isLoading={isLoading}
        filters={filters}
        onFilterChange={handleFilterSubmit}
      />

      <BiometricsTable 
        currentItems={paginationData.currentItems} 
        isLoading={isLoading} 
      />

      {paginationData.total > 0 && (
        <Pagination 
          currentPage={currentPage}
          totalPages={totalPages}
          onPageChange={setPage}
          totalItems={paginationData.total}
          itemsPerPage={10}
        />
      )}
    </div>
  );
};

export default BiometricsLogsUI;

import React from 'react';
import { useUIStore } from '@/stores';
import { Check, X } from 'lucide-react';
import { ProfileHeader, ProfileAvatar, InformationGrid, useProfile } from '@settings/Profile';
import type { Profile } from '@settings/Profile';

import MyMemosPage from '@pages/EmployeeManagementEmployee/MyMemosPage';

export default function MyProfile() {
  const sidebarOpen = useUIStore((state) => state.sidebarOpen);
  const [activeTab, setActiveTab] = React.useState<'info' | 'memos'>('info');

  const {
    user, profile, loading, saving, error, success,
    isEditing, formData, avatarPreview, setIsEditing,
    setError, setSuccess, handleChange, handleAvatarChange,
    handleSubmit, handleCancel, setProfile
  } = useProfile();

  if (loading) {
    return (
      <div className={`flex items-center justify-center bg-white rounded-2xl shadow-sm border border-gray-200 p-8 min-h-[400px] w-full transition-all duration-300 ${!sidebarOpen ? 'max-w-[1600px] xl:max-w-[88vw]' : 'max-w-[1400px] xl:max-w-[77vw]'}`}>
        <div className="flex flex-col items-center gap-3">
          <div className="w-10 h-10 border-4 border-gray-300 border-t-gray-600 rounded-full animate-spin" />
          <p className="text-gray-500 font-medium text-sm">Loading profile...</p>
        </div>
      </div>
    );
  }

  return (
    <div className={`flex flex-col bg-white rounded-2xl shadow-sm border border-gray-200 p-6 w-full overflow-hidden transition-all duration-300 ${!sidebarOpen ? 'max-w-[1600px] xl:max-w-[88vw]' : 'max-w-[1400px] xl:max-w-[77vw]'}`}>
      
      <ProfileHeader 
        isEditing={isEditing}
        setIsEditing={setIsEditing}
        handleCancel={handleCancel}
        handleSubmit={handleSubmit}
        saving={saving}
        hideEdit={activeTab === 'memos'} // Hide Edit button on Memos tab
      />

      {/* Navigation Tabs */}
      <div className="flex items-center gap-6 border-b border-gray-100 mb-6">
        <button
          onClick={() => { setActiveTab('info'); }}
          className={`pb-3 text-sm font-bold tracking-wide transition-all border-b-2 ${
            activeTab === 'info' 
              ? 'text-navy-900 border-navy-900' 
              : 'text-gray-400 border-transparent hover:text-navy-700'
          }`}
        >
          Personal Information
        </button>
        <button
          onClick={() => { setActiveTab('memos'); setIsEditing(false); }}
          className={`pb-3 text-sm font-bold tracking-wide transition-all border-b-2 ${
            activeTab === 'memos' 
              ? 'text-navy-900 border-navy-900' 
              : 'text-gray-400 border-transparent hover:text-navy-700'
          }`}
        >
          My Memos
        </button>
      </div>

      {activeTab === 'info' ? (
        <>
          {/* Alerts */}
          {success && (
            <div className="mb-6 flex items-center gap-3 bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-xl animate-in fade-in slide-in-from-top-2">
              <Check size={18} />
              <span className="text-sm font-medium">{success}</span>
            </div>
          )}
          {error && (
            <div className="mb-6 flex items-center gap-3 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl animate-in fade-in slide-in-from-top-2">
              <X size={18} />
              <span className="text-sm font-medium">{error}</span>
            </div>
          )}

          <ProfileAvatar 
            profile={profile as Profile | null}
            formData={formData}
            isEditing={isEditing}
            avatarPreview={avatarPreview}
            handleAvatarChange={handleAvatarChange}
          />

          <InformationGrid 
            profile={profile as Profile | null}
            user={user}
            isEditing={isEditing}
            formData={formData}
            handleChange={handleChange}
            setIsEditing={setIsEditing}
            setProfile={setProfile}
          />
        </>
      ) : (
        /* Memos Tab Content */
        <div className="min-h-[500px]">
           <MyMemosPage hideHeader={false} />
        </div>
      )}
    </div>
  );
}

import { useMemo } from 'react';
import { useUIStore } from '@/stores';
import { ADMIN_ATTENDANCE_HEADERS } from '@features/Attendance/components/Admin/constants/attendanceConstants';
import { useAttendanceLogs } from '../../features/Attendance/hooks/useAttendance';
import { useAttendanceStore } from '@/stores/attendanceStore';

import AttendanceHeader from '@features/Attendance/components/Admin/AttendanceHeader';
import AttendanceFilters from '@features/Attendance/components/Admin/AttendanceFilters';

import AttendanceExport from '@features/Attendance/components/Admin/AttendanceExport';
import AttendanceTable from '@features/Attendance/components/Admin/AttendanceTable';

import { useFilterOptions } from '@/hooks/useFilterOptions';
import { DTRApiResponse } from '@/types/attendance';
import { formatEmployeeId } from '@/utils/formatters';

const AdminAttendance = () => {
  const sidebarOpen = useUIStore((state) => state.sidebarOpen);
  const { getQuery, setPage, pagination: storePagination } = useAttendanceStore();
  const queryParams = getQuery();

  // 1. Fetch Data
  const { data, isLoading, error, refetch } = useAttendanceLogs(queryParams);
  
  const rawLogs = data?.data?.data || [];
  const paginationData = data?.data?.pagination;

  // 2. Transform snake_case API fields → camelCase for AttendanceTable
  const logs = useMemo(() => rawLogs.map((item: DTRApiResponse) => ({
    id: item.id,
    employeeId: formatEmployeeId(item.employeeId),
    employeeName: item.employeeName || 'Unknown',
    department: item.department || 'N/A',
    date: item.date,
    timeIn: item.timeIn ?? undefined,
    timeOut: item.timeOut ?? undefined,
    lateMinutes: Number(item.lateMinutes ?? 0),
    undertimeMinutes: Number(item.undertimeMinutes ?? 0),
    overtimeMinutes: Number(item.overtimeMinutes ?? 0),
    status: item.status || 'Absent',
    duties: item.duties || 'Standard',
    shift: item.shift || 'No Schedule',
  })), [rawLogs]);

  // Fetch Filter Options using Centralized Hook
  const { data: filterOptions, isLoading: loadingFilters } = useFilterOptions();

  const handlePageChange = (newPage: number) => {
    setPage(newPage);
  };

  return (
    <div className={`min-h-screen flex flex-col bg-gradient-to-br from-neutral-100 to-stone-50 rounded-xl shadow-xl p-7 w-full overflow-hidden text-gray-800 transition-all duration-300 ${!sidebarOpen ? 'max-w-[1600px] xl:max-w-[88vw]' : 'max-w-[1400px] xl:max-w-[77vw]'}`}>
      
      <AttendanceHeader 
        title="Attendance Records" 
        subtitle="Employee attendance monitoring"
        onRefresh={refetch}
        isLoading={isLoading || loadingFilters}
      />

      <hr className="mb-6 border-[1px] border-gray-200" />

      {error && (
        <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-6">
          {error instanceof Error ? error.message : 'An error occurred fetching attendance logs.'}
        </div>
      )}

      {/* RHF + Zod + Zustand powered filters */}
      <AttendanceFilters 
        uniqueDepartments={filterOptions.departments}
        uniqueEmployees={filterOptions.employees}
        isLoading={loadingFilters || isLoading}
      />

      <AttendanceExport 
        data={logs}
        title="Attendance Records"
        dateRange={{ startDate: queryParams.startDate || '', endDate: queryParams.endDate || '' }}
        filters={queryParams}
      />

      <AttendanceTable 
        data={logs}
        headers={ADMIN_ATTENDANCE_HEADERS.map((h) => h.label)}
        isLoading={isLoading}
        pagination={paginationData ? {
            page: paginationData.page,
            totalPages: paginationData.totalPages,
            totalItems: paginationData.total,
            limit: paginationData.limit,
            onPageChange: handlePageChange
        } : undefined}
      />
    </div>
  );
};

export default AdminAttendance;

import { useState, useCallback } from 'react';
import { DndProvider } from 'react-dnd';
import { HTML5Backend } from 'react-dnd-html5-backend';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import {
  useCalendarState,
  useCalendarNav,
  useCalendarData,
  HOURS_12,
  EVENT_COLORS,
  CalendarHeader,
  CalendarControls,
  CalendarGrid,
  EventDetailsModal,
  ConfirmDeleteModal,
  DrawerSidebar,
  getRandomEventColor,
} from '@components/Custom/CalendarComponents/shared';
import type { GridItem } from '@components/Custom/CalendarComponents/shared/components/CalendarGrid';

import { AdminAgendaView } from '@components/Custom/CalendarComponents/admin/components';
import AdminCalendarActions from '@components/Custom/CalendarComponents/AdminCalendarActions';
import { eventApi, fetchEmployees, fetchDepartments, announcementApi } from '@api';
import {
  AddEventModal,
  EditEventModal,
  CreateAnnouncementModal,
  EditAnnouncementModal,
} from '@components/Custom/CalendarComponents/admin/Modals';
import { 
  CalendarEvent, 
  Announcement, 
  EventFormData, 
  AnnouncementFormData,
  CalendarItem,
  CalendarDisplayItem,
  Holiday,
  Schedule
} from '@/types/calendar';
import { scheduleApi } from '@api';
import { ScheduleSchema } from '@/schemas/calendar';
import { ApiError } from '@/types';
import {
  useCalendarStore,
  useToastStore
} from '@/stores';
import { useHolidays } from '@/hooks/useLeave';

export default function AdminCalendar() {
  const queryClient = useQueryClient();
  const showToast = useToastStore((state) => state.showToast);

  // Zustand Calendar State
  const { 
    modals, 
    setModal, 
    selectedItem, 
    selectedType, 
    setSelectedItem, 
    currentView, 
    setCurrentView,
    closeAllModals 
  } = useCalendarStore();

  // Calendar primitive state management (for current date/drawer)
  const calendarState = useCalendarState();
  const { today, currentDate, setCurrentDate, isDrawerOpen, setIsDrawerOpen, showHolidays, setShowHolidays, showEventDetails, setShowEventDetails } = calendarState;

  // Constants
  const HOURS_LIST = Object.values(HOURS_12);

  // Navigation handlers
  const navigation = useCalendarNav({ setCurrentDate });



  /* Removed newEvent state */

  // --- QUERIES ---

  const { data: announcements = [] } = useQuery<Announcement[]>({
    queryKey: ['announcements'],
    queryFn: async () => {
      const response = await announcementApi.getAnnouncements();
      return response.data?.announcements || [];
    }
  });



  const { data: events = [] } = useQuery<CalendarEvent[]>({
    queryKey: ['events'],
    queryFn: async () => {
      const response = await eventApi.getEvents();
      return response.data?.events?.map((e: CalendarEvent) => ({
        ...e,
        color: getRandomEventColor(EVENT_COLORS)
      })) || [];
    }
  });

  const { data: schedules = [] } = useQuery({
    queryKey: ['schedules-list'],
    queryFn: async () => {
        const response = await scheduleApi.getSchedules();
        return (response.schedules || []) as Schedule[];
    }
  });

  // Holidays query
  const { data: holidaysData } = useHolidays(currentDate.getFullYear());
  const holidays = holidaysData?.holidays || [];

  // Fetch employees (if needed for filtering/display, kept consistent with original)
  useQuery({
    queryKey: ['employees-list'],
    queryFn: async () => {
        const response = await fetchEmployees();
        return response.success ? response.employees : [];
    }
  });

  const { data: departments = [] } = useQuery({
    queryKey: ['departments-list'],
    queryFn: async () => {
      const response = await fetchDepartments();
      return response.departments || [];
    }
  });

  // --- MUTATIONS ---




  const createEventMutation = useMutation({
    mutationFn: async (data: EventFormData) => {
        // Validation check before API call to mimic original logic behavior if needed, 
        // though typically this should be in the submit handler.
        if (!data.title?.trim() || !data.date) {
            throw new Error("Please fill in the Event Title and Date.");
        }
        await eventApi.createEvent(data as unknown as Record<string, unknown>);
    },
    onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['events'] });
        setModal('addEvent', false);
        showToast("Event created successfully!", "success");
    },
    onError: (error: Error | ApiError) => {
        console.error("Failed to create event:", error);
        const errorMessage = error.message || (error as ApiError).response?.data?.message || "Failed to create event.";
        showToast(errorMessage.includes("fill in") ? errorMessage : `Failed to create event: ${errorMessage}`, "error");
    }
  });

  const updateEventMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string | number, data: EventFormData }) => {
        await eventApi.updateEvent(id, data as unknown as Record<string, unknown>);
    },
    onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['events'] });
        setModal('editEvent', false);
        setSelectedItem(null, null);
        showToast("Event updated successfully!", "success");
    },
    onError: (error) => {
        console.error("Failed to update event:", error);
        showToast("Failed to update event. Please try again.", "error");
    }
  });

  const deleteEventMutation = useMutation({
    mutationFn: async (id: string | number) => {
        await eventApi.deleteEvent(id);
    },
    onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['events'] });
        setModal('deleteConfirm', false);
        setSelectedItem(null, null);
        showToast("Deleted successfully!", "success");
    },
    onError: (error) => {
        console.error("Failed to delete event:", error);
        showToast("Failed to delete. Please try again.", "error");
    }
  });

  const createAnnouncementMutation = useMutation({
    mutationFn: async (data: AnnouncementFormData) => {
        if (!data.title || !data.content) {
             throw new Error("Please fill in the Title and Content.");
        }
        await announcementApi.createAnnouncement(data as unknown as Record<string, unknown>);
    },
    onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['announcements'] });
        setModal('createAnnouncement', false);
        showToast("Announcement created successfully!", "success");
    },
    onError: (error: Error | ApiError) => {
        console.error("Failed to create announcement:", error);
        const errorMessage = error.message || (error as ApiError).response?.data?.message || "Failed to create announcement.";
        showToast(errorMessage.includes("fill in") ? errorMessage : `Error: ${errorMessage}`, "error");
    }
  });

  const updateAnnouncementMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string | number, data: AnnouncementFormData }) => {
        await announcementApi.updateAnnouncement(id, data as unknown as Record<string, unknown>);
    },
    onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['announcements'] });
        setModal('editAnnouncement', false);
        setSelectedItem(null, null);
        showToast('Announcement updated successfully!', 'success');
    },
    onError: (error) => {
        console.error('Failed to update announcement:', error);
        showToast('Failed to update announcement. Please try again.', 'error');
    }
  });

  const deleteAnnouncementMutation = useMutation({
    mutationFn: async (id: string | number) => {
        await announcementApi.deleteAnnouncement(id);
    },
    onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: ['announcements'] });
        setModal('deleteConfirm', false);
        setSelectedItem(null, null);
        showToast("Deleted successfully!", "success");
    },
    onError: (error) => {
        console.error("Failed to delete announcement:", error);
        showToast("Failed to delete. Please try again.", "error");
    }
  });


  // --- HANDLERS ---

  const handleAddEventClick = useCallback((time = '09:00') => {
    setModal('addEvent', true);
  }, [setModal]);

  const handleAddEvent = useCallback((data: EventFormData) => {
    // RHF provides the data
    createEventMutation.mutate(data);
  }, [createEventMutation]);

  const handleCreateAnnouncement = useCallback((announcementData: AnnouncementFormData) => {
    createAnnouncementMutation.mutate(announcementData);
  }, [createAnnouncementMutation]);

  const handleEditEvent = useCallback((event: CalendarEvent) => {
    setSelectedItem(event, 'event');
    setShowEventDetails(null);
    setModal('editEvent', true);
  }, [setShowEventDetails, setSelectedItem, setModal]);

  const handleUpdateEvent = useCallback((updatedData: CalendarEvent) => {
    if (!selectedItem) return;
    updateEventMutation.mutate({ id: (selectedItem as CalendarEvent).id, data: updatedData as unknown as EventFormData });
  }, [selectedItem, updateEventMutation]);

  const handleEditAnnouncement = useCallback((announcement: Announcement) => {
    setSelectedItem(announcement, 'announcement');
    setModal('editAnnouncement', true);
  }, [setSelectedItem, setModal]);

  const handleUpdateAnnouncement = useCallback((id: string | number, updatedData: AnnouncementFormData) => {
    updateAnnouncementMutation.mutate({ id, data: updatedData });
  }, [updateAnnouncementMutation]);

  const handleDeleteAnnouncement = useCallback((item: Announcement) => {
    setSelectedItem(item, 'announcement');
    setModal('deleteConfirm', true);
  }, [setSelectedItem, setModal]);

  const handleDeleteClick = useCallback((item: CalendarEvent) => {
    setSelectedItem(item, 'event');
    setShowEventDetails(null);
    setModal('deleteConfirm', true);
  }, [setShowEventDetails, setSelectedItem, setModal]);

  const handleConfirmDelete = useCallback(() => {
    if (!selectedItem) return;

    if (selectedType === 'announcement') {
      deleteAnnouncementMutation.mutate((selectedItem as Announcement).id);
    } else {
      deleteEventMutation.mutate((selectedItem as CalendarEvent).id);
    }
  }, [selectedItem, selectedType, deleteAnnouncementMutation, deleteEventMutation]);


  const handleEventDrop = useCallback((item: GridItem, newDate: Date) => {
      const formattedDate = newDate.toISOString().split('T')[0];
      if (item.id == null) return;
      const id = Number(item.id);
      if (isNaN(id)) return;
      const event = item as unknown as CalendarEvent;
      updateEventMutation.mutate({ id, data: { ...event, date: formattedDate } as EventFormData });
  }, [updateEventMutation]);

  // Calendar data processing
  const calendarData = useCalendarData({ currentDate, events, showHolidays, holidays: (holidays as unknown as Holiday[]).map(h => ({ ...h, name: h.name || h.title || '' })), announcements, schedules });
  const { month, day, year, dayName, displayedEvents } = calendarData;
  
  const isDeleting = deleteEventMutation.isPending || deleteAnnouncementMutation.isPending;

  return (
    <DndProvider backend={HTML5Backend}>
      <div className="flex h-screen bg-[#274b46] overflow-hidden">
        {/* MAIN CALENDAR AREA */}
        <div className="flex-1 flex flex-col">
          <CalendarHeader month={month} year={year} />

          <CalendarControls
            onPrevMonth={navigation.handlePrevMonth}
            onNextMonth={navigation.handleNextMonth}
            onToday={navigation.handleToday}
            showHolidays={showHolidays}
            onToggleHolidays={() => setShowHolidays(!showHolidays)}
            currentView={currentView}
            onViewChange={setCurrentView}
            allowedViews={['month', 'agenda']}
            actions={
              <>
                <AdminCalendarActions
                  onOpenDrawer={() => setIsDrawerOpen(true)}
                />
              </>
            }
          />

          {/* Calendar Body - Conditional View Rendering */}
          <div className="flex-1 overflow-auto p-8 bg-[#F8F9FA]">
            {currentView === 'month' && (
              <CalendarGrid
                currentDate={currentDate}
                today={today}
                onDateClick={navigation.handleDateClick}
                showHolidays={showHolidays}
                holidays={holidays as unknown as GridItem[]}
                announcements={announcements}
                events={events}
                displayedEvents={displayedEvents}
                onEventDrop={handleEventDrop}
              />
            )}
            {currentView === 'agenda' && (
              <AdminAgendaView
                events={events}
                announcements={announcements}
                schedules={schedules}
                onAddEvent={() => handleAddEventClick('09:00')}
                onEditEvent={handleEditEvent}
                onDeleteEvent={handleDeleteClick}
                onAddAnnouncement={() => setModal('createAnnouncement', true)}
                onEditAnnouncement={handleEditAnnouncement}
                onDeleteAnnouncement={handleDeleteAnnouncement}
              />
            )}
          </div>
        </div>

        {/* DRAWER SIDEBAR */}
        <DrawerSidebar
          isOpen={isDrawerOpen}
          onClose={() => setIsDrawerOpen(false)}
          currentDate={currentDate}
          today={today}
          month={month}
          year={year}
          onDateClick={navigation.handleDateClick}
          onPrevMonth={navigation.handlePrevMonth}
          onNextMonth={navigation.handleNextMonth}
          displayedEvents={displayedEvents}
          hours={HOURS_12}
          onEventClick={(e) => setShowEventDetails(e as CalendarDisplayItem)}
          showHolidays={showHolidays}
          holidays={(holidays as unknown as Holiday[]).map(h => ({ ...h, name: h.name || h.title || '' }))}
          announcements={announcements}
        />

        {/* Event Details Modal */}
        {showEventDetails && (
          <EventDetailsModal
            event={showEventDetails as unknown as CalendarEvent}
            onClose={() => setShowEventDetails(null)}
            hours={HOURS_12}
            month={month}
            day={day}
            dayName={dayName}
            isAdmin={true}
            onEdit={handleEditEvent}
            onDelete={handleDeleteClick}
          />
        )}

        {/* Announcement Modal */}
        <CreateAnnouncementModal
          show={modals.createAnnouncement}
          onClose={() => setModal('createAnnouncement', false)}
          onCreate={handleCreateAnnouncement}
          hours={HOURS_LIST}
        />

        {/* Edit Announcement Modal */}
        <EditAnnouncementModal
          show={modals.editAnnouncement}
          announcement={selectedItem as Announcement}
          onClose={() => {
            setModal('editAnnouncement', false);
            setSelectedItem(null, null);
          }}
          onUpdate={(id, data) => handleUpdateAnnouncement(id, data)}
          hours={HOURS_LIST}
        />



        {/* Confirm Delete Modal */}
        <ConfirmDeleteModal
          show={modals.deleteConfirm}
          title="Confirm Deletion"
          message={`Are you sure you want to delete "${(selectedItem as CalendarItem)?.title || 'this item'}"? This action cannot be undone.`}
          onConfirm={handleConfirmDelete}
          onCancel={() => {
            setModal('deleteConfirm', false);
            setSelectedItem(null, null);
          }}
          isDeleting={isDeleting}
        />
      </div>
    </DndProvider>
  );
}

import React, { useState } from 'react';
import { AdminDTRHeader } from "@features/DailyTimeRecord/components/Admin/AdminDTRHeader";
import { AdminDTRNotification } from "@features/DailyTimeRecord/components/Admin/AdminDTRNotification";
import { AdminDTRFilters } from "@features/DailyTimeRecord/components/Admin/AdminDTRFilters";
import { AdminDTRTable } from "@features/DailyTimeRecord/components/Admin/AdminDTRTable";
import { AdminDTRPagination } from "@features/DailyTimeRecord/components/Admin/AdminDTRPagination";
import { AdminDTREditModal } from "@features/DailyTimeRecord/components/Admin/AdminDTREditModal";
import { ReviewCorrectionModal } from "@features/DailyTimeRecord/components/Admin/ReviewCorrectionModal";
import { useAdminDTR } from "@features/DailyTimeRecord/hooks/Admin/useAdminDTR";
import { dtrApi } from "@api/dtrApi";
import { DTRRecord } from "@features/DailyTimeRecord/Utils/adminDTRUtils";

const DailyTimeRecord = () => {
  const {
    sidebarOpen,
    filters,
    searchQuery,
    debouncedSearchQuery,
    currentPage,
    isLoading,
    error,
    successMessage,
    paginationData,
    totals,
    uniqueDepartments,
    uniqueEmployees,
    editingRecord,
    
    // Setters
    setEditingRecord,
    setError,
    setSuccessMessage,
    
    // Handlers
    handleFilterChange,
    handleApply,
    handleClear,
    handleSearchChange,
    handleRefresh,
    handlePrevPage,
    handleNextPage,
    getStatusBadge,
    handleEdit,
    handleSaveEdit
  } = useAdminDTR();

  // --- Review Correction State ---
  const [reviewingRecord, setReviewingRecord] = useState<DTRRecord | null>(null);

  const handleReview = (item: DTRRecord) => {
    setReviewingRecord(item);
  };

  const handleApproveCorrection = async (id: number) => {
    try {
      await dtrApi.updateCorrectionStatus([id], 'Approved');
      setSuccessMessage('Correction request approved successfully.');
      handleRefresh();
    } catch (err: unknown) {
      const errorMsg = err instanceof Error ? err.message : 'Failed to approve correction.';
      setError(errorMsg);
    }
  };

  const handleRejectCorrection = async (id: number, reason: string) => {
    try {
      await dtrApi.updateCorrectionStatus([id], 'Rejected', reason);
      setSuccessMessage('Correction request rejected.');
      handleRefresh();
    } catch (err: unknown) {
      const errorMsg = err instanceof Error ? err.message : 'Failed to reject correction.';
      setError(errorMsg);
    }
  };

  const currentItems = paginationData.currentItems;
  const today = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

  return (
    <div className={`min-h-screen flex flex-col bg-gradient-to-br from-neutral-100 to-stone-100 rounded-xl shadow-xl p-7 w-full overflow-hidden text-gray-800 transition-all duration-300 ${sidebarOpen ? 'max-w-[1400px] xl:max-w-[77vw]' : 'max-w-[1600px] xl:max-w-[88vw]'}`}>
      <AdminDTRHeader 
        today={today}
        handleRefresh={handleRefresh}
        isLoading={isLoading}
      />

      {error && (
        <AdminDTRNotification 
          type="error"
          message={error}
          onClose={() => setError(null)}
        />
      )}

      {successMessage && (
         <AdminDTRNotification 
         type="success"
         message={successMessage}
         onClose={() => setSuccessMessage(null)}
       />
      )}

      <AdminDTRFilters 
        uniqueDepartments={uniqueDepartments}
        uniqueEmployees={uniqueEmployees}
        isLoading={isLoading}
      />

      <AdminDTRTable 
        currentItems={currentItems}
        getStatusBadge={getStatusBadge}
        debouncedSearchQuery={debouncedSearchQuery}
        filters={filters}
        onEdit={handleEdit}
        onReview={handleReview}
        totals={totals}
      />

      {paginationData && (
        <AdminDTRPagination 
          startIndex={paginationData.startIndex}
          endIndex={paginationData.endIndex}
          totalRecords={paginationData.totalRecords || 0}
          currentPage={currentPage}
          totalPages={paginationData.totalPages}
          handlePrevPage={handlePrevPage}
          handleNextPage={handleNextPage}
          isLoading={isLoading}
        />
      )}

      <AdminDTREditModal 
        isOpen={!!editingRecord}
        onClose={() => setEditingRecord(null)}
        onSave={handleSaveEdit}
        record={editingRecord}
      />

      <ReviewCorrectionModal
        isOpen={!!reviewingRecord}
        onClose={() => setReviewingRecord(null)}
        record={reviewingRecord}
        onApprove={handleApproveCorrection}
        onReject={handleRejectCorrection}
      />
    </div>
  );
};

export default DailyTimeRecord;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useUIStore } from '@/stores';
  
// Hooks
import { 
  useAdminLeaveData, 
  useAdminLeaveFilters, 
  useExport,
  useCredits 
} from '@features/LeaveRequests/hooks/Admin';

// Components
// Components - Direct imports for faster initial parse
import Header from '@features/LeaveRequests/components/Admin/Header';
import Filters from '@features/LeaveRequests/components/Admin/Filters';
import SearchBar from '@features/LeaveRequests/components/Admin/SearchBar';
import Table from '@features/LeaveRequests/components/Admin/Table';
import LoadingSpinner from '@features/LeaveRequests/components/Admin/LoadingSpinner';
import ErrorAlert from '@features/LeaveRequests/components/Admin/ErrorAlert';
import SuccessAlert from '@features/LeaveRequests/components/Admin/SuccessAlert';
const CreditsTable = React.lazy(() => import('@features/LeaveRequests/components/Admin/CreditsTable'));
import Pagination from '@/components/CustomUI/Pagination';

// Modals
const ApproveModal = React.lazy(() => import('@features/LeaveRequests/Modals/Approve'));
const RejectModal = React.lazy(() => import('@features/LeaveRequests/Modals/Reject'));
const ProcessModal = React.lazy(() => import('@features/LeaveRequests/Modals/Process'));
const AddCreditModal = React.lazy(() => import('@features/LeaveRequests/Modals/AddCreditModal'));
const EditCreditModal = React.lazy(() => import('@features/LeaveRequests/Modals/EditCreditModal'));
// ConfirmDeleteModal is a named export, so handle differently or change export
// Assuming ConfirmDeleteModal is default export in its file or handled via module
const DeleteCreditModal = React.lazy(() => import('@features/LeaveRequests/Modals/DeleteCreditModal'));

// API YAN BOI OK!
import { useFilterOptions } from '@/hooks/useFilterOptions';
import { AddCreditInput, CreditUpdateInput } from '@/schemas/creditsSchema';
import type { LeaveCredit, AdminLeaveRequest } from '@features/LeaveRequests/types';

const AdminLeaveRequest = () => {
  const today = useMemo(() => new Date().toLocaleDateString('en-US'), []);
  const sidebarOpen = useUIStore((state) => state.sidebarOpen);
  const [activeTab, setActiveTab] = useState<'requests' | 'credits'>('requests');

  // Request Management State
  const [errorObj, setErrorObj] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  
  // Modal states
  const [approveModal, setApproveModal] = useState<{ isOpen: boolean; request: AdminLeaveRequest | null }>({ isOpen: false, request: null });
  const [rejectModal, setRejectModal] = useState<{ isOpen: boolean; request: AdminLeaveRequest | null }>({ isOpen: false, request: null });
  const [processModal, setProcessModal] = useState<{ isOpen: boolean; request: AdminLeaveRequest | null }>({ isOpen: false, request: null });
  
  // Credits Modal States
  const [isAddCreditOpen, setIsAddCreditOpen] = useState(false);
  const [editCredit, setEditCredit] = useState<{isOpen: boolean, data: LeaveCredit | null}>({ isOpen: false, data: null });
  const [deleteCredit, setDeleteCredit] = useState<{isOpen: boolean, data: LeaveCredit | null}>({ isOpen: false, data: null });

  // Fetch Filter Options using Centralized Hook
  const { data: filterOptions, isLoading: loadingFilters } = useFilterOptions();
  const departmentOptions = filterOptions.departments;
  const employeeOptions = filterOptions.employees.map(e => e.name);


  // Custom hooks
  // Note: useAdminLeaveData now manages state internally (page, limit, filters)
  const { 
    leaves, 
    loading, 
    error: dataError, 
    refreshLeaves, 
    pagination, 
    setPage, 
    updateFilters 
  } = useAdminLeaveData();

  // We still use useAdminLeaveFilters to manage the "Draft" state of the filter form
  const {
    filters: draftFilters,
    appliedFilters,
    searchQuery,
    debouncedSearchQuery,
    handleFilterChange,
    handleApplyFilters,
    handleSearchChange,
    handleClear
  } = useAdminLeaveFilters();

  // Credits Hook
  const { 
    credits, 
    pagination: creditsPagination,
    setPage: setCreditsPage,
    search: creditsSearch,
    setSearch: setCreditsSearch,
    isLoading: loadingCredits, 
    employees: allEmployees, 
    isLoadingEmployees, 
    updateCredit, 
    isUpdating, 
    deleteCredit: removeCredit, 
    isDeleting 
  } = useCredits();

  // Auto-dismiss messages
  useEffect(() => {
    if (errorObj || dataError) {
      const timer = setTimeout(() => setErrorObj(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [errorObj, dataError]);

  useEffect(() => {
    if (successMessage) {
      const timer = setTimeout(() => setSuccessMessage(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [successMessage]);

  // Sync Search with Server
  useEffect(() => {
    updateFilters({ search: debouncedSearchQuery });
  }, [debouncedSearchQuery]);

  // Sync Applied Filters with Server
  useEffect(() => {
    // When "Apply" is clicked in filters, we update the server filters
    updateFilters({
      department: String(appliedFilters.department || ''),
      employee: String(appliedFilters.employee || ''), 
      fromDate: String(appliedFilters.fromDate || ''),
      toDate: String(appliedFilters.toDate || '')
    });
  }, [appliedFilters]);

  // Sync Clear Action
  // We need to detect when filters are cleared. 
  // simplified: just rely on the effect above IF appliedFilters updates to empty strings on clear.
  // Checking useAdminLeaveFilters: handleClear sets pending and applied to empty strings. So the effect above covers it.

  const handleRefresh = useCallback(async () => {
    await refreshLeaves();
    setSuccessMessage('Data refreshed!');
  }, [refreshLeaves]);

  // Modal handlers
  const openApproveModal = useCallback((request: AdminLeaveRequest) => {
    setApproveModal({ isOpen: true, request });
  }, []);

  const openRejectModal = useCallback((request: AdminLeaveRequest) => {
    setRejectModal({ isOpen: true, request });
  }, []);

  const openProcessModal = useCallback((request: AdminLeaveRequest) => {
    setProcessModal({ isOpen: true, request });
  }, []);

  const closeApproveModal = useCallback(() => {
    setApproveModal({ isOpen: false, request: null });
  }, []);

  const closeRejectModal = useCallback(() => {
    setRejectModal({ isOpen: false, request: null });
  }, []);

  const closeProcessModal = useCallback(() => {
    setProcessModal({ isOpen: false, request: null });
  }, []);

  const handleActionSuccess = useCallback(() => {
    closeApproveModal();
    closeRejectModal();
    closeProcessModal();
    refreshLeaves();
    setSuccessMessage('Action completed successfully!');
  }, [closeApproveModal, closeRejectModal, closeProcessModal, refreshLeaves]);

  // Credits handlers
  const handleAddCreditSubmit = async (data: AddCreditInput) => {
    await updateCredit({
      employeeId: data.employeeId,
      creditType: data.creditType,
      balance: data.balance
    });
  };

  const handleEditCreditSubmit = async (data: CreditUpdateInput) => {
    if (!editCredit.data) return;
    await updateCredit({
      employeeId: editCredit.data.employeeId,
      creditType: data.creditType,
      balance: data.balance
    });
  };

  const handleDeleteConfirm = async () => {
    if (!deleteCredit.data) return;
    await removeCredit({
      employeeId: String(deleteCredit.data.employeeId),
      creditType: deleteCredit.data.creditType // Corrected to creditType
    });
    setDeleteCredit({ isOpen: false, data: null });
  };

  // Combined error
  const currentError = errorObj || dataError;

  return (
    <div className={`min-h-screen flex flex-col bg-gradient-to-br from-neutral-100 to-stone-50 rounded-xl shadow-xl p-7 w-full overflow-hidden text-gray-800 transition-all duration-300 ${sidebarOpen ? 'max-w-[1400px] xl:max-w-[77vw]' : 'max-w-[1600px] xl:max-w-[88vw]'}`}>
      
      {/* Header */}
      <Header 
        onRefresh={handleRefresh}
        isLoading={loading}
        today={today}
      />

      <hr className="mb-6 h-px bg-gray-200 border-0" />

      {/* Tabs */}
      <div className="flex space-x-1 bg-gray-100 p-1 rounded-xl mb-6 w-fit">
        <button
          onClick={() => setActiveTab('requests')}
          className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg transition-all ${
            activeTab === 'requests' 
              ? 'bg-white text-gray-700 shadow-sm' 
              : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
          }`}
        >
          Leave Requests
        </button>
        <button
          onClick={() => setActiveTab('credits')}
          className={`flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg transition-all ${
            activeTab === 'credits' 
              ? 'bg-white text-gray-700 shadow-sm' 
              : 'text-gray-500 hover:text-gray-700 hover:bg-gray-50'
          }`}
        >
          Credits Management
        </button>
      </div>

      {/* Content */}
      {activeTab === 'credits' ? (
          <div className="flex flex-col h-full space-y-4">
              <React.Suspense fallback={<LoadingSpinner />}>
                <CreditsTable 
                  credits={credits}
                  loading={loadingCredits}
                  pagination={creditsPagination}
                  onPageChange={setCreditsPage}
                  searchTerm={creditsSearch}
                  onSearchChange={setCreditsSearch}
                  onAdd={() => setIsAddCreditOpen(true)}
                  onEdit={(credit) => setEditCredit({ isOpen: true, data: credit })}
                  onDelete={(credit) => setDeleteCredit({ isOpen: true, data: credit })}
                />
              </React.Suspense>

              <React.Suspense fallback={null}>
                  <AddCreditModal 
                    isOpen={isAddCreditOpen}
                    onClose={() => setIsAddCreditOpen(false)}
                    onSubmit={handleAddCreditSubmit}
                    employees={allEmployees}
                    isLoadingEmployees={isLoadingEmployees}
                    isSubmitting={isUpdating}
                  />

                  {editCredit.data && (
                    <EditCreditModal 
                      isOpen={editCredit.isOpen}
                      onClose={() => setEditCredit({ isOpen: false, data: null })}
                      onSubmit={handleEditCreditSubmit}
                      credit={editCredit.data}
                      isSubmitting={isUpdating}
                    />
                  )}

                  <DeleteCreditModal 
                    isOpen={deleteCredit.isOpen}
                    onClose={() => setDeleteCredit({ isOpen: false, data: null })}
                    onConfirm={handleDeleteConfirm}
                    isDeleting={isDeleting}
                    credit={deleteCredit.data}
                  />
              </React.Suspense>
          </div>
      ) : (
          <div className="flex flex-col h-full space-y-4">
              {/* Alerts */}
              <ErrorAlert message={currentError} />
              <SuccessAlert message={successMessage} />

              {/* Filters */}
              <Filters
                filters={draftFilters}
                departments={departmentOptions}
                uniqueEmployees={employeeOptions}
                onFilterChange={handleFilterChange}
                onApply={handleApplyFilters}
                onClear={handleClear}
              />
              {/* Search */}
              <SearchBar
                searchQuery={searchQuery}
                onChange={handleSearchChange}
              />

              {/* Table */}
              {loading && leaves.length === 0 ? (
                 <LoadingSpinner />
              ) : (
                 <Table
                    data={leaves}
                    onOpenApprove={openApproveModal}
                    onOpenReject={openRejectModal}
                    onOpenProcess={openProcessModal}
                 />
              )}

              {/* Server-Side Pagination */}
              <Pagination
                currentPage={pagination.page}
                totalPages={pagination.totalPages}
                totalItems={pagination.totalItems}
                onPageChange={setPage}
                itemsPerPage={pagination.limit}
              />

              {/* Modals - Lazy Loaded */}
              <React.Suspense fallback={null}>
                {approveModal.request && (
                    <ApproveModal
                    isOpen={approveModal.isOpen}
                    request={approveModal.request}
                    onConfirm={handleActionSuccess}
                    onCancel={closeApproveModal}
                    />
                )}

                {rejectModal.request && (
                    <RejectModal
                    isOpen={rejectModal.isOpen}
                    request={rejectModal.request}
                    onConfirm={handleActionSuccess}
                    onCancel={closeRejectModal}
                    />
                )}

                {processModal.request && (
                    <ProcessModal
                    isOpen={processModal.isOpen}
                    request={processModal.request}
                    onConfirm={handleActionSuccess}
                    onCancel={closeProcessModal}
                    />
                )}
              </React.Suspense>
          </div>
      )}
    </div>
  );
};

export default AdminLeaveRequest;

import { useQuery } from '@tanstack/react-query';
import { DndProvider } from 'react-dnd';
import { HTML5Backend } from 'react-dnd-html5-backend';
import {
  useCalendarState,
  useCalendarNav,
  useCalendarData,
  HOURS_12,
  EVENT_COLORS,
  CalendarHeader,
  CalendarControls,
  CalendarGrid,
  EventDetailsModal,
  DrawerSidebar,
  getRandomEventColor
} from '@components/Custom/CalendarComponents/shared';

import { EmployeeCalendarActions } from '@components/Custom/CalendarComponents/employee/components';
import { useHolidays } from '@/hooks/useLeave';
import { announcementApi, eventApi, scheduleApi } from '@api';
import { CalendarEvent, Holiday, ScheduleEntry } from '@/types/calendar';

export default function EmployeeCalendar() {
  // Calendar state management
  const calendarState = useCalendarState();
  const {
    today,
    currentDate,
    setCurrentDate,
    isDrawerOpen,
    setIsDrawerOpen,
    showHolidays,
    setShowHolidays,
    showEventDetails,
    setShowEventDetails
  } = calendarState;

  // Navigation handlers
  const navigation = useCalendarNav({ setCurrentDate });

  // Events query
  const { data: events = [] } = useQuery({
    queryKey: ['events'],
    queryFn: async () => {
      const response = await eventApi.getEvents();
      return response.data?.events?.map((e: CalendarEvent) => ({
        ...e,
        color: getRandomEventColor(EVENT_COLORS)
      })) || [];
    }
  });

  // Announcements query
  const { data: announcements = [] } = useQuery({
    queryKey: ['announcements'],
    queryFn: async () => {
      const response = await announcementApi.getAnnouncements();
      return response.data?.announcements || [];
    }
  });

  // Schedules query
  const { data: schedules = [] } = useQuery<ScheduleEntry[]>({
    queryKey: ['schedules-list'],
    queryFn: async () => {
        const response = await scheduleApi.getSchedules();
        return (response.schedules || []) as unknown as ScheduleEntry[];
    }
  });

  // Holidays query
  const { data: holidaysData } = useHolidays(currentDate.getFullYear());
  const holidays = holidaysData?.holidays || [];

  // Calendar data processing
  const calendarData = useCalendarData({
    currentDate,
    events,
    showHolidays,
    holidays: (holidays as unknown as Holiday[]).map(h => ({ ...h, name: h.name || h.title || '' })),
    announcements,
    schedules
  });
  const { month, day, year, dayName, displayedEvents } = calendarData;

  return (
    <DndProvider backend={HTML5Backend}>
      <div className="flex h-screen bg-[#274b46] overflow-hidden">
        {/* MAIN CALENDAR AREA */}
        <div className="flex-1 flex flex-col">
          <CalendarHeader month={month} year={year} />

          <CalendarControls
            onPrevMonth={navigation.handlePrevMonth}
            onNextMonth={navigation.handleNextMonth}
            onToday={navigation.handleToday}
            showHolidays={showHolidays}
            onToggleHolidays={() => setShowHolidays(!showHolidays)}
            actions={
              <EmployeeCalendarActions
                onOpenDrawer={() => setIsDrawerOpen(true)}
              />
            }
          />

          {/* Calendar Body */}
          <div className="flex-1 overflow-auto p-8 bg-[#F8F9FA]">
            <CalendarGrid
              currentDate={currentDate}
              today={today}
              onDateClick={navigation.handleDateClick}
              showHolidays={showHolidays}
              holidays={holidays as unknown as import('@components/Custom/CalendarComponents/shared/components/CalendarGrid').GridItem[]}
              announcements={announcements}
              displayedEvents={displayedEvents}
            />
          </div>
        </div>

        {/* DRAWER SIDEBAR */}
        <DrawerSidebar
          isOpen={isDrawerOpen}
          onClose={() => setIsDrawerOpen(false)}
          currentDate={currentDate}
          today={today}
          month={month}
          year={year}
          onDateClick={navigation.handleDateClick}
          onPrevMonth={navigation.handlePrevMonth}
          onNextMonth={navigation.handleNextMonth}
          displayedEvents={displayedEvents}
          hours={HOURS_12}
          onEventClick={(e) => setShowEventDetails(e as unknown as typeof showEventDetails)}
          showHolidays={showHolidays}
          holidays={(holidays as unknown as Holiday[]).map(h => ({ ...h, name: h.name || h.title || '' }))}
          announcements={announcements}
        />

        {/* Event Details Modal */}
        {showEventDetails && (
          <EventDetailsModal
            event={showEventDetails as unknown as CalendarEvent}
            onClose={() => setShowEventDetails(null)}
            hours={HOURS_12}
            month={month}
            day={day}
            dayName={dayName}
          />
        )}
      </div>
    </DndProvider>
  );
}

import React from 'react';
import { useState, useEffect } from 'react';
import { useUIStore } from '@/stores';
// API
import { leaveApi } from '@/api/leaveApi';
import { useQuery } from '@tanstack/react-query';
// Components
// Components
import { SubmitLeaveRequestModal } from '@/components/Custom/Timekeeping/LeaveRequestComponents/Employee/Modals/SubmitLeaveRequestModal';
import FinalizeModal from '@/components/Custom/Timekeeping/LeaveRequestComponents/Employee/Modals/Finalize';
import Header from '@/features/LeaveRequests/components/Employee/Header';
import LoadingSpinner from '@/features/LeaveRequests/components/Employee/LoadingSpinner';
import ErrorAlert from '@/features/LeaveRequests/components/Employee/ErrorAlert';
import SuccessAlert from '@/features/LeaveRequests/components/Employee/SuccessAlert';
import Filters from '@/features/LeaveRequests/components/Employee/Filters';
import SearchBar from '@/features/LeaveRequests/components/Employee/SearchBar';
import Table from '@/features/LeaveRequests/components/Employee/Table';
import Pagination from '@/components/CustomUI/Pagination';

// Hooks
import { useLeaveData } from '@/features/LeaveRequests/hooks/Employee/useLeaveData';
import { useFilters } from '@/features/LeaveRequests/hooks/Employee/useFilters';
import { EmployeeLeaveRequest } from "@/features/LeaveRequests/types";
import { LeaveStatus } from "@/components/Custom/Timekeeping/LeaveRequestComponents/Employee/constants/leaveConstants";
import type { LeaveBalance, ApplicationStatus, LeaveType } from '@/types/leave.types';

const LeaveRequest = () => {
  const sidebarOpen = useUIStore((state) => state.sidebarOpen);

  // State management
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);
  const [finalizeModal, setFinalizeModal] = useState<{ isOpen: boolean; request: EmployeeLeaveRequest | null }>({ isOpen: false, request: null });
  
  // Custom hooks
  // Extracted server-side pagination/filtering functions
  const { 
    leaves, 
    loading: isLoading, 
    error: dataError, 
    refreshLeaves: refetch, 
    pagination, 
    setPage, 
    updateFilters: updateServerFilters 
  } = useLeaveData();

  // Fetch Credits gamit ang React Query boi
  const { data: credits = [] } = useQuery<LeaveBalance[]>({
    queryKey: ['employee-leave-credits'],
    queryFn: async () => {
      const res = await leaveApi.getMyCredits();
      return res.data?.credits || [];
    },
    staleTime: 1000 * 60 * 10, // 10 minutes
  });
  
  // useFilters para e-manage ang UI state of filters only
  const { 
    filters, 
    appliedFilters, 
    searchQuery, 
    debouncedSearchQuery, 
    handleFilterChange, 
    handleApplyFilters, 
    handleSearchChange, 
    handleClear 
  } = useFilters(leaves); // Passing leaves helps useFilters know data structure, though we don't use its filteredData return anymore for rendering
  

  // Sync Search with Server
  useEffect(() => {
    updateServerFilters({ search: debouncedSearchQuery });
  }, [debouncedSearchQuery]);

  useEffect(() => {
    updateServerFilters({
      startDate: String(appliedFilters.date || ''),
      endDate: appliedFilters.date ? undefined : undefined, 
      status: (appliedFilters.status || '') as ApplicationStatus | '',
      type: (appliedFilters.type || '') as LeaveType | ''
    });
  }, [appliedFilters]);

  // Auto-dismiss messages
  useEffect(() => {
    const error = errorMessage || dataError;
    if (error) {
      const timer = setTimeout(() => {
        setErrorMessage(null);
      }, 5000);
      return () => clearTimeout(timer);
    }
  }, [errorMessage, dataError]);

  useEffect(() => {
    if (successMessage) {
      const timer = setTimeout(() => setSuccessMessage(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [successMessage]);

  // Handle submit modal
  const handleSubmitRequest = () => {
    setSuccessMessage('Leave request submitted successfully!');
    setIsSubmitModalOpen(false);
    refetch();
  };

  const handleOpenFinalize = (request: EmployeeLeaveRequest) => {
    setFinalizeModal({ isOpen: true, request });
  };

  const handleFinalizeSuccess = () => {
    setSuccessMessage('Leave request finalized successfully!');
    setFinalizeModal({ isOpen: false, request: null });
    refetch();
  };

  // Combined error message
  const currentError = errorMessage || dataError;

  return (
    <div className={`min-h-screen flex flex-col bg-gradient-to-br from-neutral-100 to-stone-50 rounded-xl shadow-xl p-7 w-full overflow-hidden text-gray-800 transition-all duration-300 ${!sidebarOpen ? 'max-w-[1600px] xl:max-w-[88vw]' : 'max-w-[1400px] xl:max-w-[77vw]'}`}>
      {/* Header */}
      <Header 
        onRefresh={refetch}
        isLoading={isLoading}
      />

      <hr className="mb-6 h-px bg-gray-200 border-0" />

      {/* Alerts */}
      <ErrorAlert 
        message={currentError} 
        onDismiss={() => setErrorMessage(null)} 
      />
      <SuccessAlert 
        message={successMessage} 
        onDismiss={() => setSuccessMessage(null)} 
      />

      {/* Filters */}
      <Filters 
        filters={filters}
        onFilterChange={handleFilterChange}
        onApplyFilters={handleApplyFilters}
        onClear={handleClear}
        onNewRequest={() => setIsSubmitModalOpen(true)}
        isLoading={isLoading}
        hasCredits={credits.length > 0 && credits.some((c) => c.balance > 0)}
      />

      {/* Search, Credits, and Create Button Row */}
      <div className="flex items-center justify-between gap-4 mb-6">
        {/* Search Bar */}
        <div className="relative flex-1 max-w-md">
           <SearchBar 
              searchQuery={searchQuery}
              onChange={handleSearchChange}
              isLoading={isLoading}
              resultCount={pagination.totalItems}
           />
        </div>

        {/* Right Side: Credits + Create Button */}
        <div className="flex items-center gap-4">
            {/* Credit Cards - Enhanced */}
            <div className="flex items-center gap-2">
              {credits.map((credit, idx) => (
                <div 
                  key={idx} 
                  className="bg-white px-3 h-10 rounded-md border border-gray-200 shadow-sm flex flex-col justify-center min-w-[100px] transition-all hover:shadow-md hover:border-gray-300"
                >
                  <span className="text-[9px] font-bold text-gray-400 capitalize whitespace-nowrap leading-tight">
                    {credit.creditType.replace(' Leave', '').toLowerCase()}
                  </span>
                  <div className="flex items-baseline gap-1 leading-tight">
                    <span className={`text-sm font-black tracking-tight ${Number(credit.balance || 0) > 0 ? 'text-gray-900' : 'text-gray-400'}`}>
                      {Number(credit.balance || 0).toFixed(1)}
                    </span>
                    <span className="text-[8px] font-medium text-gray-400 uppercase">Days</span>
                  </div>
                </div>
              ))}
            </div>

            {/* Create New Request Button */}
            <button
              onClick={() => setIsSubmitModalOpen(true)}
              className="flex items-center gap-2 px-4 h-10 bg-gray-900 text-white rounded-md font-bold shadow-md hover:bg-gray-800 transition-all active:scale-95 whitespace-nowrap text-xs"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M5 12h14"></path>
                <path d="M12 5v14"></path>
              </svg>
              New Request
            </button>
        </div>
      </div>

      {/* Table */}
      {isLoading && leaves.length === 0 ? (
        <LoadingSpinner />
      ) : (
        <Table 
          data={leaves}
          searchQuery={debouncedSearchQuery}
          filters={filters}
          onFinalize={(req) => handleOpenFinalize(req)}
        />
      )}

      {/* Server-Side Pagination */}
      <Pagination 
        currentPage={pagination.page}
        totalPages={pagination.totalPages}
        totalItems={pagination.totalItems}
        onPageChange={setPage}
        itemsPerPage={pagination.limit}
      />

      {/* Submit Leave Request Modal */}
      <SubmitLeaveRequestModal
        isOpen={isSubmitModalOpen}
        onSubmit={handleSubmitRequest}
        onClose={() => setIsSubmitModalOpen(false)}
        credits={credits}
      />

      {/* Finalize Modal */}
      {finalizeModal.request && (
        <FinalizeModal
          isOpen={finalizeModal.isOpen}
          request={finalizeModal.request}
          onConfirm={handleFinalizeSuccess}
          onCancel={() => setFinalizeModal({ isOpen: false, request: null })}
        />
      )}
    </div>
  );
};

export default LeaveRequest;

import { z } from 'zod';
import { EDUCATION_LEVELS } from './recruitment';
import { createIdValidator, ID_REGEX } from './idValidation';
import { PdsQuestionsSchema } from './pdsSchema';

export const LoginSchema = z.object({
  identifier: z.string().min(1, "Email or Employee ID is required"),
  password: z.string().min(1, "Password is required")
});

export const RegisterSchema = z.object({
  employeeId: z.string().optional(),
  firstName: z.string().min(1, "First name is required"),
  lastName: z.string().min(1, "Last name is required"),
  middleName: z.string().optional(),
  suffix: z.string().optional(),
  
  // Address
  address: z.string().optional(),
  isMeycauayan: z.string(), // "true" or "false"
  barangay: z.string().optional(),

  email: z.string().email("Invalid email format"),
  password: z.string()
    .min(8, "Password must be at least 8 characters")
    .regex(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/, "Password must contain at least one uppercase letter, one lowercase letter, and one number")
    .optional().or(z.literal("")),
  role: z.enum(["Administrator", "Human Resource", "Employee"]).optional(),
  department: z.string().optional(),
  position: z.string().optional(),
  dutyType: z.enum(["Standard", "Irregular"]),
  appointmentType: z.enum(['Permanent', 'Contractual', 'Casual', 'Job Order', 'Coterminous', 'Temporary', 'Contract of Service', 'JO', 'COS', '']).optional(),
  dateHired: z.string().optional(),
  avatar: z.instanceof(File).optional(),

  // Personal Info
  birthDate: z.string().optional(),
  placeOfBirth: z.string().optional(),
  gender: z.enum(["Male", "Female", ""]).optional(),
  civilStatus: z.enum(["Single", "Married", "Widowed", "Separated", "Annulled", ""]).optional(),
  nationality: z.string().optional(),
  bloodType: z.string().optional(),
  heightM: z.string().optional(),
  weightKg: z.string().optional(),

  // Contact & Detailed Address
  resRegion: z.string().optional(),
  resProvince: z.string().optional(),
  resCity: z.string().optional(),
  resArea: z.string().optional(),
  resHouseBlockLot: z.string().optional(),
  resSubdivision: z.string().optional(),
  resBrgy: z.string().optional(),
  resStreet: z.string().optional(),
  permRegion: z.string().optional(),
  permProvince: z.string().optional(),
  permCity: z.string().optional(),
  permBrgy: z.string().optional(),
  permStreet: z.string().optional(),
  permHouseBlockLot: z.string().optional(),
  permSubdivision: z.string().optional(),
  
  residentialAddress: z.string().optional(),
  residentialZipCode: z.string().optional(),
  permanentAddress: z.string().optional(),
  permanentZipCode: z.string().optional(),
  telephoneNo: z.string().optional(),
  mobileNo: z.string().optional(),
  emergencyContact: z.string().optional(),
  emergencyContactNumber: z.string().optional(),

  // Government Identification
  gsisNumber: createIdValidator(ID_REGEX.GSIS, "GSIS Number").optional().nullable().or(z.literal('')),
  pagibigNumber: createIdValidator(ID_REGEX.PAGIBIG, "Pag-IBIG Number").optional().nullable().or(z.literal('')),
  philhealthNumber: createIdValidator(ID_REGEX.PHILHEALTH, "PhilHealth Number").optional().nullable().or(z.literal('')),
  umidNumber: createIdValidator(ID_REGEX.UMID, "UMID Number").optional().nullable().or(z.literal('')),
  philsysId: createIdValidator(ID_REGEX.PHILSYS, "PhilSys ID").optional().nullable().or(z.literal('')),
  tinNumber: createIdValidator(ID_REGEX.TIN, "TIN").optional().nullable().or(z.literal('')),
  agencyEmployeeNo: z.string().optional().nullable().or(z.literal('')),

  // Educational Background
  educationalBackground: z.enum(EDUCATION_LEVELS).or(z.literal('')).optional(),
  schoolName: z.string().optional(),
  course: z.string().optional(),
  yearGraduated: z.string().optional(),
  yearsOfExperience: z.string().optional(),
  experience: z.string().optional(),
  skills: z.string().optional(),

  // Eligibility
  eligibilityType: z.string().optional(),
  eligibilityNumber: z.string().optional(),
  eligibilityDate: z.string().optional(),

  // Social & Others
  facebookUrl: z.string().optional().nullable().or(z.literal('')),
  linkedinUrl: z.string().optional().nullable().or(z.literal('')),
  twitterHandle: z.string().optional().nullable().or(z.literal('')),
  ignoreDuplicateWarning: z.boolean().optional(),

  // Applicant data linking (auto-populated when pre-filling from hired applicant)
  applicantId: z.number().optional(),
  applicantHiredDate: z.string().optional(),
  applicantStartDate: z.string().optional(),
  applicantPhotoPath: z.string().optional(),
  dateAccomplished: z.string().optional(),
  pdsQuestions: PdsQuestionsSchema,
  isOldEmployee: z.boolean().optional().default(false),
}).superRefine((data, ctx) => {
  if (data.isMeycauayan === "true") {
    if (!data.barangay || data.barangay.length === 0) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Barangay is required",
        path: ["barangay"],
      });
    }
  } else {
    if (!data.address || data.address.length === 0) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Address is required",
        path: ["address"],
      });
    }
  }

  // Duty Type Conditional Validation
  if (data.dutyType === "Standard") {
    const requiredGovIds = [
      { key: "gsisNumber", name: "GSIS" },
      { key: "pagibigNumber", name: "Pag-IBIG" },
      { key: "philhealthNumber", name: "PhilHealth" },
      { key: "tinNumber", name: "TIN" }
    ];

    requiredGovIds.forEach(({ key, name }) => {
      const val = data[key as keyof typeof data];
      if (!val || val === "" || (typeof val === "string" && val.trim() === "")) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: `${name} Number is required for Standard employees`,
          path: [key],
        });
      }
    });

    if (!data.eligibilityType || data.eligibilityType === "none" || data.eligibilityType === "") {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Eligibility is required for Standard employees",
        path: ["eligibilityType"],
      });
    }
  }
});

